INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1321, 67, '용서에 대해, 그리고 지금 이순간이 정말 소중하다고 생각들게 만들어주는 책이네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1322, 67, '무언가를 바라보는 시선이 참 중요하다 느낀 책결국 나를 펑펑울린. 공지영책중에 제일 좋아하는 책이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1323, 67, '감수성 풍부할때 펑펑 울며 보다 책장을 넘기기도 힘들었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1324, 67, '행복한 시간이라는것에 대해 다시금 생각하게 하는 글. 공지영씨 책 중에 제일 좋아하는 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1325, 67, '책으로만 보고 영화는 보지 않았는데.. 영화도 기회가 되면 봐야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1326, 67, '더 깊은 어둠을 작가는 바라보지 않는다.독자들이견뎌낼수있는적당한어둠만을고른..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1327, 67, '잘살고 싶다 제대로 살고싶다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1328, 67, '몇 년 전까지만 해도 나는 외로움에 쉽게 무너지는 인간이었다. 예고도 없이 찾아드는 이 감정에 사무칠 때면, 지독한 생각의 저주에 갇혀서 헤어 나오질 못했다. 그랬었는데 뭐랄까, 이제는 외로움과 제법 어울리며 살고 있다. 고독은 부딪혀야 할 대상이 아니라 친구처럼 지내야 한다는 걸 알게 됐다. 혹여 이런 게 세월이 가져다주는 선물이려나.그런데 말이다. 외로움이야 어떻게든 해보겠는데, 소외감만큼은 도무지 꼼짝을 못 하겠다. 그럴 때면 두 팔에 수갑이 채워지고 입에 재갈이 물린 듯한 망상에 빠진다. 또 초라함의 늪에서 솟아나는 불안을 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1329, 67, '공지영의 소설을 읽을 때면 나는 마음 한 켠이 불편해진다. 내 것이 아닌 아픔과 마주쳐야 하는 그 느낌. 외면하고 싶지만 애써 외면할 수 없게 만드는, 어쩌면 내 것일지도 모를 그 아픔으로 내 일상을 조금 저어 놓기 때문이다. 무의미한 생각들 속에서 내 의도와는 상관없이 하고 싶지 않은 고민들이 불쑥 끼어드는 순간의 그런 불편함 말이다. 사형수에 관한 이야기라는 것을 알고 나는 이 책을 읽기가 조금 더 망설여졌던 건지도 모르겠다. 어린 시절의 상처로 인해 세 번이나 자살을 기도한 여자와 마찬가지로 불우한 어린 시절을 보내고 이제...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1330, 67, '지인에게 공지영의 신작소설을 읽었다고 했더니 이 작가를?높이 평가하지 않는 그는?시큰둥한 반응이었다.?그냥 그렇게만 말했으니 망정이지 곧이곧대로 눈물 콧물 다 쏟으며 질질 짜며 읽었다고 했으면?무지하게 민망할 뻔 했다. 읽기는 무척 빨리 읽었는데 읽고 나서는 감정이 복잡했다. 뭔가 신파에 속은 것 같기도 하고, 어쩌다가 그렇게 쉽게 무장해제가 되었는지도 영 모르겠고,?무엇보다 그렇게 휘둘려서 읽은 책을 어떻게 평가를 하나 싶었다. 인기작가라서?그런지 이 작가의 작품들에는 몇가...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1331, 67, '오랜만에 소설을 읽었다. 영화로도 만들어져 히트를 했고, 소설로는 무려 70쇄 가까운 재판을 거듭하고 있는 초대형 베스트셀러, 공지영의 ''우리들의 행복한 시간''이다. ?사실 나는 공지영의 글을 그...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1332, 67, '고등학교 시절 세계사 선생님은, 수업만 가지고 평가한다면 낙제점이었다.? 교재 연구를 과연 하시기는 하는 걸까 생각이 들었으며, 책에 빼곡히 적어오신 요점정리(참고서 수준) 외에 수업에 도움되는 어떤 얘기도 들을 수 없었다.? 학생들 사이에선 졸업할 때 저 책 훔쳐버리면 내년부턴 수업 못하실거야... 라는 얘기가 공공연히 돌았다. 그렇게 수업에 있어서는 박한 점수를 받는 그 선생님은, 그러나 역설적이게도 학생들 사이에서 많은 존경을 받는 분이셨다.? 이유는, 그분이?평소 선행을 많이 하시기 때...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1333, 67, '이건 정말 칭찬이다. 전에 읽었던 공지영은 왠지 제 안에 콕 쳐박혀 좁은 창틈으로 세상을 내어다 보는 작가란 느낌이 강했다.남들에게는 별로 관심이 없고, 그저 제 삶의 무게에 짓눌려 세상을 향해 소리를 지르려고 여린 비명을 지르는 듯한 목소리. 그래서 공지영 소설이 눈에 많이 띄었는데도, 별로 손이 안 갔다고 할 수 있다.그런데, 요즘 유난히 이 책이 여기 저기서 눈에 띄어 가볍게 읽었는데...내용이 전혀 가볍지 않았다. 제목부터가 우리들의 행복한 시간이 뭐냐.''우리''라니... 그리고 ''행복''이라니...공지영은 ''우리''란 말도...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1334, 67, '읽는 내내 마음이 불편했다. 눈물샘이 마르지 않는다는 것이 이런 거구나, 느낄 때가 한 두 번이 아니었다. 한 인간의 비극적이면서도 불행한 삶을 들여다보는 일은 적지 않은 애증이 온 몸을 휘감았다. 더구나 그 대상이 평범한 사람이 아닌 사형수라고 하니 뭐랄까, 날카로운 고통이 아닐 수 없었다. 이처럼 공지영은 『우리들의 행복한 시간』에서 사형수라는 만만치 않는 삶의 무게에 대해 고백을 한다. 어쩌면 사형을 둘러싼 정신적인 암(癌)에 대한 투병이며 휴먼 스토리다. 사형수와 만남과 이별을 통해 죽음을 두려워하는 것이 아니라 오히려 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1335, 67, '영화로 만들어질거라는 이야기를 듣고 구입했었는데, 영화로 개봉되었다는 이야기를 듣고서야 읽게 되었네요. 한편으로는 영화 때문에 읽는 재미가 약간 반감된것도 사실이예요. 대체로 책을 읽을때 정확한 줄거리를 모른채 읽는 경우가 많은데, 영화 덕분에 많은 이야기를 아는 상태에서 책을 읽어서인지 스토리의 신비성과 재미가 떨어지더군요. 반면, 영화 덕분에 읽는동안 머리속에 상황들이 그려지는 장점도 있었습니다. 주인공의 회상신으로 전체적인 줄거리를 알면서도 세부적인 내용들을 조금씩 풀어가는데, 정말 감질맛 나더군요^^ 물론, 그 점이 이 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1336, 67, '감미롭게 속삭이던 나나 무스쿠리의 목소리가 어느새 울음으로 바뀌어 있었다. 테이프 레코더의 볼륨을 높였다. 쓰달픈 이야기가 흘러나오고 있었다. 테리 잭스가 불렀던 을 리메이크한 곡이었는데 무스쿠리의 또렷하면서도 미묘한 떨림이 배어있는 음색이 원곡의 의미를 절절하게 살려내고 있었다.? 문외한인 나도 내용이 빠안히 그려지도록 노랫말 하나하나, 작은 멜로디라인까지 귀에 쏙 들어올 정도였다.? 한동안 흠뻑 취해있는데 2절인가로 넘어가며 아버지에게 마지막 유언...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1337, 67, '출판계 불황에도 불구하고 혼자 이 책 하나로 78만부를 팔아버린 스타 작가. 요즈음 언론에게 공지영을 소개할 때 쓰는 수식어다. ? 너무 유명한 책이라 읽기 싫었다고 하면 어패가 있을까. 공지영이라는 작가를 딱히 싫어하지 않음에도 불구하고 어쩐지 읽기 싫었던 책을, 영화를 보고 나서 읽었다. 그것도 동네 책방에서 700원 주고 빌려다가 말이다. 헌데, 이 책을 쥐고 읽기 시작하면서 나는, 이미 다 알고 있는 내용을 읽고 있음에도 작가의 치밀한 문장과 묘사에 반하여 수시로 이 책을 손에 쥐고 읽어나가면서 급기...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1338, 67, '공지영의 책엔 항상 꼴통틀의 진짜이야기가 있다. 꼴통은 유정이고 윤수이며 상처받은 나이다. 이야기속엔, 상처를 받고 슬픔을 간직한체 아르렁 거리다가 어떤 것을 계기로 그것을 드러내게 되고 치유받는 우리들이 있기 때문이다 이책은 그래서 사형에 대한 것이라기 보다는 삶과 사랑에 관한 이야기를 하고 있는 것이다. 두주인공이 누구나 알아차릴만한 상처를 입은 사람들이라지만 현실의 주인공들도 역시 삶속에서 상처받고 좌절하기를 반복한다. 그것이 아무리 사소한 것일 지라도. 상처란 것은 본래 깊이가 보이지 않는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1339, 67, '가난을 모르는 사람은 인간이 가진 아픔을 진정 다 이해할수 없다고 생각하던 때가 있었다. ?언제였던가. 남부럽지 않은 집안에서 태어나 남부럽지 않은 교육을 받고 또 남부럽지 않게 작가로서 성공한 어느 여류작가가 이런 말을?하던 것을 들은?적이 있었다. 자신은 오히려 가난하고 실패하고 세상의 온갖 처절함과 아픔을 다 겪어본 사람들이 부럽다고, 아픈 그들의 그 치열한 생의 경험들을 자신의 문학속에 다 담아 낼수 없는 것이 아쉽다고...... 나는 그녀의 그 말을 비난했었다. 진정한 아픔과 가난의 고통...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1340, 67, '이 책을 읽으면서... 정말 많이 울었는데... 슬퍼서였는지...감동때문이었는지...잘 모르겠다. 그냥 슬프다기엔 부족한듯하고...감동이란 말은 더더구나 어색한것같다. 가슴이 답답하고 먹먹하고 아팠다고 해야 할까... ? 난 책을 읽을때... 읽는 시점의 내 처지나 고민, 관심사등에 따라... 때론 다른 사람들과는 전혀 다른 관점에서 읽게 되는 경향이 있는데... 이 책을 읽으면서는 유정의 엄마(읽는이들 모두가 이해하지 못했을...어쩜 이런 엄마가 있을까...엄마가 어떻게 이럴수 있을까...생각했을만...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (68, '박종훈의 대담한 경제', 236, 4.84, 0, 0, 3, 31, 202, 233, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1341, 68, '겁 없이 경제이야기를 했다는 뉘앙스를 주는 제목답게 책 속에서는 정부의 재정정책과 경제 관료의 태도, 대기업의 정책을 날카로운 비판하기도 하고, 반대의 입장을 거침없이 일갈합니다. 해서 독자의 입장에서는 유쾌하고 상쾌하고, 통쾌한 이야기이기에 재미있게 읽으며 오늘의 경제위기에 대한 해법을 생각할 수 있어서 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1342, 68, '경제부총리 피부로 경기불황의 늪을 알고 있을까?한국경제에 밑바닥 이책을 읽다보면 보입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1343, 68, '점점 더 침체기에 빠지는 것 같은 대한민국 경제. 어떻게 해야하는지 박종훈 저자의 날카로운 시선으로 바라보는 경제의 모습을 함께 읽으면서 공감하고 고민하며 그 대책을 생각해보고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1344, 68, '대한민국 경제의 흐름과 앞으로의 전망과 생존 전략에 대해서 자세히 배울 수 있는 유익한 도서', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1345, 68, '현재 중요한 경제이슈를 대부분 다루면서 심도 있게 분석해주고 있어서 매우 의미있다. 바쁜 시간이라도 짬을 내서 읽는다면 지금 우리가 어떤 현실에 처해있고 어떻게 대처해야할지 조금은 판단이 설 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1346, 68, '다소 어려운 주제를, 명쾌하고 알기쉽게 정리해 주었다. 최신 경제 동향을 파악하는데 많은 도움을 준다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1347, 68, '마음 깊이 남을 만한 책이엇다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1348, 68, '오옷, 이 책이 나왔네요~ 자본주의 경제에서 살아가는 사람으로서 기다릴 수 밖에 없는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1349, 68, '어려울수록 더많이 알고 더 많이 공부해야 하는 것 같네요 전문가의 입장에서 보는 좀더 쉽게 다가 오네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1350, 68, '지금까지 궁금했던 경제관련 내용들이 이 책 속에 모두 담겨 있습니다. 날카로운 분석, 경제관련 현안들이 쉽게 다가옵니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1351, 68, '경제에 대한 환상이 아닌 현실을 직시할 수 있게 해 주었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1352, 68, '현 경제에 대해 가려운 부분을 시원하게 긁어주는 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1353, 68, '앞으로 곧 다가올 경제불황을 이겨내기 위해서 준비하며 읽어야 할 책!! 경제를 읽는 사람들이 하나같이 이야기하는 경제불황이 계속 이어지고 있고 앞으로도 지금보다 더 나빠지는 것 밖에 안남았다면 월급밖에 보고 살게 없다면 필히 읽고 준비해야 겠네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1354, 68, '한국경제에 대해서 낱낱이 알려주는 책이에요. 앞으로 한국에서 어떻게 살아가야 할지 도움이 되는 것 같습니다. 경제를 잘 모르는 사람들에게 강추!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1355, 68, '현재의 경제 상황이 왜이리됐는지 이 책을 통해서 날카롭게 알수있네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1356, 68, '이 책은 일반인들보다 나라의 살림을 사는 사람들이 먼저 구독을 하고 실천을 해야 하는 책으로 보입니다. 노인문제, 청년실업, 저출산등에 대한 해법으로 국정 교과서에 준하는 책으로 평을 하고 싶습니다. 잘 보았어요. (감사합니다)', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1357, 68, '박종훈님의 책이 드디어 나왔군요! 진정한 실전 경제의 진수를 맛보세요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1358, 68, '경제는 전문가만 하는 것이라고 생각했다. 복잡하고 알 수 없고 가정으로 가득 차 있는 경제를 알기 쉽게 풀어 쓴 글이다. 역시 칼럼을 쓰는 저자답게 눈을 잡아끄는 매력적인 제목하에 세태를 분석하고 미래를 예측할 수 있게 머리에 남도록 글을 써준다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1359, 68, '열심히 읽고 있는데 염소처럼 곱씹고 되새김질해서 잘 소화시키고 싶은 책-이라 진도가 조금 걸리는 책~ 조금 걸려도 시간이 절대 아깝지 않은 책~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1360, 68, '경제 지식을 아는 것은 생존의 문제라는 말이 와 닿을 만큼 경제난으로 너도나도 살기 어려운 시기입니다.경제의 기초 상식부터 우리 경제 현 주소를 냉정히 판단,분석까지 문제점들을 진단하고 또 미래에 대한 예측을 통해 앞으로 우리가 어떤 준비를 해야 될지의 생각을 하게 해 주는 점이 좋네요', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (69, '누가 내 치즈를 옮겼을까?', 235, 3.86, 11, 14, 44, 95, 71, 166, 44, 25);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1361, 69, '나의 치즈는 무엇일까?썩은 치즈는 아닐까?치즈가 사라지거나 곰팡이 피는 걸 나는 알아챌수 있는가?치즈가 사라진 것을 알고나서 난 떠날수있는가?두려움이 있을까?나는 어떤 인물일까?여행과 같은 삶을 살 수 있을까?', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1362, 69, '마음에 힘을 주는책 입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1363, 69, '쉬우면서도 간단하게 잘 읽혔던 책.덕분에 아직까지도 책 내용의 핵심을 잊지않고 노력하며 살아감.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1364, 69, '어떤자식이내 치즈를 옮긴거야 치즈가 요기있넹!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1365, 69, '서점이나 인터넷 책 사이트에서 널리 알려진 글이었지만, 관심 분야가 아니어서 보기를 미루던 책이었다. 얼마나 많은 사람들이 불안해 왔고, 지금도 불안하며, 앞으로에 대해 불안해 하고 있으면 이런 책이 베스트셀러가 되는 것인지 마음이 아팠다.사실 이 이야기가 주는 교훈은 단 한 가지다. 변화는 언제든 생길 수 있으니, 늘 준비하라.그러나, 과연 우리에게 치즈는 있었던 것일까? 우리의 거품 경제에서 거품이 걷히는 지금, 그 속을 제대로 꿰뚫어본다면, 무엇이 남아 있을까. 경공업과 전자산업까지 우리의 목숨줄이었던 경제 기반은 중국과 몇 ...+ 더보기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1366, 69, '추석연휴 마지막 날, 천안서 늦게까지 술을 마시는 바람에 외박을 해야 했다. 같이 마시던 선생님 댁으로 가 아들을 다른 방으로 보내고 거기서 잤다. 습관처럼 6시에 잠을 깼고, 그 선생님이 일어날 때까지 기다리느라 알랭 드 보통의 을 읽었다. 일주 전부터 붙잡고 있던 책인데, 열페이지쯤 남아 있었기에 다 읽고 나니 6시 15분이다. 책꽂이를 보니 가 있다. 이거면 한시간은 버티겠지 하고 책을 폈는데, 읽고 난 소감을 써본다. 1) 러닝타임...+ 더보기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1367, 69, '이 책을 읽어보지 않은 사람이 있다면 대한민국 사람이 아닐 것이다. 맞나?2000년에 친구의 선물로 읽어봤는 데 회사에서 전직원에게 이 책을 권장도서로 1권씩 선물하여 다시한번읽을 수 있었던 책이다. 변화하지 않으면 살 수 없다는 매세지가 강했기에 회사차원에서 권장하지 않았을 까 생각해본다. 이 책의 줄거리는 어느날 시카고의 한 레스토랑에서 고교 동창생 몇명이 둘러 앉아 졸업 후의 변화된 생활에 대해 담소를 나눈다. 이 자리에서 마이클은 자기 호사에 밀어닥친 변화를 제대로 파악하지 못하고 예전방식으로 일을 처리하다 회사를 그만 둘...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1368, 69, '이책은 정말 우연히 읽게 되었다. 솔직히 이런 자그만 책을 사기는 좀 아까워서 서점 같은데 가서도 베스트 셀러라고는 하나.아마 사지는 않게 될 가능성이 많을 것이다. 정말 우연히 누나의 숙제때메 학교도서관에서 빌려와서 보게 되었는데... 첫째로 읽기가 지루하지 않다. 왜? 짧으니까.둘째로 생각의 틀을 바꿔준다. 사실 이걸 읽으면서 놀라웠다.바로 책속의 내용이 나의 내용이기에 그러했다. 책을 읽기전에는 내가 이런사람이란걸 몰랐고, 읽으면서도 몰랐으나. 점점 읽다보니 수긍이 가고 나자신을 1%...아니 0.0001%라도 볼수 있게 해주...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1369, 69, '이 책이 몇 권이나 팔렸을까? 아마 전세계적으로 몇 백만권 정도 팔렸을 것 같다. 그런데, 나는 이 책을 이제서야 읽어보았다. 사실, 안 읽어봐도 거의 뻔한 이야기이기 때문에 아쉬움은 없었으나 보통 사람들이 모여 있는 곳에 괜한 호기심이 생기기 마련이다. 그러면 기웃거리다가 까치발을 딛고 훔쳐보게 된다. 그러나 보통 그렇게 보고 난 후엔 ''아... 저거 별거 아닌데 왜 이렇게 사람이 모여있었지''라고 생각하며 발걸음을 돌리곤 한다. 이 책의 내용은 특별한 것이 없다. 예상대로... 재밌으면 짧아서 아쉬운 느낌이 들텐데 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1370, 69, '오랜만에 책꽂이를 점검했을 때 본 이 책은 노란 표지 만큼이나 정겨운 느낌이다. 혹여 잊어서 서운하지는 않았나 조심스럽게 만져주며 다시 읽었을 때, 그 때의 내용이란 감회가 새롭다.누가 내 치즈를 옮겼을까의 치즈는 단순히 우유로 만든 그 유지제품이 아니다. 그저 돈으로 볼 것도 아니다. 생계 유지수단의 돈, 성공… 그리고 크게는 행복과 생명까지! 치즈와 대처하여...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1371, 69, '30. 누가 내 치즈를 옮겼을까? 사라져 버린 치즈에 대한 미련을 빨리 버릴수록 새 치즈를 빨리 찾을 수 있다. 나에게 치즈라 무엇일까 되세겨 볼 수 있는 시간이었다. 그리고 나는 헴 처럼 새로운 것에 도전할 수 없는 사람인가? 아니면 허 처럼 변화를 두려워 하지 않는 사람인가? 솔직하게 말하면 나는 헴처럼 살고 싶지 않다는 의지를 가지고 있지만 아직 허처럼 행동하지 못하는 것은 아닌가 싶다. 나도 새로운 치즈를 찾는데 게으른 생각을 하지 말아야지.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1372, 69, '한 때 이 책을 읽지 않으면 대화에서 몹시 소외되는 것처럼 느껴질 때가 있었다. 베스트셀러였고, 너도 나도 감동 받았고 자극도 받게 했었다. 내가 이 책을 읽었을 때도 마찬가지였다. 그래! 우물쭈물하고 있을 때가 아니야! 앉아서 기회가 오길 기다려선 안 돼지! 이 자리를 박차고 나가 열심히 달려야 해! 라고. 사실 그건 어떤 감동이나 감상 이전에 책이 가르쳐 준 교본대로 내가 반응한 것과 다름 없었다. 그게 문제라고도 생각해본 적 없었다. 그런데... 좀 지나서 생각해 보니 탐탁치...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1373, 69, '" 책에 나오는 우화는 바로 일상적 삶에 있어서 변화와 창조적 삶의 지혜를 깨닫게 해준다. 변화의 의지를 갖고 새로운 출발을 하는 자는 항상 모험의 즐거움과 적응의 지혜를 배우게 된다." 이 책을 추천한 글 중의 하나다. ?? 정말 그런가? 이런 책이? 2000년에 나와서 지금도 꾸준히 읽힐 뿐만 아니라, 여전히 잘 팔리는 책이라고 한다. 나는, 그냥, 어리둥절할 뿐이다. 내게 이 책은, 회사 사보 같은 데 나오는, 매출 신장을 위해...+ 더보기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1374, 69, '는 "변화에 대응하는 방법"에 대한 이야기다. 미로 속에서 늘 즐겨먹던 치즈가 갑자기 사라진 후 변화에 대처하는 스니프, 스커리, 헴, 허를 보여주고 있다. 생쥐 두 마리와 생쥐 인간이라...그러나 워낙 작기에 멀리서 보면 그냥 다 생쥐로 보인다는 설정에서 독자의 시각은 이제 미로 속의 생쥐를 내려다보는 시각으로 변한다. 관조하는 자세가 된다. 이 책은 기업이나 단체에서 교육할 때 이 책 하나만으로도 &nbsp...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1375, 69, '이 책은 우리에게 변화의 중요성에 대해서 일깨워 준다. 변화가 시작 되었을 때 생쥐는 새로운 이동을 시작했다. 그리고 치즈를 찾아낸다. 하지만 인간은 그렇게 하지 못했다. 과거에 얽매여 미래를 볼 수 없었다. 우리는 매일 매일 변화하는 세상에 살고 있다. 자신이 변화하지 않으면 결국 도태되는 세상에 살고 있다. 결국 우리는 과거의 직찹을 버리고 현실을 직시해야 한다. 그리고 미래를 준비해야 한다. 그리고 한가지 더 모든 일에 직면해서 다음을 상기해 보자 Don''t worry, be happy', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1376, 69, '주말이고 해서 시간이 남고 집에 바로 가기는 싫어서 서점을 갔다. 읽을 책을 찾다 구석에 새 책들 사이에 끼어 있는 낡고 닮아빠진 이 책을 발견했다. 제목도 굉장히 많이 들어보았고 베스트 셀러도 된 책이라서 그리고 서점에서 읽기에 적당한 두께였기 때문에 다 읽을 심산으로 어린이들 책 코너에서 애들틈을 비집고 들어가 앉아서 책을 보기 시작했다.(음반코너 옆이라서 음악이 굉장히 크게 흘러나왔다.. ''어머나''가 말이다.. ㅡ.ㅡ;;)줄거리는 간략하게 들은 기억이 났는데 그런 내용속에 정신을 가다듬게 만들어 주는 책이라는 사실은 잊고 있었...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1377, 69, '이 책이 유난히 눈에 띄는 이유는 이 책만이 가지고 있는 단순함.. 이 책은 정말 단조로운 내용임에도 불구하고 그 속에는 좋은 말들이 가득히 담겨져있다. 여기서의 치즈는 성공, 부, 명예 등 자신의 노력에 의해 얻게 되는 것들이다. 이 책의 인물들은 치즈를 찾기 위해 노력하는 사람과 노력하지 않는 사람이 있다. 늘 노력에만 성공과 기쁨이 있기에 난 이 책을 읽으면서 늘 노력하고 꾸준히 반복하면서 노력해야겠다고 생각한다. 앞으로 난 나만의 치즈를 찾기 위해 인생의 길을 열심히 달릴것이다. 혹시나, 그 중간에 미로가 있더라도...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1378, 69, '누구나 한번쯤은 이 책의 제목을 들었을 것이다. 이처럼 이 책은 전세계적으로 베스트 셀러다. 스펜서 존슨의 이름을 전세계에 널리 알린 책이 아닐까 한다. 책 제목에서 치즈는 과연 무엇일까? 아마도 우리에게 행복을 주는 것들이 아닐까? 좋은 직업, 돈, 건강, 명예 등등 행복을 주는것들은 무수히 많다. 행복은 모든 사람이 원하는 것이다. 이 책은 변화를 어떻게 대처해야 하는지 4명의 등장인물로 묘사한다. 현실에 만족하고 안주해 변화를 감지하지 못하고 변화를 부정하며 과거에만 집착한다면 도태될 수밖에 없음을 일깨워주고 있다. 변화란 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1379, 69, '스펜서 존슨의『누가 내 치즈를 옮겼을까?』이 책에 대해 간략하게 소개하자면(껍데기만 소개하자면), 1998년에 미국에서 출간되어 1년만에 "아마존 비즈니스 부문 베스트셀러 1위" "「이코노미스트」「포춘」「워싱턴 포스터」등의 세계 언론이 새 천년의 필독서로 추천!" "GM, 시티뱅크, 제록스, 코닥 등의 세계적 기업들이 교육용 매뉴얼로 채택!"이라는 꽤 유명한 책입니다. 그래서 만약 기대에 잔뜩 부풀어 본다면 기대한만큼 실망으로 이어질 수도 있는 책입니다. 고등학교 국어 식으로 ''이 책의 주제는 무엇인가?''라고 한다면 그저 ''변화에 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1380, 69, '* 이 글은 2007년에 작성한 글을 업데이트 하는것입니다. 추가한 내용도 있습니다. 누가 내 치즈를 옮겼을까? 이책은 제목은 많이 들어봤는데 실제로 읽어보지는 못해서 "한번 볼까?" 하고 읽게되었다. 이때 책책책 책을읽읍시다 였었던가.. TV에 나와서 더 인기있었던걸로 기억해요. 읽어보니 쉬운내용이면서도 참 중요한 사실들을 알려주고 있어 좋은책이라는걸 알게 되었다. 이 책은 크게 세 부분으로 구성되어있다. 첫...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (70, '이윤기의 그리스 로마 신화 1', 234, 4.27, 2, 5, 30, 88, 109, 197, 30, 7);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1381, 70, '이윤기 (지음)/ 웅진지식하우스 (펴냄)이 책은 먼저 벽돌 책 합본으로 지난 두 달간 읽은 적이 있다. 신화를 무척 좋아하지만, 그리스 로마 신화를 속속들이 잘 알지는 못한다. 왜냐면, 신화에 등장하는 수많은 낯선 이름들 그리고 지역적 거리감, 서양 중심 세계관 더 나아가 미국 중심주의가 어쩐지 불편했다. 200년 역사의 초강대국 미국이 자신들의 없는 뿌리를 확고히 하기 위해 디즈니나 할리우드 영화로 그리스 로마신화를 수없이 차용해서 썼다. 그리스 로마 신화의 유명한 어지간한 신들은 다 콘텐츠화되었고 이제 더 재해석할 것이 없는지 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1382, 70, '시중에는 수많은 가 있다. 아이들에게는 학습 만화로 성인용으로도 여러 버전의 그리스 로마 신화가 있다. 그 중 가장 널리 알려진 가 있다면 그건 번역가이자 소설가로 유명한 『이윤기의 그리스 로마 신화』이다. 그렇다면 이윤기님은 누구인가? 그는 우리에게 잘 알려진 열린책들 출판사에서 출간된 , 등을 번역한 최고의 번역가이자 등의 소설가이다.&nbsp...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1383, 70, '#그리스로마신화1 #이윤기 #웅진지식하우스 #서평단이윤기의 그리스로마신화 1권, 신화를 통해 찾는 내 마음 속 신전테세우스가 아리아드네의 실타래를 사용해 미궁을 탈출한 이야기는 우리에게도 익숙한 신화입니다. 실타래가 없는 상황에서도 독자는 상상력을 통해 길을 찾을 수 있다는 저자의 인상적인 멘트로 시작합니다. 이윤기 선생님의 그리스로마신화 시리즈가 출간 25주년을 맞아 새롭게 출간되었다는 소식에 예전 책을 다시 읽어보며 비교해보았습니다. 변화된 세부 사항 중 가장 눈에 띈 것은, 미궁에 바쳐진 남녀의 수가 종전의 12명에서...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1384, 70, '이 무수한 신들이 연출하는 드라마는 뒷날 인간세상에서 그대로 되풀이된다. 신화를 아는 일은 인간을 미리 아는 일이다. 신화가 인간 이해의 열쇠가 되는 것은 이 때문이다. (p.112)다양한 신의 군상만큼이나, 인간의 삶은 복잡하다. 사랑, 질투, 분노, 인내, 희망, 탐욕 등인간의 변화무쌍한 생각과 감정을 물론,변하지 않는 인간의 본능까지도. 그 중에서도 질투와 시기, 사랑 이야기는 늘 재미있다. 1. 파리스와 헬레나신들의 여왕 헤라, 지혜의 여신 아테나, 미의 여신 아프로디테, "가장 아름다운 여신에게"라는 글귀가 쓰여진 사과 한...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1385, 70, '이윤기는 국내에서 그리스 로마 신화의 대중화를 이끈 대표적인 저자이자, 생동감 넘치는 입담으로 신화와 인문학을 자유롭게 오가는 이야기꾼입니다. 신화적 상상력과 문학적 해석을 결합해 독자들이 신화를 쉽게 이해하도록 안내해 왔으며, 그의 글은 오랜 세월 동안 한국 독자들에게 사랑받으며 ‘신화 읽기의 즐거움’을 선사했습니다.25주년 개정판으로 돌아온 "이윤기의 그리스 로마 신화 1"은 240만 독자의 사랑을 받은 베스트셀러로, 독자들에게 상상력의 ‘실타래’를 제공해 신화 속 복잡한 미궁을 헤쳐 나가도록 돕습니다. 테세우스와 미노타우로스 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1386, 70, '최근 내 잠을 빼앗은 책이 있다. 바로 이다. 25주년을 맞아 새롭게 출시된 이 책은 아름다운 표지와 함께, 신화에 대한 깊이 있는 이해를 제공한다. 이윤기 작가는 그리스 로마 신화를 대중화한 주역으로, 이번 작품에서도 독자들이 신화를 통해 삶의 의미를 되새기고 감정을 연결할 수 있도록 돕는다.책은 신화를 이해하는 데 필요한 열두 가지 이야기를 담고 있으며, 각 이야기는 신화 속 상징을 풀어내는 열쇠 역할을 한다. 특히 아프로디테와 헤파이토스의 이야기는 강렬한 인상을 남긴다. 사랑과 아름다...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1387, 70, '이윤기의 그리스 로마 신화 5년전에 나왔던 특별합본판이 최고의 그리스로마신화 소장각이라 생각했는데 이번에 새롭게 25주년 개정판으로 나온 이 책도 만만찮은 퀄리티였다. 종이질부터 삽입된 사진자료까지 최고의 구성이라 다섯권 모두 가지고 싶은 욕구가 샘솟았다. 이미 240만 독자가 읽은 베스트셀러로 돌아가신 이윤기 작가의 부재가 여전히 아쉽다. 1권에는 신화를 이해하는 12가지 열쇠라는 부재로 미궁과 같은 방대한 그리스로마 신화의 열쇠가 되어주는 이윤기 작가의 해설이 담겨있다. 개인적으로도 미궁과 열쇠라는 비...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1388, 70, '이윤기의 그리스 로마 신화_25주년 개정판_240만 독자가 읽은 베스트셀러시간의 흐름에 따라 설명을 하는 것이 어찌 보면 당연한 전개일진대 이 책은 12가지 신화를 이해하는 열쇠로 아래와 같은 주제를 정해놓고 설명하고 있다. 물론 ''1권''답게 신화의 시작이 어떻게 시작되고 있는지에 대한 이해를 첫머리에 쉽게 이해되도록 풀어내주고 있다. 잃어버린 신발을 찾아서 황당하게 재미있는 세계 사랑의 두 얼굴 길 잃은 태양 마차 나무에 대한 예의 저승에도 뱃삯이 있어야 간다...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1389, 70, '이윤기의 『그리스 로마 신화』는 출간 25주년을 맞아 개정판이 새롭게 출간되었어요. ​​1권은 그리스 로마 신화를 이해하는 데 필요한 열두 가지 이야기를 담고 있으며, 이를 통해 신화의 복잡한 상징과 은유를 해석하는 열쇠를 제공하는 책입니다 ​​이윤기 작가는 신화를 단순한 옛이야기가 아닌, 현대인의 삶과 밀접하게 연관된 지혜로 해석하는 것 같아요.​​특유의 감칠맛 나는 문체와 풍부한 해설로 독자들을 신화의 세계로 안내하며, 각 이야기의 상징적 의미를 현대적 시각에서 풀어냅니다.​​ ​​​​개정판은 디자인을 정돈하여 가독성을 높였고...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1390, 70, '#도서협찬​ 이윤기의그리스로마신화 이윤기 웅진지식하우스​ 가 처음이냐고? 그럴리가. 2013년 그리스 여행을 준비하면서 가장 먼저 읽은 책이 바로 였고 신화의 나라 그리스 가는데 당연한 선택이라 생각했다. ​너무나 많은 신들의 이름에 내 기억력을 자책하기도 했다. 물론 다 외울 필요는 없었지만 말이다. 이해는 했는가? 딱히 이해가 필요하다는 생각은 없었고 흥미롭게 읽었다.​ 를 꼭 읽어야 할까? 현대를 살아가는 우리가 구닥다리 서양 신화를 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1391, 70, '새 옷을 입은 명저, 25주년 개정판은 참을 수 없죠. 칼리언니에게는 특별한 의미가 있는 “이윤기의 그리스 로마 신화” 웅진 지식 하우스에서 보내주셨습니다.이윤기의 그리스 로마 신화는 21세기 인문분야 도서의 상징입니다. 출간 후에 한해가 지나도 교보문고 인문분야 베스트셀러에서 내려오지 않아 당시에는 이 책을 어떤 책이 누르고 그 자리를 차지하는 지가 저자들의 초유의 관심사! 저도 그들 중 하나였습니다. 그리고 이 책을 누르고 잠시(!) 2001년에 베스트셀러가 된 것이 오랫동안 저의 자랑거리가 되었죠. 책이 진열되기 전날 베셀 기...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1392, 70, '어렸을 때부터 꼭 읽어야 할 필독도서하면 첫번째로 그리스신화를 꼽을 수 있습니다. 유럽문명의 근간이며, 여러 신들과 인간들의 이야기를 통해 인류 문명의 원형을 보여주는 책입니다.그리스로마 신화를 다룬 여러 책들중에서 를 최고의 책으로 꼽을 수 있는데요. 이번에 출간 25주년을 맞이하여 새롭게 개정판이 나왔습니다.1권에서는 그리스로마신화의 얼개를 짜는 데 필요한 12가지 이야기가 담겨 있습니다. 책 처음에 나오는 신발이야기는 다른 그리스로마신화에서 볼 수 없는 신선한 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1393, 70, '이윤기의 그리스 로마 신화웅진지식하우스 출판, 이윤기 지음그리스로마신화를 많이 들어서 알지만 제대로 앉아서 읽어본 적은 없었던 것 같다. 현대인의 교양서적 그리스로마신화를 모르고서는 서양문화를 이해할 수가 없다. 수많은 책, 그림, 음악이 모두 신화에서 유래한 것이 많다. 비슷한 이유로 최근에 일리아스를 벽돌책 모임에서 읽었는데 이번에 좋은 기회로 그리스로마신화를 읽게 되었다. 240만 독자가 읽은 25주년 개정판이 책은 이윤기 선생님의 그리스로마신화 25주년 개정판이다. 나 빼고 다 읽은 건지... 읽은...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1394, 70, '그동안 ''그리스 로마 신화''하면수많은 신들의 등장으로 미궁 속에서 헤매는 느낌을 받으며읽어도 읽어도 헷갈리는 이름들만 잔상으로 남아 있었어요.​이제는 의 이야기에 푹 매료되어 신성한 존재들이 아름다운 영상미를 뽐내며뇌리에 박혀 도무지 떠나지를 않습니다.​신화에서 유래되어 현재까지도 사용되는 단어들을탐구하는 값진 시간이기도 했고요.​테세우스가 아리아드네의 실타래로 미궁을 빠져나온 것처럼이윤기 선생님의 풍부하고 생명력이 넘치는 인물들의 스토리텔링으로 시대를 초월한 멋진 여행을 하고 돌아올 수 있었...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1395, 70, '아직도 눈에 선한 아킬레우스 브래드피트트로이전쟁.그시절 정말 핫했던 올랜도블룸과헥토르 에릭바나.그리스 로마신화는 이름만 들어도한편의 대 서사같은 신들의 세계가눈에 아른거리는 것 같다.에로스와 프쉬케헤라클래스제우스하데스다프네아프로디테포세이돈 등등신과 인간의 세계를 오가는 스펙터클한 무수한 신들의 이야기는 한 때 내마음을 설레게 한 이야기들.서양의 역사와 문화의 밑바탕이 되어지는그리스 로마 문명의 신화는수많은 예술인들과 작가들에게 영감이 되어주었다.처음 이윤기의 그리스 로마 신화가 나왔을때그야말로 열풍이라고 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1396, 70, '반짝반짝 빛나는 은박과 사냥하는 아르테미스(조반니 마리아 벤조니)의 표지로 새롭게 태어난 25주년 개정판 축하드립니다 신화를 이해하는 12가지 열쇠 1편이윤기의 그리스 로마 신화는 재밌는 이야기로 우리나라에 그리스로마 신화 붐을 일으켰던 작품으로 작가님만의 재치있는 입담으로 늘 누가 누군지 몰랐던 신들의 이름을 알게된 계기가 되었던 책이었습니다.1편에는 신화 이해와 해석에 필요한 열두 개의 열쇠들이 숨어 있다고 합니다.미궁속 괴물 미노타우로스를 죽이고 미궁을 빠져 나온 테세우스 이야기로 들어가는 문을 열면서 아름다운 공주 아...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1397, 70, '는 구수한 맛이 있다. 담백하면서도 시원시원한 입담 속에는 능글맞은 구석이 있다. 중간중간 필자의 주관이 개입하여 상황을 더 극적으로 만들기도 하고 코믹스레 바꾸어 놓기도 한다. 과연 이야기 보따리를 수 백 개쯤 쟁여놓은 이야기꾼답다.누구나 들어봄직한 유명한 그리스 로마 신화를 왜 ‘이윤기’ 작가의 글로 읽어야 할까? 내용과 구성, 해석 등 모든 방면에서 답을 찾을 수 있었던 1권이다.[이윤기의 그리스 로마 신화 1]: 신화를 이해하는 12가지 열쇠이윤기 저 | 웅진지식하우스전래동화나 그리스 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1398, 70, '그리스 로마 신화는 인문학 전반과 함께 인류의 삶과 세계를 널리 포괄하고 반영한 고전이다. 서구 문명의 근원이라고 할 수 있는 그리스 로마 신화는 고대에서 현대까지 이제는 국가를 막론하고 셀 수 없을 정도로 많은 창작자들의 영감이자 작품의 원천이 되었다. 다만 그리스 로마 신화는 복잡하다. 미궁과 같은 상징적이고 은유적인 이야기의 향연에, 이번에는 기필코 그리스 로마 신화를 정복하리라 마음먹더라도 쉽게 지칠 수 있다. 심지어 그리스 로마 신화에는 벌어지는 사건도 많고, 사건이 많은 만큼 등장인물은 더 많다. 이렇듯 방대하게 쏟아지는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1399, 70, '아이의 신화 이야기를 듣는 것에서 시작된 관심이 이번에 이윤기 선생님의 그리스 로마 신화로 한층 깊어진 경험으로 이어졌습니다. 총 5권으로 구성된 이 시리즈는 240만 독자들에게 사랑받아온 스테디셀러로, 25주년 기념 개정판의 표지가 아름답게 재탄생해 소장 가치를 더해줍니다. 선명한 인쇄와 빳빳한 재질의 사진 자료는 신화의 장면을 생생하게 담아내어, 마치 박물관 속에 있는 듯한 감동을 선사합니다. 표지를 보는 것만으로도 구매 욕구를 불러일으킬 만큼 매력적인 디자인이 책의 가치를 한층 높여주죠.특히 시리즈의 첫 번째 권에는 신화를 이...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1400, 70, '#이윤기의그리스로마신화 신화 이야기가 이렇게 재미있는 거였나요?처음 신화 이야기를 접했을 땐 저의 정서와는 살짝 맞지 않아서 읽다 덮었거든요~그러다 아이들이 신화에 흥미가 생기니 만화로 된 신화 책을 엄청 읽고저에게도 엄청 많은 이야기를 해줬어요.전 제가 읽은 줄 알았어요~ ㅋㅋ하지만 이름을 잘 못 외우는 전이름이 많이 등장하는 책은 써가면서 읽기도 해요.이 책쓸 수가 없어요~신들이 왜 이렇게 많아요??아이들이 이야기해 준 신들보다 못 들어본 신들이 더 많아요 어쩌면 들었는데 기억 못 하는 걸지도요~ 25주년 개정판 240만 독...+ 더보기', 5);
