INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1402, 71, '2007년도에 우연히 읽은 책이다. 정말 읽어도 후회없는 책이다..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1403, 71, '영화로 나온 것 같은데... 영화는 나중에 찾아서 보고 책으로도 보고싶네... 요즘 어린이 책들이 많이 땡긴다... 왜일까...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1404, 71, '황선미작가 최고의 책, 이보다 더한 모성애를 그려낼 수 있을까?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1405, 71, '애니 개봉되기 전에 꼭 책으로 먼저 읽어보고 싶었다. 잎싹의 용기에 눈물과 박수를!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1406, 71, '아이를 위한 동화책이지만 늘 반복되는 일상에 매너리즘에 빠진 어른들이 읽으면 좋을 것 같은 아이와 어른이 모두 읽을 수 있는 책이지요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1407, 71, '동화라는 포맷을 지니고 있지만 일종의 철학서와 같은 심오함을 지니고 있는 특별한 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1408, 71, '잎싹이가 너무 불쌍하여 눈물 뚝뚝.. 어린이 책을 읽으면서 가슴이 정말 찡했답니다..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1409, 71, '아이들의 책이라 무시할 수 없다. 으레 해피엔딩으로 끝날 법도 했을 이 책의 엔딩은 참으로 강하고 따뜻한 잎싹이의 마음과 같다. 잎싹이의 마지막 모습을 잊을 수 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1410, 71, '8살 딸아이와 함께 이야기 하면 읽었던.... 잎싹의 희로애락을 같이 공감하며 보았던.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1411, 71, '아이 때문에 선택한책, 제가 더 재미있게 읽었어요. 영화개봉된다고 하니 기대되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1412, 71, '가슴벅차고 눈시울뜨거워짐. 삶-먹고먹히는 심오한관계, 아무도 이유없인남을물지않는', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1413, 71, '동화지만어른들이읽어도감동적인책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1414, 71, '어른들이 읽기에도 좋은 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1415, 71, '가슴 뭉클해지는 동화책입니다. 아이들의 꿈을 키워주는데 정말 좋은책~!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1416, 71, '아이들이 읽기에는 결말이 너무 참혹하다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1417, 71, '다른 어떤 육아지침서보다 울륭합니다. 잎싹이는 나의 멘토입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1418, 71, '어릭적의 꿈을 다시생각하게 하는 동화..울딸과 보고 싶네여ㅛ...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1419, 71, '암탉의 마지막이 여운이 많이 남았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1420, 71, '안전한 마당을 나와 위험을 무릅쓰고 소망을 이루려는 잎싹. 과연 나는 그럴 수 있을까.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (72, '살인자의 기억법', 233, 4.09, 2, 6, 52, 82, 91, 173, 52, 8);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1421, 72, '한동안 제목을 오해하고 있는 줄 몰랐다.아멜리 노통브의 ''살인자의 건강법''이 검색창에 떠 순간 멍~했었다.이 책도 손에서 놓질 못해 몰아쳐 읽었더니 결말에서 멍~했다.멍2를 당했다.오래전에 읽었던 ''살인자의 건강법''은 당최 기억나질 않으나,''살인자의 기억법''은 오랫동안 기억될 것 같다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1422, 72, '김영하의 장점은 잘 읽힌다는 것. 대개 문학적 노력 없는 클리셰이 덩어리들이기 때문. 따라서 읽으나 안 읽으나 똑같다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1423, 72, '추리소설 같기도 하고, 반전이 꽤 괜찮다. 영화에서 이걸 어떻게 풀어냈을까 궁금하지만 굳이 볼 생각을 들지 않는다. 김영하작가 특유의 분위기는 그대로다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1424, 72, '연쇄촌철살인범지금까지 읽은 한국 스릴러 중 최고', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1425, 72, '같은 것을 보더라도 사람은 제각각 자기 시점에서 기억하기 때문에 기억은 조금씩 다르다던데 이 책을 보고 딱 그 생각이 들었다. 나는 무엇을 잘 못 기억하고 있었을까? 과연 내 기억들이 다 맞을까?', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1426, 72, '소설보다 무서운 건 김영하의 이름값.뭐 그래도 다들 평이 좋으니까 내가 발견 못한 매력이 있는 거겠지 (생각하고) 싶다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1427, 72, '자신이 자신을 모르게되는, 간접적인 공포안에 갇힌 사람의 이야기. 두번째 읽을때는 김영하가 깔아놓은 복선 찾는 재미가 쏠쏠했다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1428, 72, '결말은 다소 아쉬웠다.17.06.28', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1429, 72, '이책이 그렇게 유명하던데 읽고싶어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1430, 72, '스토리텔링(장르소설로서)으로서는 모자란 면이 있고, 깊은 사유와 주제의식(순문학으로서)으로서는 아쉽지만, 읽는 재미는 있는 소설. 그 중간에 위치하는 작가의 소설이다. 그래서 양쪽 다 기대한다면 둘다 아쉽고, 동시에 양쪽의 어느 정도 수준은 충족하는 작품.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1431, 72, '저자 : 김영하읽는 내내 영화 가 떠오르더라는...전개가 매우 빠르고 몰입감이 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1432, 72, '알츠하이머에 걸린 노인. 대량살인마. 하나뿐인 딸의 아버지. 연관성없을 세요소는 사실 한 인물을 지칭하는 또다른 이름에 불과하다. 하루하루 지날적마다 흩어져갈뿐인 과거와 그에 연동되는 현실의 것들. 예상의 철로에서 치밀히 달리던 소설은 돌턱에 걸리고 결국 와르르 와르르르 무너져 내린다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1433, 72, '책을 단숨에 삼켜버린다는 것이 이런 건가.영화로는 상상할 수 없는 긴박감과 혼동독자를 쥐락펴락하는 필체에 또 한 번 몰입을 경험한다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1434, 72, '빠른호흡!! 손에서 도저히 놓을수록 없었던 멋진소설!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1435, 72, '더이상 더할 것도 뺄 것도 없다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1436, 72, '수치심과 죄책감에 대한 김영하의 정의는 어디에서 유래한 것일까(베네딕트의 구별과 반대다). 그리고 많은 독자들이 공감하듯, 또 비평가가 아무리 애써 변호해도 마지막이 너무 아쉽다.. 알츠하이머 환자의 내면세계를 재구성하는데 환자의 시각과 의사의 시각이 혼재된 듯한 느낌..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1437, 72, '자극적이지만 편안했다. 이게 잘 팔리는 글이지 싶었다. 하지만 막판에 이야기를 흔들어버려서 다 헛소리가 되어버렸다. 흔들어서 새로 생기는 구조가 없다면 그건 ˝뻥˝일 뿐이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1438, 72, '숨도 안쉬고 몰입했다! 진실이 궁금하다. 한국판 메멘토를 같은 느낌이었다?? 영화는 어떻게 풀어나갔을지 궁금하기도 하고 한편으로는 가지고 있는 이미지들이 깨질까봐 안볼까조 싶다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1439, 72, '같은 책을 읽고 같은곳에서 감탄하는 바보중의 바보??', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1440, 72, '분명 쉬운 책은 아니지만 흥미 진진한 책이다 25년 전 살인을 저지른 알츠하임어 이야기 그는 그의 딸 은희를 박태주에게서 지키려 하는데', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (73, '리딩으로 리드하라', 233, 3.64, 48, 10, 30, 34, 111, 145, 30, 58);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1441, 73, '세상에서 성공하고 자본주의의 승자가 되기위해 인문학을 공부하는게 아니다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1442, 73, '그저 시류에 편승햇서 돈이나 벌려고 인문학까지 파는구나. 싸구려 돈벌이용 책.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1443, 73, '이런 시덥잖은 글뭉텅이 팔아 주지말고 ˝인문고전강의˝ 읽는게 4천만배 낫다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1444, 73, '내용이 너무 부실한데 좋다는 분들이 많은게 참 희안하네요.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1445, 73, '머리나쁜 사람들은 이런거 읽고도 좋아할 수 있겠네요 ㅋㅋ 인문학을 얄팍한 출세를 위한 비법으로 알고, 아무 노력 없이 누가 인문학 비슷한 걸 떠먹여 주길 원한다면 이딴 책이나 읽으세요. 그게 아니라면 가서 제대로 된 책 읽으시구요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1446, 73, '39세100억,젊은 부자의 부동산 투자법과 다를 것이 없는 책이다.고전은 이게 아니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1447, 73, '인문을 팔아먹는 책이군.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1448, 73, '책이 많이 팔려서 저자는 “자본주의 시스템의 승자”가 되었을 듯.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1449, 73, '이책은 인문고전 독서법에 대한 것이 아니다.단순히"인문학 읽어야 너도 잘나가"를 ''똥''같이 싸놓은 것.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1450, 73, '이 책이 베스트셀러였다는게 황당하고, 한국의 독서수준을 보여주기에 안타깝다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1451, 73, '이 책은 인문학 책이 아니라 자기계발서입니다. 저는 솔직히 이렇게 엉터리 인문학 책은 처음입니다. 갑자기 현실이 서글퍼지네요.....ㅜ', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1452, 73, '인문학은 자본주의의 승리와 리더가 되기 위한 학문이 결코 아니다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1453, 73, '읽다가 내용이 어려워서 일단 보류한 책은 몇 권 있지만 화가나서 접은 건 이 책이 처음이다. 진짜 어울리는 책 제목은 ˝리딩으로 분노하라˝가 적당할 듯 싶다. 평점과 베스트셀러의 환상을 보여준 책.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1454, 73, '인문고전만 읽으면 무엇이든 해결될 것 같은 논리를 펴서 억지스럽다는 느낌이 드네요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1455, 73, '좀 심하게 말하자면 약팔이 작가 이상으로는 안보인다. 지금까지 읽어본 책들도 그렇고 이책도 그렇고.. 내용을 과장하고 단순화해서 그럴듯해보이는 책으로 제조해 내는 작가', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1456, 73, '아이들에게 책을 더 멀어지게 하는 책.이 책을 읽은 어른들이 아이들에게 행하는 만행이란...이 책만 읽지 말고 여기 소개된 책들을 읽고 아이들에게 책을 권하기를!', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1457, 73, '인문학을 공부하는 방법이 하나님을 믿는 것이다??? 이 사람 인문학 뜻이나 알고있나? 내용도 억지스러운 전형적인 기획된 베스트 셀러. 별 하나가 아깝다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1458, 73, '인문고전을읽는것이중요하긴하지만 천재,리더,성공 등 자극적인내용은아쉽기만하다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1459, 73, '이런 책 읽지 말고요 그냥 원전을 읽으세요.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1460, 73, '읽다가..읽다가 도저히 못읽겠다. 왜..이 책은 결과만 가지고 주장을 펼치는지..근거도 없고..성공이란...잣대가 무엇인지...에디슨도 그렇고..월가 사람들도 그렇고..그들이 성공한 이들이 맞을까..절대적으로 공감하지 않는 나로서는...절반정도 읽다가...누구 주기도 이 책이..부끄럽다.', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (74, '글자전쟁', 233, 4.69, 2, 2, 11, 36, 182, 218, 11, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1461, 74, '이런 스타일의 소설은 김진명 저자가 대한민국에서 유일무이하다고 감히 말할 수 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1462, 74, '고구려는 안 쓰시고 싸드에 이것까지....고구려에 집중해 주시길...', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1463, 74, '김진명의 소설은 언제나 흡입력 있고 지적호기심을 강하게 자극하지만, 읽고 나면 ｀그래서 어쩌라고?｀하는 생각이 들곤 한다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1464, 74, '글자를 향한 작가님의 깊고 풍부한 지식과 스토리는 혀를 내두르게되지만, 상위 1% 주인공들의 익숙한 패턴이 계속해서 같은 소설을 읽고 있는듯 착각을 일으킨다. 스토리에 비해 인물구성의 참신성이 참 아쉽다고 해야할까? 책을 읽으면서 ｀천년의 금서｀가 오버랩 되는 이유도 그때문인듯해서 아쉽다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1465, 74, '믿고 안보는 김진명', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1466, 74, '한 가지는 확실하다. 그럴듯한 떡밥을 잘 던지고 끝까지 밀고 당기는 실력이 대단하다는 것.읽을 때는 상당히 재밌게 보게 되지만 다 읽은 후에는 거슬리는 점들이 하나둘 나타나기 시작한다. 그래도 머리속을 비우고 보면 스토리에 잘 끌려 갈 수 있는 책이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1467, 74, '중국에는 ｀답(畓)｀ 자라는 없다는 의문의 시작으로 정체불명의 파일을 찾아 헤메면서 역사에 숨겨진 거대한 비밀이 서서히 드러나게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1468, 74, '한자는 중국말이라고만 생각했던 내 생각을 깨버리는 소설!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1469, 74, '여전하신 김진명 선생. 억지로 소설이란 옷을 입히니까 이렇게 되는 거라고 봅니다요..', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1470, 74, '자기반복에 능한 대단히 상업적으로 능력있는 작가.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1471, 74, '를 읽으면서 알게 된 김진명 작가의 책은 흥미진진하기에 대부분 읽고 있습니다. 이번에는 USB, 무기중개상, 중국, 글자의 조합으로 흥미진진한 이야기를 만들었군요. 과거와 현재를 넘나드는 방대한 스케일, 동아시아를 아우르는 이야기가 몹시 흥미진진합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1472, 74, '허구지만 현실보다 더현실적인 소재와 진실같은 내용', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1473, 74, '처음 책을 읽으면서 김진명 작가님을 알게 되었네요. 그 뒤로 늘 작가님의 작품을 애독하고 있어요. 스토리에 감탄하게 되는 작가님의 작품 정말 좋아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1474, 74, '부터 김진명 작가의 소설을 빼놓지 않고 읽고 있습니다.이번에는 입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1475, 74, '작가님의 책을 읽으면 항상 얻는다. 분명하고 뜨거운 그것을. 그리고 배운다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1476, 74, '국경을 넘나들며 펼쳐지는 이야기의 전개가 너무 재미있어 식음을 전폐하고 읽었습니다. 생각지도 못했던 결말에 너무 놀랐습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1477, 74, '허상과 실체사이의 간극을 찾기 어려울 정도로 스펙타클하네요!!! 긴장감이 쭈욱~~~~~~ 헉', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1478, 74, '흠,,, 결국은 이도저도 아닌책이 되었다김진명의 필력이 이정도밖에 안되었을까???이건뭐 역사의식 고취시키는 일도 못되는 책이 되었다책속의 책내용이 더 재밌다는,,, 뭔가 급하게 마무리 짓고 끝냈다는 느낌!!!고구려 빌려놨는데,,, 에휴!!', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1479, 74, '단 한개의 글자를 단서로 이렇게 많은 이야기를 건져올릴 수 있는데, 우리나라 역사학계는 인정하지 않는 사료들이 어찌 그리 많은건지..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1480, 74, '지금 이북으로 보고 있는 책. 역시 김진명답다. 일단 천재비스무름한 주인공 한 명 나온다. 항상 그래왔듯이.450쪽(617페이지 정도, 이북, 13 폰트크기로) 읽었는데, 남은 부분이 어떻게 전개될 지 정말 궁금함.글자 하나 가지고 소설을 쓰다니...', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (75, '웬만해선 아무렇지 않다', 232, 4.69, 0, 3, 6, 51, 172, 223, 6, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1481, 75, '웬만해서 소설을 이렇게 빨리 읽어내지 못하는데 다음편을 읽고 싶어 자꾸 가속도가 붙는다.읽으면서 ''이렇게 후딱 읽으면 안되는거 아닌가?''생각하면서도 자꾸 책장을 넘기게 만드는 작가의 힘.이건 웬만해서 아무렇지 않은게 아니지 않은가!!40개의 짧은 단편들 각각의 여운은 정신없이 휘몰아친다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1482, 75, '마음산책 책은 정말 디자인이 늘 예쁘단 생각을 해요.^^ 꽁트 같은 면들이 있어서 이전 김영하의 ''무슨일이 일어났는지는 아무도'' 라는 책 읽었을때 충격과 거의 맞먹었죠.그 책도 단 몇줄짜리 글이 단편으로 나오고 한편 한편인데 연작 처럼도 나오고 해서 신선했었거든요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1483, 75, '믿고 보는 이기호... 기대합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1484, 75, '2016-081_[관악도서관]짧은 이야기. A4용지 3page이내의 글들. 이런 짧은 소설이 가능한 것인지. 책소개를 살펴보면 박완서 [세가지 소원], 정이현 [말하자면 좋은 사람] 이 있다. 이기호의 짧은 소설은 가볍지만 가볍지 않은 소설. 짧은 시간을 내어 보기에 괜챦은 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1485, 75, '감각적인 언어로 빚어낸 웃픈 시대의 그림자들로 새겨진 40편의 이야기 탄생과 죽음조차 공평하지 않은 현실이 빼곡하게 담겨 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1486, 75, '잔잔하고 피식 웃어버리는 소소한 이야기들', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1487, 75, '이기호 작가님의 이야기는 담백하면서도 깨달음을 줍니다. 힘들고 바쁜 세상속에서 이 책덕분에 마음에 위로가 되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1488, 75, '여러 명의 일기의 어느 날을 띄엄띄엄 읽은 듯... 그렇다 웬만해선 아무렇지 않은 것이다. 다들 그렇게 하루를 또 살아내고 있다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1489, 75, '웃고 웃을 수 있는 단편 소설인데다 책 속의 이야기 40편 안에는 등단 15년의 내공이 들어 있음을 알 수 있는 책이죠.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1490, 75, '제목부터 눈에 들어오는 작품인데, 경기침체로 많이 힘든 요즘 저 뿐 아니라 많은 사람들이 책을 읽고 위로받을 수 있으면 좋겠네요. 단편집이라 읽기 더 쉬워요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1491, 75, '한뼘 소설 같이 짧은 단편을 좋아하는데 내 구미에 딱 맞는 작품들이 묶여 있다. 짧은 글이라고 무시했다가 힘들었다는 작가의 말이 마음에 남는다. 독자들은 그저 즐길 수 있어서 좋은 단편집.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1492, 75, '현재를 살아가는 우리에게 웬만해선 아무렇지 않은 이야기를 쓰고 있다. 이런 세상에 웃음과 울음이 필요한 우리가 아닌가 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1493, 75, '아주 짧지만 아주 많은 이야기가 담겨있는 책. 오랫동안 책을 읽지 않았던 독자나 무거운 책만 읽어 머리가 묵직한 독자가 기분전환으로 읽기 적합한 책이다.다만 너무 짧아서 시원한 맛이 없다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1494, 75, '이제까지 읽었던 이기호 소설중 최고!호흡이 짧은 단편임에도 구성이 완벽하다. 난｀ 소용없다는 말｀이 가장 와닿네', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1495, 75, '짧은 순간 포착된 우리의 삶.삶은 웃음과 눈물, 황당함, 허망함, 짜릿함과 어이없음 등등그 밖의 모든 가능성을 담고 있다.그래서 우리는 웬만해선 아무렇지 않다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1496, 75, '가끔 우리에게 절대적으로 필요한것은 위로와 격려, 칭찬 이런것들인지도 모릅니다. 삶에 지쳐있을때 우리가 기댈수 있는 요소들이니까요. 이 책을 읽다보면 절로 그런 단어들이 연상됩니다. 작위적으로 위로를 건네지 않더라도 자연스럽게 위로가 되는 느낌, 피식 웃다가 근심을 내려놓게되는 느낌...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1497, 75, '정말 아무렇지 않고 흔들리지 않았으면 좋겠어요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1498, 75, '유쾌하고 재미있습니다. 힘든 하루하루를 살아가는 현대인들에게 많은 도움이 될 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1499, 75, '제목부터 왠지 짠하다는 느낌이 듭니다. 재미있게 읽겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1500, 75, '슬픈 농담같은 이야기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (76, '나의 라임 오렌지나무', 230, 4.58, 4, 0, 18, 44, 164, 208, 18, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1501, 76, '동녘...아이유 때리고 돈 좀 버셨수?', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1502, 76, '동녘 대표님. 제제는 노이즈 마케팅에 사용될 그런 아이가 아닙니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1503, 76, '성장하려면 반드시 ｀자신만의 환상｀을 깨야 한다. 아무리 ｀순수｀와 ｀천연덕스러움｀이 좋다지만, 청소년, 어른이 되어서까지 그렇게 헤헤 웃으며 살 수는 없다.제제가 스스로 그 ｀환상｀을 깨어가며 성장하는 스토리가 인상깊다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1504, 76, '다시 읽어도 충격적인 결말 슬프다 못해 솔직히 좀 무섭다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1505, 76, '한 여가수의 이미지 망가뜨려서 순위올라간 소감이?', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1506, 76, '어린시절부터 나와 함께 자라온 라임 오렌지나무 성인이 된 후에야 이 책의 진가를 알 수 있음', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1507, 76, '이렇게 슬픈 내용이었나.가난뱅이인 아빠가 싫어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1508, 76, '초등학교 때 학교숙제로 허겁지겁 읽었던 기억. 진짜 재미없다고 느꼈었는데 20년후 읽었을때는 눈물을 멈출 수가 없었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1509, 76, '아빠가 가난뱅이라서 진짜 싫어.”운동화를 떠난 눈길은 그 옆에 놓인 슬리퍼로 옮겨 갔다. 아빠가 우리를 내려다보고 있었다. 아빠의 눈은 슬픔으로 굉장히 커져 있었다. 이구절이 감동. ㅠㅠㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1510, 76, '웃으면서 읽기 시작해서 눈물로 끝맺는 책. 내가제일 좋아하는 책이고 제목만 생각해도 눈물짖게 되는책! 제제 사랑해!!!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1511, 76, '읽을수록 감동이 깊어져 갑니다. 좋은 책 함께 나눕시다 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1512, 76, '내가 가장 아끼는책. 10살때 읽었을때도 30여년이 지난 지금 읽어도 여전히 뽀루뚜가 아저씨의 죽음은 너무 슬프고 아프다. 어른이 되는건 철없는 어린시절에 대한 벌이라는걸..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1513, 76, '부산행 기차에서 읽고 바보같이 엉엉울다가 결국 친구에게 전화해서 주저리주저리 말하면서 울었던 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1514, 76, '어릴 적 엄청 재미있게 읽은 기억이 난다. 제제가 내 친구같았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1515, 76, '우리는 왜 철이 들어야 할까? 너무나도 빨리 현실을 깨우쳐야 했던 ‘제제‘의 성장소설. 성장소설이지만 너무나도 가슴이 아픈 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1516, 76, '제제,여렸을 적 너와 만났을 때에 나는 널 참 철이 없고 못된 아이구나 생각했어나이들어 다시 너와 만난 지금 왜 이렇게 바보처럼 눈물이 나는지 모르겠구나', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1517, 76, '중학교때 읽었는데 아직도 이책이 이렇게 많은 사람들에게 알려지는 것에는 이유가 있을것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1518, 76, '먹먹하게 남았던 소설의 기억, 지금도 떠오르는 망가라치바.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1519, 76, '이 세상 어디가에 있을 수많은 제제들을 위로해주고 싶다. 사랑한다고 말해주고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1520, 76, '애초에 이런 책이 왜 청소년 권장도서인 거지? 악동학대에 대한 걸 어린이들한테 가르칠 작정인가?', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (77, '빅 픽처', 229, 4.28, 4, 3, 26, 87, 109, 196, 26, 7);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1521, 77, '옮긴이는 독자의 반응을 예상했고나는 그 예상을 고스란히 뒤따랐다.참신한 소설, 전형적인 독자.읽는 내내 살인자를 응원하는 기묘한 경험!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1522, 77, '더글라스 케네디의 강한 몰입을 유도하는 문체는 어느 순간 독자 자신을 극중 주인공이 되게 만들어 긴박하게 전개되는 이야기 속에서 책을 잡은 손에 땀을 베개 만듭니다. 또한, 사진을 좋아해서 중간 중간 나오는 사진과 사진 세계에 대한 이야기도 무척 흥미로웠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1523, 77, '순식간에 읽음. 다른 작품들도 찾아서 읽는 중', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1524, 77, '더글라스 케네디는 다작 작가인듯 하지만, 이 책 한권으로 충분하고 이 이야기가 최고이다. 작가의 다른 이야기가 재밌고 빠르게 읽을 수 있다면, 이 책을 거기에 ‘살아있다는 것‘에 대한 생각을 덧붙인다. 단연 이 책이 그의 작가 인생에 최고이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1525, 77, '후반 부분은 줄거리 위주로 읽었으나, 세련되고 전개가 빠른 스릴러로 머릿속으로 그림을 그려가며 읽게되는, 뿌듯한 포만감을 느끼게 하는 매력적인 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1526, 77, '1997년에 출간되었다고 나오는데 9.11테러가 내용에 포함되어 있어요. 뭘까요?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1527, 77, '꿈? 결국 치정극아닌가?... 내가 당장 버려야 하는 것이 있다면 책을 처음부터 끝까지 읽어야 한다는 강박관념. 기욤 뮈소의 구해줘와 함께 막하를 가리는 그닥인 소설.. 왜 이런소설이 인기있는거지?', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1528, 77, '역자의 말대로 한번 읽기 시작하면 그대로 단숨에 읽어내려가는 흥미진진한 소설.강추', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1529, 77, '정신없이 재밌게 읽었으니 뭐라 불평은 못하겠다만.... ˝문학˝이라고 부르기는 애매한 책. 마지막 부분, 너무 쉽게 너무 빤하게 비켜가는 운명이 좀 아쉽기도 하고. 그러나 재미있음.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1530, 77, '중반 이후 끝없이 빠져들게 된 책.한 동안 멀리했던 소설에 대한 열정이 다시 살아났다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1531, 77, '케네디의 작품들은 마치 로맨스가 거의 없는 차가운 기욤 뮈소의 작품을 읽는 것 같다. 뮈소의 작품은 ‘너‘가 중요하지만 케네디의 작품은 ‘내‘가 주가 되는 느낌? 하지만 이 작품은 두말 할 것 없이 그의 작품 중 최고이다. 읽고나면 한없이 쓸쓸해진다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1532, 77, '주제와 스토리가 함축된, 표지만으로도 강렬한 월스트리트 변호사의 목에 걸린 카메라.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1533, 77, '몰입하게 만들어 지루하진 않으나... 그닥.. 말그대로 영화같은 이야기다..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1534, 77, '보는내내 긴장감으로 쉴틈없이 책장을 넘겼다. 삶에대해강력한충고를받은것같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1535, 77, '친구에게서 빌려봤는다 다시 한번 보고 싶은 재밋는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1536, 77, '완벽한 야누스적인 인간을 본듯 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1537, 77, '재미있는 구성 괜찮네', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1538, 77, '흡인력있고 술술 읽히는건 틀림없네요^^', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1539, 77, '처음 접했던 더글라스 케네디 소설! 재미있다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1540, 77, '제일 큰 형벌은 세상을 살아가야하는 ''인간''이란 굴레인지도 모른다.', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (78, '음의 방정식', 229, 4.59, 1, 5, 15, 45, 163, 208, 15, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1541, 78, '미야베 미유키이기 때문에 조금 아쉬웠어요.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1542, 78, '를 통해 알게 된 미야베 미유키의 소설. 얇은 책인데도 캐릭터가 살아있고 교사와 학생 간의 긴장감이 팽팽히 느껴진다. 억압하는 쪽과 억압 받는 쪽을 그릴 때는 어떤 메시지도 읽히는 듯하다. 독자에 따라선 얇은 분량의 한계 때문에 추리 소설의 맛만 보다가 끝났다고 생각할지도 모르겠다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1543, 78, '교실에서 사망한 학생의 죽음을 추적하는 탐정 스기무로 사부로,사춘기 교사와 학생의 위압관계 어긋난 우정과 사랑을 통해 사춘기 소년 소녀들의 심리를 예리하게 파고든 작품', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1544, 78, '에 이은 20년 의 시간이 흐른 후에 변호사 후지노 료코가 다시 만난 교내 미스터리로 사립중학교 1박 2일 캠프 행사에서 교사의 부적절한 언동에서 시작되는데~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1545, 78, '스릴과 긴장감이 제대로인 책이네요. 교내 미스터리이기에 교사와 학생들이 더욱 좋아할 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1546, 78, '미미여사님 신간!!!!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1547, 78, '오랜만에 가볍게 짧은 시간내에 읽었다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1548, 78, '2016-095_[컬쳐클럽]132page 정도의 소설은 중장편 소설이라고 할 수 있을까? 단편에 가까운 소설. 미야베 미유키의 화차는 영화로 보았고 처음 읽는 소설. 기대를 한 것은 아니지만 그냥 미스터리의 형식만을 가지고 있을 뿐 이야기 하고자 하는 것이 명징하게 보여지지 않는 소설.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1549, 78, '장편소설이라는 분류가 부끄러울 정도로 분량도 심하게 적고 내용도 단순간략. 미미여사의 독자를 홀리는 필력을 기대한다면 실망하기 십상...솔로몬의 위증과 행복한 탐정 시리즈의 사부로의 만남만이 의미 있는, 두 소설의 번외편 정도로 생각하고 가볍게 읽으면 좋을 듯..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1550, 78, '생생하게 살아있는 캐릭터들을 미야베 미유키의 소설 속에서 늘 만날 수 있는 것 같아요. 우리 아이와 비슷한 또래 아이들의 학교에서 일어난 사건. 흥미진진한 작품이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1551, 78, '미미여사님 실로 간만이네요. ｀괴수전｀을 보며 기다리고 있습니다. 작년에 개봉한 솔로몬의 위증은 영화로만 봤는데 그 여주의 집요함이 마음에 들었습니다. 사실 행복한 탐정 시리즈는 제가 좋아하는 시리즈는 아니지만 료코의 등장으로 마음이 설렙니다. 이 기대를 채워주실거라 믿어의심치 않아요ㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1552, 78, '후반부로 갈수록 미미여사의 색이 드러난다. 너무 성급하게 책장을 덮지는 마시길...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1553, 78, ', 3권짜리를 진짜 3일만에 다 읽었던 기억이.. 미미 여사님 신간이라니 기대됩니다~ㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1554, 78, '˝솔로몬의 위증˝을 잇는 미야베 미유키 신작 미스터리 ˝음의 방정식˝ 재미있고 스릴이 넘치는 소설입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1555, 78, '얽힌 인간 관계의 끝에서 드러나는 음의 방정식... 어떤 것을 집어넣어도 마이너스가 되는 인간 관계를 소설로 읽는 것은 언제나처럼 씁쓸했다. 그나마 미미여사의 책이라서 그 씁쓸함이 덜했달까.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1556, 78, '학교에서 벌어지는 사건을 소재로 하는 미스터리물이라 그런지 더 기대하게 만드는 미야베 미유키의 신작이로군요. 흥미맀는 소재라 더 궁금해지는 작품입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1557, 78, '미미여사는 다작인데도 항상 기대를 가지게 만듭니다.우리도 이런 멋진 작가가 많이 등장해서 출판계의 힘이 되기를 희망합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1558, 78, '짧지만 임팩트있는 소설', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1559, 78, '미야베 미유키의 작품 중 를 영화로 본 적 있기에 기대가 된 소설이었어요. 학생과 교사들의 교내 미스터리이기에 색다른 소설입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1560, 78, '이전 주인공들의 20년 후를 그린 신작이라니 너무 시간이 많이 지나간거 아닌가요!', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (79, '개미대학 세력의 매집원가 구하기', 228, 4.97, 0, 0, 1, 5, 222, 227, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1561, 79, '주식투자 공부의 기초 지침서가 될 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1562, 79, '개미들이면 꼭 읽어봐야하는 책!!딱 필요한 내용들로 써져있으며초보에게 추천해주어도 절대 욕먹지 않는 책 입니다.강추!!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1563, 79, '작년부터 주식을 새로운 마음으로 공부하기 시작하며 이책을 접하게 되었다. 기술적 분석, 기본적 분석 모두 중요하다. 그리고 이 책은 정리하기 힘든 기술적 분석을 정리하는데 정말 많은 도움을 준다. 전석저자의 내공을 알 수 있는 책이며, 개미들에게 필수적으로 알아야 내용을 잘 정리한 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1564, 79, '그동안 여러권의 주식 서적을 읽어보고 비싼 수강료를 지불하고 유명강사의 강의도 들어 보았지만 늘 부족함을 느껴왔었는데......초보자도 쉽게 이해할 수 있도록 서술되어 있으면서도 세력의 입장에서 매집원가라는 새로운 접근법을 제시하고 있는 이책은 주식공부에 좋은 지침서가 될듯 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1565, 79, '오랫만에 유튜브에 업글이 떠서 찾아보니 책으로도 나왔네기본에 충실해서 무시하는 개미도 있나본데,주식판에서 산전수전 겪다보니 나중에는 기본으로 돌아가게 되던데,기본을 무시하면 나중에 기본에게 개무시 당하고 한강에서 동기생들만나게 될껄~! 책 내용은 좋은데 컬러가 너무 야해서~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1566, 79, '주식시장 입문 5개월차입니다. 인터넷 유튜브 도서등으로 주식공부중인 저에게 이책은 가히 혁명적인 책입니다. 왜냐하면 주식공부의 목적은 수익을 위한 것인데 이 책의 내용만큼 실제적이며 수익실현에 도움을 주는 탁월한 책은 없기 때문입니다. 또한 초보들에게도 이해가 쉽도록 쓰여여졌습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1567, 79, '처음주식을 접하는사람은 신기하고 어느정도 경력이있는 사람이보면 저절로 엄지가 올라오는책 그리고 읽으면 읽을수록 우러나오는 사골같은책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1568, 79, '유튜브로 먼저 전석선생님을 알게 되어 유튜브 정주행을 하고 나서 책을 구매하였습니다.그래서 보는데 술술 잘 읽히드라구요. 어려울 줄 알았는데 초보자들을 위해서 잘 풀어서 해석한 것 같구요.어떤 책을 읽어야 할지 막막했는데 잘 구매한 것 같습니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1569, 79, '읽어 내려가는 순간 여태봐온 책들과는 차별화가 있습니다. 좋은 책 알게되어 기분 좋았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1570, 79, '주식시장에서 초심자의 행운이라는 말이 있습니다. 그게 독이되어 자신의 실력을 과대평가를 하다 막대한 손실을 보는 경우를 꽤 봐왔습니다. 저역시 그중 하나였고 주식시장의 세계는 냉정하다는 것을 배웠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1571, 79, '주식관련된 다른 책 몇권 봤는데, 이론에 치우쳐서 실제 적용하기 어렵거나 뜬구름 잡는 이야기 혹은 자기 자랑만 하는 경우가 많았습니다.이 책은 관점을 바꾸어서 세력의 입장에서 시장을 바라볼 수 있게 해줍니다.책을 읽고 내용을 이해한다면 실전에서 적용이 가능한 책이라고 생각합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1572, 79, '차트에 어떤 특별한 비법이 있는 줄 알고, 그런 책들만 읽어 왔던 저에게 이 책은 그야말로 보물과도 같습니다. 여지껏 머릿속에서 정리가 안된 내용들이 이 책을 읽으면서 차곡차곡 정리되네요... 이책 저책 필요없습니다. 주린이분들에게 자신있게 이 책을 권해드립니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1573, 79, '믿음이 가는 작가님이십니다. 보다보면 이해가 가기 쉬우며, 지인들한테도 소개했습니다. 주린이라,, 아직은 저도 배워가는 입장입니다만 이책보시고 네이버카페, 유투브, 단체카톡방에 입문하게 되면 주식의 빨간불를 맛보게 될것입니다~ 주식공부는 나의 자산을 늘려줍니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1574, 79, '다른책보다 눈에 쏙쏙 머리에 톡톡 박히게 될수밖에없는 사이다같은 설명입니다.기술적분석의 찐갑.보이느냐 보이지않느냐 차이는 엄청나게 큽니다. 구매 하셔서 3번 이상 읽어보는 걸 추천 합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1575, 79, '주린이에게 꼭 필요한 책이에요. 주린이 눈높이에 맞춰 이해하기 쉽게 설명되어 있고 차트를 이해하는데 도움이 되요!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1576, 79, '세력이란 무엇인가... 그것을 알게 해주고 느끼게 해주는 책앞쪽에 보면 독자 후기가 몇편 나와있는데.. 책을 읽다보면 알게되는 그러한 책!늦게나마 알게되어 정말 다행이라고 생각되는 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1577, 79, '주식을 재테크의 수단으로 정하고 나름 시중에 유명하다는 책은 훑어 보았지만 어떻게 접근하는지에 대한 궁금증에 대한 갈증은 해소 되지 않던 차에 운이 좋게 이 책을 보게 된것은 참으로 다행이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1578, 79, '주식 초보입니다. 여러 종류의 주식관련 책을 보고 있는데 우연찮게 이 책을 알게 되어 보게되었네요.결론만 말씀드리면 정말 쉽게 구성되었습니다. 다른 책들은 이론에 이론만을 가미해서 실전에 적용하기가 어려웠어요. 하지만 개미대학 책은 실전에 써먹을수 있는 내용들이 많이 있어요. 강추해요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1579, 79, '틀에박힌 주식책을 벗어난, 실전전문 주식입문서 !기존책들에서 배웠던 내용들에서 몰랐던 내용도 많이 알게되었고,개미대학책 공부와, 카페 강좌등의 많은 유익한 내용들을 토대로 어느정도 저만의투자 스타일도 갖추게되었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1580, 79, '초보자의 입장에서 체계적으로 지식을 정리되어 있습니다.. 막연히 경제상황에 따라 주가가 오르고 내리고 하는게 아니라..세력의 개입이 있다는 점을 배우게 되었네요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (80, '고백', 227, 4.51, 0, 6, 13, 68, 140, 208, 13, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1581, 80, '나비효과와도 같은 사건과 인물의 연환고리. 뭔가 무척 일본스럽지만 한편으로는 매우 한국적인 면도 없지 않다. 어떤 경향이든 일본에서 일어난 건 대략 10-20년 후에는 한국에서도 일어났던 것이 많아서 그런지도.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1582, 80, '범인은 마지막에 정당한 응징을 받아야 제맛!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1583, 80, '작가의 다른 책들을 검색한다. 이렇게 강렬한 데뷔작이라니... 흡인력이 상당하고, 재미있다.미야베 미유키의 을 떠올리게 하는 지점들이 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1584, 80, '충격적이고 놀랍도록 스릴있다참 잼나게 읽은책!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1585, 80, '너무 기대가 컸다. 오래 도서관 대출을 눈여겨 보았는데...그래도 가나에의 작품은 다 읽을거다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1586, 80, '특이한 구성, 빠른전개 속에 각 인물의 심리묘사가 탁월하고 마지막 반전이 압권이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1587, 80, '영화도 나쁘지 않고 드라이한 느낌이 좋다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1588, 80, '충격적이고 재미있고!!! 완소강추!!! 소설!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1589, 80, '단 한순간도 눈을 뗀적 없이 단숨에 읽었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1590, 80, '무서운 것은 태도 불량한 반항아들이 아니다. 양육자로부터 나 아닌 다른 이를 향한 측은지심 사랑 등을 배우지 못한 소위 똑똑하다고 일컫는 아이들의 지식적인 무장이 가장 경계해야 할 것이다. 영화도 봐야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1591, 80, '여름이네요 손에 추리소설을 쥐고 수박을 같이 먹으면 정말 좋겠어요 꺄아~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1592, 80, '갑자기 얼마전 벽돌을 던져 살인을 저지른초등학생사건이 생각난다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1593, 80, '충격적인 이야기를 매력적으로 풀어낸 작품', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1594, 80, '일본의 정서는 반윤리적이다. 교사와 학생이 주인공이 되어서는 안되는 소설.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1595, 80, '치밀한 심리묘사를 바탕으로 흥미롭게 작품을 이끌어가는 힘이 느껴집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1596, 80, '[고백] 차분하고 완벽한 복수극! 고백은 처음부터 끝까지 각장의 주인공이 차분한 말투로 서술한다. 그런 분위기라 긴장감은 친천이 고조되고 마지막 마다 펑펑 터지는게 이작품의 백미! 특히 마지막의 그것은 내가본 모든 복수중의 가장 완벽한 복수였다. 복수극이라면 이정도는 해야지! ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1597, 80, '단숨에 읽었다. 다만 두번읽을 필욘 없을 듯,,,', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1598, 80, '사건 뒤의 이면으로 꽉 차 있는 이야기. 형식도 형식이지만 문체나 전개방식이 뭐 하나 새롭지 않은 것이 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1599, 80, '엄마 엄마 엄마 어머니', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1600, 80, '무조건 읽어야만 할 책...!!초강추', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (81, '이기적 유전자', 225, 4.16, 12, 10, 28, 54, 121, 175, 28, 22);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1601, 81, '코스모스를 생각할 때처럼 까마득한 먼 과거를 거슬러 올라가 ‘원시 수프’에서부터 진화한 유전자의 아득한 시간성을 상상해 본다. 나란 개체는 고작 100년 동안 유전자의 생존기계이자 운반자의 역할을 수행하지만, 그 연결성과 시간성이 켜켜이 쌓여 진화가 이루어졌음을 망각하지 말자.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1602, 81, '각종 사례들을 통해 유전자가 생존기계에 어떤 영향을 미치는지 보면서 유전자의 특성들을 이해하는데 큰 도움이 되었다. 소개된 사례들은 주로 동식물에 관련된 것들이지만 거기서 도출된 핵심 메시지들은 사람에게도 얼마든지 적용가능하다. 이에 더해 요즘 많이 쓰는 용어인 ‘밈‘에 대해서도 배웠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1603, 81, '위에 있는 예문만 봐도 읽고 싶지 않은 번역이네요. 두번이나 샀는데 아직도 못 읽고 있음', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1604, 81, '번역을 수정해주셨나요? 외장만 이쁘게 바꿀 것이 아니라, 내부의 오역들을 대대적으로 수정해주시길 바랍니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1605, 81, '교x문고에서 봤는데 번역 그대로네요. 에혀 과학교양서 구린전역 양대산맥이 이기적 유전자, 괴델 에셔 바흐 였는데 이중 괴델에셔바흐는 개정판 내면서 번역에 대한 아쉬움이 해소 되었는데 Selfish Gene은 아직 ㅜㅜ', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1606, 81, '번역이 손봐진 개정판이라면 흔쾌히 사겠소', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1607, 81, '번역때문에 구매가 망설여지네요', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1608, 81, '개정판이 자꾸만 이뻐져서 나오니 이제는 더 미루기도 어려울 성싶다. 더군다나 가격도 계속 오르니 더 비싸지기 전에 집긴 집어야 할 거 같은데.. 이번 개정판 역시 말 많은 번역만은 그대로일 것 같아 걱정이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1609, 81, '최악의 번역번역 다시해서 출간하시오이런 번역은 죄짓는 일이오당최 읽을수가 없소', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1610, 81, '아주 오래전에 홍영남이 번역한 책을 읽다가 짜증이 나서 책을 덮었다가 다시 읽어보려고 하니 여전히 화가 난다 .평소에 과학에 관한 책을 즐겨봐서 웬만한 내용은 이해가 되는데 홍영남의 번역은 정말 수준이하라는 생각이다 집중도를 떨어뜨리는 번역. 나만의 생각이 아닌듯해 위로가 된다', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1611, 81, '재미있고 의미있는 책이긴 한데 저자의 문체인지 번역의 문제인지 나에겐 너무 장황하게 느껴졌다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1612, 81, '번역 왜그래요 진짜..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1613, 81, '번역빼고 다 마음에 든다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1614, 81, '나도 그랬고 많은 사람들이 경험하지만, 세계관을 바꾼다는 의미에서 충격요법으로 정말 의미있는 책인 듯.다만 읽고나서 몇 번이나 새판이 나왔지만 정말 답 안나오는 번역때문에 다시 사기가 주저되기도 하고, 학술적 연구성과가 반영된 최근의 책도 많은데 굳이 이걸 또 살 필요가 있을까 싶음.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1615, 81, '번역상태가 심각하며, 판본이 바뀌어도 개선되지 않고 있다고 알고 있습니다.그렇다면 값싼 중고로 읽는 것이 합리적이지 않을까요.(한 번 짤린 평인데 명분으로 지적한 부분을 수정해서 다시 올립니다 ^.^ 관계자님 괜찮죠?)', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1616, 81, '이제는 도킨스와 대화할 마음의 준비자세 완료...그의 세계속으로 빠져보고 싶다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1617, 81, '자연선택의 단위가 집단이 아닌 개체(자가복제자)이기에 이기적이라고 하는 것이다. 하지만 11장의 밈 이론을 통해 비혈연자에게까지 이타성이 확장될 수 있는 가능성을 열어둔다.좀더 큰 시각을 갖게 해준 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1618, 81, '저자의 말대로 환타지라고 생각하고 눈 딱 감고 앞의 두 세 챕터를 읽어내면 너무도 재밌는 세상이 펼쳐진다. 인간 군상들 만큼 다양한 동물의 세계. 앞의 서문을 꼭 읽으셔야 해요. 저자의 생각이 빼곡히 담겨 있답니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1619, 81, '인간은 고작 유전자를 나르는 ‘생존 기계‘일 뿐.... 이 말에 오히려 생명의 위대함과 자유로움을 느꼈다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1620, 81, '생각의 변화를 불러일으키는 책의 대명사가 아닐까. 이 책을 읽고 인생관이 하루아침에 뒤바뀌는 경험을 했다는 최재천 교수의 추천사가 절실하게 와 닿는다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (82, '잠깐 애덤 스미스 씨, 저녁은 누가 차려줬어요?', 224, 4.73, 4, 2, 5, 28, 185, 213, 5, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1621, 82, '경제학에서 언급 가치도 없었던 ˝여성˝이란 변수를 끌고 들어왔다는 사실!!그걸 쉽게 독자에게 이해시키는 작가 필력이 대단합니다.이성적이고 명확하게 여성학이 필요한 이유를 설득합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1622, 82, '맨스플레인이라며 욕하는 사람 아무도 없는데 맨스플레인이라며 욕먹었다고 맨스플레인하고 있을 줄 알았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1623, 82, '가장 인상깊었던 글은.. 여성이 최근들어서 일하기 시작했다고는 하지만 사실은 그 전부터 여성은 일을 하고 왔었다는 말이 참 충격으로 다가왔다. 집에서 살림하면 우리는 그여자를 집에서 논다고 하지 일한다고 하지 않는다. 그만큼 얼마나 우리가 여성의 일을 우습게 여기는지 나조차도 반성..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1624, 82, '우리가 저녁을 먹을 수 있는 것은 푸줏간 주인 양조장 주인 혹은 빵집 주인의 자비심 덕분이 아니라 자신의 이익을 추구하려는 그들의 욕구 때문이다 라는 일화로 시작되는 이책은 근원적인 경제 문제를 파고들었던 애덤스미스 그가 살았던 시대와 현재 경제 상황을 새롭게 조명한 책, 소설처럼 읽혀요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1625, 82, '경제학자의 보이지않는 손이 그 자신의 어머니라니. 엉뚱한 말같지만 사실 당연한 말이네요. 경제학자의 내밀한 이야기와 보이지 않던 여성들의 이야기가 사뭇 인상적입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1626, 82, '여성과 경제학의 만남. 우리가 알던 그 관점과 좀 다르네요. 열심히 읽어봐야겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1627, 82, '페미니즘 얘기가 많이 나왔는데 경제학적으로 바라본 책은 거의 처음인듯. 근데 페미니즘 뿐 아니라 주류 경제학은 이런저런 면에서 비판할 소지는 많기는 하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1628, 82, '애덤 스미스가 이책을 좋아할까요~ ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1629, 82, '경제학자 애덤스미스의유명한 일화에서 시작하는데 저녁식사를 차린‘보이지않는손‘,어머니 그리고 여성들의 관점에서 창의적으로 관점을 창의적으로 나타냈다는 점이 신선하다. 페미니스트의 입장에서본 경제학에서는 여성의 권리,애덤스미스의 가까이에 있는 어머니부터 경제학속에 포함해야한다는 것', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1630, 82, '책에 대한 비판을 맨스플레인이라며 욕하고 있을 줄 알았다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1631, 82, '요즘 다른 분들의 서평을 열심히 읽어보고 있는데, 제목이 독특해서인지, 이 책의 서평을 여러편 읽어봤어요. 그런데 서평마저 톡톡 튀어서 기대가 자꾸 커져요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1632, 82, '경제 그리고 국부론에대한 관찰을 통해 이해해보자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1633, 82, '그동안 경제학에서 다루지 않은 여성의 입장에서 경제학을 새롭게 바라볼수 있어서 흥미롭네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1634, 82, '저게 비판인가? 뭘읽어라 제대로 읽어라가?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1635, 82, '경제학 서적을 굉장히 좋아하는데, 페미니스트 관점에서 경제학을 보는 책은 처음이네요. 읽기 불편한 페미니즘 책은 아니며, 재밌고 쉽게 읽힙니다. 다만 개인적으로 제목은 조금 아쉽습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1636, 82, '페미니즘이 성공하기 위해선 남성을 적으로 삼거나 배제해선 안된다.또 남성을,남성들이 여성들에게 그래왔듯이 일방적인 계몽대상으로 봐서도 곤란하다.그 보다는 남성을 해방되어야 할 동지로 보면 어떨런지.남성 역시 ‘남성성‘이라는 감옥에 갇혀 살아온 모순적 존재이니.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1637, 82, '주류경제학이 애써 외면해 온 경제학에 숨겨진 진실들을 속시원하게 파헤친 보기 드문 젠더경제학 책이다. 그간 경제학의 뒷편에서 묵묵히 제 몫을 다한 여성의 역할을 새롭게 인식함으로써, 점점 파국으로 치닫고 있는 자본주의의 위기를 근본적으로 변화시킬 수 있는 실마리를 우리 모두에게 던진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1638, 82, '여성 노동 가치의 새로운 관점으로 경제학을 분석해 볼 수 있어서 학문의 시야를 넓혀가는데 도움 받을수 있겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1639, 82, '제목이 기발하고 재미있습니다. 내용도 여성과 경제학에 대해유쾌하게 풀어나갈듯해서 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1640, 82, '애덤스미스가 밥을 먹을 수 있었던 것은 엄마의 손 때문이라는 말이 와닿습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (83, '엑시트 EXIT (리커버)', 224, 4.94, 2, 1, 0, 3, 218, 221, 0, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1641, 83, '‘선생님‘이라고 부르고 싶은 책이다. 한 페이지도 허투루 읽을 수 없었다. 투자 마인드를 새로이 배웠고, 삶을 살아가는 태도를 다시 배웠다. 1.생활비 이상의 현금 흐름 만들기, 2.간접 경험 진하게 쌓기, 3.항상 겸손하고 남을 존중하는 자세 가지기. 3가지를 늘 되새길거다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1642, 83, '저자가 강조한 부자가 되기 위한 시간 3년,이 책이 알려주는 레시피대로 차근차근 따라 하며 포기만 하지 않는다면 나는 확신한다.나도 부자가 되는 것은 충분히 가능한 일이라고.. 당신도 할 수 있는 일이라고...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1643, 83, '동생에게 선물하고 싶은 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1644, 83, '인생을 바꿔줄 문을 빨리 만나보고 싶습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1645, 83, '˝ 사람은 자신이 그린 대로 삶을 살게 된다!˝-누구나 방법만 제대로 알면 꿈을 현실로 만들고 부자가 될 수 있다. ‘된다‘ 라고 마음먹고 꾸준히 정진하라!-', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1646, 83, '‘송사무장‘ 이 이름으로 모든 설명을 생략한다.반드시 사서 읽어라. 열 번이고 스무 번이고, 이분의 가르침이 나에게 피가 되고 살이 될 때까지 읽어라', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1647, 83, '부자의 길로 EXIT할 지침서가 되는 인생책입니다 . 속시원하고 명쾌한 해답을 얻으실 수 있어요 ~!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1648, 83, '인생 전반적으로 도움이 많이 되는 꿀팁 대방출이네요!! 기본적으로 5번은 읽어보려구요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1649, 83, '실제 부자의 리얼 스토리 경험담입니다. 강추합니다~^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1650, 83, '인생이 뿌옇다면 그래서 앞이 잘 보이지 않는다면 EXIT를 찾으세요. 가장 빠른 출구입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1651, 83, '간만에 읽은 너무 좋은 책을 읽었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1652, 83, '나의 인생을 바뀌줄 터닝 포인트가 될 택을 찾았다, 그것은 바로 엑시트 EXIT인생 챕터에서 나는 과연 몇번째를 맞이하고 있을까. 많이 지나왔다 생각했지만 이책을 보고 이제 시작이구나 라는 생각이 들었다, 누구나의 인생책이 될만한 EXIT', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1653, 83, '자본주의 시장에서 살아가는 방법을 제시하고 있는 책! 원래 책 제목이었다는 ˝돈 버는 것이 제일 쉬웠어요˝라는 말이 정말 와닿습니다. 이 자본주의 사용설명서를 이해한 사람은 성공한다는 믿음으로 시작하려 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1654, 83, '송사무장님의 인생책^^나의 인생책. 책 한권이 인생을 바꿀 수 있다고 얘기한다. 이 책 한권이면 충분하다. 시간과 돈을 모두 가진 행복한 부자로 살 수 있는 방법이 여기에 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1655, 83, '읽고난 뒤 내 인생 책이 되었네요~^^ 함께 읽어보시죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1656, 83, '평소에 존경하던 송사무장님의 신간서적. EXIT는 평범한 사람들도 부자가될 수 있다는 길을 올바르게 인도해주는 책입니다. 이 책을 읽고 자신감과 확신을 얻었으며, 부자가 되는 힌트를 가르쳐주는 것 같아 좋았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1657, 83, '하루라도 빨리 부자가 되고 싶다면당장 읽어야 할 책찐부자가 들려주는 찐~짜 부자 이야기 !!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1658, 83, '경제적 자유를 얻기 위한 방법, 진정한 부자로 거듭나기 위한 방법이 고스란히 녹아 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1659, 83, '진짜 부자가 알려주는 자본주의 입문서', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1660, 83, '송사무장님의 EXIT 엑시트 책을 정말 오래 기다렸네요제가 그토록 바랬던 경제적 자유의 길로 #EXIT 엑시트 할수 있는 빙법을저같은 초보자도 어렵지 않게 간결하지만 힘있게! 전달하고 있습니다!!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (84, '아파트 제대로 고르는 법', 222, 4.81, 0, 0, 3, 37, 182, 219, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1661, 84, '이책을 통해 일반서민들에게 전재산인 집, 아파트를 언제 어디서 어떻게 구입해야 하는지 뿐만아니라 아파트 부동산 시장 규모와 구조 그리고 기복이 심한 아파트 매매에 대한 지식을 차근차근 쌓을수 있을것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1662, 84, '광고에 현혹되지 않고 예산에 맞춰 투자가치를 생각하면서 어떻게 아파트를 골라야하는지 자세한 정보를 알 수 있는 책 큰 도움이 되겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1663, 84, '부동산 전문가분이 쓰셔서 참 믿음이 갑니다. 부동산을 보는 안목을 기를 수 있었어요. 또 앞으로 아파트 투자 시장이 어떻게 변할지 궁금했는데 이 책이 해결해주었네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1664, 84, '다른 책과의 차별점: 1) 전세가/매매가 차이 적지만 매매가 변동 없는 곳. 사용가치 있고 투자가치 없음. 2) 주거의 멀티화와 매개상품 인기 상승. 밧 매개상품은 불안&유동성 안 좋다. 3) 미분양통계 불신, 준공후미분양통계 제안. 4) 전세난, 과장된 면 있다. 5) 아파트 사업구조에 대한 이해 강조.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1665, 84, '주거용 아파트 세세하게 잘 고르는 방법 궁금했는데 실용적인 책이네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1666, 84, '아파트 전문이라니 신선하네요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1667, 84, '부동산 재테크의 정석은 아파트투자죠.부동산 버블을 이야기해도 아직은 아파트투자가 유망하기에 저도 흥미롭게 이 책을 읽었습니다.아파트 구입에 관해 세세하게 유의사항들을 알려주고 있기에 큰 도움이 되었습니다.적극 실생활에 활용할수 있어서 좋고,재테크를 시작하는 사람들에게도 힘을주네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1668, 84, '아파트에 관한 많은 정보가 들어있는거 같아 기대됩니다. 아파트 구매와 매매할떼에도 많은 도움이 될거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1669, 84, '정말 중요한 것을 알려주는 책이네요.이런것을 학교에서 배웠어야 하는건데', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1670, 84, '제테크나 투기의 대상에서 벗어나 최소한 손해를 보지 않기 위해서라도 이 책이 필요하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1671, 84, '주식을 분석하는 만큼 아파트를 고르면 성공한다는 말을 들었다. 몇배 더 신중하게 구매해야할 아파트에 대한 모든것이 들어 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1672, 84, '아파트 구매할 때 주거목적도 고려하지만 나중에 팔았을 때를 생각해서 투자의 개념도 있는데요. 그것을 전문가가 조목조목 짚어주는 내용이네요. 단순히 조감도나 광고만 보고 선택하지 말고 여러가지 조건을 따져 보라고요. 아울러 아파트 관리관련 내용도 있어서 나름 사후서비스도 있다 싶습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1673, 84, '가장 큰 돈을 쓰게 되는 상품인데 제대로 알고 구입하기가 힘들어서 이런 책이 필요한 거 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1674, 84, '고민을 많이 하고 구입하게 되는 아파트 제대로 고르는 법을 배울 수 있을 것 같아 기대가 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1675, 84, '집을 고를 때 어떤점을 주로 봐야 할지 명확하게 설명이 된 것 같네요. 아무래도 부동산에서 하는 이야기랑은 다를 것 같아요. 궁금한점이 참 많은 책! 읽어보고 싶어요!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1676, 84, '어떤 집을 사느냐에 따라 애물단지가 되기도 하는 만큼 아파트 고르는 법을 알려주는 책이 있어서 신선하네요 아파트 사는것도 고민이죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1677, 84, '우리나라에서 말도 많고 탈도 많은 아파트를 어떻게 고르는지에 따라서 인생이 바뀌는 경우가 많은 것 같습니다. 내가 살집을 잘 고르는 것이야말로 노후보장의 길잉라 생각이 듭니다. 내 인생 최고의 책 강추!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1678, 84, '제가 살고 있는 지역에서도 요즘 아파트 분양이 많아 고민하고 있는데, 아파트에 대한 기본 정보를 알 수 있는 책이라 먼저 이 책을 읽으면서 지식과 정보를 얻어야할 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1679, 84, '아파트라고 해서 다같은 아파트가 아닌데 이책은 가치있는 아파트를 보는 방법을 잘 알려주고 부동산에 대한 안모을 키워주는거 같아서 기대가되는 책입니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1680, 84, '아파트를 고를 수 있는 지식을 배울 수 있는 시간이 될 것 같아 꼭 읽어봐야할 것 같습니다. 기대됩니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (85, '상실의 시대', 222, 4.05, 9, 8, 40, 70, 95, 165, 40, 17);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1681, 85, '이런 바보같은 일을 보았나?! 상실의 시대가 노르웨이 숲이 였다니 이미 읽은 책을 또 샀으니...', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1682, 85, '“우리는 그 슬픔을 실컷 슬퍼한 끝에 거기서 무엇인가를 배우는 길밖에 없으며, 그리고 그렇게 배운 무엇도 다음에 닥쳐오는 예기치 않은 슬픔에는 아무런 도움이 되지는 못하는 것이다.” p.413', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1683, 85, '2000년도에 읽고 2008년에 또 읽은 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1684, 85, '언제 읽어도 서늘하고, 신선하고, 새롭고, 아련하고, 아리고, 따습고, 서글프고, 설레인다. 하루키의 모든 소설과 수필을 좋아하지만 한 권을 꼽으라고 하면 역시 이 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1685, 85, '열아홉살에 처음 읽었을 땐 사람들이 왜 이 책에 열광하지? 싶었고 스물네살에 두번째 읽었을 땐 일본 아저씨 작가의 속이 빤히 보이는게 유치하다 못해 짜증이 나서 덮어버림ㅠㅠ', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1686, 85, '다좋은데... 레이코랑 꼭 할 필요가 있는 내용이었을까....', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1687, 85, '아 정말 목소리 잔뜩 깐 남자가 멋진 척 쿨한 척하면서 주변 여러 여자들이랑 잠자는 이런 섹스 편력기를 무슨 대단한 의미가 있는 것처럼 난리법석을 피우다니. 주인공 와타나베는 속을 감추고 사람들 듣고 싶은 얘기만 들려주는 괴물 같다. 하루키는 바람의노래를들어라 말고 전부 별로인듯', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1688, 85, '여성만 나오면 빠지지 않고 노골적인 성적 묘사를 한다. 애절한 감정이 담긴 문장들도 좋고 죽음에 대해서 잘 풀어쓴 책이라고 평하고 싶지만.. 작가의 여성관이 보여 읽는 내내 굉장히 불편했다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1689, 85, '하루키가 다시 이런 책을 쓸 수 있을까. 거대한 변화의 물결이 곧 덮쳐 올 것 같았던 순간, 한참을 기다리다 뒤돌아보니 그 물결은 어느새 사라져 있고 나는 이전보다 늙어있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1690, 85, '스물, 서른, 마흔에 읽을 때 다르게 와닿을 줄 알았으나 한결같이 처음 읽었을 때의 허허로움이 느껴지는 책입니다. 종종 잊고 살아가지만 문득문득 청춘다움이 그리워질 때 꼭 생각나는 시금석 같은 책입니다. 로 처음 만나서 그런지 보단 이 책이 훨씬 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1691, 85, '소문난 잔치에 먹을 것 없었다. 남는건 주인공의 여성편력..정도이다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1692, 85, '일종의 의무적으로 읽어야 하는 책이다. 천천히 스며드는 대신 그 공명의 충격은 상상 이상이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1693, 85, '하루키 매니아가 되도록 만든 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1694, 85, '15, 19, 20, 25에 읽을 때마다 다른', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1695, 85, '창밖엔 비가 내리고 있었다. 장마철 특유의, 바람을 동반하지 않고 곧게 내리는 비로, 모든 것을 남김없이 적시고 있었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1696, 85, '진짜너무잘본책이다하루키책중에 제일 좋기도하고여운도많이남고 생각도많이하게된다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1697, 85, '하루키의 수많은 책들중. 단연 손꼽을 수있는 가장 명저. 노르웨이의 숲이라는 노래까지 찾아 듣게 되었다는... 간략하게 드러나는 짧은 글(하루키의 작품중에서는)로 표현되는 쓸쓸함. 삶의 아픔. 고독...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1698, 85, '오래전에 읽어서 기억이 하나도 나지 않아 다시 읽으니 변해버린 내 감정...', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1699, 85, '나만 그런가...왠지 이질감이 느껴지는건.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1700, 85, '하루키 특유의 분위기가 물씬 풍겨나면서 어느때 읽어도 재미있습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (86, '반짝반짝 빛나는', 221, 4.22, 3, 5, 32, 81, 100, 181, 32, 8);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1701, 86, '읽고 싶었던 작가의 개정판 소설 너무 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1702, 86, '에쿠니 가오리 작가님의 소설, 25주년 기념 특별 개정판, 최고예요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1703, 86, '알코올 중독자 아내와 게이 남편, 그의 애인이라는 상식과 조금 벗어나는 이들의 관계가 어떻게 연관이 되어 있을지 기대가 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1704, 86, '이 책을 읽었던 건 동명이작 드라마 때문이었다.막 시작한 드라마보다도 이 책이 먼저 검색이 되어 동네 도서관에서 간 김에 단숨에 읽었다.그리고, 이 책이 다시 25년만에 출간되어 반가웠다.서로 다름을 침해하지 않고 이어가는 생활은 각자의 방식으로 균형을 이뤄 단단하다.반짝반짝 빛나는!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1705, 86, '도무지 해결책이 보이지 않는 암담한 상황에서 인간은 무엇을 할 수 있을까. 혹시나 있을지도 모르는 신의 허점을 찾아 숨바꼭질을 하듯 찾아 헤매야 할까. 아니면 모든 것을 포기한 채 그저 시간이 흘러가기를 바라야 할까. 그렇게 세월이 흐르고 모든 게 바뀐 상황에서 그 결과를 어쩔 수 없는 처분처럼 달게 받아야 하는 것일까. 에쿠니 가오리의 소설 을 읽는 독자라면 누구나 한 번쯤 그런 생각에 부딪히고 말 것이다. 작가는 이따금 너무나 낯선 설정으로 독자를 당황하게 한다. 물론 소설가라는 직업의 특성...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1706, 86, '[이 글은 해당 출판사에서 도서를 무상 제공받아 작성하였습니다.] 반짝반짝 빛나는.신혼부부인 쇼코와 무츠키 부부 그리고 무츠키의 동성 연인 곤.이 작품을 처음 읽었던 10여 년 전이었다.이 작품을 원어로 읽어보겠다는 욕심에 일본 문고본을 구매했고 이제는 표지 뒤편의 일본어를 무난히 읽을 수 있을 정도의 일본어 실력도 늘었다.​알코올 의존증에 조울증 증세까지 있는 아내 쇼코.의사 집안의 아들로 태어나 자신도 의사로 일하며 청소를 좋아하는 무츠키.고교 시절 옆집에 살던 대학원생 형 무츠키를 사랑하게 되어 연인이 된 곤.쇼코와 무츠키는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1707, 86, '"눈부시진 않지만 별처럼 빛나는 사랑"에쿠니 가오리의 를 읽고"눈부시진 않지만, 반짝반짝 빛나는 조금 이상할지 모르는 세 사람의 사랑"-20년 만에 개정판으로 돌아온 에쿠니 가오리 작가의 투명하고 반짝반짝 빛나는 이야기- 우리가 말하는 정상적인 사랑의 모습과는 정반대인 사랑의 모습은 비정상이라고 말할 수 있을까. 무엇이 정상이고 비정상이란 말인가. 그렇게 나에게 사랑이란 무엇일까 하는 근본적인 물음을...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1708, 86, '출판사로부터 도서를 제공받아서 작성한 리뷰입니다 출간 25주년 기념으로 만나는 에쿠니 가오리의 반짝반짝 빛나는은 잔잔하게 흐르는 강물처럼 조용하게 마음에 와닿는 이야기입니다. 각자의 사연을 가진 세사람이 살아가는 방식이 결코 평범하지는 않지만 그들에 대해 우리가&...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1709, 86, '예전에 ''냉정과 열정사이'' 라는 책을 재미있게 읽었습니다. 남자 작가와 여자 작가가 각각 남자와 여자의 입장에서 소설을 썼는데 같은 사건에 대해 서로 어떻게 생각을 하는지, 그리고 나중에 하나의 이야기로 어떻게 합쳐지는지를 보면서 무척 신선하였네요. 당시 무라카미 하루키 등 일본 현대 작가들에게 빠져 있었는데 이 책을 읽으면서 에쿠니 가오리에 대해서도 알게 되었고 이후 여러 책을 찾아봤었습니다.한동안 일본 소설을 읽지 못했었는데 ''반짝반짝 빛나는'' 은 2000년대 초반에 한국어로 번역이 되어 나왔었네요. 이번에 새롭게 출간된 책은 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1710, 86, '- 출판사에서 도서를 제공 받아 본인의 주관적인 견해에 의하여 리뷰를 작성했습니다.에쿠니 가오리의 작품 『반짝 반짝 빛나는』이 벌써 출간 25주년을 맞았다고 한다. 이를 기념하기 위해 이번에 기념 개정판이 출간되었는데 꽤나 멋진 구성이다. 마치 내 어린시절 유행했던 열쇠 달린 비밀 일기장처럼 패키지 박스로 되어 있고 하드커버에 전체적인 디자인도 굉장히 예쁘다. 제목과 참 잘 어울리는 표지 디자인이라는 생각이 든다. ​특히 한국 출간 25주년을 기념한 국내 독자들을 향한 작가의 친필 코멘트까지 담긴 도서라 더욱 의미있게 다가온다. ​...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1711, 86, '[ 출판사로부터 도서를 제공받아 작성한 리뷰입니다. ]25년 전이었다면 어땠을까요.지금과는 조금 다르게 느꼈을 수도 있지만 그들의 사랑을 응원하는 마음은 크게 다르지 않았을 거예요. 사랑하는 마음은 늘 반짝반짝 빛이 나니까요. 서로 진실한 마음만 볼 수 있다면 얼마나 좋을까요. 현실에는 너무 많은 껍데기들 때문에 봐야 할 것들을 보지 못할 때가 있어요. 에쿠니 가오리 작가님의 소설은 불필요한 껍데기를 벗겨내고 순수한 알맹이, 즉 인물의 내면을 섬세하게 묘사하는 데에 탁월한 것 같아요. 소설 속 인물들의 일상 이야기로 시작...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1712, 86, '출간 25주년 기념 개정판이다.오래 전 읽었다고 생각했는데 아닌 모양이다.한참 가오리 책을 읽을 때 읽은 다른 소설 제목과 착각한 것 같다.읽었다면 이 놀라운 가족 구성과 삶의 모습을 기억하지 못할 리 없다.알코올의존증 아내와 동성애자 남편의 결혼 이야기라니.결혼할 마음이 없는 두 남녀가 만나 결혼한 후 일어나는 일을 다룬다.그 둘만의 삶이라면 큰 문제없이 살 수 있을 것이다.하지만 결혼은 단순히 둘 만의 문제가 아니다.다른 가족이 끼어들면서 예상하지 못한 일들이 생긴다.사회적으로 둘 다 불안한 상태에 있다.남편 무츠키는 곤이라는 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1713, 86, '[출판사로부터 도서 협찬을 받았고 본인의 주관적인 견해에 의하여 작성함]누군가를 좋아하게 된다는 것, 그 사람을 느낀다는 것,인간은 누구나 천애 고독하다고 생각한다.반짝반짝 빛나는, 이 제목은 이리사와 야스오씨의 시에서 빌려왔다고 한다.반짝반짝 빛나는 것을 우리 일상속에서 함께 해 나가지만 우리는 그 빛남을 알지 못하고 그냥 스쳐지나거나 생각도 하지 못하고 흘러보내게 된다.반짝반짝 빛나는 모든 것,눈부시지 않지만 반짝반짝 빛나는 세사람의 사랑이야기를 들어보자결혼이라도 하면 그 따위의 무책임한 조언 덕분에 일곱번이나 선을 봐...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1714, 86, '예전에 작가 ''에쿠니 가오리''의 소설을 읽은 적은 있지만 너무 오래전이라 작가에 대한 기억이 희미했다. 그런 시점에 이 작품 을 읽게 되면서 작가 ''에쿠니 가오리''의 작품이 이렇게나 ''세련되었나''라는 생각이 들었다. 이 작품 은 최근에 쓰여진 작품이 아니다. 무려 약 25년 전에 출간된 작품이다. 그럼에도 여전히 반짝반짝 빛이 나는 작품에 대해 뭐라고 할 말을 잃을 정도였다. 하루를 끝낼 무렵인 밤에 읽기 시작했기에 어쩌면 약간의 감수성이 더해졌을 수도 있지만 섬세하고 강하지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1715, 86, '의 작가 에쿠니 가오리는 동화, 소설, 에세이까지 폭넓은 집필활동을 한다. 작가는 참신한 감각, 세련미를 겸비한 독자적인 작품세계를 가지고 있다.내가 에쿠니 가오리의 소설을 읽기 시작한 것은 츠지 히토나리와 함께 쓴 이다. 이 책은 하나의 소설을 여성 작가와 남성 작가가 그들의 시선으로 쓴 소설이다. 에쿠니 가오리는 여자 주인공의 이야기를, 츠지 히토나리는 남자 주인공의 이야기를 썼다. 물론, 책은 , <냉정과 열정 사이 Blu&...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1716, 86, '**네이버카페 북뉴스의 지원으로 개인적 의견을 솔직하게 작성한 리뷰입니다**뭐든 반짝반짝 빛나는 것들을 좋아하는게 사람이다. 아니 대부분의 사람들이 그러한 경향을 가지고 있다고 본다.허나 그러한 모습이 우리의 삶이나 인생이라면 더더욱 우리는 바라마지 않는 욕망으로 뒤바뀔 상황이 될 수 있다.마음 한가득 반짝반짝 거리고 빛나는 삶과 인생을 위해 우리는 오늘도 고군분투하는 자신의 모습들을 목도하고 있지 않나 싶다.그...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1717, 86, '#협찬 #서평>>에쿠니 가오리의 『반짝반짝 빛나는』에 가장 먼저 호기심이 생긴 이유는, 게이 남편과 알코올 중독을 동반한 조울증 아내라는 설정 때문이었다. 이 두 사람은 어떤 사연으로 부부가 된 걸까. 그 점이 무척 궁금했다.결혼한 지 열흘 된 부부, 아내 쇼코는 술에 쉽게 의지하고 감정의 기복이 큰 사람이며, 남편 무츠키는 남자를 사랑하는 내과 의사다. 게다가 무츠키에게는 오래 사랑해 온 대학생 애인 곤이 있다. 각자 애인을 둬도 된다는 조건으로 결혼한 두 사람이지만, 현재 쇼코에게는 따로 만나는 사람이 없다. 이 세 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1718, 86, '출판사로부터 도서를 제공받아 주관적인 견해에 의해 작성한 리뷰입니다​​이 소설 《반짝반짝 빛나는》은 조금 충격적인 소설이었습니다. 작가 이름은 알고 있었지만 기억에 남을 정도로 책을 읽을 적은 없습니다.그런 에쿠니 가오리라는 작가의 《반짝반짝 빛나는》은 동성애자 커플인 무츠키와 곤, 또다른 게이 커플 카키아와 카지베, 무츠키의 아내 쇼코가 나옵니다.무츠키와 애인 곤은 12년동안 연인입니다. 연인이지만 사회적으로 용인되지 못하다 보니 쇼코와 중매결혼을 합니다.하지만 무츠키는 자신이 게이라는 것을 가족에게도 친구에게도 숨기지 않습니다....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1719, 86, '출판사로부터 무상으로 제공된 후기입니다^^ 반짝반짝 빛나는 예전 어렸을 때 읽었던 에쿠니 가오리의 "반짝반짝 빛나는"이 25년만에 리뉴얼되어서..또 읽게되니~ 그때와는 전혀 다른 느낌이라니!!! 이 에쿠니 가오리의 짧은 문체가 좋아요. 알코올 중독과 조울증이 있는 아내 쇼코와 게이 남편 무츠키~ 정말 특이한 조합이예요. 각자의 연인 관계를 상관하지 않는..부부라니~~ 신기하기도 하고 요즘 세상엔 적지 않게 있을 것도 같고요. 저는 원래 동성연애에 대한 거부감(?)이 조금 있어서.. 모르고 읽었을 때 놀랐었는데~ 지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1720, 86, '아내 쇼코는 알코올 중독과 조울증을 앓고 있고,남편 무츠키는 대학생 애인 곤을 둔 게이다.무슨 생각을 하는데, 라고 무츠키가 물었다."인생에 대해서"엉뚱한 대답을 했는데, 무츠키는 진지한 표정으로고개를 끄덕인다. 아이리시 위스키를 마시면서 이렇게남편과 밤바람을 쐴 때 나는 아주 행복하다.엄마의 전화는 이래서 싫다. 우울한 일만 생각하게 된다.무츠키는 여자를 안고 싶어 하지 않는다. 키스도 해 주지않는다. 그러니까 이런 거다. 알코올 중독에 걸린 아내와게이 남편. 참, 그야말로 끼리끼리다."그 녀석과 결혼을 하다니, 물을 안는 것이나...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (87, '순간의 힘', 221, 4.79, 0, 1, 7, 29, 184, 213, 7, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1721, 87, '결정적 순간이란 오래 기억하고 싶은 의미를 지닌 짧은 경험을 뜻한다여기서 짧은은 한평생 중 한 달일 수도 있고 통화 중 1분일 수도 있다모든 순간은 같지 않고 어떤 순간은 모든 것을 바꾼다평범한 순간을 결정적 기회로 바꾸는 경험 설계의 기술 이책을통해 연마해보자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1722, 87, '인생을 바꾸는 강렬하고 극적인 순간을 ‘스스로‘ 만드는 법을 알려주는 책. 기회를 기다리기만 하는 게 아니라 스스로 기회를 만드는 법을 알려준다는 점이 좋았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1723, 87, '짧은 순간 하지만 인생을 바꿀수도 있는 순간 기회를 놓치기 않기 위해 미리 대비하는게 중요한듯한데요 경험설계라는 단어도 이책을 통해 처음 듣고 배울수 있을것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1724, 87, '시간이 흐른 뒤에야 뒤늦게 깨닫게 되는 결정적인 순간이었던 그 선택의 찰나를 어떻게 제대로 보내야 할지 알고싶네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1725, 87, '누군가에게는 특별하고 의미있는 중요한 순간이고, 누군가에게는 그냥 놓치고 마는 순간들! 이 책은 특히 놓치지 말아야 할 순간들에 대해 어떻게 생각하고 대처하면 좋을지 깨닫게 해주는 책 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1726, 87, '누구나 인생에 기회가 3번은 있다는데 그 기회를 놓치지 않으려면 순간을 잘 포착해야겠죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1727, 87, '인생의 중요한 순간들은 너무 빨리 지나가버린다는 생각이 들어요 내가 노력해서 만들어갈수 있다는 것만으로도 흥미롭게 느껴지네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1728, 87, '찰나에 인생이 많이 바뀔수있다. 그 순간을 노려라.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1729, 87, '매순간 집중하라는 깊은 뜻이 담겨 있는 책. 순간에 집중을 못하면 기회가 온 것도 모르고 지나칠 수도 있으니.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1730, 87, '삶의 변화가 절실한 사람들이 평범한 순간을 결정적 기회로 바꾸는 방법에 대한 가장 최고의 조언을 들어볼수 있을것 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1731, 87, '히스형제의 책은 무조건 읽고본다 ㅎ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1732, 87, '늘 특별한 순간을 찾아서 두리번 거리라는 말이 마음에 와닿는것 같습니다.평범한 순간을 결정적인 기회로 바꾸는 경험설계의 기술이 평범한 사람에게는 정말 특별한 순간이 될것 같습니다.극적인 순간을 나의 것으로 만드는 힘을 길러야되겠어요!기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1733, 87, '자신의 인생극장에서 주인공이 되려면 삶에 대한 적극적인 참여가 필요할듯 합니다. 모든것은 자신의 의지에 달려있겠죠.작은 변화로 평범함에서 특별함으로 바꿀수있는 순간을 설계하는 [순간의 힘]_고양,통찰,긍지,교감 4가지 요소에 주목해서 나와 나의 주변을 설계해볼 필요가 있다 생각이 듭니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1734, 87, '결정적 순간은 바로 지금이라는 생각도 드네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1735, 87, '순간을 캐치할 수 있는 힘을 기를 수 있어야하고 그걸위해 준비되어있어야 한다는 것을 다시한번 깨달았다. 앞으로 남은 시간을 더 값지게 보내기 위해 많은 노력을 해야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1736, 87, '나에게 오는 많은 순간을 캐치할 수 있는 능력을 길러보고 싶었던 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1737, 87, '사람들은 순간순간 선택을 하면서 살아가는데 그 찰나의 순간을 이야기 하네요. 이 책은 평범한 일상을 결정적 순간으로 만드는 경험 설계의 기술을 말하면서 기업들이 고객의 불평을 처리하는 것도 중요하지만, 고객들에게 특별한 순간을 선사하는 마케팅을 하는 것도 빼놓지 말아야 한다고 이야기 함', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1738, 87, '결정적 순간으로 인해 인생과 삶이 바뀌거나 큰 변환점이 되기도 합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1739, 87, '성공하기 위해서는 노력도 중요하지만 나의 노력이 빛을 발할 결정적 순간을 알아챌 수 있는 안목도 있어야 합니다. 기회가 와도 놓치면 그만이죠. 나를 위한 최선의 기회를 잡고 싶은 분들께 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1740, 87, '결정적인 순간이란게 늘 오는건 아닌데 그것을 오게 할려면 어떻게 해야하는가를 잘 알려주는 책이네요. 순간의 힘을 잘 축적해놔야 특별하게 어떤 기회가 오는것을 잘 알려주고 있습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (88, '베어타운', 219, 4.67, 0, 1, 9, 52, 157, 209, 9, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1741, 88, 'N23080 처음 읽은 ''프레드릭 배크만''의 작품. 벽돌책이긴 하나 재미있어서 한번에 읽었다. 다양한 인물들이 등장하지만 누가 주인공이라고 할것도 없이 모든 캐릭터가 살아있다. 단순한 아이스하키 이야기가아님. 양심과 이익 사이에서 갈등한다면? 애매할때는 부끄럽지 않은 방법을 선택하는게 답이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1742, 88, '압도적인 도입부. 깔끔한 문장과 온도. 읽고 나면 가슴에 곰을 품고 살아가는 이들을 계속해서 생각한다. 우리가 발 딛고 서 있는 이곳과 다를 바 없기 때문에.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1743, 88, '주옥같은 삶의 문장들이 정말 많다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1744, 88, '소설의 전반을 지배하는 ˝탕탕탕탕탕˝분위기를 형성하는 동시에 소설의 복선을 암시하기도 한다.공동체의 침묵. 그리고 한 사람의 외침.미투운동으로 혼란한 이 시기에 읽기 좋은 소설이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1745, 88, '작가가 캐릭터를 한명 한명 풀어나가는 방식이 흥미롭다 :)잠시 잊고 있었던 청소년기의 감정도 새록새록 떠오르고, 어른들의 이익을 위한것인데도 본인들의 꿈이라고 굳게 믿고 하키의 꿈을 키우는 아이들에게 연민을 느끼기도 한다. 다양한 감정이 드는 스토리.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1746, 88, '두툼한, 아주 두툼한 프레드릭 베크만의 신간~베어타운의 고급 주택 하이츠와 중산층이 거주하는 중심가 연립주택에 거주하는 사람들의 이야기를 만나본다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1747, 88, '중반부까지는 하키를 사랑하는 마을의 박진감 넘치는 청소년하키부의 이야기인 듯 했으나 후반부는 이야기의 중심이 바뀌었다. 가해자와 피해자의 생각의 차이. 여성과 남성. 지키려는 자와 다투려는 자.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1748, 88, '등장하는 인물들 각자의 마음 속 세상에서 욕망과 좌절, 상처와 고통, 희망과 사랑, 비루함과 용기, 분노와 성장의 세계가 그려진다. 순백과 암흑의 세상은 그저 물리적 배경일 뿐. 오늘, 여기, 우리의 이야기와 다르지 않다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1749, 88, '다수의 이익을 위해 진실을 왜곡하는 많은 사람들.. 그속에 내 모습이 있네요정당화 될 수 없는 잘못들, 정직과 용기의 기준이 왜곡되는 순간 우리는 인간이기를 포기합니다. 너무나도 많은 생각을 하게 하는 작품입니다.나라면..뭔가를 바꿀수 있었을까..마야와 아맛의 진정한 용기!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1750, 88, '그 와중에도 좋은 사람들이 있어서 다행이었고, 그 와중에도 마야가 자신의 두 발로 일어서서 고마웠다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1751, 88, '공동체와 연대의 진정한 의미가 무엇인지 생각해보게 하는 작품입니다연달아 작품을 성공시키기에는 힘들텐데 작가의 필력이 정말 대단하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1752, 88, '잔잔하지만 오래 기억에 남을 작품이네요 긴여운을 간직하기에는 충분한 듯 합니다 전작들과 비슷한 분위기이지만 전혀 다른 내용으로 또 한번의 감동을 줍니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1753, 88, '책소개기울어 가는 조그마한 마을인 베어타운... 이곳에서 펼쳐지는 가슴에 곰을 품은 사람들의 희망 스토리입니다. 아마존, 뉴욕타임스 1위 『오베라는 남자』의 작가 프레드릭 배크만 신작 장편소설... 절대 후회되지 않을 감동 이야기입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1754, 88, '프레드릭 배크만의 작품을 모두 읽은 독자로서 은 좀 실망스러운 작품이다. 전작들과 동어반복인 구성도 그렇고 성차별적 표현이 너무 아무렇지 않게 나와서 당황스러웠다. 시적 허용의 범주로 인정하기엔 주제 의식을 고려해 보면 더 당황스러운 면이 있는듯. 번역의 섬세함이 아쉽다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1755, 88, '이 작가의 책들을 다 읽어보고 싶었다하키 경기장에 있는기분책을 읽고있지만영상으로 보는듯한 기분대단하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1756, 88, '너는 왜 거부하지 않았는데, 왜 바로 말하지 않았는데, 왜 거기까지 따라갔는데. ‘그럴 수도 있겠지만’에서 ‘당해도 싸다’라고 생각하는 사람들에게 억지로 쥐여주고 싶은 책이었다. 얼마나 울었는지 모르겠다. 그 작고 단단한 마야의 삶이 조금의 공허와 큰 성취와 만족으로 이어졌으면 한다. 이 땅에 수많은 마야들도.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1757, 88, '가볍게 읽을 수 있는 소설', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1758, 88, '믿고 보는 베크만이죠. 이번에도 실망은 없습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1759, 88, '천재 작가의 천재적인 스릴러역시 대단하네요 추천.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1760, 88, '학교 도서관에서 읽어봤는데 초반에 지루했지만 갈수록 흥미진진하길래 완독했습니다. 처음만 넘어가면 읽기 수월해요. 그런데 프레드릭 배크만 책이 다 그런가요? 창문 넘은 100세 노인인가 그것도 비슷한 느낌을 받았는데 흠.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (89, '필 스터츠의 내면강화', 219, 4.89, 0, 0, 2, 19, 198, 217, 2, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1761, 89, '감정이 바뀌길 기다리지 말고 움직여야 한다는 스터츠의 메시지, 삶을 다시 흐르게 만드는 내면 훈련서.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1762, 89, '고통마주하기연습 을 이 책에서 배울 수 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1763, 89, '인생의 고통을 이겨내는 지혜', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1764, 89, '삶의 역경을 헤쳐나갈 수 있는 행동의 힘, 변화를 위한 통찰 30가지!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1765, 89, '과거의 정리보나 앞으로 나아감으로 치료를 한다는 것이 인상깊었어요. 과거정리없이 나아갈수 있는게 맞는걸지..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1766, 89, '정신과 의사인 저자 필 스터츠는 전통 치료법을 탈피, 치료 과정에서 새로운 ‘도구(툴스)‘를 사용하는 치료법을 개발했다. 이 치료법이 효과를 거둠으로써 정신의학계에서도 주목을 받고 있다. 심리치료를 한층 업그레이드 했다는 평가와 함께 매우 획기적 치료법이 될 것으로 기대되고 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1767, 89, '이 책은 40년간 교도소 수감자부터 상위 0.01%의 셀럽들까지 다양한 계층의 사람들을 만나온 세계적인 정신과의사 필 스터츠가 실제 상담 경험과 철학적인 견해를 담은 마음 훈련서이다. 삶에 대한 위로가 아니라 새로운 삶을 살기 위한 실천을 제안한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1768, 89, '저자는 우리의 내면에 강화를 갖출 수 있도록 지혜로운 통찰력을 제공해 주세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1769, 89, '자신의 내면을 강화하고 올바른 방향으로 나아가도록 하는 조언을 해주는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1770, 89, '그의 명성에 비해 책은 매우 겸손하고 친절하다. 다음 후속은 좀 더 구체적인 그의 이론을 더 알고 싶다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1771, 89, '내면을 강화시키는 필 스터츠만의 비법을 알게되어 행운입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1772, 89, '정신의학전문가사건의 철학철학으로써 삶에 대비하는 법', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1773, 89, '삶은 고통이 있다는 것, 불확실성을 인식해야 한다는 것, 그렇기 때문에 노력해야 한다는 것을 이야기해준다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1774, 89, '정말 좋은 책이에요. 자신을 더 발전시키고 새로운 미래를 만들고 싶다면 읽어보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1775, 89, '나 자신을 사랑하고 진정 자유로운 삶을 시작하는 고통 마주하기 연습을 통해 내면 강화 훈련하는 법을 배울 수 있는 책이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1776, 89, '고통은 어떻게 문을 여는가, 돌아갈 수 없는 길, 진정 자유로운 삶, 내 삶에 더 큰 힘을 들이는 법, 어둠만이 알려주는 것들, 아픔을 넘어서는 관계로 되어있다. 심리치료 심리학서다. 키워드는 영적인 성장의 가치. 영적 기술은 일상에서 의미를 찾아 우주와 관계 맺기다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1777, 89, '우리의 삶은 어느 한 순간에 영화의 엔딩처럼 끝이 아니다 완벽귀결이 아니다 현재진행형이다. 완벽한 어떤 환상에나 있을법한 인생의 우리의 기준이 되어서는 스스로를 불행으로 떨어지게 만든다. 우리의 삶은 끊임없이 움직이고 사건들이 계속되며 변화무쌍하다 예측불가이나 경이로울 수 았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1778, 89, '. 앞으로 살아갈 날들은 조금은 단단해져서, 괜찮은 울타리가 되고 싶습니다. 이번에 읽은 ‘내면강화‘는 그 방법을 찾기 위한 노력입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1779, 89, '고통을 감내하고 현실을 인정하며 내면을 단단하게 만들어 줄 팩트만을 이야기하는 도서에요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1780, 89, '고통을 외면하지 않고 마주하는 법, 필 스터츠의 현실적인 조언이 담긴 인생 가이드', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (90, '구해줘', 219, 3.97, 6, 15, 45, 67, 86, 153, 45, 21);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1781, 90, '판타지와 인간의 끝없는 사랑, 온정을 믹스해 놓은 작품!시각적인 투영성은 확실하다. 여러분이 책을 읽는다면 이미 당신은 맨하튼 일대를 초고속으로 누비며 질주하는 주인공과 하나 된 상황일 것이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1782, 90, 'p338-조디의 푸른색 눈이 마치 바다에 불을지른것처럼 붉게타오르고이 있었다. 마침내 루텔리는 그 눈에서어떤 메세지를 읽었다. 도움을 요청하는 간절한 메세지.구해줘!', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1783, 90, '뮈소 작품의 특징은 한편의 영화를 보듯이 가볍게 볼 수 있다는 점!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1784, 90, '하도 베스트셀러가 많은 작가길래 궁금해서 한 권 읽어봤다.슥- 하고 헐리우드 영화 한 편을 본 듯.소설 좋아하는 사람은 누구나 좋아하겠다.연출을 잘하는 글쟁이인 것만은 분명하나,내 취향 아님.;-)', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1785, 90, '기욤 뮈소의 신작이 나올때마다 늘 찾아서 읽어보는 편입니다. 대체로 그 다운 내용과 예상되는 스토리임에도 불구하고 자꾸 읽게 되는건 현실에서는 일어날수 없는 얘기들을 마치 그 주인공이 내가 된 듯한 느낌이 들게 작품을 쓰는 매력때문이죠. 줄리에트, 그녀가 가장 이입되는 주인공이였습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1786, 90, '그냥 단순 흥미소설...', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1787, 90, '처음으로 접한 기욤뮈소의 책..그후로 당신의 팬이 되었지', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1788, 90, '기욤뮈소 작가 유명하길래 읽어봤으나왜 유명한지 모르겠다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1789, 90, '도서관에서 내가 빌린 구해줘는 너무 많은 사람이 읽어 표지가 닳고 종이는 누랬다. 퀴퀴한 종이를 손끝으로 살짝 집어 넘기면서도 읽는 걸 멈출 수가 없었던, 스릴 넘치는 책이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1790, 90, '진정 사랑한다면당신 앞을 막아설 운명은 없습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1791, 90, '기욤 뮈소의 소설 그 이상도 그 이하도 아닌 작품', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1792, 90, '책을 읽는 순간만큼은 괜찮은 흡입력,그러나 이야기가 끝나면 그것으로 끝,여운은없다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1793, 90, '날 기욤뮈소의 광팬으로 만든 책.....미친듯이 기욤뮈소 책을 읽게 만든 그책.......', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1794, 90, '한숨에 읽게 만드는 기욤 뮈소의 흡입력.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1795, 90, '기욤 뮈소 책 중에서 제일 처음에 읽게된 책인데 이 책 읽고 기욤 뮈소에 푹 빠지게 되고 책 다 찾아서 읽어보게됐습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1796, 90, '저는 너무 재미있어서 여러번읽었습니다 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1797, 90, '친구가 슬프다고 해서 읽었는데 ... 그냥 프랑스 여자가 뉴욕인가에 가서 혼자 타지생활하는데 남자 만나서 원나잇 하는 내용...연애소설 좋아하는 분만 권장함', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1798, 90, '2013년에도 이 책의 리뷰를 위해 노트에 펜을 들었건만, 내가 쓴 말은[두 달이 지난 후 그 책의 내용이 기억나지 않는다면...?]지금은 어렴풋이 그때보다 기억이 선명하네.한 번은 보아도 괜챦아요.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1799, 90, '단번에 기욤 뮈소의 팬으로 만들어 준 작품. 문학성 강한 책들 읽기 싫어하는 사람들에게 적격인...', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1800, 90, '프랑스든 어디서든 베스트셀러 할 만하다. 딱 그런 성격의 소설이다. 대중영상물과 대중문학 간 상상력 상호 침투가 너무 고스란히 드러난다는 것 정도가 특이하달까. 이 소설의 히트는 평범한 것도 이렇게 전형적으로 평범해지면 시장에서 큰 장점으로 작용한다는 것을 보여준다.', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (91, '향수 (양장)', 219, 4.38, 1, 2, 23, 79, 114, 193, 23, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1801, 91, '기괴하고, 독특하고,,, 거기에 재미까지 더 했다. 이 책에 더 얹을만한 소스는 없을 것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1802, 91, '특이하게도 주인공이 죄를 지을수록 분위기가 암울해지지 않고 점점 밝아져가는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1803, 91, '중학교때는 이해하지 못했던 주인공의 집착과 재능을 다시 알게된 소설 미치도록 광기가 넘치치만 그가 불쌍하다고 생각했던 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1804, 91, '푸코라면 아마 이 책을 읽고 냄새와 대공포라는 장을 생각했을지도 모르겠다. 와 겹쳐 읽어도 좋을 듯.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1805, 91, '최고...완전무결한 ‘결말‘ 이란 이런 것.영화로 만들지 말았어야했음.그의 마지막을 어찌 감히 시각언어로 표현하려하셨나이까...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1806, 91, '천재적인 글 솜씨에 감동. 너무 재미있게 읽었다. 나의 책장에 소장해 두고 아끼는 책중에 하나이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1807, 91, '매우 아름답고 재미있다. 글의 세련됨은 고전을 읽는 기분이 들게 하고 내용의 흥미로움은 공상소설을 읽는 기분이 들게 한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1808, 91, '인간의 상상은 어디까지 가능할까? 세속을 외면한 작가 특유의 냉소가 느껴진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1809, 91, '향기를 소재로 이런 소설이 나올수가 있구나~ 멋진 작가,멋진 작품이다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1810, 91, '내용도 문장도 어렵지만 매끄럽고 흡입력있는 깔끔한 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1811, 91, '소름끼치게 신선하고 고개를 끄덕이개 했던 작품.주인공을 미워할 수가 없었다는 것, 오히려 가엾게 여겼던 것이 인상깊다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1812, 91, '아름다움을 향한 그의 욕망은 안쓰러웠으나 욕망을 추구하는 방식은 추악했다향기 없는 주인공 그리고 온갖 냄새와 향기로 가득찬 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1813, 91, '파리의 우울한 잿빛 하늘, 오물과 악취, 그리고 그것들을 감추기 위한 숨막힐 듯한 향수 냄새가 뒤섞인 소설', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1814, 91, '영화 때문에 읽게 되었는데, 영화보도 훨씬 재미있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1815, 91, '매혹, 에로틱, 데카당스', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1816, 91, '18세기 프랑스에 한 남자가 살고 있었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1817, 91, '책도 영화도 그닥..별루야이런 음침한거 시러소재의 독특함은 인정!', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1818, 91, '재밌다독특한소재 악마의재능', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1819, 91, '책 속에 우주가 들어있는 것 같다차원 이상의 상상력..오랜만에 ｀소설을 읽는 짜릿함｀을 풍부하게 즐겼다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1820, 91, '아름다움이 무엇인가를 생각하게 하는 책', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (92, '미 비포 유', 218, 4.58, 1, 0, 15, 57, 145, 202, 15, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1821, 92, '지금껏 읽었던 모든 책들중 가장 심장이 저릿한 기분을 들게 한 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1822, 92, '25장에 이르러 참았던 눈물이 쏟아졌다. 마치 아무일도 해줄 수 없던 루처럼. 한때 자신의 삶을 즐기며 살았던 윌이였기에 진정한 삶이 무엇인지 온힘을 다해 그녀에게 들려주던 모습이 잊혀지지않아 한동안 마음을 추스리기 힘들었다. 그리고 묻게된다. 도대체 내 발목을 잡고 있는게 무엇인지를.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1823, 92, '여전히 가능성이 있다는 걸 알고 사는 건, 얼마나 호사스러운 일인지 모릅니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1824, 92, '오늘 영화로 보고 왔는데~ 모처럼 좋은 영화를 만난 듯~ 윌리엄의 입장이 되어 사랑하는 사람을 눈 앞에 두고도 아무것도 할 수 없다면?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1825, 92, '삶과 죽음에 대한 선택의 기로에 선 이의 이야기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1826, 92, '의지가 있을 때 내 삶을 결정 내릴 수 있는 ‘본인‘ 자체가 얼마나 소중하고 중요한 것인지 깨닫게되었습니다. 동시에 여러 입장에서 다시 생각해보게 하는 책이네요. 죽음을 맞는 주인공과, 남겨져야하는 사람들의 입장 등.. 재밌게 잘 읽었습니다 ^^ 소설의 여운이 영화보다 크네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1827, 92, '클라크보다 윌에게 더 감정이입이 된다. 윌의 선택을 반대하지 않는다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1828, 92, '이 책의 흡입력은 엄청나다. 이 두꺼운 책을 틈날 때마다 붙잡고 하루에도 몇 번씩 윌이 되기도 루가 되기도 했다. 내가 그들인 것처럼 고민했고, 기뻤고, 슬펐다. 괜스레 허전해지는 가을을 맞이하는 책으로 제격이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1829, 92, '영화를 먼저봐서인지 인물들에대해선 배우의 얼굴이 떠올랐지만 아는 전개에도 불구하고 책만의 매력이 분명히 있다. 둘다 봐서 더 좋았던 경우다. 영화도 책도 둘 다 봐야하는 이야기였다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1830, 92, '가볍게 읽으려고 선택한 책이었는데, 내 존재를 규정하는 것은 무엇인가, 죽음이란 무엇인가에 대해 생각이 많아졌다. 피닉과 대너리스의 결합이라니, 영화도 기대된다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1831, 92, '흔한 스토리와 뛰어난 흡입력.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1832, 92, '아 진짜 눈물 펑펑 쏟으며 읽은 책그저께 딱 윌 케이스 25살 환자가 입원 했는데너무 안타깝다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1833, 92, '헤어나오기 조차 싫은 이야기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1834, 92, '명불허전. 처음부터 마지막 페이지까지 다 읽으면 안다. 대단한, 제인 오스틴의 후예들.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1835, 92, '결말에 도달하기 전까지는 재미있게 읽었으나 끝까지 읽고 난 뒤는 마음에 찝찝함이 계속 남아있다. 남녀간의 사랑보다 인간의 존엄한 죽음에 대해서 계속 생각하게된다. 그냥 읽고싶었던 책으로 남겨둘껄 하는 마음이 크다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1836, 92, '참 여운이남았던 책입니다.개인적으로 이 소설이 영화화된다면 여주인공으로 레이첼 맥아담스가 제격이라는 생각을 했었어요!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1837, 92, '나만 지루했나봐필요없는이야기가 너무많았다고생각..진도너무안나가서읽는게 힘들었다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1838, 92, '친구가 빌려줘서 읽었는데 끝을 향해갈수록 맘속으로 해피엔딩을 얼마나 외쳤는지...너무너무 마음이 아파서 많이 울었네요...정말 여운이 긴 책입니다너무 재미있었구요...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1839, 92, '챡이 너무 아름다워서', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1840, 92, '왠만해서 책을 끝까지 읽기 쉽지 않은 나로서는 이 책으로 부터 매우 감동 받았다. 여운이 길게 남고 특히 중반 넘어가서부터는 그 다음 전개가 궁금해서 견딜수 없을 정도 였다. 비록 세드앤딩이지만 과연 그게 당사자에게는 세드앤딩이 아닐수도 있다는 느낌을 받았다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (93, '지도로 읽는다 미스터리 세계사', 217, 4.79, 0, 1, 7, 28, 181, 209, 7, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1841, 93, '세계사의 미스터리한 이야기를 지도와 그래픽을 통해 자세하게 설명하기에 새롭습니다. 그 당시의 현장 속으로 들어가는 느낌이 들 정도로 현실감을 주기에 시간여행하는 기분이 들 정도입니다. 지도 위에 그려진 상세한 그래픽이 마음에 든 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1842, 93, '역사상 중요한 사건과 인물에 얽힌 여러갈래로 뻗은 미스터리를 새로운 연구 성과를 토대로 역사적 사실과 현장을 생생하게 복원해낸 이책을 통해 신화와 전설 속에 숨겨진 놀라운 비밀들이 이토록 많은지 처음 알았네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1843, 93, '미스테리와 지리과역사의 장대한 지식이 결합된 책같네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1844, 93, '지도를 따라가면서 읽으면 알아보기 쉽고 이해하는데도 편할 것 같네요 항상 머리속에서 그리면서 보는게 힘든데 지도가 있으면 좀 더 쉽게 이해할 수 있을 것 같아서 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1845, 93, '세계사나 한국사 책에서 지도 없이 지역명을 떠들며 4대문명이니 뭐니 떠들어대는 걸 읽으면서 대체 무엇을 이야기하는 것인지 종잡을 수 없었던 기억을 가진 사람으로서, 지도만 보면 그냥 홀딱 홀려버리는 감정을 자동으로 지닌사람이 되어 그냥 책바구니에 담아버림.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1846, 93, '우리가 궁금해온 그러한 역사속 알짜배기이야기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1847, 93, '아직까지 진상이 밝혀지지 않은 미스터리를 지도와 함께 볼 수 있어서 새롭네요4대 대륙에 걸친 흥미진진한 역사 속의 미스터리를 만나볼 수 있을 것 같아서 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1848, 93, '세계 미스터리 역사를 지도를 통해 생생하게 규명하면서 여러가지 설로 증명해 가는 해설이 아주 좋네요. 유럽과 아시아, 아메리카, 아프리카의 미스터리를 1장~4장으로 나눠 전세계적 역사적 중요 이슈를 비교적 상세하게 다루고 있어 관심있는 독자의 흥미를 유발하고 궁금증을 해소해 주네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1849, 93, '지도로 보는 세계사라 어떤 내용일지 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1850, 93, '지도를 통해서 역사를 인식할수 있으니 시도가 좋은것 같습니다.지도를 펼쳐놓고 지역에 따라 얽힌 세계의 역사를 한눈에 볼수 있어서 이해가 쉬울것 같아요. 기대되는 책중 하나입니다.세계사에 관심을 기울이는 어른들은 물론 아이들도 이런류의 책들을 곁에 두고 열심히 읽으면 좋겠군요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1851, 93, '역사에 관심없는 사람도 재미있게 느낄만큼 지도와 미스터리 내용등이 담겨있어 기대가 생기네요 아이들과 함께 세계사에 대해 이야기하며 읽으면 더더욱 좋을것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1852, 93, '지도로 읽는 시리즈는 다 값어치가 있죠', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1853, 93, '역사이야기를 좋아해서 이책도 흥미로워보이네요. 지도를 통한 세계사의 미스터리를 읽어볼수 있다니 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1854, 93, '세계사의 미스터리를 지도와 텍스트가 결합된 새로운 형식의 구성으로 접하면서 몰입감을 높이게 하는 흥미로운 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1855, 93, '지도로 역사를 배우면 더 효율적일거라 생각해요. 지도에 표시를 해가며 역사를 배웠지만 거기에 그치지 않고 텍스트를 더 추가시켜 설명을 더하고 미스터리한 이야기들을 함께 한다면 흥미롭게 방대한 양의 세계사를 깔끔하게 정리할 수 있을 것 같아요. 시대별 보다 지도의 땅으로 나뉜 점도 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1856, 93, '세계의 미스터리를 모아 볼수있다니 정말 매력적인 책인거 같아요~!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1857, 93, '신의지문 이후로 제일 재미있었습니다. 특이 미스터리세계사는 서양 뿐 아니라 동양의 미스터리에 대한 부분이 특히 감명받았습니다. 앙코르와트가 미스터리이긴 했지만 방향부분은 또 새로왔습니다. 미스터리들을 과학적으로 설명하여 알기쉽게 해설한 부분이 책을 읽으며 같이 공감 할 수있었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1858, 93, '미스터리한 역사를 지도로 볼수 있는 기회가 된것 같다. 지도를 따라가면서 역사의 실마리를 하나하나 풀어간 재미가 솔솔하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1859, 93, '단순하게 지도를 놓고 이야기 하는 책이라 생각했는데 비교적 알려지지 않은 사건의 지도를 통한 다양한 미스테리를 풀어놔서 참 재밌다 싶습니다. 아가사 크리스티의 잠적과 관련한 지도라든가 케네디 암살당시의 지도를 통한 것들요. 미스테리와 세계사의 만남, 아주 흥미진진한요소다 싶어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1860, 93, '역사상 중요한 사건과 인물에 얽힌 여러 가지 흥미진진한 미스터리를 지도와 함께 볼 수 있어서 좋아요. 지도를 통해서 어떤 지역에서 있었던 일인지 직접 찾아볼 수 있어서 더 흥미롭네요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (94, '개수작 : 개인투자자 수익 대박 작전', 217, 4.78, 0, 2, 6, 30, 179, 209, 6, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1861, 94, '제목은 유쾌하고, 내용은 유익한 책이네요. 개인투자 수익을 높이는 작전! 투자에 대해 무지한 편이라서 조심스럽지만, 알고 있어야 할 주식투자의 비밀들이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1862, 94, '제목이 코믹한데, 내용은 실전 재테크이기에 유용하네요. 재테크는 누구나 관심을 갖기에 도움이 될 조언들이 가득하네요. 개인 수익 작전! 나의 소비패턴, 재태크에 대해 돌아보게 해서 좋아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1863, 94, '책 구성, 내용 전반적으로 퀄리티는 최고다. 양교주 깔때기 인정합니다.!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1864, 94, '재무설계, 리스크관리, 노후관리 등 개인 재테크 비법 선행학습서로 읽어봅니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1865, 94, '깊이가 너무 얇지만 그래도 몇 개 건졌다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1866, 94, '전문가들의재테크보험주식들살아가면서관심을가지는주요단어들을쉽게설명해좋아요옆에두고계속읽어볼만책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1867, 94, '주식을 잃고 실의에 빠졌다면 이책을 추천해요. 저도 5000천만원 잃고 이책을 보니 다시 힘이나네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1868, 94, '인생은 수작부림에서 시작이다...재테크 역시!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1869, 94, '개성있는 제목만큼 다른 주식관련 책에서 찾을 수 없는 참된 조언이 가득합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1870, 94, '점잖을 빼지 않고 군더더기 없게 세력들의 작전을 분석하고 개미들에게 설명한 책이라 무척 새롭고 반갑다. 주식투자가 재무분석 등의 기본분석이나 기술분석 대로만 된다면야 성공하지 않는 투자가 없겠지만 주식판은 그리 만만치 않기에 개수작을 통해 많은 영감을 얻어 가고싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1871, 94, '꼭 필요한 재테그! 많이 배워봅니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1872, 94, '청개구리 주식 사람들을 통해 많이 들어왔는데 책이나왔네요 책보고 주식한번 시작해 봐야겠어요 !', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1873, 94, '주식투자 어렵구도 어려운길이다. 이책으로 많은 도움이 되었으면 한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1874, 94, '개인 투자자가 주식등으로 돈 벌기 힘들다고 들었습니다. 그래서 펀드등을 많이 하는 것이구요. 작전세력에 휘말리지 않는 법 등의 주식투자실패확률 줄이는 법 가르쳐 주는 책이라 나름 실용서지 싶어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1875, 94, '제목때문에 깜짝 놀랐는데, 좋은 정보가 가득한 책인거 같네요. 특히나 팟캐스트로 많은 사랑을 받았다니 더욱 믿음이 가네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1876, 94, '세력을 이용하는 방법이라니?! 내용이 궁금하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1877, 94, '덮어놓고 남이 하라는데로 하면 망한다는 주식투자! 그리고 몰라서 못하고 알아도 못하는 그 주식, 보험, 연금에 대해 알려준다니 궁금합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1878, 94, '쉽지않는 주식투자에서 개미들에게 방향을 알려주는 책 같네요~~`', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1879, 94, '투자 전략의 가장 기초와 핵심을 모두 담고 있습니다. 입문서로 최고의 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1880, 94, '투자의 세계도 빈익빈 부익부 현상이 나타나서 안타까운데요. 개미투자자들에게 도움이 되었으면 좋겠습니다.', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (95, '괭이부리말 아이들', 217, 4.39, 0, 5, 20, 77, 115, 192, 20, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1881, 95, '몇 년만에 다시 읽었지만 그때의 감각과는 또 다른 느낌을 받았다. 어려운 환경 안에서 자라나는 아이들 각자 사정에 대한 이야기. 그리고 느끼는 감정은 어릴 때나 어른이 되어서 보더라도 충분히 공감되고 왠지 모르게 지금의 삶에 행복을 느끼게 만드는 작품.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1882, 95, '6.25 전쟁 후 가난했던 서민들의 삶을 고스란히 닮아낸 달동네를 보는 듯 애잔하면서도 인간미가 흐르는 동화다. 6,70년대 보릿고개를 겪으며 먹고 살기에 바빴던 시절, 부모로부터 소외됐지만, 괭이부리말을 배경으로 서로 위로하고 의지하며 꿋꿋하게 성장해나가는 아이들의 모습을 따뜻하게 그렸다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1883, 95, '따뜻하게 읽었다고 느낀 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1884, 95, '하루하루 열심히 살며 감사하자-', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1885, 95, '아픈 기억, 아픈 상처, 눈에 맺히는 ...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1886, 95, '20대 초반 책을 읽지 않는 나에게 독서의 세계로 이끌어준 소중한 도서', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1887, 95, '가난은 죄가 아니다 약간 불편할 뿐이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1888, 95, '작은마을의 크나큰 감동', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1889, 95, '소설은 소설일 뿐이다. 소설에 등장하는 주인공들은 어떻게든 인간답게 살아가려고 발버둥치는 감동적인? 모습을 보이지만, 현실에서 이렇게 열심히 사는 빈민층들이 몇이나 될까?? 이런 비루한 현실은 작가가 잘 알 테고, 성인 독자들도 알 것이다. 그럼에도, 마음 한구석에 감동과 희망이 솟아오른다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1890, 95, '삶이 던지는 묵직한 감동.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1891, 95, '오래전에 선정도서로 채택이 되어 읽었던 기억이 난다. 지금도 이 책을 보면 잔잔한 감동과 기분이 좋아지는 묘한 매력이 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1892, 95, '아이들의 마음을 건드린다. 정서적으로 부족한시대에 읽으면 좋을 책 지금까지 최고의 책으로 올라와있는 걸 보면 대단하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1893, 95, '중고로 사서 봤지만 새책으로 다시 사려고 들어와 글까지 남기고 싶은 책 !', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1894, 95, '인내심 많고, 착하고 희생적인 주인공인 영호형을 만들어, 가난을 개 개인이 짊어지고 해결할 수 있게 문제화 한 것보다는, 다른 해결책을 제시하는 결말로 이어졌으면 하는 아쉬움이 들었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1895, 95, '향수를 불러일으키는 책...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1896, 95, '소외된아이들 하지만 행복한아이들', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1897, 95, '이책을 보고 눈물을 참 많이 흘렸는데. 정말 감동 받을만한 책 , 꼭 보면 도움이 될듯', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1898, 95, '추억을 느끼게해주는책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1899, 95, '어렸을때 재미있게 읽었던 기억이 있어 선택했습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1900, 95, '가난을 소재로 한 글들은 참으로 아팠다. 그 대상이 아이일 때는 더욱 아팠다. 가난 구제는 나랏님도 못한다지만, 그들을 그토록 가난하게 살게 만드는 이 세상의 야박함이 싫어질 때가 참으로 많았다. 그것이 단지 허구속 상상의 산물이 아니라, 현실을 반영하고 있음을 알기에 더욱 가혹하게 느껴질 때도 많았다. 그것은 결국 우리 모두의 이야기로 보여졌으니... 아마도 현실은, 모든 이야기가 해피엔딩으로 끝나진 않을 것이다. 지독히 가난한 집 아이들이 그래도 마음만은 곱고 다부져서 오뚝...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (96, '시를 잊은 그대에게 (리커버)', 216, 4.76, 0, 0, 6, 39, 171, 210, 6, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1901, 96, '나는 공명해낼 수 있는가', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1902, 96, '나의 잃어버린 감성은..여기까지가 끝인가보오.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1903, 96, '항상 최고의 시를 쓰는 작가', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1904, 96, '고교시절 친구들과 늘 멋진 시를 찾아보았던 그 느낌을 이 책을 감상하면서 동일한 감정을 경험할 수 있어서 좋았어요. 젊어진 것 같고 추억도 되살릴 수 있었고, 아름다운 시를 만나 행복했네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1905, 96, '시를 맞이하는 기분에 따라 다르게 다가오는 시는 강의를 들으면서도 딴 생각하면 따로~~니 껍대기는 다 가라고 외쳐야 하나??', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1906, 96, '다시 시를 읽도록 하게 해준 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1907, 96, '시를 평가하는데 정답이 있다는 게 학교 교육의 가정이지요. 시의 해석도 쓰는 사람의 입장을 헤아려야 할까요, 읽는 이 맘대로 해석해야 할까요? 아무튼 이 책은 저자 나름의 해석과 더불어 독자의 주관도 배려합니다. 천천히 씹어 읽어야 할 듯.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1908, 96, '시 읽기를 오랫동안 잊고 살았는데 저자의 강의로 시를 접하다보니 새로운 감정이 생기는 듯 하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1909, 96, '단순히 암기를 하는것이 아닌 시를 읽고 감성을 일깨우도록 도와주는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1910, 96, '너무 퍽퍽하게 살아왔는데, 조금은 촉촉해지기를 기대합니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1911, 96, '교수님 강의가 좋아서!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1912, 96, '시를 잊은 나에게 선물하는 작은 사치', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1913, 96, '우리나라 말이 정말 아름답다는 것을 새삼 깨닫게 된 책입니다. 무턱대고 정답 맞추기에 골몰했던 시들을 마음껏 음미하며 읽으니 시가 재미있어 집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1914, 96, '시를 잊고 산 매마른 가슴...가을에 읽어보기 좋아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1915, 96, '정말로 제가 시를 잃었기에 그것도 아무 이유없이 그냥 잃었기에 꼭 읽어보고 싶었던 책입니다. 생각해보니 수능시험때를 마지막으로 시는 오랜만이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1916, 96, '입시를 위해서만 시를 읽었던 나에게 시에 대한 매력을 알려준 책. 시를 읽자', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1917, 96, '이 가을에 읽으면 좋은 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1918, 96, '시에 무지했던 나를 시의 세계로 이끈 책.주말 아침 이 책을 읽다 웃고 울게 만든 저자의 맛깔스런 글 솜씨는 경이로울 정도다.이런 책을 읽을 수 있었음에 감사합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1919, 96, '시는 마냥 어렵다고만 생각했었는데 다른 시각으로 새롭게 알게되어 너무좋았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1920, 96, '그동안 시의 감동을 잊고 살았음을 꺠우쳐주는 책.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (97, '창가의 토토', 216, 4.47, 0, 2, 17, 75, 122, 197, 17, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1921, 97, '다른 출판사에서 다른 번역이 나왔기에 재독. 예전판은 김난주 번역가, 이번판은 권남희 번역가. 예전판 번역은 예전판스럽고, 이번판은 이번판스럽다. 읽기 편하기론 권남희 역, 노스탤지어는 김난주 역. 교육/양육할 대상이 있다면 필독하자. 그 대상에게 축복있으라.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1922, 97, '동심, 참교육, 성장소설 등의 키워드에 부합되는 소설로 뜨거운 감성을 자극하는 신파보다 특유의 관조적 성격이 느껴지는 점은 좋았다. 다만 일제강점기와 태평양전쟁 시절 전범국인 그들의 피해자 코스프레에 눈살이 찌푸려진다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1923, 97, '창가의 토토를 읽으면서 마음이 굉장히 따뜻해졌다. 순수한 토토와 친구들을 보며 유년 시절을 떠올리며 그 때는 이런 생각을 가졌었구나 하기도 했고 교장선생님을 보며 이렇게 좋은 선생님을 만난다는 건 인생에 정말 큰 행운이겠구나라는 생각도 들었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1924, 97, '《창가의 토토》를 처음 만났던 때가 어렴풋이 기억난다. 대학교 도서관에서 파스텔톤의 여자아이가 그려진 포근한 그림에 이끌려 읽었더랬다. 그때는 토토가 착하고 귀여운 아이라고만 생각했지, 별다른 감흥이 없었던 것 같다. 아이들이 읽는 동화가 꾸준한 밀리언 셀러인지 이해하지 못했다. 그리고 나이가 더 들어 다시 만난 토토는 사회가 만들어 놓은 틀을 비집고 나온 토토가 고군분투하며 성장하는 이야기였다. 토토가 겪었던 일을 차근차근 곱씹어 보니 마음 한편이 아려왔다. 나는 참 나쁜 어른임을 느꼈다...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1925, 97, '예전에 자주 하던 생각이 있었다. ‘내가 기존의 제도권 교육이 아닌 조금 더 자유로운 곳에서 학교를 다녔다면 어땠을까’ 하는 생각이었다. 나 말고도 이런 생각을 하는 사람이 꽤 많을 것이다. 늘 그렇듯 ‘가지 않은 길’에 대한 미련과 후회에서 나오는 말이다. 나의 경우 경상도의 보수적인 동네에서 초중고등학교를 나왔다. 고등학교는 성적순으로 서열이 있었고, 야간 ''자율'' 학습을 밤 10~11시까지 강제로 해야 했다. 그 과정에서 내가 어렸을 때부터 하고 싶었던 일들을 많이 포기하고 참아야 했다. 시작부터 얘기가 푸념 글로 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1926, 97, '소설은 토토가 2차 세계대전이 시작되기 직전 고바야시 소사쿠 선생님이 운영하던 일종의 대안학교 ''도모에 학원''에 입학하면서 이야기가 시작된다.토토짱은 기존 학교에서 책상 뚜껑을 하루에 100번 이상 열었다 닫았다 하는가 하면, 선생님 말씀을 듣지 않고 창가에서 지나가는 친동야(이상한 복장을 하고 악기를 울리면서 거리를 돌아다니며 선전하는 사람) 아저씨를 부르는 등, 요새라면 ADHD 판정을 받았을 법한 행동을 해서 퇴학 당한다.엄마는 이런 토토짱을 데리고 지유가오카 역 부근에 있는 도모에 학원에 데리고 가는데 교장 선생님인 고바야...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1927, 97, '너는 사실 참 착한 아이야 초등학교 때 필독서로 를 읽었던 기억이 난다. 그때 토토의 학교에서 제일 부러웠던 건 국영수를 하지 않아도 되는 자유로운 학교 시간표였다. 초등학생이었던 나는 이 책을 읽으며 공부를 하지 않아도 되는 학교에 다니고 싶었다면 20대가 되어 이 책을 다시 읽은 나는 고바야시 선생님과 같은 어른이 되고 싶다는 생각을 하게 된다. 이 책의 주인공 토토를 한 마디로 정의하자면 정말 난감한 학생이다. 고작 초등학교 1학년을 문제아라고 낙인찍어 말하는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1928, 97, '나는 여름방학을 맞이한 대학교 4학년이다. 아마 지금이 고3이후로 겪는 내 미래에 대해 조급하고 가장 불안한 시기일 것이다. 그런 내가 라는 책을 선택한 것은 단순히 순진무구한 어린아이의 모습을 보며 스트레스를 풀고 싶었기 때문이다. 사실 는 초등학생 때 학교 도서관에서 빌려 읽었던 책인데, 그 당시 나는 토토가 다니는 학교에 나도 다니고 싶다 정도로만 생각했던 것 같다. 지금 다시 보는 토토의 학교는 어떨까? 그리고 10여년전 읽었던 학교의 모습을 바라보는 나는 바뀌었을까? &...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1929, 97, '이 책을 처음 읽었던 것은 초등학교 5학년 때 였던 것 같아요. 성인이 된 지금 다시 만날 수 있다니 설레네요.ㅎㅎ어릴 적 를 처음 읽었을 때는 막연히 ''나도 도모에 학교에 다니고 싶다!''고 생각했던 것 같아요. 하지만 어른이 된 지금, 다시 읽어보니 아이들의 모습을 그대로 보듬어 줄 수 있는 도모에 학교같은 사회를 아이들에게 만들어 줄 수 있는 그런 어른이 되고 싶다는 생각을 했습니다.토토의 시각으로 본 세상은 너무나도 아름답습니다. 아무런 편견없이 세상을 있는 그대로 바라보는 책 속의 토토를 보면서 가슴...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1930, 97, '진정한 교육자라면 한번쯤 읽어봐야 할, 어린시절의 꿈을 되새겨 볼 수 있는 책입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1931, 97, '역시! 하고 손벽을 치게 만드는책 꼭 읽어보세요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1932, 97, '읽으면서 너무도 순수했던 추억이 담긴 책...~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1933, 97, '나의 어린시절도 생각나면서 너무 즐겁게 읽었던 작품. 글 속의 토토는 너무나 사랑스럽고 천진하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1934, 97, '누구나 한때 어린이였다... 쉽게 망각하지만, 그 시절은 치명적이다.. 고바야시 선생님 같은 어른을 만난다면 행운인 시절. 모든 어린이는 어른이 되지만 어떤 어른이 될지는 아무도 모른다...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1935, 97, '아이가 최고의 책이라고 뽑은 책입니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1936, 97, '우리는 누구나 토토와 같은 어린 시절을 보내기를 바란다. 토토가 만났던 선생님과 학교에 다니기를 바라지만 그런 행운을 갖게 되는 경우는 너무나 드물다. 그래서 우리의 어린 시절은 아름답지만은 않다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1937, 97, '언젠가는 나도 이렇게 순수했었다. 언젠가는, 어떤 순간에는.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1938, 97, '읽었던 책 다시 읽기!상황에 따라 같은책 다른 감동조금더 어렸던 나와 현재의 나.. 같은책임에도 다른 메시지를 얻는다.좋은, 어른이 되고싶다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1939, 97, '대안학교?에 대한 아이의 생각이 귀여웠고, 사랑스러운 책이었어요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1940, 97, '너무 아름다운 책입니다~ 2번이나 봤구요.지인에게 선물도 했었지요..', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (98, '고구려 6', 215, 4.71, 2, 2, 5, 38, 168, 206, 5, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1941, 98, '여태 읽어본 역사서 중에서 단연 최고라고 말하고 싶은 민족의 대서사시! 작가의 직관과 상상속에 고구려는 다시 태어나고 역사의 혼불이되어 온몸으로 전율이 된다. 김진명 작가님! 정말 존경 스럽습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1942, 98, '고구려 6 소수림왕 : 한의 바다 고구려와 연나라의 몰락 이후 새로운 패자로 떠오른 전진은 언제라도 한족의 동진을 집어삼킬 기세였으니 지금의 동진은 전진을 비롯한 강국들의 비위를 맞추며 그 틈바구니에서의 생존을 도모할 뿐이었습니다. ‘내가 죽고도 다섯 해가 흐르기 전까지는 전쟁을 금해다오, 무슨 일이 있더라도.’ 백제의 화살에 죽은 사유는 유언을 남겼고 구부는 누구도 생각지 못한 백제를 향해 전쟁을 선포 합니다. 최전성기를 구가하는 백제와 다 무너진 고구려의 싸움이란 계란으로 바위를 치는 것과 다름없었다며 코웃음을 치며 백...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1943, 98, '어릴 때부터 총명함은 물론이고 기발하며 엉뚱했던 구부.해가 뜨고 지는 곳을 찾는다는 기행까지 보여줬던 구부가 드디어 왕이 되었다.세상을 바라보는 시선 자체가 다르니 하는 행동과 생각은 도저히 이해할 수 없는 수준이다.이런 엄청난 천재를 얻은 것이 바로 고구려의 자랑이자 행운이었다.시대가 영웅을 만드는 것인지, 영웅이 시대를 만드는 것인지.이 부분에 대한 내 대답은 어디까지나 철저하게 전자다.어떤 능력을 갖고 있다해도 시대에 맞지 않는 능력은 별 소용이 없다.엄청난 무예 능력을 갖고 있어도 현대에는 격투기선수가 최대치 아닐까 한다.그...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1944, 98, '고구려 1부가 7권으로 드디어 완결되었다.읽지 않은 6권은 "소수림왕"에 대한 책으로 앞쪽을 읽지 못했다해도 상관없이 단 권으로도 읽을만한 책이다.이 책으로 멋진 소수림왕 구부를 만나볼 수 있다.''유학''을 받아들였지만 파생되는 여러가지 사실에 대해 계속 우려하고 고민했던 소수림왕 구부."전진, 동진"등 고구려를 위협하는 나라와 격돌하고, 동아시아의 흐름을 바꿔놓기 위해백제와 함께 계획을 세운다.오랜 벗같은 모습으로 고구려의 구부와 백제의 부여구의 모습을 볼 때는자존심이나 욕심이 아닌 진정한 "왕"으로, 나라를 위하는 마음이 가득 보...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1945, 98, '김진명 고구려 역사소설은 1-6권과 7권으로 나누어져 있다. 내가 왜 두 분류를 했냐면 출판사가 변경이 되었기 때문이다.처음 출판된 곳은 새움 2016년도에 출판이 되었으면 2021년 새로운 회사와 계약을 통해 지금인 이타 북스와 계약을 하였다.전권은 이타 북스에 있으니 새로운 책 7권과 함께 많은 관심과 기대를 가져다주시길 바랍니다.김진명 작가는 참 대단하고 멋있는 남자다. 다양한 책들을 편찬을 하면서 소재 중복되는 것이 없다.유명한 책들로는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1946, 98, '연의 몰락, 전진의 약진, 강국으로 발돋움한 백제. 구부를 둘러싼 세계,구부의 시대에 고구려동아시아 전쟁과 정치의 거센물결,21세기 한반도가 처한 상황과 겹쳐보이게 만드는 작품', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1947, 98, '2016-292_[컬쳐클럽]고구려5권이 나오고 3년 5개월만의 출간. 5권까지의 내용이 기억날까? 기우였다. 다시 시작되는 소수림왕의 이야기는 7권을 기다려지게 만든다. 공자의 나라 한나라에 대한 소수림왕의 생각들...더 큰 그림을 볼 수 있는 리더...재미만 가지고 읽기에는 지난 역사가 아프다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1948, 98, '작가의 이야기를 역사 그대로의 이야기라고 받아들이는 것만 조심한다면, 분명 김진명은 우리 시대 최고 이야기꾼 중 하나이다. 역사 속 깊이 잠들었던 고구려는 작가의 손 끝에서 웅장한 위용을 뽐내며 되살아나고 있다. 고구려는 분명, 우리의 마음을 요동치게 하는 그 어떤 매력이 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1949, 98, '나오자마자 구매했죠. 역사를 재밌게 풀어내서 참 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1950, 98, '우리 역사에 대한 확고한 인식으로 동아시아 강국 고구려라는 창을 통해 민족의 자긍심을 고취시키는 특유의 흥미진진한 스토리와 작가의 필력.. 감탄스럽다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1951, 98, '고부의 꿈 공자의 나라가 아닌 우리만의 문화와 미래를 꿈꾸었던 시대의 거인 고부가 걸아간 삶 고구려의 또다른 역사를 만나보는', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1952, 98, '그냥 읽을만한 무협소설. 그 이상도 그 이하도 아닙니다. 무협소설을 읽고 민족적 자부심과 역사의식을 느끼는건 좀 많이 이상한거 같다는 생각이..... 역사소설로는 평가하고 싶지 않습니다. 역사소설로 평가하면, 엉터리 고증때문에 별 1개도 아까울것 같으니까요.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1953, 98, '6권 금방 읽고 7권 기다리고 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1954, 98, '처음 1,2,3권 나올때 을불에 반하고 여노에 두 번 반하고 그뒤 새 시리즈 나올때마다 사서 읽었네요 ㅎ 6권 나올때까지 오래걸리고 중간에 다른 책도 내셔서 중단된건가 했는데 ㅠㅠ 작가님 13권까지 꼭 완결해주세요!! 넘 재밌어요 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1955, 98, '대한민국 나라중 가장 진취적이였다고 생각하는 고구려의 역사를 소설로 접할 수 있다는 것이 무척 행복합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1956, 98, '고구려 정말 대작입니다. ㅠㅠ 왜 이렇게 늦게 내주셨어요 기다리다 죽는 줄 알았네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1957, 98, '소설속에서나마 이토록 카리스마 있고 뜻이 바른 왕들을 만나게 되어 통쾌하고 짜릿하기 그지 없습니다. 우리 현실도 이와 같으면 얼마나 좋을까요. 현실만 생각하면 안타깝고 슬퍼 자꾸만 소설속으로 도피하게 되는 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1958, 98, '절대강자의 이야기 그 광활한 이야기에 빠져봅시다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1959, 98, '김진명 작가는 정말 우리나라를 좋아하는것같아요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1960, 98, '6권이 나와서 그 전편도 다시 꺼냈습니다. 정말 반가워요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (99, '내 옆에는 왜 이상한 사람이 많을까?', 215, 4.7, 2, 2, 8, 34, 169, 203, 8, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1961, 99, '‘이상한 사람 질량 보존의 법칙‘에 따라 여기 제시된 유형의 사람들을 살면서 다 겪어본 거 같다. 당하기도 하고 맞서다가 곤욕도 많이 치러서 답이 아닌 걸 알아도 대체로 피한다. 이 책을 통해 유형별 파악은 쉬워졌다. 현재 자신을 힘들게 하는 사람이 저자들이 제시한 12가지 유형(남의 업적을 가로채는 사람, 뭐든지 아는 체하는 사람, 화를 잘 내는 사람, 치근덕거리는 사람, 거짓말을 일삼는 사람, 남의 성공을 시기하는 사람, 까다로운 척하는 사람, 불평불만이 많은 사람, 그때그때 인격이 달라지는 사람, 거저먹으려는 사람, 불행 바이러스를 퍼뜨리는 사람, 긍정을 강요하는 사람) 중에 있다면 참고삼아 읽어볼 수는 있겠지만 대처와 효과는 자신의 역량에 달려 있을 거 같다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1962, 99, '어떤 조직,단체에는 이상한 사람들이 섞여 있는데.. 상대가 어떤 사람인지 정확하게 간파한 후 그에 맞게 자신을 무장하라는 조언 명심합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1963, 99, '이상한 사람이 내 옆에만 많은 게 아니더군요. 하지만 자신이 중심을 잡고 현실을 직시할 수 있다면 주변인들에게 영향을 덜 받을 것 같아요. 흥미로운 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1964, 99, '매우 현실적인 주제를 바탕으로 나름의 대처법과 원인분석 및 해결법을 모색하고 있어 제법 많은 도움이 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1965, 99, '재밌게 읽었어요 ^^ 이상한 사람들 유형에 대한 소개와 그에 대한 대처방법이 흥미로웠습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1966, 99, '유유상종은 아닌지 자신을 돌아보는게 필요하겠죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1967, 99, '유형별 분류는 흥미로우나 해당 분류를 극적으로 설명하기 위한 예시의 극적인 구성과 장황함. 대처법이라 하기엔 실망스러운 면이 있네요.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1968, 99, '아쉽게도 별 내용이 없다.˝이상한 사람을 만났을 때도 자신의 자존감을 잃지마라˝외에는 없음. 이상한 사람이 많을 수 있다는 거랑', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1969, 99, '저 챕터들에 해당하는 이상한사람 거의 다 겪어본듯합니다. 각각의 내용과 대응법이 흥미롭네요. 게다가 마지막 챕터를 보면서 나를 되돌아보기까지... 새해 맞아서 마음도 다질겸 읽어보면 좋겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1970, 99, '요즘 정말 이상한 사람들을 많은것 같아요. 당시 상황에는 그냥 그냥 넘어갔는데 나중에서야 곱씹으면서 후회했는데 이책의 대응법보면서 많이 배우네요. 정말 꼭 한번 읽어볼만한 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1971, 99, '나를 돌아볼 수 있고 주변 사람들의 이상함이 이해가 되며 연민을 느끼게 된다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1972, 99, '이 책을 통해 돌아이질량보존법칙이 외국에도 있다는 사실에 놀랐고, 작은 위로도 받았습니다. 나만 그런 상황에 처한것이 아니구나 싶었어요. 주위에 약간 대하기 힘든 사람들을 대하는 방법을 가르쳐주는 심리학서적으로 소설형식이라서 꽤 술술 읽힙니다. 생각보다는 구체적이에요. 그래서 놀람.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1973, 99, '어디서나 인간관계때문에 사람들은 누구나 고생하는군요 참 이상한 인간들은 어디나 있는것 같아요 공감가는 제목입니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1974, 99, '진상 인간관계에서 좋게만 지내는것이 좋은 관계는 아닌것 같아요. 한편으로는 나 자신도 주변인에게 진상 인간이 아닌지 되돌아 보게 합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1975, 99, '이상한 사람은 누구나 기피하고 싶기 마련인데 이 책을 통해 좀더 자세히 어떻게 대처해야 할지 알수 있었으면 하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1976, 99, '가끔은 내 마음을 두근거리게 해 주는 사람이 옆에 있을 때도 있었지만, 대부분의 시간은 가급적이면 같이 있고 싶지 않은 사람과 함께 했던 기억이 불현듯 떠올랐다. 이 책을 보면서 무의식적으로 아하~하면서 감탄하고 있는 내 자신을 발견할 수 있었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1977, 99, '이 책 너무 좋아요~내 옆에 이상한 사람에 대해서는 모든 회사원들의 고민인데, 유쾌하게 풀어냈어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1978, 99, '딱 내가 읽어야할 책이네요. 살면서 이상한 사람 여러명 만났는데 뭐가 문제였는지 이 책을 통해서 알아보고 싶네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1979, 99, '제목에서 궁금증을 유발하네요~', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1980, 99, '나를 짜증나게 하는 사람들의 모습을 생생하게 표현해주고, 그들이 어떤 상태인지에 대해 이야기해줍니다. 사람을 이해하는 데 아주 유용한 책입니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (100, '여성 혐오를 혐오한다', 215, 4.63, 7, 3, 4, 34, 167, 201, 4, 10);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1981, 100, '진즉 읽었어야할 책인데 이제사ㅠ. 재밌다. 페미니즘 고전인듯.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1982, 100, '이해하기 쉽고 간결하게, 구체적으로. 우에노 지즈코의 글에서 얻을 수 있는 가장 큰 강점인 것 같다.종종 동의하기 어려운 이야기들도 있지만 살아온 세계가 무척 다르기에 그렇게 바라볼 수도 있다는 생각이 들고, 그 부딪침도(혹은 그 부딪침이야말로) 이 책을 읽는 보람이 아닐까.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1983, 100, '역자후기 기분나빠요^^이책을 번역하고도 역자후기에 보슬아치라는 단어를 쓰다니.....여혐이 뚝뚝 묻어나네요', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1984, 100, '구입하지 마세요. 역자가 쓰레기입니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1985, 100, '번역자와 출판사부터가 이렇게 여혐을 해서 전에 우에노 선생님께서 강연 오셨을때도 그랬군요. 네 앞으로 은행나무 출판사에서 여혐하는 것 아주 잘 알겠고, 여기 출판사에서 나온 책은 사지 않겠습니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1986, 100, '역자후기:남자로 태어났다는 이유만으로 우리 사회에서 짊어져야 하는 짐이 너무 무겁기 때문, 승리와 패배, 절망과 희망이 반복되는 이런 굴레가 남자에게만 씌워진 것, 보슬아치라는 용어를 옹호한다는 내용', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1987, 100, '출판사랑 역자가 여성혐오', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1988, 100, '역자 후기???? 왜 전자책은 삭제 안 해주냐.. 책보고 만족했는데 역자후기때문애 기분 잡쳤다. 여성학에 대해서 다루는 책에서도 징징거리는 꼴이라니.. 남성학을 만들어서 거기서 지지고 볶고 책 쓰고 하라고.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1989, 100, '여성 혐오든 남성혐오든 이유없는 혐오는 경계해야겠지요. 하지만 우리 사회나 일본 사회나 전세계의 여성혐오는 그 도가 지나친 것 같습니다. 시대당착적인 사고를 개선하는 것이야말로 평등으로 가는 길이겠지요. 일본사회의 여성 혐오에 대한 글에 위안부이야기도 ㅣㅆ기에 관심이 갑니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1990, 100, '2세대 페미니즘의 한계', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1991, 100, '개인적으로는 이세상 모든 사람들이 이책을 읽어봤으면 좋겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1992, 100, '약한사람이 약한그대로 존중? 의무는 강한남자들이 지고 권리와 혜택은 우리 약한여자들이 누리겠단 생각이네? 남녀평등 외치더니 의무는 절대 안지려는 무책임하고 무개념적인 여자들에겐 꿀같은 소리겠다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1993, 100, '여성혐오자가 변역한 페미니즘 도서. 아이러니하다. 출판사는 번역자 고를때 좀 더 신중했어야 하지 않나.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1994, 100, '최근 강남역의 묻지마 살인 사건으로 인해 여성혐오라는 주제가 이슈가 되고 있네요. 여성혐오뿐만 아니라 약자에 대한 폭력성 또한 우리가 경계해야 할 부분이라고 생각합니다. 일본인 저자가 일본 사회에 뿌리 깊은 왜곡된 성의식과 여성혐오에 대해 쓰고 있는 이 책이 우리에게도 많은 공감을 줍니', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1995, 100, '책제목이 2015년의 캠페인이 되어야 합니다. ˝여성 혐오를 혐오한다˝ 이보다 현 상황에 어울리는 슬로건을 찾을수 없을것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1996, 100, '이책은 예술, 문학작품에 시각적은유적으로 내포된 여성 혐오 사상, 스토리, 의식에대해 집중 서술하고 있습니다. 사회전반에 깔려 있는 여성혐오, 어디서부터 고쳐야 할까요. 할머니 할아버지 부모님으로 부터 무의식중에 각인되는 사고의식들..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1997, 100, '남자들이 좀 딱하다 싶기도 하고. 밉기도 하고. 이런 남자들을 만든것도 여자들 아닌가 싶기도 하고.여튼, 이런류의 책들을 읽을때마다 내가 얼마나 심각하게 잘못된 남성의 시각으로 세상을 바라보고 있는지정말 많이 놀라고 반성하게 된다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1998, 100, '읽는 내내 머리가 지끈 지끈 아팠어요. 아마 이 책을 다 소화하지 못 했을 거에요. 그러나 나는 이제 나를 혐오 하지 않을 겁니다. 남자에게 내가여자라고 인정받고 싶어했던 과거를 청산합니다. 그것만으로 내게는 엄청난 성취라고 생각해요. 고맙습니다. 우에노 치즈코!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (1999, 100, '말도 안되는 세상이야기에 이러한 화두까지 참으로 안타깝지만, 현실에서 일어나는 일 심도있게 살펴볼 필요가 있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2000, 100, '여성혐오뿐만 아니라 남성혐오, 인종차별 이런걸 왜하는지 도무지 이해가 안되요~', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (101, '리타 헤이워드와 쇼생크 탈출', 214, 4.84, 0, 1, 3, 26, 184, 210, 3, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2001, 101, '영화,책 보기 외 다른 취미가 없다. 그런데도 쇼생크 탈출은 아직까지 못 봤다. 따라서 이 영화에 원작이 있는 줄 몰랐다. 게다가 스티븐 킹의 원작이? 영화를 보지 못했지만, 대충 내용은 알아서 얼핏 킹과 이 소설이 매치되지 않는다. 이점이 신선하게 다가온다. 이참에 원작과 영화 둘 다 볼까싶다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2002, 101, '[쇼생크 탈출]영화 재개봉!｀스티븐 킹｀이란 작가를 알게 해준 영화인데, 이제는 그의 작품중 중 하나가 되었네요. 다시 본다면 이제는 덜 쇼킹할까요?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2003, 101, '이제는 명실상부 고전명작의 반열에 오른 쇼생크 탈출. 영화도 훌륭하지만 영화와는 또 다른 매력을 듬뿍 지닌 원작만의 향기를 느껴보기를 바랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2004, 101, '감동적인 영화 의 원작이기에 읽고 싶어요. 영화도 재개봉하고 원적도 다시 나왔군요. 명작이기에 다시 보고 싶고 다시 읽고 싶은 마음이 간절한 영화랍니다. 추억의 영화이기도 하고요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2005, 101, '보통은 원작소설을 영화로 만드면 소설의 재미를 못 살려내는데 이 작품은 소설과 영화 모두 걸작이었던 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2006, 101, '영화를 보면서 정말 굉장하다고 생각했는데, 나중에 원작이 스티븐 킹의 작품임을 알고 꼭 읽어야겠다고 생각했는데, 이번 기회에 읽으면서 스티븐 킹의 필력을 다시 한번 느끼며 영화 그 이상의 감동을 받고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2007, 101, '봄은 더할 수 없는 절망속에서 희망을 말하고 여름은 풍요와 평화 속에서 파멸과 절망의 이야기를 풀어놓고 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2008, 101, '공포 소설가가 아닌 스토리텔러로서의 스티븐 킹을 만나볼 기회를 제공한다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2009, 101, '정말재밋게본 영화입니다. 베스트에 뽑히는영화인데 원작소설이 있었군요.영화에서느꼈던감동을다시금책을통해 느껴보고싶네요 원작소설도 읽어보고 싶어요 재개봉되는영화도보고싶구요 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2010, 101, '재미있게 봤던 영화가 스티븐 킹의 원작 소설이라는것만으로 무척 놀랐습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2011, 101, '스티븐킹의 소설이 영화로 나온 것이 정말 많은데 쇼생크 탈출도 최고의 작품 중 하나죠. 밀리언셀러클럽에서 나온 책이라서 더욱 기대가 되네요. 스티븐킹의 많은 작품 중에서도 최고의 작품을 모아놓은 것 같습니다. 소장가치 대박 강추!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2012, 101, '스티븐킹의 대표작이자, 전 소설을 통틀어서도 최고의 수작입니다. 필독하세요. 반드시 읽어보셔야 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2013, 101, '쇼생크 탈출이 스티븐 킹 작품이었다는 것은 몰랐다!! 왠열!! 완전 좋아했던 영화의 원작자가 전혀 그 느낌적 느낌도 안나는 스티븐 킹이었다니. 배우처럼 완전히 자기 색을 지우지는 못해도 (알고 읽으면 조금씩 티가 나는 그의 폭력에 대한 지나치리만큼 자세한 묘사와 차가움) 반전있는 원작자!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2014, 101, '스티븐 킹은 호러소설만 주로 읽어서, 아직까지 이 작품은 읽지를 않았네요. 영화는 무척 재미있게 봤는데, 스티븐 킹의 감동적은 소설은 왠지 거부감이 생겨서... 패스했는데, 이번 기회에 도전해 봐야겠습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2015, 101, '포레스트 검프도 좋았지만 쇼생크 탈출을 놓친건 정말 아카데미의 큰 실수였어요영상으로 보여주지 못했을 원작소설을 기대합니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2016, 101, '영화 의 원작소설을 만날 수 있다니, 설렙니다. 팀 로빈슨이라는 배우를 처음 알게 된 영화인데다 교도소 인권을 고발하는 영화였기에 아직도 강렬하게 기억되는 추억의 영화인데요. 재개봉이 되는군요. 원작소설도 읽고 싶어요. 스티븐 킹의 문장도 만나고 싶어요. 기대가 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2017, 101, '재개봉한다고 하던데 원작을 늦게나마 읽어보는 기회를 갖을 수 있어 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2018, 101, '영상미와음악 그리고 스토리가 참으로 인상깊었던 작품을 재개봉하면서다시 음미하는 소중한 시간이 될것 같아요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2019, 101, '텍스트로 다시 만나는 엔디 듀프레인', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2020, 101, '이 작품 책으로 보고 싶었는데 반갑네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (102, '그들이 말하지 않는 23가지', 214, 4.64, 2, 0, 4, 62, 146, 208, 4, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2021, 102, '우리는 학교에서 평등한 사회, 다 함께 사는 좋은 사회를 만들어야 한다고 배운다. 그러나 정작 학교를 졸업하고 나온 사회는 정말 ‘불평등’ 한 곳이라는 걸 알게 된다. 그러다가 이런 불평등도 어느 순간 자연스럽게 받아들이게 되는데 그런 즈음에 또 한번씩 위기가 온다. 지금껏 알고 있던 혹은 진짜라고 믿었던 것들이 거짓이라고 누군가 말하기 시작한다.처음에 황우석 박사의 논란도 믿기 힘들었다. 가까이 있던 지인은 처음부터 뭔가 냄새가 났었기에 자꾸 의심하는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2022, 102, '이 책은 읽는 것이 너무 힘들었다.어려워서? 흥미진진하지 않아서?읽어가면서 알아가는 현실이 맘을 불편하게 만들기 때문이다.난 그동안 속아서 살아 왔던가...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2023, 102, '한번에 이해하기 힘들니 2~3번 읽어보세요 조금씩 작가가 말하고자하는게 이해됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2024, 102, '그래도 자본주의가 그나마 (고쳐쓰면) 낫다는 말은 동의하기 어렵지만, 대체로 인정', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2025, 102, '빨리 만나보고 싶은데 발행예정일이 아직 많이 남아 있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2026, 102, '읽어보면 왜 경제부문 1위에 올랐는지 알수있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2027, 102, '나쁜사마리아인도 봣엇는데! 약간심오하면서도 괜찮은 책인것같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2028, 102, '신자유주의와 자유무역의 모순을 알려주다. 그들이 말 할 수 없는 많은 이야기들.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2029, 102, '천민자본주의를 통렬히 비판하고 빈부격차의 심각함을 독설로 마무리한 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2030, 102, '경제나 정치가 멀리 있는게 아닌 우리의 일상에 많은 관련이 있다는 걸 최근에야 알게 되는 경우가 많은것 같아요정부나 경제학자들이 제대로 이야기해주지 않는 많은 것들에 대해서 궁금하지만 알기 힘들었던 사항을 하나하나 알아볼수 있어서 많은 관심이 생기네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2031, 102, '제가 이 책으로 경제학에 입문했습니다. 몰랐던 것들을 알아가는 것이 너무나도 신나는군요ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2032, 102, '세계경제의 흐름과 논리를 알고 싶은가??!!단연코 최고의 책이다!!!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2033, 102, '자유주의가 전부는 아니지만 수정된 자유주의는 그런대로 쓸만하다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2034, 102, '장하준 교수의 다른책들을 읽어보셨다면 크게 다른 내용은 없지만 그래도 읽게되는책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2035, 102, '자본주의 시스템에 갖혀 있어 보지 못했던 문제들 적나라하게 드러내주는 파란 알약책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2036, 102, '경제학에 관해 더 나은 시각을 갖게 됨', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2037, 102, '더 나은 경제를 위해 꼭 필요한 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2038, 102, '유명한 만큼 유명세를 톡톡히 하는 영양가 있는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2039, 102, '평소 궁금했던 경제 관련 의문점에 대해 아는 시간이 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2040, 102, '"나쁜 사마리아인" 이후 저자 최대의 문제작!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (103, '결혼보다 월세', 212, 4.69, 2, 3, 4, 40, 163, 203, 4, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2041, 103, '재테크와 관련없는 신변잡기류의 내용전작의 인기를 이용하여 출판한 전형적인 알맹이 없는책', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2042, 103, '경제적 독립,자립이 우선입니다. 꼼꼼한 취재,알뜰한 재테크 비법이 담겨 있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2043, 103, '푼돈 모아 목돈을 마련하고 투자를 하고 남의 일이 아닌 앞으로의 내 일이 되었으면 좋겠어요. 좋은 동기유발이 되어준 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2044, 103, '주부로써 꼭 봐야겠네요. 반성하게 됐습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2045, 103, '에세이 읽듯이 편하게 읽어나갈수 있는 책이라입문서로 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2046, 103, '제목 잘 지었네요. 매달 수익이 나오는 구조 구축 중요하지요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2047, 103, '가난보다는고독해도부자인게낫죠혼자서도잘사는언니의재테크에대한에세이', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2048, 103, '경험담이라서 믿음이 갑니다. 저도 좀더 열심히 살아야겠다는 생각이 드네요 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2049, 103, '어쩔 수 없지만 현실. ㅠㅠ 이 책은 친구에게도 보여줘야겠어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2050, 103, '성선화기자의 책을 다 읽어봤는데 구구절절 맞는 말들이 정말 많더라구요 이번 책도 진짜 기대되고 도움을 많이 받을 수 있을 거 같습니다. 미혼녀들에게 희망이 되어주는 책!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2051, 103, '쉽지않겠지만 금리가 제로에 가까운 요즘에 좀더 현실적인 도움이될만한 책이네요~~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2052, 103, '성선화 기자님의 책은 믿고 봅니다. 이론만 떠드는 책이 아닌, 진짜 실전 경제서적입니다. 옆집 언니와 수다 떨듯이 읽어보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2053, 103, '1) 재테크는 그 인간의 심층과 관련되어 있다. 돈을 쓰는 데는 다 이유가 있다. 그 이유를 직시하라. 2) 왕관 쓰려는 자, 그 무게를 견뎌라. 돈은 불행과 함께 찾아온다. 돈과 관계된, 돈으로 인한 문제들. 싫으면 돈을 떠나 살면 된다. 3) 일단 지르고 그 다음 해결하라. 경험만이 널 강하게 만든다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2054, 103, '재테크에 관심이 많아도 막상 성공하기는 쉽지 않은데.월급도 좀 적고 그래서 과연 어떻게 해야 내가 가진 돈으로 잘 투자해서 부자가 될 수 있을지 궁금하고 이 책을 통해 그 방법 중 하나를 배울 수 있으면 좋겠다는 생각이 드네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2055, 103, '결혼이랑 월세랑에 대한 이야기인데 이책을 통해 결혼과 월세에 생각과 현실적인 목표를 세워서 경제적으로 자유로워지는 방법을 제시해 주는것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2056, 103, '돈 모을 자신을 모두가 가지기를 바랍니다. 여성뿐만 아니라 남성도요. 그래야 밥줄 끊는다고 협박해도 굴하지 않고 자신이 믿는바를 말할 수 있는 세상이 오겠지요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2057, 103, '경제와 결혼은 상관관계가 있다. 시대상에 맞는 생활패턴에 적응하자..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2058, 103, '싱글 여성의 경제적 재테크에 도움이 되겠네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2059, 103, '경제적인 면에서 스스로 바로 서기 위해 꼭 필요한 재테크 노하우를 배울 수 있네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2060, 103, '돈을 모르라는 강한 메세지가 표지이미지에서부터 전해온다. 이 책을 참고하여 오늘부터 시작이다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (104, '무일푼 막노동꾼인 내가 글을 쓰는 이유', 211, 4.78, 1, 2, 6, 25, 177, 202, 6, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2061, 104, '이 많은 리뷰 중 구매자가 쓴 글은 딱 3개. 도서관에서 빌려본 나로서는 별로 공감도 안되고 무엇보다 글이 너무 지루했다. 저자의 다른 책들도 거의 비슷한 글들이 많아서 별로였다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2062, 104, '가지런한 글쓰기를 통해 마음을 다스리고 싶다. 또 잘 쓴 글을 써보고 싶다는 욕심도 생긴다. 때문에 글쓰기관련 도서는 욕심이 날 수밖에. 주로 유명작가의 영역인 이 분야에서 낯선 저자의 등장이 호기심을 끈다. 기존의 책들과 어떤 차별점을 가지고 있을지 궁금하다. 비법보다 삶이 드러난 글이길!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2063, 104, '머릿속으로 떠다니는 번잡한 생각들을 노트에 한문장 씩 적다보면 스스로 마음을 잡아나갈수 있을까, 그저 습관처럼 저절로 손끝은 스마트폰을 향해 움직이고 시간은 잘도 흘러간다.지뢰밭 같은 인생을 이렇게 한권으로 정리할수 있는 용기 부럽네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2064, 104, '무엇을 이야기 할려고 하는지 모르겠다. 글이 논리적이지도 않고 자기 경험이지 공감도 그렇게 안된다. 지속적으로 같은 내용 반복 이고.. 처음에는 흥미가 있지만 반복되는 내용 이다 보니 나중엔 지루하다. 그냥 심심 풀이로 읽어볼 정도..', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2065, 104, '글쓰는 것으로 세상을 바꾼 이야기는 들었지만 막노동꾼이 글을 쓰면서 자신을 바꾸었다니 대단한 이야기네요. 저도 좋은 글을 쓰기 위해 오늘부터 노력하고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2066, 104, '글을 쓴다는 것에 대해 무척 매력적으로 다가오게 해주는 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2067, 104, '글쓰기를 통한 자기감정 통제를 이루어낸 작가가 대단하게 느껴집니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2068, 104, '굴곡진 작가의 삶속에서 지탱해주었던 힘은 글쓰기였다. 글은 어떤 면에서 사람을 발전시킬 수 있는 위대한 힘을 지닌 것 같다. 작가의 예사롭지 않은 삶에서 그에게 글쓰기가 어떤 위로와 희망이 되었는 지 들여다 보고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2069, 104, '목차에서 ｀단지 적는 것 만으로도 현실을 마주할 용기가 난다면｀이라는 소제에 마음이 움직였어요. 잘 쓰는 글이라든지 감성, 힐링 같은 것을 내세우지 않고 기름기 없는 담백한 말투의 글쓰기에로의 권유라 신뢰가 더 갑니다. 나만의 글쓰기에 대한 가이드로 읽고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2070, 104, '글쓰는것에 대한 것 어려운 글쓰기를 내면의 다스리기 위한 처방전으로 만든 작가의 정신에 감탄하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2071, 104, '글 쓰기의 의미를 되새겨 볼 수 있네요.단순히 글자를 적는 것 뿐만이 아닌 글쓰기를 통해 얻을 수 있는 위안과 노력 등 많은 생각을 하게 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2072, 104, '저도 글을 쓰고 있는 사람으로서 이은대 저자는 어떤 마음과 자세로 글을 썼는지, 그리고 변화하는 부분을 함께 공감하면서 저 역시 실천 해 보고 싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2073, 104, '글쓰기에 대해서 진지하게 다가갈수 있어서 기대가 됩니다. 책을 읽으면서 글쓰기 능력을 키워보고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2074, 104, '자신의 생각을 글로 그대로 옮긴다는건 참 힘든 일이라고 생각합니다 더군다나 뭔가 집중하고 오랜 시간을 거쳐 글을 쓴다는 것도 힘들죠 전문 작가가 아닌 일반인이 글쓰기로 뭔가 바꿨다는 그 이야기가 와닿네요 진심이 담긴 글처럼 호소력짙은것도 없다고 생각합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2075, 104, '글쓰기에 대해 진지하게 생각해보게 될 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2076, 104, '글을 쓰게 되며 자신을 한 번 돌아보게 되는 계기가 될 수 있을 거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2077, 104, '글쓰기를 통해 인생의 힘든 시간을 지탱할수 있었던 저자의 삶도 궁금해지구 글쓰기에 대한 경험담도 읽어보고 싶어지네요 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2078, 104, '나이가 들어갈수록 현재의 위치에 대해 고민,걱정이 많습니다. 앞으로 어떻게 살아가야할지...이책을 통해 저의 미래를 다시한번 성찰해보고 글쓴이는 글로써 어떻게 이겨냈는지 탐독해볼수 있는 책입니다. 글쓰기를 통해 삶이라는 것에 희망을 다시 느끼고 싶어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2079, 104, '작가분이 살아온 이야기만으로도 흥미롭습니다. 그분의 삶과 글쓰기에 대한 이야기가 궁금해집니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2080, 104, '회사를 그만두고 왜 이리 글을 열심히 쓰셨을까요? 그 원동력이 무엇인지 궁금하네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (105, '책장의 정석', 211, 4.71, 1, 2, 10, 32, 166, 198, 10, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2081, 105, '책을 모으기 위해 독서를 하는 것은 아니지만 독서를 하다보니 자꾸만 책이 쌓입니다. 넘치는 책들을 정리하고 싶지만 주변에 나눠줘도 자꾸만 책탑은 쌓이고 공간은 좁아지고 있기에 이런 책은 도움이 되네요. 요즘은 책 욕심을 덜 부리게 되기에 조금씩 정리하게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2082, 105, '책장정리를 하면서 과거의 나를 만나고 미래의 나를 설계해서 어제와 다른 나로 변화시킵니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2083, 105, '그저 쌓아두기만 하는 책들보다 그책을 정리하면서 효울적인 내게 맞는 독서생활을 할수 있다는 장점이 있다니 신기합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2084, 105, '책장을 신선한 책장, 메인책장, 타워책장 이렇게 나누는 방법은 참고할만 하다. 서평가인 저자가 소개한 서평쓰는법도 도움이 되고 참고할만 하다. 여기서 핵심은 참고할만 하다는거.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2085, 105, '그리 많은 책이 있는 것이 아님에도 책장이 늘 어수선합니다. 이 책의 내용들은 단순히 정리가 아닌 인생이 변화될수 있다고하니 관심이 갑니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2086, 105, '요새 교양서적을 빙지한 자기개발서가 늘고 있다.이책은 정확히 이 범주에 속한 책이다.책을 좋아하는 사람들이 책장을 채울때의 그 기쁨을이 책에서는 전혀 느낄 수 없다.책 내용 중에 이런 글이 있다.˝쓸모없는 책은 굳이 다 읽을 필요가 없다˝이 책에 그대로 적용해도 된다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2087, 105, '신선한 책장과 메인 책장, 타워 책장의 구분이 필요하다.일단, 슬라이딩 책장부터 만들어야지', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2088, 105, '책장을 보면서 책을 관리하기가 버겁기도 한데요. 효율적인 장서의 관리을 배워보고 싶어요. 장서의 괴로움도 고역이거든요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2089, 105, '책을 좋아하는 편이라 책이 많이 쌓여있는데 어떻게 정리해야하는지 꼭 읽어봐야겠어요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2090, 105, '책장을 통해 이런 이야기들을 알수가 있다니 너무나 신기하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2091, 105, '책이 정말 많습니다. 이사 하자마자 챙겼던게 안방이 아닌 서재였으니까요. 이사 올 때만해도 꽤 질서있게 정리했다고 생각했었던 서재가 다시 참 지저분해져 버렸습니다. 뭔가 정리법이 따로 있는 걸까요? 책을 읽고 그 책을 정리하기 위한 내용들. 저에게는 꽤 유용할 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2092, 105, '저는 방에 책이 넘쳐서 간신히 잘 공간만 확보한 상태다보니 책장정리가 불가능하네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2093, 105, '책은 점점 늘어가는데 정리할 방법이 떠오르지 않아서 고민이 많은데, 책을 읽으면서 깔끔하게 정리하고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2094, 105, '독서에 얽힌 이런저런 고민을 차근차근 풀어나갈 수 있으리라 기대합니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2095, 105, '나의 지식창고를 좀더 효율적으로 활용하고, 스마트한 책장 변신을 위해서 정리방법을 실천해보고 싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2096, 105, '책장의 책을 순환하자~ 그것 뿐이다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2097, 105, '어떤 책을 어떻게 놓고 있느냐도 굉장히 중요합니다손이 많이 가게 되는 책을 곁에 둔다면 더 좋듯이 배치자체도 상당히 중요하죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2098, 105, '무엇을 어떻게 읽느냐, 읽은 뒤에 어떻게하냐를 알려주는 책이 될것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2099, 105, '나의 책장을 한번더 쳐다보게 만드는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2100, 105, '이동진 작가가 보면 좋아할 듯 ㅎㅎ', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (106, '문구의 모험', 211, 4.75, 0, 1, 6, 37, 167, 204, 6, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2101, 106, '2019.5.4 산책문방구 애호가로서 집어 들지 않을 수 없던 책. 정말로 잘디잔 문구에 대한 역사 외에도 문구가 꽤나 거대한 산업적 영향력이 있는 영역임을 알게 해준다. 문방구 갈 때마다 깨알같은 지식자랑 할 수 있게 해주는 매니아 책.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2102, 106, '책상에 앉아있는 일이 많다 보니 문구에 관심이 많다. 다 쓰지도 못한 볼펜과 형광펜, 샤프, 지우개가 서랍에 가득이다. 이 같은 문구들에 대한 이야기를 가지고 한 권의 책이 엮일 수 있다는 게 재밌다. 또 그 같은 열정이 대단하다. 일종의 덕력일까. 정치사아닌 미시사 생활사의 재기발랄함이 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2103, 106, '제가 문구류를 좋아해서인지, 정말 행복한 독서시간이었습니다. 다만 번역이 조금 거친 것이 안타깝죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2104, 106, '이렇게 분류해놓은 문구류를 보니 종류가 엄청 많이 있네요. 내가 갖고 있는 문구류는 무엇이 있으며 나는 그 문구를 어떻게 사용했는지, 저자는 어떻게 그 문구들을 사용하면서 이 글을 썼는지 정말 재미나요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2105, 106, '책을 좋아하는 사람들은 필연적으로 문구 덕후가 되기 마련이다. 우리가 일상적으로 사용하는 흔하고 잡다한 문구들의 기원이 어떠한지 보통은 잘 모른다. 사람들이 거기에 대해 알고 싶지 않다기보다는 거기에 대해', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2106, 106, '그림이나 삽화가 많아야 이해할 수 있는 내용인데 너무 부족하고 뜬금없이 튀어나오는 아재 개그에 눈살이 찌푸려짐.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2107, 106, '아기자기한 문구사는 걸 참 좋아하는 편인데, 연대기라니 새롭고도 신비한 느낌이 드네요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2108, 106, '문구류에 대해서 관심이 많아서 그런지 더 재미있는 책. 이 책 속에서 문구들이 겪는 에피소드를 꼭 만나보길 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2109, 106, '책상앞에 앉아있는 시간이 많거나, 디지털 시대에도 아날로그적 감성이 풍부한 알라디너들이 무척이나 좋아할 책이다. 문구와 관련해 많은 지식과 소소한 재미를 얻어간다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2110, 106, '갈수록 흥미로워지는 어크로스의 출간 목록.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2111, 106, '일상을 빛나게 만드는 내곁의 문구들이 퍼즐처럼 엮인 아름다운 에세이입니다.지식의 확장,습득의 열렬한 보조자인 문구류들 스마트폰의 차가움과 다른 주인의 손길로 닳아없어질때까지 곁에 있는 문구류를 향한사랑이 가득담긴 향현서~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2112, 106, '목차를 보니 이 책 정말 흥미롭네요. 문구의 기원에서부터 오래 전 그러니까 볼펜이나 샤프 같은 걸 만들기 전부터 어떤 문구류를 어떻게 써왔는지를 연구했군요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2113, 106, '책을 눈으로만 보는 사람은 없기 때문에 문구는 필수적이다. 문구를 다룬 책을 읽는 일은 문방구에서 헤매는 일만큼이나 황홀한 일이라고 생각한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2114, 106, '이 책 서점에서 표지만 보고 흥미로울 것 같다고 생각한 책이에요. 사소한 문구류를 통해 많은 것들을 이뤄낸 사람들이 이야기라니 진짜 재미있을 것 같네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2115, 106, '책의 종류는 다양하고 소재도 다양하지만 문구에 대한 이야기라니 흥미롭다. 문구들에 대한 사연, 그리고 작가들이 좋아하는 문구들 등 흥미로운 이야기들이 많이 담겨있을듯.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2116, 106, '색다르면서도 재미난 소재네요. 자신이 사용했던 문구류를 떠올리면서 읽을 수 있는 책이랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2117, 106, '솜씨 좋은 목수가 연장 탓을 하겠는가마는. 솜씨 좋은 목수가 좋은 연장을 쓴다면 더 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2118, 106, '우리가 항상 사용하는 문구에 대한 책입니다. 거장들과 문구라는 뭔가 신선한 조합이네요. 작가가 사상한 문구라니..너무 너무 기대됩니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2119, 106, '작고 흔한 문구들의 이야기라 소소하지만 재미잇어 보입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2120, 106, 'ebook 으로 소장하여 틈틈히 보고 있는 책입니다. 소소한 것들 수집벽이 있는 제게는 딱 취향저격식의 신선한 소재에 흥미진진하면서 담백한 문체가 마음에 듭니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (107, '시작하기 전에 알았더라면 좋았을 것들', 210, 4.76, 2, 1, 4, 31, 172, 203, 4, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2121, 107, '알라딘은 정말 이런 댓글알바를 모조리 뿌리뽑지않는이상, 나는 더이상 알라딘의 후기를 믿고 책을 고를 수 없을 것 같다. 이 아래있는 사람들은 전부 실구매자가 아니라는 사실을 모두 인지하길 바란다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2122, 107, '자기계발서는 대개 당연한 말을 바르게 늘어놓아서 일견 지루하게 느껴진다. 자기계발서에 대한 글이 조심스러운 것은 누군가에겐 이 책이 처음 접하는 자기계발서일 것이기에 쉽게 평할 수 없다는 것. 늘 의지박약인 나는 조금 더 어릴 때 이런 책을 통해 변화했더라면, 하는 아쉬움이 가득하다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2123, 107, '실패를 통해 얻는 것도 많지만 시작하기 전에 알았더라면 돈과 힘 낭비를 줄일 수 있겠죠. 성인이 되는 20대에 알았더라면 좋았을 것들은 너무 많죠. 이런 책을 통해 좌절보다 용기를 얻을 수 있길 빕니다. 유비무환이라는 말처럼 준비된 이십대라면 알차게 보낼 수 있겠지요. 제목부터 공감한 책..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2124, 107, '비즈니스 관련 책 저자들의 추천사는 싸구려처럼 노골적이라 거부감이 들고..비슷비슷한 책들이 워낙 많이 넘쳐나는 것도 선택을 어렵게 한다.게다가 구매자 100자평은 딸랑 한편 뿐이라니..기대는 되는데 막상 보기는 싫다는 건가?..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2125, 107, '열정에 제동을 걸어줄 그 무엇, 행동하는것만이 열정으로 이어질까?열정은 경험을 통해 솟아난다는 사실을 알려주는 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2126, 107, '100세 시대. 아직 살아온 나날보다 살수 있는 날이 많이 있기에 앞으로도 더 창조적인 삶과 발전있는 삶을 위해서 도전하렵니다. 이 책을 읽는 모든 사람들이 보다 나은 미래와 꿈을 굴 수 있기를 바랍니다. 그리고 우리 아이에게도 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2127, 107, '능력을 발휘하기 위한 기회와 방법을 전해주리라 믿습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2128, 107, '무슨일을 시작하기 전에 알았더라면 좋았을 것들이 얼마나 많은가 저자는 자신을 생각을 실행하기 위한 상상력, 창조성, 끈기등을 통하여 우리에게 또 하나의 희망을 주고 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2129, 107, '꼭 지나고나서 알게 되어 후회하는 경우가 많은데 이 책을 통해 시작하기 전부터 미리 준비할 수 있으면 좋겠네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2130, 107, '자신들의 아이디어를 실현시켜 소위 성공한 사람들에 대한 이야기와 함께 그들이 성공하게 된 방법적인 부분을 쓴 책이네요. ｀젊은이여, 야망을 가져라｀ 구체적인 실천법이지 싶어요. 꼭 창업뿐이 아니라 인생을 좀 더 적극적으로 살도록 도와주는 책이라고 생각했습니다. 삶에 만족도를 높일 수 있음', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2131, 107, '실패하기전 알아두었으면 졸았을것들 실패를 두려워하지않는 새로운 시작을 가르쳐주는것 같네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2132, 107, '어떻게 하면 생각했던 바를 실행할 수 있을까 하는 생각이 들게 만드는 책이라고 봅니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2133, 107, '정말 직장, 혹은 공부를 시작하기 전에 알았더라면, 이 책을 알았더라면 더 좋았겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2134, 107, '되도록 실패하지 않도록 자신을 이끌어 내는 데 도움이 될 것 같네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2135, 107, '혁신, 창조성, 기업가 정신... 모두 미리 알고 몸과 머리로 익혔더라면 더 좋았을 것들이죠. 특히 스무살 시절부터 이런 정신으로 사회에 대한 눈을 뜨고 도전을 했더라면 시행착오를 줄일 수 있었겠죠. 이런 지식들로 미리 준비된 자에겐 도전에 박차를 가할 수 있겠지요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2136, 107, '정말로 제가 가게 하기전에 알았으면 좋았을것을 이미 망해서 늦었네요 ㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2137, 107, '무언가를 시작하기 전에 알았더라면.. 이라는 후회를 하고는 합니다. 경험이라고 할 수 있지만 그래도 미리 대비하고 사전 준비를 했더라면 더 좋은 결과가 나왔을 거라고 생각이 됩니다. 이 책으로 저의 시행착오를 미리 줄여보는 것도 좋겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2138, 107, '지나와서 든 생각이지만 이십대에 뭔가를 꼭 이루어야하고 그때가 지나면 아무것도 할수 없을거란 생각은 틀렸다는걸 깨닫게 되었네요 뭔가 시작하기전에 준비해야할것이 무엇이고 어떻게 자신의 능력을 키울수 있을지 고민이 많을때 읽어보면 좋을것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2139, 107, '사회생활을 하면서 꼭 읽어두면 좋을 현실적인 조언들이 담겨있는거 같아 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2140, 107, '지인들이 해주지 못하는 얘기들이 있다. 그런 점들을 책을 통해 채운다. 지금 나는 중요한 시작점에 서 있다. 그래서 여러 책들을 둘러보고 마음의 내공을 쌓는 중인데 그전에 읽었던 저자의 또다른 책을 알기 때문에 이 책도 신뢰가 간다. 현실적인 조언을 해주는 책이라 기대된다', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (108, '자기 결정', 209, 4.8, 0, 0, 5, 31, 173, 204, 5, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2141, 108, '자존감과 자존심의 밸런스를 지키는 건 생각보다 어렵다. 그 어려움에 대해 생각해 보게 만든다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2142, 108, '타인의 시선을 너무 의식하지 않고 자신만의 기준을 올바로 세우며 그 기준에 맞춰서 무엇이든 결정을 할 수 있는 능력과 행동을 길러야할 것 같아요,', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2143, 108, '내 인생은 나의 것. 적정선에서 내가 옳다고 생각하는 대로 행동하자.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2144, 108, '주도적인 삶이 아닌 주변에 휩쓸리는 삶은 행복하지 않는것 같아요. 자신의 삶을 위해 개인적인 선택할수 있는 용기를 배우기에 좋은 책이예요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2145, 108, '자기 신념을 따라 살아간다는 것은 정말 힘들고도 어려운 일이다 하지만 행복하게 살기 위해서는 신념에 따라 행동하고 생각해야 할 때가 있다. 신념에 따라 자기 스스로 결정해서 선택할 수 있도록 도와주는 책이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2146, 108, '나의 삶을 스스로 결정하고 생각하는 힘을 길러야 할 것 같습니다. 남에게 휘둘리지 말고 나만이 내 인생을 바꿀 수 있다는 것을 알게 해주네요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2147, 108, '내삶을 결정하는건 결국 나인거는 맞는데 그게 쉽지는 않지요. 자신에 대한 믿음을 좀더 길러주는듯한 책이네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2148, 108, '자신의 인생을 행복하고 윤택하게 살기 위해서는 자신만의 인식을 통해 결정을 해야만 한다는 삶과 자신의 자존감을 높일 수 있다는 생각하게 만드는 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2149, 108, '스스로 무언가를 결정한다는 건 그에 따른 책임이 따름. 그런데 세상은 책임을 질 나이가 되기까지 스스로 결정할 수 있는 것이 사실 거의 없음. 이제 책임을 질 나이가 되면 어깨에 짊어진 무게가 너무나 커서 겨우 걸어다닐 수 있을 뿐.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2150, 108, '어떻게 살아갈지는 스스로 결정하는 자기결정을 통해 진정한 행복에 가까워질 수 있도록 많은 도움이 되겠네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2151, 108, '결국 최종 결정은 나만의 몫이다. 결국 최후의 의사결정을 하는 결단력이 필요하고 그 결정은 나 자신이 한다. 이 책을 통해서 자신만의 삶을 모색해본다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2152, 108, '여러가지 주변 상황이나 타인에 휩쓸리지 않고 스스로 결정하고 내딛는 미래, 그리고 자기자신의 삶. 주체성과 정체성을 가지고 신념에 따른 삶을 살라는 메시지가 많은 것을 느끼게 하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2153, 108, '한 발 물러나서 생각해보기. 끊임없이 수정하고 고쳐나가며 자신의 영역을 넓게 만들기. 행복해지려면 자기 스스로를 정확하게 알아야 한다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2154, 108, '내가 쥔 운전대를 어떻게 움직이느냐에 따라 다음 길이 달라집니다. 수동적으로 밀려나지 말고 주체적으로 자기 결정을 내립시다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2155, 108, '내 스스로 개척해 나가는 삶을 위해 이 책이 지침서가 될 듯 해요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2156, 108, '이 세상에서 제일로 어려운건 자기 결정입니다. 왜냐하면 늘 후회와 외로움을 얻으려니까여', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2157, 108, '어떻게 살아갈지는 많은 사람들이 하는 고민. 내 인생은 내가 고민하고 내가 결정하고 책임지는 것. 어떤 이야기들이 담겨 있을지 궁금하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2158, 108, '타인을 기준으로 삼거나 타인에 끌려다니는 삶만큼 불행한 삶도 없다. 작가는 리스본행 야간열차에서 자신의 삶을 주체적으로 찾아가는 여정을 그렸듯이 이번엔 철학적인 글로서 자기 삶의 주인이 되기 위한 성찰을 하고 있다. 쉽고 부담없이 읽을 수 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2159, 108, '자기 삶의 주인이 되는법 자기자신의 판단법 중요한것같습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2160, 108, '결정적인 순간에 나만 생각 하는 게 아니라 다른 사람을 우선 혹은 배제를 하지 않는 게 배려라고 생각하고 살아 았는데.그러면서도 왠지 나 자신한테는 소홀해지는 게 아닌가 싶을 때도 있었는데.내 인생에 있어서 우선 순위는 어디에 있으며 어디에 둬야 될지에 대한 생각을 하게 하네요.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (109, '생각을 읽는다', 208, 4.86, 0, 0, 1, 27, 180, 207, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2161, 109, '신체언어로 범인을 추적한다는 FBI의 이야기를 듣고 관심 가졌던 신체언어입니다. 생각을 드러내는 신체언어라니, 놀라운 이야깁니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2162, 109, '신체 언어에도 규칙이 있다는 사실 이책을 통해 처음알았네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2163, 109, '사람의 무의식적인 행동으로 생각을 읽는다니 놀랍네요 이책 인간관계개선등에 도움이 될듯하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2164, 109, '작가소개가 전부 사실이라면 거의 초능력자인데요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2165, 109, '사소한 행동 하나하나가 결국 이유가 있는 법이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2166, 109, '신체 언어에 대해 흥미로운 이야기를 담았네요. 알고 싶었던 신체언어이기에 반가웠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2167, 109, '마치 미드 멘탈리스트의 실존인물을 보는 것 같아요 행동심리는 평소 관심이 많은 분야인데 실생활에 접목한 예시가 많아서 인간관계에 도움이 되겠네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2168, 109, '마치 한 편의 마술을 보는 것 같은 기분이 드네요. 머리에서 멀리 있는 발은 거짓말을 못한다는 내용이 참 신기했어요. 유용한 지식이 참 많네요. 또 동의를 구하려면 끄덕이면서 설명해보라고 합니다. 끄덕이는 행동은 전염성이 있다고하네요. ^^ 재밌으니 꼭 읽어보세요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2169, 109, '생각을 읽어낼 수만 있다면 그야말로 인간관계에 날개가 돋히는 것과 같습니다. 반드시 읽어보시고 생각과 동기를 읽어내보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2170, 109, '멘탈리스트는 정말 사람을 이용해서 활용하는것이 아니라 사람의 심리를 이해해서 서로 좋게 만드는 멋진사람이라 생각이 들어요 전세계적으로 멘탈리스트가 별로 존재하지 않는데 정말이지 지은이는 너무나 멋진거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2171, 109, '소통을 위한 몸짓, 신체언어. 관찰을 통해 그들이 원하는 것을 읽어내기 위한 규칙과 방법을 알아보자.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2172, 109, '멘탈리스트라는 미드를 정말 재미있게 봤는데, 여기에 진짜 멘탈리스트가 있네요! 실존한다는 것에 놀랐고, 저자가 매력적이셔서 또 놀랐는데, 책 내용도 재미있어요. 사람의 성격이나 이면을 몸의 언어로 이해한다는 발상이 신기합니다. 오래간만에 흥미를 끄는 재미있는 책을 발견했네요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2173, 109, '타인의 생각을 읽는 방법을 알수있어 재미있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2174, 109, '신체언어에 관련된 책을 처음 접해봐서 매우 흥미롭고, 재미있게 읽을 수 있었습니다. 신체언어로 인하여 인간관계도 더 좋아진다는 것을 배웠으니 이제 활용할 일만 남은 것 같아요! 제 인간관계에 도움이 많이 될 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2175, 109, '신체언어를 단순 사례만으로 나열하지 않고 그것을 접목해서 삶에 변화가 될수 있다는 긍정적인 발상을 전해주는 책이다. 놀랍도록 신기하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2176, 109, '궁금한 내용. 기대됩니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2177, 109, '의사소통에 있어서 좀 더 편해질것 같습니다.청각으로 이해할 뿐만 아니라 그 사람이 말할때 취하는 행동 하나하나를 통해 숨겨진 의미나 생각을 알 수 있다고 하니 신기하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2178, 109, '신체언어를 통하여 상대방의 생각을 읽을 수 있기 때문에 규칙만 알면 인간관계에 도움이 된다고 생각합니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2179, 109, '사람의 마음을 읽는 몸짓, 사람들의 간단한 몸짓의 관찰을 통해 상대방의 생각을 읽고, 나의 몸짓으로 나의 신체 언어를 표현함으로 생활속에서 보다 유익한 소통을 만들어 주는데 도움이 되는 흥미로운 책인것 같습니다,', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2180, 109, '앞으로 살아가면서 필요하고 알아두어야 할 신체언어에 대해 자세히 설명하는 것 같아요. 사람과 관계를 맺는데 있어서 사소한 몸짓하나가 상대방에게는 좋고 나쁜 인상을 줄 수 있는 것인데 우리나라에는 잘 소개되지 않았었는데 이 책 한 권이면 충분할 것 같습니다!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (110, '팥빙수 눈사람 펑펑 1', 208, 4.98, 0, 0, 0, 5, 203, 208, 0, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2181, 110, '읽어볼만한 다양한 점들과 주제가 흥미롭고 좋은 내용이 좋은 것 같습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2182, 110, '너무재미있고 감동적입니다 한글뗀저희딸이 처음으로 완독한책입니다..2편,얼른나왔으면좋겠어요 ㅠㅠ 어쩜이렇게따긋하고사랑스러운 이야기를만들수있죠ㅠㅠ 너무나재미있고 독특하고 따듯합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2183, 110, '팥빙수 눈사람 펑펑의 신비한 마법안경으로 손님들이 행복을 찾아가는 내용이 따뜻했어요. 제가 어렸을때는 안경이 놀림거리가 되는일이 간혹 있었는데 이런 동화를 접하며 자라는 아이들은 안경도 특별한 무언가라고 느낄 수 있을것같아요. 아이와 함께 재미있게 잘보았습니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2184, 110, '팥빙수 눈사람 펑펑(1)_나은 동화_보람 그림팥빙수 를 좋아하는 펑펑이 만드는 신비한 안경이야기다.아이들이 좋아하는 눈, 얼음, 빙수가 가득한 겨울 이야기속에서 마음만큼은 따뜻해지는 에피소드들이 들어있다.길게만 느껴지던 무더위가 가고 찬바람을 맞이할 즈음, 선물받은 책으로 다가올 크리스마스도 겨울도 기다려집니다. 아이의 감상문 전문 사람의 마음, 미래, 과거 등을 보여주는 안경을 만드는 안경점입니다.먹는 모습이 가장 귀여워서 인상에 남는 귀여운 책이었습니다.마음으로 ''나는 못한다'' ''나는 실패할거다'' 같은 부정적인 마음으로 살아가면 인생이 기쁘지 않고 슬플것입니다.하지만 반대로 ''나는 할 수있다.'' ''나는 최고다''같은 말들로 나를 응원하고, 지지하며 살아간다면 인생이 기쁘고 행복할 것입니다.사람이든 동물이든 죽어서도 꼭 없어지는 건 아닙니다.마음속에도 남고, 다른 어딘가에도 행복하게 있을거라 생각합니다.그러니 수명이 다 되어가도, 혹 잃게되는 아픈 상처를 입었다하더라도 너무 슬퍼하지', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2185, 110, '아이나 어른이나 할 것 없이 보면서 미소가 절로 지어지는 가슴 따뜻한 이야기였습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2186, 110, '팥빙수산, 눈사람 안경점 , 신비한 안경 이야기가 너무 재미있었나봐요우리 아이에게 책을 읽어주었는데 팡팡이 만들어주는 신비한 안경을 자기도 갖고 싶대요뭐가 보고 싶냐 물었더니 “시골”이 보고싶대요작년에 가족들과 친척들과 시골집에서 놀았던 기억이 좋았나봐요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2187, 110, '즐거운 상상 속에서 배움이 필요한 이야기를 품고 있는 팥빙수 눈사람 펑펑1 정말 저학년들에게 강추해요!읽고나서 2편 얼른 나오길 기다리고 있어요!!내가 보고싶은 것이 무엇인지 생각해보는 시간도 되고 배움도 있던 동화에요 :)', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2188, 110, '팥빙수 눈사람 책을 읽고 어린아이가 된 기분이었어요~ 원하는 장면을 볼 수 있게 도와주는 안경! 눈사람 펑펑이는 우리에게 위로이자 따뜻함과 포근함을 주는 대상으로 느껴졌어요 그림들도 아기자기하고 크레용으로 그린듯한 느낌이 따뜻함을 더 북돋아주네요^^2권도 얼른 나오면 좋겠어요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2189, 110, '저마다의 이야기를 안고 안경점을 찾아온 사람들에게 정성스레 대하고 진심을 다해 이야기를 들어주고, 조언해주는 펑펑은 사랑스럽고 따뜻하고 한결같은 눈사람이다. 안경점을 찾은 사람에게도 그랬듯이 우리가 놓쳤을 무언가를 발견하고 용기내어 나아가라고 위로하는 따뜻한 그림책이랍니다^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2190, 110, '원하는 장면을 보게 도와 주는신비한 능력이 있는안경을 만들어 준다. 눈사람 “펑펑”이는…보고 싶은 것이 많은 이들에게위로가 되어 주는 우리의 마음을어루만져 주는….따뜻함 그 자체의 달콤한 이야기….그러', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2191, 110, '펑펑이와 함께하는 사람들은 너무 행복할것 같아요. 안경을 사고싶어요 ㅜ 보고싶은게 있거든요아이도 상상력을 가지고 재미있게 보내요 딸은 놀이동산을 보고 싶다고 했어요마음이 따듯해지는 동화입니다. 글밥도 있어서 초등학생이 보기 딱입니다.추천합니다.2언제나오나용', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2192, 110, '안경값 대신 빙수재료를 받는 펑펑이의 마법같은 이야기입니다. 2편에서 스피노와의 호흡이 기대 된다.각기 다른 사연에 걸맞는 안경을 눈과 얼음만으로뚝딱 만들어주는 펑펑이. ˝꿈꾸는 건 누구에게나 자유란다.상상하면돼 그럼 무엇이든 가능하지...˝마음 따뜻한 이야기, 함께 공감 할 수 있는사연', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2193, 110, '다양한 상황속 고민들과스스로 해결하고 단단해지는 방법을 찾을 수 있도록 도움을 주는 동화였어요.* 힐링도서부드럽고 잔잔하게 읽히고 조언과 희망을 느낄수 있는문장들로 이루어져 보는 내내 마음이 따뜻해집', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2194, 110, '팥빙수산에서 안경점을 운영하는 눈사람 펑펑과 스피노를찾아와 풀어 놓는 손님들의 이야기는가슴 뭉클해지며 때론 공감되기도 하죠귀엽고 신기한 안경과손님이 가져다 준 재료로 만들어진 팥빙수는팥빙수 눈사람 펑펑에 빠져들게 만들어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2195, 110, '귀엽고 따뚯한 펑펑이의 안경점나도 가고싶어요:)글밥이 평소 읽는 것 보다 많은 책은 힘들어 한 첫째도너무 즐겁게 끝까지 완독한 펑펑이펑펑이도 그려가며 함께 안경점에 간 상상도 해보고어른에게도 많이 위로가되고 따쓰웠던 책이예요_2권 기다립니더', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2196, 110, '펑펑은 정성다해 손님이 원하는 안경을 만들어주는데요.동화속 이야기 처럼 차마 말하지 못했던 마음속 이야기나 아무도 모르게 꽁꽁 숨겨두었던 이야기들은 누구나 있을거예요. 진심을 담아 이야기도 잘 들어주는 펑펑은 모두에게 위로가 되어줍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2197, 110, '팥빙수 눈사람 펑펑 팥빙수 재료를 안경값으로 받는 눈사람 펑펑. 안경은 자신이 보고 싶은 것을 볼 수 있게 해준다고 한다.눈이 안경테, 얼음은 렌즈^^나도 이 안경점에가서 사람들의 마음을 보는 안경을 사고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2198, 110, '처음에는 과거도, 미래도, 마음도 볼 수 있는 펑펑 안경점의 안경이 탐났는데, 책을 읽으며 안경 없이도 우리는 충분히 잘 해낼 수 있다는 사실을 불현듯 깨달았어요.누구나 고민을 안고 있다는 데서 위로받을 수 있었어요. 살다 보니 불안하고, 힘들고, 후회될 때가 참 많아요. 그때 그러지 말걸, 다음에도 이러면 어쩌지, 그런 걱정을 안고 사느라 놓쳐버린 게 있는 건 아닌지 돌아보게 되네요.안경점 주인인 펑펑 역시 전지전능하고 완벽한 존재는 아니에요. 얼음을 놓치기도 하고, 삐끗하기도 하더라고요. 그래도 안경을 만들고 써보는 안경점의 모두는 실수하고 배우며 함께 성장해요.혼자 애쓰지 않아도, 함께라면 나아갈 수 있다는 희망을 배웠어요. 참 좋은 동화네요. 다음 이야기가 기다려집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2199, 110, '따뜻한 마음씨를 가진 펑펑이 손님의 이야기를 주의깊게 듣고 정성을 다해 만든 안경으로 고민이 해결되는 솜사탕같이 달콤한 그림과 이야기가 책속에 펼쳐진다. 저학년 어린이게 추천하고 싶다. 책을 읽고 따뜻하고 즐거운 마음을 가질 수 있을 것이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2200, 110, '화려한 긴장감 대신 잔잔한 위로와 따뜻한 메시지를 전하는 작품이다. 특히 마음이 지치거나 위로가 필요할 때 펼쳐보면 더욱 큰 감동을 느낄 수 있다. 어린이뿐 아니라 어른에게도 조용히 스며드는, 오래 기억에 남을 이야기다.#출판사에서도서를제공받았습니다', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (111, '허삼관 매혈기', 207, 4.47, 1, 3, 11, 75, 117, 192, 11, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2201, 111, '피를 파는 허삼관. 인민재판 당하는 허옥란. 일락 이락 삼락의 우여곡절. 마지막 구절의 눈썹과 좆털까지... 해학과 눈물로 쓴 서사시이자 삶의 여정을 그린 위화의 최고작.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2202, 111, '위화그런데 번역인지 편집인지 이유는 모르겠다.중간, 중간 구멍 뚫린 이야기들이 어색하다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2203, 111, '개인적으로 이해도 안되고 억지스럽고 괴상한 이야기다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2204, 111, '상황은 분명 슬픈데, 그들의 말과 행동에 웃음이 나온다. 긍정적인건지, 무덤덤한건지, 이 또한 현실 극복 방식일지도. 끝 부분에 아들 셋을 다 키우고 아내와 돼지볶음을 먹는 허삼관의 모습에 우리 아빠의 모습이 겹쳐져 무겁고 서글퍼졌다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2205, 111, '솔직한 현실 분위기를 제대로 묘사한 가족 이야기인 것 같네요. 제 자식이 아니라고 일락이를 매몰차게 대한다든지, 나중엔 제 자식 이상으로 사랑한다든지 하는 것이 보통의 사람 패턴이니까. 그러나 피를 팔아 살아간다는 주제는 솔직히 불편했습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2206, 111, '2004년, 연극을 봤다. 책을 읽은 후였다. 연극에서는 허삼관이 피를 팔 때마다 홍등이 하나씩 내려왔다. 연극의 거의 마지막, 암전이 되고 무대가 밝아졌다. 무대 위가 홍등으로 가득했다. 어깨를 들썩이며 울었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2207, 111, '피 안 팔아봤으면 말을 하지마^^ 넘 잘 읽었어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2208, 111, '흡입력 넘치는 소설. 위화의 이름을 한국에 알린 작품. 끈끈한 피처럼 활자가 눈에 달라붙어 책장을 넘기게끔 하는 힘이 있다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2209, 111, '중국인 특유의 삶. 슬픔속에 웃음. 우프다란 말이 적절한 소설왜 운수 좋은 날이 생각나지?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2210, 111, '가족을 위해 피를 파는 허삼관의 고단한 삶, 하정우와 하지원이 주연으로 영화화해서 화재에 오르기는 했지만 영화는 크게 성공하지 못했다네...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2211, 111, '‘인생‘과 더불어 위화의 대표적 소설. 피를 팔아서 생활비를 충당해야 하는 중국인민의 삶을 유머와 해학을 곁들여 그렸다. 우리나라에서 하정우 주연의 영화가 제작,개봉되었으나 아마 흥행에는 실패한 것 같다. 인생이라는게 별거 아니다. 애키우고,먹고 살다 병들어 죽는다는 것.쓸쓸하다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2212, 111, '엄마가 kbs방송보시고 적극추천해주셔서 지금 읽고 있는데, 너무 재밌어요~이거 뭐지?왜 웃기지? 이렇게 웃기지 않은 상황에서 어떻게 웃길 수 있지? 하는 중입니다. 하정우씨와 하지원씨가 영화로 제작하실거라고 들었는데, 어떻게 나올지 정말 궁금하네요!중국특유의 유머와 해학이 좋아요^^재밌어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2213, 111, '정말 재미있는 소설 그러나 슬픈.....', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2214, 111, '영화보다 소설이 훨씬 더 재미있다. 웃으면서 울면서 봤다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2215, 111, '가족을 위해 힘도, 젊음도, 생명도 파는 아버지의 이야기.피를 팔고 돼지간볶음을 먹던 기억에 돼지간볶음을 먹기위해서는 피를 팔아야만 한다고 생각하게 된 가장의 웃픈 장면!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2216, 111, '문화대혁명, 중국의 가장 혼란했던 시기에서 한 가장의 이야기,,˝다만 내가 늙어서 죽을 때, 그저 내가 널 키운 걸 생각해서 가슴이 좀 북받치고, 눈물 몇 방울 흘려 주면 난 그걸로 만족한다.˝', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2217, 111, '진적 많이 들었던 책인데 이제야 구입하네요. 약간은 읽기가 두려운 책...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2218, 111, '웃다가, 울다가. 중국 소설은 고리타분하고 지루할 것이란 편견을 깨준 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2219, 111, '이 말을 들은 허삼관이 허옥란에게 근엄하게 한마디 했다. “그런 걸 두고 좆 털이 눈썹보다 나기는 늦게 나도 자라기는 길게 자란다고 하는 거라구.” -알라딘 eBook (위화) 중에서', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2220, 111, '오래전에 장이모 감독의 [인생]이란 영화를 봤다. 공리의 명연기가 인상적이었고, 무척 감동적이었다. 꽤 오래전 일인데도 기억에 생생히 남아있다. 그 후 한참 뒤에야 [인생]이 위화의 소설( )을 바탕으로 했다는 걸 알게 됐다. 읽어야지 읽어야지 하면서도 읽지 못했다. 위화에 대한 관심의 고리는 다행이 끊어지지 않고 이어졌는데, 우연히 위화의 다른 작품 를 접하게 된 것이다.한마디로 말하겠다. 는 정말 대단한 작품이다. 삶의 모든...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (112, '빨간 머리 앤', 207, 4.84, 1, 1, 4, 18, 183, 201, 4, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2221, 112, '그림이랑 책 편집이랑 번역.. 모든게 맘에 듭니다.너무 이뻐요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2222, 112, '사랑하는 딸과 아들에게 보내는 독서편지 0. 빨간 머리 앤. 너무 유명한 작품이란다. 동화로도 많이 알려져 있어서 너희들도 이미 읽어 본 책이고… 아빠가 어렸을 때 텔레비전 만화로도 해서, 빨간 머리 앤이라고 하면 텔레비전 만화 속 앤의 얼굴이 가장 먼저 떠오르는구나. 비록 많이 보지는 않았지만, 워낙 유명한 캐릭터니까 말이야. 생각해보니 어렸을 때 동화책로 된 을 본 것 같지도 않았어… 줄거리가 어떻게 되었지? 생각해 보니 막상 떠오르지 않더구나. 그러니까, 그 작품...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2223, 112, '이 책을 읽으려면 몇 날 며칠이 걸리겠지 생각했던 것과 다르게 너무나 술술 읽혔다. 4일 하루는 아침부터 오후까지 할 일이 많았는데도 이 책을 한 번 붙잡으니 놓을 수가 없었다. 책에 빠져든다는 기분이 이런건가 싶었다. 거의 교육서를 많이 읽는 편이라 이런 고전을 읽는 맛이, 재미가 이런 건가 했다. 속으로 푹 빠지도록 쓴 작가는 루시 모드 몽고메리. 1874년 의 실제 배경이 되는 캐나다 프린스에드워드 섬에서 태어났다. 몽고메리는 이 책의...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2224, 112, '#도서협찬빨간머리앤루시 모드 몽고메리 지음김지혁 일러스트김양미 옮김글담출판사 이 책 보자마자 얼마나 소장하고 싶었는지 몰라요.. 너무 예쁨가득이라서 한눈에 반해버린 책이였거든요..어릴때 티비로 보기도 했고 책으로 봤던 빨간 머리 앤을다시 그 추억여행 떠났답니다."주근깨 빼빼마른 빨간 머리 앤 "이 노래 아시는 분 ?ㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡㅡ "아름답지 않아요? 비탈에서 몸을 갸우뚱하고 있는,저 하얀 레이스 같은 나무를 보면 뭐가 떠오르세요?" "나중에 알아볼 것들을 생각하는 일도 근사하지 않나요?살...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2225, 112, '만화보다 재미있게 읽었다. 사랑스러운 앤 이야기가 나를 흐뭇하게 만들었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2226, 112, '언제 읽어도 빨간머리 앤은 우리들의 추억. 인디고의 책은 삽화까지 정말 이뻐 갖고 싶은 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2227, 112, '어릴적 나의 뮤즈였어요 언제나 밝은 긍정적인 아이.. 다시ㅣ 읽는동안 행복했어용', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2228, 112, '몇번을 읽어도 좋고 닮고 싶은 앤!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2229, 112, '빨간머리 앤을 좋아해서 책이 이미 있지만 삽화가 너무 아릅다워서 책을 구매한 기억이 납니다. 소장하고싶은 책이네여~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2230, 112, '글만 읽을 때와 그림과 함께 글을 읽을 때와 감동이 다르다. 앤에게 더 가까이 다가가는 느낌이 든다. 이 한 권의 책으로 마음이 더 윤택해진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2231, 112, '읽고나면 가슴 따뜻해지는 앤의 성장이야기를 아름다운 일러스트와 함께 만나볼 수 있어 정말 좋았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2232, 112, '삽화가 정말 예뻐요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2233, 112, '빨간 머리 앤..귀여운 소녀..빨간 머리 앤 우리의 친구..어린 시절 재미있게 봤던 빨간 머리 앤이네요..지금도 다이애나와 앤 같은 친구의 우정이너무 부럽고 사랑스러워 보입니다..때로는 내 맘을 이해해 주는 한 명의 소중한 친구를 통해서도한 사람이 위대한 삶을 살기도 하네요..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2234, 112, '빨강머리앤이 하는 말(백영옥)을 읽고, 읽게 된책!! 어린이들의 동화책이 아니다. 이렇게 가슴시리도록 아름다운 문장들과 캐릭터들이 별들처럼 쏟아진다.가련하고 사랑스러운 앤,고마운 매슈,마릴라!!화장지 한통은 사용한 듯...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2235, 112, '아..... 저는 앤처럼 말이 많은 사람은 처음입니다 ㅋㅋ 우리학교애도 그런애는 있내요사실 저는 앤처럼 말이 많은 사람은 싫답니다.........................', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2236, 112, '다이애나와 앤처럼. 저도 마음이 맞는 소울메이트 친구가 있어서 그분에게 이 아름다운 책을 선물했어요.우리의 우정이 영원하기를. 작은 행복들을 모아 진주알로 목걸이를 만들듯 삶의 순간을 더 빛나도록 열심히 노력하고 그만큼 성장하고 단단해지는 저를 만들어준 책이라 의미가 깊어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2237, 112, '따뜻하고 포근한 문체로 쓰여진 글을 가만 읽고 있자면, 마음까지 닮아 가는 기분이다. 행복한 날이란 멋지고 놀라운 일들이 일어나는 날이 아니라 진주들이 하나하나 한 줄로 꿰어지듯, 소박하고 자잘한 기쁨들이 조용히 이어지는 날들인 것 같다는 대사가 인상적이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2238, 112, '이젠 전 길모퉁이에 이르렀어요. 그 모퉁이에뭐가 있을지는 모르지만 가장 좋은 것이 있다고믿을 거예요. 길모퉁이는 그 나름대로 매력이 있어요. 아주머니, 모퉁이를 돌면 무엇이 나올까 궁금하거든요. 어떤 초록빛 영광과 다채로운 빛과어둠이 펼쳐질지, 어떤 새로운 풍경이 있을지, 어떤 낯선 아름다움과 맞닥뜨릴지, 저 멀리 어떤 굽이길과 언덕과 계곡이 펼쳐질지 말이예요.-519p번역에서는 길모퉁이라고 표현했지만 나는터닝 포인트라고 표현하고 싶다.비록 앤 자신이 원하는 대로 살지 못하게 되었지만 새로운 삶을 향해 나가는 좋은 기회가 된거라고 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2239, 112, '내가 당신을 사랑하듯 당신이 날 사랑한다면, 죽음이 아니고서는 우릴 갈라놓지 못하리.(263p) '' 빨강머리 앤이 어렸을 적에 ''는 여태까지의 앤의 이야기가 아니라 앤이 어렸을 적 이야기를 하고 있다. 앤이 태어나고 우리가 알고있는 초록 지붕 집으로 오기까지의 이야기가 담겨있었다. 잔잔하면서도 여운있는 이야기에 제대로 읽어보지 못한 앤의 이야기가 궁금해지게 된 이유였다. 그리고 만나게 된 빨간 머리 앤. 사실 빨강머리 앤이 어렸을 적에를 읽게 된 이유가, 그리고 빨간 머...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2240, 112, '만화로도 유명한 빨간머리앤 빨간머리앤은 전에도 읽어본적이 있지만 삽화가있는 책으로 다시금 읽어보고싶어서 구입했는데 색감이 예쁜그림책같은 느낌이랄까 그림동화같은 느낌이 들어서 책도 자그마해서 그림책같은 느낌이 물씬난다 특히 표지에서 나오는 앤이 처음 매튜를 만나서 아름다운 풍경에 감탄하는 모습을 잘표현한것같다 빨간머리앤은 작가가 자신의 어린시절을 투영해서 썼다고 알려졌는데 그래서 작가가 어린시절을 보냈던 캐나다 섬 (정확한 이름은 잊어버렸지만)에 무척이나 가보고싶기도 했었다 주근깨에 빼뺴마르고 고아소녀인 앤...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (113, '얼굴 빨개지는 아이', 206, 4.49, 0, 0, 17, 71, 118, 189, 17, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2241, 113, '멋진 우정이에요. 다시 만나는 미래에 행복해져요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2242, 113, '｀친구｀에게 선물하고 싶은 책.˝니가 너라서 좋아.˝ 라는 메모와 함께.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2243, 113, '사랑스럽고 귀여운 마음이 몽글몽글해지는 동화', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2244, 113, '"얼굴 빨개지는 아이"는 그림과 글로 구성된 어린이뿐만 아니라 어른이 읽어도 좋을 그런책이다. 짧은시간에 읽을 수 있는 그림중심의 책이지만 책을 덮고나서 많은 생각을 하게 만드는 책이기도 하다. 책의 내용을 잠깐 소개하면, 마르슬랭이라는 이유도 없이 얼굴이 빨개지는 아이가 있다. 마르슬랭은 늘 얼굴이 빨갛다. 이유없이 말이다. 더 기가막힌 것은 정작 빨개져야 하는 상황에서는 그렇지 않다는데 있다. 마르슬랭은 점점 친구들과 멀어져 혼자 놀게 된다. 단지 얼굴이 빨개진다는 이유 하나 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2245, 113, '마치 아무렇게나 낙서한 듯한 성의없는 그림체에 실망감을 느낀 것도 잠시 한 장 한 장 넘길수록 마르슬랭과 르네의 우정에 감동하여 시간가는 줄 모르고 읽었던 기억이 난다.시도때도 없이 얼굴이 빨개지는 병에 걸려 혼자가 되어버린 마르슬랭과 마찬가지로 때와 장소를 가리지 않고 재채기를 해대는 르네의 좌충우돌 벌이는 재밌고 유쾌한 에피소드들이 읽는 내내 나의 입가에 미소를 짓게 만들었다.마르슬랭과 르네처럼 서로의 단점을 감싸주고 이해해주는 그런 진정한 친구가 과연 내 곁에 있을까? 란 의문과 함께 나의 삶에 대해 반성하는 계기가 되었던 것...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2246, 113, '좋은 친구 이야기가 많다. 백아와 종자기의 이야기는 유명하다. 지음이란 말이 거기서 나왔다고 한다. 지난 겨울 상담 공부를 하는데, 지금 자기의 상황을 색종이나 색연필로 그린 다음에 설명하는 시간이 있었다. 나는 나와 가까운 사람들을 그리는데... 친구가 없었다. 내가 살면서 정말 친했던 친구가 있었다. 지금은 카자흐스탄이란 낯선 땅에서 한국어도 모르는 고려인 여인과 함께 살고 있다. 이제 연락하기도 어렵다. 또 한 선배는 하늘 나라로 갔다. 난 친구는 함께 있어도 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2247, 113, '장 자끄 상뻬의 에 이어 읽게 되는 두번째 작품, . 이 책은 왕따에 관한 문제를 안고 있다. 그렇지 않을 수도 있다. 그는 그저 내던져놓을 뿐이다. 어떤 문제에 대해서 시시콜콜 이야기하거나 하지는 않는다. 보는 사람에 따라 다르게 볼 수 있는 넓은 폭을 가지고 있다. 그래서 그의 글과 그림이 더욱 푸근한지도 모르겠다. 나는 그 많은 갈래의 가능성 중에 왕따를 읽었을 뿐. 시도때도 없이 얼굴이 빨개지는 아이가 있다. 친구들로부...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2248, 113, '누구에게나 감추고 싶은 자신만의 비밀이 있다. 는 편견 속에서 싹튼 우정을 담은 일종의 ''어른 동화 책''이다. 때문에 책의 구성은 대부분 그림으로 가득 차 있으며, 글은 페이지당 한 문장이 전부이다. 하지만 그 이야기가 담고 있는 메세지는 강한 파도 만큼이나 나에게 생각 거리를 만들어 주었다. 이유없이 얼굴이 빨개지는 ''마르슬랭''과 이유없이 재채기를 하는 ''르네''는 자신의 콤플렉스로 친구들에게 외면을 당하다가 우연히 둘은 마주치게되고, 그 둘은 누구보다도 가까운 절친한 사이가 된다. 더 이...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2249, 113, '우리는 살기좋은 대한민국에 태어나서 아주 좋은 인생을 살아가고 있다. 하지만 사람이라면 콤플렉스 즉 단점을 가지며 살아간다. ''얼굴 빨개지는 아이''에도 주인공인 마르슬랭은 얼굴이 빨개지는 콤플렉스를 가지고 있다. 얼굴이 빨갛기 때문에 유독눈에 뛰는데 내가 만약 이런 콤플렉스를 가졌다면 행복한 인생을 살아가는데 무척 힘들어할것같다. 하지만 마르슬랭은 인생을 아주 당당하게 살면서 우연히 재치기 콤플렉스를 가진 르레라토를 만난다. 르레라토는 틈만나면 재치기를 하기 때문에 이 사실을 모르는 사람들은 감기에 걸렸나(?)하는 생각을 하게된다....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2250, 113, '남는 게 시간이다보니 도서관에 가서 나름대로 소규의 목적을 달성하자는 생각에 장 자끄 상뻬의 책을 전부 읽기로 하고 잔뜩 찾아서(약 8권) 앉았지만, 수면 부족으로 그만(...) 결국 세 권만 읽고 나머지는 몰래 숨겨 놓고 왔는데 읽은 세 권은 1.얼굴 빨개지는 아이 2.자전거를 못 타는 아이 3.랑베르 씨의 신분상승 이었다. 세 권 전부 동화 같은 이야기에 무척 좋은 그림이 있어서 읽기 좋았다. 라고 가져간 노트에 쓴 순간 나는 이 문장에 저주를 느낄 정도로 상투적이라는 생각을 했다. 결국 이런 저런 식으로 세 권의 책을...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2251, 113, '왜 그렇게 얼굴이 빨갛니? 동화책인데.. 감동이 담뿍 담겼다.. 늘 얼굴이 빨간 마르슬랭에게 친구들은 늘 묻는다. "왜 그렇게 얼굴이 빨갛니?" 대답이 귀찮은 마르슬랭은 혼자 노는것을 더 좋아하게 되는.. 그래서 늘 혼자인 그.. 그에게 쉬도 때도 없이 재채기를 하는 친구 르네가 다가온다 서로 즐겁게 지내다가 르네가 이사를 가서 다시 혼자가 된 마르슬랭.. 먼 훗날 어른이 되어 다시 만나게 된다.. 여전히 빨간 얼굴과 여전히 재채기를 하는 모습 그대로. 여전히 둘은 즐겁다 서로에게 말하지 않아...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2252, 113, '그림책은 참오랜만이다. 참짧고, 귀여운 그림체로 많은 것들을 남겨준책이다. 마르슬랭과 르네는 고칠수없는 병때문에 위축되고, 외로웠지만 이웃으로 만나 좋은 친구가 되어 서로의 콤플렉스를 이해해준다. 그래서 좋은 친구가 된다. 둘도없는 ... 하지만 르네가 이사를 가서 어른이 되도록 만나지못하지만 우연히 르네의 기침소리를 듣고 마르슬랭과 르네가 만나게 된다. 지금의 나는 완벽할수없다. 그흠이 크던작던 난 태어난 이상 그흠때문에 위축되기보다는 더욱더 떳떳하게 살것이다. 얼굴이 빨개지는 아이마르슬랭처럼.. 기침을 자...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2253, 113, '친구란 어떤 존재인 지 정확하게 표현하고 있는 책이다. 그럼 내용이 얼마나 어려울까 생각하기 쉽지만 실상 이 책은 너무 쉽다. 작고 앙증 맞은 그림이 우선 눈에 들어 오는 책. 많지 않은 글자 수에 부담없이 쉽게 손에 들 수 있는 책. 내용을 보면 얼굴이 빨개지는 아이(마르슬랭 까이유)와 재채기가 늘 나오는 아이(르네 라토)의 우정에 관한 이야기. 결정적인 순간엔 빨개지지 않으면서 정작 일상에선 늘 빨개져서 힘들어 하는 아이와 바이올린을 잘 켜지만 자주 나오는 재채기로 인해 힘들어 하는 아이가 만나 서로...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2254, 113, '아무런 이유없이 얼굴이 빨개지는 아이가 있다..마르슬랭! 아이들이 그에게 빨개진얼굴이 어쩌고 하며 관심을 가질때마다 점점 견디기 힘들어하는 아이는 이제 혼자놀며 시간을 보낸다. 그러다 우연히 아주 우연히 한 아이를 알게 된다.그아이는 간난아기때부터 감기기운이 없는데도 자꾸만 재채기를 하는 병에 걸렸다.ㅎㅎㅎ 라토는 바이올린을 켜는 훌륭한 학생이었다.늘 "에취", "으아취"를 반복하고 다니지만 마르슬랭처럼 외롭기는 마찬가지였다.. 서로의 이야기를 들어주고 서로의 특성을 이해하고 감싸주는 친구 이둘은 어느새 언제 어디...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2255, 113, '"얼굴 빨개지는 아이"라는 제목을 보는 순간, 아! 하는 동질감에서 시작된 호기심이었다. 평소에 보통사람들보다 더 작은 감정변화나 기온변화에도 쉽게 얼굴이 빨개지는 나는, 내 얼굴이 빨개졌다는 걸 다른 사람들이 알아차릴때엔 더욱더 빨개졌다. 거짓말을 한다거나 했을때 내 마음이 조금이라도 동요되고 있다면 얼굴이 빨개져서 쉽게 거짓말을 할 수도 없었다. 하지만 그것은 나이가 들면서 뻔뻔해져서인지 조금 덜해졌지만, 그 외의 다른 작은 일들이나 기온차이에도 얼굴이 빨개지는 것은 여전하다. "얼굴 빨개지는 아이"의 주인공 마...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2256, 113, '난 얼굴이 흰 편이다. 주량은 보통이지만(소주 1병 반정도), 맥주, 소주, 동동주를 불문하고 1잔만 마시면 얼굴이 빨개진다. 푸쉬업이나 윗몸일으키기를 조금만 해도 얼굴이 빨개진다. 그리고 아무 이유 없이 얼굴이 빨개질 경우도 많다.중-고등학교때 이 현상때문에 곤란한 경우도 많았다. 난 하나도 창피하지 않은데, 괜시리 얼굴이 붉어지곤 했다. 그럼 난 아이들에게 "창피한데 아닌척 하고 있는" 상태로 여겨진다. 난 아무렇지도 않은데, 부끄러워하고 있는게 되어 버린다. 아무렇지도 않다가, 아이들이 "어 얼굴 빨개진다.. 빨개진다" 하...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2257, 113, '도서관에서 책이 넘어질 뻔한 것을 잡아주다가 발견하게 된 책이다. 하얀 바탕의 책 위에 붉은 제목의 글씨가 단정하면서 산뜻했고, 꼭 보지 않으면 안될 것 같은 분위기도 갖게 했다. 작품 속 주인공은 두 명의 소년이다. 아무 이유도 없이 얼굴이 빨개지곤 하는 아이 마르슬랭과, 어디에서고 느닷없이 재채기를 해대는 르네 라토. 각각의 콤플렉스를 가진 두 아이는 만나자마자 친구가 된다. 그리고 오랜 시간 같이 있게 되었고, 우정이 깊어가자 서로 아무 말 없이도 아주 편히 있을 수 있는 사이가...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2258, 113, '꼭 구분지어 말하자면, 전 장 자크 상페의 글 보다는 그림의 팬입니다. 글도 좋지만, 그림이 없는 그의 글은 상상이 안 되는걸요. 아무렇게나 쓱쓱 그려낸 것 같이 자유와 기지가 느껴지는 오밀조밀한 삽화들을 들여다보고 있으면 언제나 마음이 따뜻해집니다. 고물거리고 있는 아기의 주먹을 펼쳐보는 기분이 들어요.동심의 흐름에서 가장 소중한 것들을 적절한 순간에 들여다볼 수 있는 능력은 아무에게나 있는 것이 아닐겁니다. 특히나 나이 먹어 어른이 되어서도 그런 능력을 유지하기는 정말 어렵겠지요. 하지만 꼬마 니콜라를 처음 봤을 때의 감동이 얼...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2259, 113, '우린 우리와 다른 누군가를 무의식적으로 배타하기도 한다.. 어찌보면 얼굴이 이유없이 빨개지는 아이인 마르슬랭이 만약 한국에서 살았다면 쉽게 왕따를 당했을 수도 있을 것이다.. 하지만 그런 마르슬랭에게도 친구가 있다.. 끊임없이 재채기를 하는 르네.. 르네도 끊임없는 재채기로 혼자있기를 즐기는 아이였지만 마르슬랭과 만난 후로 둘은 많은 것을 같이 할 수 있었다.. 서로를 이해하고있기에 서로의 차이는 극복할 수 있었을 것이다.. 그리고 르네의 갑작스런 이사후에도 르네를 기억하며 다른 친구를 사귀게 될 수 있었던 마르슬랭... 짧고 간...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2260, 113, '얼굴 빨개지는 아이 좋아용 짱이에용 굿이에용 JH 굿이에용 몬테크리스토 짱 막있겠네용', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (114, '하루하루가 이별의 날', 206, 4.64, 0, 0, 9, 56, 141, 197, 9, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2261, 114, '허무맹랑한 듯 싶어서 프러드릭 베크만의 신간을 굳이 서둘러 읽지 않으려고 했으나 빈번히 눈에띄니... 이도 어쩔 수 없네... 한여름 햇살처럼 눈부신 감동을 준다나?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2262, 114, '아름답다 아름답다나도 이리 아름다운 노인이 될수있을까...이리 아름 답게 이별 할수있을까...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2263, 114, '기억을 잃어가는 노인과 그 가족들의 이야기.이별은 언제나 슬프다고만 생각했다. 아름다운 이별이고 뭐고 헤어지면 슬프니까. 그래도 이 책은 슬프면서도 미소가 지어지더라. 서로의 추억을 꺼내보는 과정이 참 아름답게 그려졌다. 서서히 기억을 잃어가는 것도 슬프지만 그래도 이별을 조금씩 준비할 수 있는 건 마음의 준비를 좀 더 할 수 있게 되는 것같다.일하느라 아들과는 별로 친하게 지내지 못 했지만 손자와 정말 잘 지내고, 아내와도 애틋한 사랑을 했던 할아버지. 기억을 잃고 무너져내리는 듯한 모습을 볼 때는 가슴 아파도, 할머니와의 사랑, 손자와의 추억을 꺼내놓을 때는 따뜻해지더라. 손자를 기억 못 할까봐 걱정하는 할아버지에게 다시 처음부터 친해질 수 있어서 좋겠다고 하는 손자도 감동이었다.그림과 함께 따뜻함을 전달해주는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2264, 114, '마지막에 나도 모르게 눈물이 터져 나왔다짧지만 여운이 있는..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2265, 114, '할아버지와 손자의 이별할아버지와 아들의 이별할아버지와 할머니의 이별그과정속에서 드러나는 프레드릭 배크만작가님에 의도와 표현들은 말로 다표현하지 못할정도로 감동적이에요!또 같은 이야기가 반복되며, 같은 장면이 반복되며, 같은 행동이 반복되며 등장하는 인물들과 배경이 이책에 묘미중 하나인것 같네요.이별이란 다소 어렵고 두려운 소재를 감동적이면서 재치있게 잘 표현하신것같아요.그래서 더욱더 이책은 짧지만 강렬했고, 읽은후에도 여운이남아 이책에대해, 또 이별에 대해 다시 생각하게 해주었어요.책에 있는 글들을 한자 한자 읽어가면 결국 마지막장이 들어나기 마련인데 이책에 마지막장을 본순간 작가의 의도가 보여서 다시 읽게 되는것 같아요.다시읽으면 이책에 또다른 궁금중과 또다른 묘미로 계속해서 읽게하네요.프레드릭 배크만 작가님이 쓰신 ''독자 여러분께''에 있는 말들중에"솔직히 누군가에게 보일 목적으로 시작한 원고가 아니였다. 나는 글로 적어야 이해할 수 있는 사람이기에 그냥 내 생각을 글로 정리하려고', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2266, 114, '누구나 하는 이별이지만 받아들이는 느낌이 다른데담담하면서도 깊은 애정과 사랑을 느낄수 있는 이별을 준비하는 이들에 대한 소설', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2267, 114, '이별, 슬픔만 느껴지는 단어에서 아름다움도 느껴지게 하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2268, 114, '치매를 아름다운 동화처럼 묘사한 책. 현실은 더 가혹하거나 더하겠지만 어떤 경우든 집으로 돌아가는 길이 멀어진다는 건 참 슬픈 일이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2269, 114, '논리적으로 이해되지 않는 부분들이 있지만 상관없다. 아 슬프고 따뜻하다 여러 번 읽어도 여전히 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2270, 114, '짧지만 감동적인 책입니다. 삶과 죽음에 대해 많이 생각하게 하는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2271, 114, '처음에 하루하루가 이별의 날이라는 책 제목과 책 설명만을 보았을때는 일반적으로 예상가능한 슬프고 마음아픈 일들만 가득한 내용이지 않을까 생각했었는데, 기억을 잃어가는 과정이 담담하면서도 천천히 아름답게 그려지는것을 보면서 의외로 힐링이 되는 책이었다. 삽화도 너무 예쁨.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2272, 114, '하루하루가 이별이라는..죽음도 기억을 잃어버림도 아직은 이해할 수없는나이인 어린 손자와 기억을 잃으며 손자의 손을 잡아보고 얼굴을 보고 또 보았을 할아버지이정도의 설명으로도 충분히 얼마나 가슴이아려오는지 알수있다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2273, 114, '지난 주말에 요양병원에 계시는 엄마를 뵙고 왔다. 지난 번에 뵈었을 때보다 살이 내린 모습에 안쓰러운 마음이 먼저 들었다. 텃밭에서 따 간 빨간 자두를 드렸을때 달게 드시는 모습을 보고 안도했고, 잘게 썰어진 음식을 맛있게 드시는 모습을 보고 또 안도했다. 엄마에게 갈 때마다 이번이 마지막일 수도 있다는 생각을 한다. 내가 무심코 보낸 하루가 엄마와의 마지막이 될 수도 있다는 사실을 자각하면 울컥해진다. 만일 엄마가 아프지 않았다면 엄마를 모시고 여기저기 여행도 다니고 했을텐데 하는 아쉬움을 갖는다. 뒤늦은 후회다...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2274, 114, '치매만큼 무서운 것도 또 없는 것 같다. 다른 병들은 비록 육신이 고달퍼도 자신의 영혼만은 그대로다. 내가 누구인지, 사랑하는 사람들, 그들과의 기억, 결코 놓치고 싶지 않은 추억 등은 고스란히 남아 오히려 병으로 인한 통증과 절망을 이길 수 있도록 도와준다. 그러나 치매는 그 모든 것을 잃는다. 육신은 멀쩡해도 그 멀쩡하다는 것을 알 수 있는 영혼은 없는 것이다. 거울을 봐도 내가 누구인지 알 수 없고 날 아끼고 사랑하는 이의 얼굴도, 지금 나를 보는 그들의 아픔도 알 수 없다. 육신이 아픈 자들은 죽음이 임박했을 때,...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2275, 114, '인류의 의학, 과학, 기술이 발전하면서 생활환경이 나아졌고, 그 나아진 환경으로 인해 평균수명이 엄청나게 늘어났다. 예전에는 환갑이라고 하면 오래 산, 경사스러운 일이었는데, 요즘 환갑잔치를 한다고 하면 젊은데 무슨 잔치냐는 핀잔을 듣게 된다. 환갑을 넘어 80이 기본이 된 지 오래. 이제는 백세 시대를 눈 앞에 두고 있다. 그런데 이런 백세 시대에 예상하지 못한, 어쩌면 예상한 복병이 있는데, 그것은 바로 치매다. 자신을 잃어버리고 목숨만 부지하고 있는 상태... 이 소설에서는 할머니와 할아버지의 상반된...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2276, 114, '''날 때가 있고 죽을 때가 있으며''- 성경, 전도서 3장 2절 상반절''생자필멸(生者必滅)1'', ''회자정리(會者定離)2'' 가까운 분들이 하늘로 가셨어요. 언제나 함께 계실 줄 알았던 분들. 한 분, 한 분 떠날 때 마음이 아팠어요. 떠나시기 전, 이별을 준비하시던 분들도 계셨지요. 저를 바라보시던 그분들. 오래 기억하고 있어요. 그리고 작년, 아버지께서 암 수술을 하셨어요. 췌장과 직장의 암을 수술하셨지요. 특히, 예후(豫後)3가 좋지 않다는 췌장암. 재발과 전이의 위험이 아직...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2277, 114, '우리는 저마다 ''남다르게 평범한 인생''을 살아가는 게 아닐까 싶어요. 지구가 생겨난 이후 완전히 똑같은 날씨는 단 하루도 없었다는 것처럼 깨알같이 많은 사람들이 살다가지만 서로가 서로를 완벽하게 닮은 삶을 살았던 사람은 결코 존재하지 않겠지요. 어제와 오늘의 날씨가 비슷해 보이고 나와 당신의 삶이 그닥 크게 다르지 않은 것처럼 보이기는 하지만 말입니다. 프레드릭 배크만의 소설 은 비록 남들이 볼 때는 평범해 보일지라도 우리들 삶이 우리를 기억하는 특별한 사람들에게 만큼은 특별한 의미로 남을...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2278, 114, '78. 프레드릭 배크만의 하루하루가 이별의 날을 읽었다. 얇은 산문같은, 동화같은, 그림이 있는 이야기 책.읽다보면 시같다가 노래같다가 흥얼흥얼 콧노래같다 하며 고개를 갸유뚱 거리다 어느새 눈가가 자꾸 흐려지게 되는 책. 짧은 책이지만 여운은 길고 사이 사이 손자의 손을 꼭 잡은 뒷모습을 그린 그림과 아름다운 자연들 그리고 할머니의 히야신스 그리고 빠질지도 모르는 우주가 잠시잠시 숨을 내쉬게 하고 할아버지의 기억이 조금씩 머리 안에서조차 좁아지는 그림들에 더 슬퍼지지만 손자...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2279, 114, '하루하루 기억을 잃는 할아버지, 그래서 손자 노아와 매일 이별하는 연습을 한다. 할아버지의 머리 속 세상은 갈수록 작아져도 노아와의 기억으로 가득하다.실패는 한번 더 시도하지 않은 게 유일한 실패라 말하고, 수학과 우주와 할머니와 가장 평범한 일상을 같이 얘기한다. 우리의 삶도 저절로 특별하지 않다. 같이 서로 의지하고 필요한 때에 함께 있는 것이 특별해지는 유일한 길인것처럼.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2280, 114, '프레드릭 배크만, 그를 처음 알게 된 것은 라는 작품에서였죠. 그를 스타작가로 만든 그 작품이 데뷔작이기도 했는데요. 그 후에 발표한 작품들 역시, 독특한 캐릭터와 블랙 유머가 만들어 낼 수 있으라 싶은 따듯하고 감성적인 이야기라는 느낌이 강했어요. 그런데 그의 신작 은 또 다른 느낌으로 다가옵니다. 한국 제목도 그렇지만, 영문 제목인 ‘And Every Morning the Way Home Gets Longer and Longer’ 역시 시적이라는 느낌을 ...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (115, '가시고기', 206, 4.25, 2, 8, 24, 74, 98, 172, 24, 10);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2281, 115, '너무 슬퍼요ㅠㅠ 꼭 옆에 휴지 챙기고 읽어야 하는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2282, 115, '가시고기저자 조창인산지2019-05-10소설/시/희곡 > 한국소설엄마 가시고기가 알을 낳고 떠나면 아빠 가시고기는 알을 낳고 떠난 엄마 가시고기를 대신하여 새끼들을 돌보고 결국 자신의 몸까지 내어줍니다.자신의 몸을 내주어도 아깝지 않은, 부성애를 진하게 느낄 수 있는 소설, 바로 『가시고기』입니다.씩씩하고 밝은 다움이는 많이 아픕니다.곧 3학년 여름방학이 다가오지만 2년 전부터 입, 퇴원을 반복하면서 다움이는 학교에 여섯 달도 못 가봤지요.똑똑한 다움이는 알려주지 않아도 모든 것을 알고 있습니다.아빠가 다움이에게 무슨 병명인지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2283, 115, '아버지의 사랑을 다시 생각해 봅니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2284, 115, '정말 크게 울었다. 돌아가신 어머니도 생각나고. 내리사랑의 힘은 역시 크구나.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2285, 115, '아주 어렸을 때 이 책을 읽었던 기억이 난다. 벌써 나온 지 10년이 넘었다니.... 오랜만에 다시 책을 꺼내들어야 겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2286, 115, '아버지의 헌신적인 자식사랑에 그저 눈물을 흘릴수밖에없었다. 나의 눈물샘이 이렇게 풍부한지 몰랐다. 눈물쏙빼놓는 걸작.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2287, 115, '너무 감동적이얌~ 올해들어 처음 눈물 흘려봤네요..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2288, 115, '이 책을 읽고 난 후의 나의 소감이라면..슬픔이었다... 난 이책을 읽기 전에는 이 가시고기의 뜻을 전혀 알지 못했다. 그런데 읽고 나서 가시고기의 뜻을 알게 되었다. 10살 밖에 되지 않은 어린 나이에 백혈병으로 긴 투병생활을 하고 있는 아들... 그렇게 죽어가고 있는 아들을 보며 무척이나 가슴 아파하는 아빠... 어쩌면 살아있다는 것 그 자체가 아들에겐 힘겨운 고문일지도 모른다. 하지만 아버지는 아들을 위해 모든 걸 희생하고 아들과 함께 있는 것만으로도 행복해했다. 아들의 병을 낫게 하기 위해선 골수이식이 필요했다. 그런데 더 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2289, 115, '요즘 어린이들은 읽기를 싫어합니다. 왜냐면... 책읽는 어른들을 본 적이 없기 때문일거예요. 근데 이 책은 어린이들도 잘 읽습니다. 아줌마들도 잘 읽습니다. 꼭 연속극처럼 읽히거든요. 연속극처럼 적당히 유치하고, 적당히 눈물나고. 초등학교 저학년을 위한 만화책도 있습니다. 어느 날 아들래미가 울면서 전화를 했더군요. 아빠, 보고싶어. 왜냐고 물었더니 가시고기를 읽고나니깐 아빠가 너무 보고 싶더라는 거예요. 적당히 멜로, 적당히 관조, 적당히 허구 그리고 글읽기 싫어하는 한국인을 꼬시는 감상주의.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2290, 115, '아들에 대한 아버지의 사랑을 그린 소설이다. 읽는 내내 아버지가 대단하다고 느꼈고, 그러한 아버지를 닮고 싶었다. 병원비를 마련하지 못해서 어떻게 해서든지 구해보려는 아버지의 노력은 나를 슬프게 했다. 자신의 자존심은 버린지 오래고, 신장과 각막까지 아들을 위해 버렸던 그... 왜 이렇게 멋진 아버지에게 돈이 따르지 않았을까? 부정(父情)과 돈은 반비례관계인 것일까? 무능력한 남편으로 밖에 보지 못한 옛 아내... 아들을 정말 자신보다 더 사랑하는 아버지로 왜 봐주지 않는 것일까? 현대 우리의 실정도 이러한 것 같다. 돈을 잘 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2291, 115, '내주변에는 가시고기를 안 읽어본사람은 드물정도로 거의 읽은 소설이다. 내가 가시고기를 알게 된건 주위에서 많이 읽어보길래 한번 읽어보았다. 가시고기가 드라마도 나왔다는데, 나는 몰랐다. 어쨋거나 가시고기를 읽어보면 모정이 아닌 비현실적일거 같을 정도의 부정이 엄청나다. 아이의 병을 고치기 위해 사방으로 뛰는 아버지가 안쓰럽기 까지 했다. 가시고기를 읽으면서 진정한 자식사랑이 무엇인지를 알게 된다면 좋겠다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2292, 115, '학교에서 쉬는 시간 마다 이 책 읽었던 것이 기억나네요.. 책이랑은 정말 거리가 먼 사람인데.. 친구들은 다 놀고 있는데 책에 집중하느라 떠드는 줄도 모르고 읽었어요.. 눈물 나오는 거 참으면서요.. 정말 가족의 사랑을 느낄 수 있는 책입니다.. 이 책 읽고 부모님께 잘 해야 겠다 하는 생각도 많이 했었구요.. 내용이 어렵지 않아 나이가 어린 학생도 쉽게 읽을 수 있을 꺼 같아요..^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2293, 115, '흔히 자식에 대한 사랑이라면 아버지의 자식에 대한 사랑보다는 어머니의 자식에 대한 사랑을 먼저 떠올릴 것입니다. 어머니의 자식에 대한 사랑은 주로 겉으로 드러남에 비해서 아버지의 사랑은 그렇지 아니한데서 비롯된다고 생각해요. 어머니든 아버지든 자식에 대한 사랑은 헤아릴 수 없을 정도로 깊은데 말이죠. 그 깊은 사랑이 겉으로는 주로 표현되지 않아 잘 느끼지 못할 때가 많은데, 이 가시고기를 읽으면서 그런 잊고있던 것들에 대해서 깨달음을 얻고, 느낌으로 인해서 더 큰 감동이 다가온것 같아요. &...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2294, 115, '너무 이픈 건 싫으네. 너무 슬픈 건 싫으네. 너무 지독할 만큼 애틋한 것도 싫으네. 너무 그러하니 펑펑 쏟아낼거라는 친구의 말이 무색할만큼 눈물은 적었네. 아이나마 건강해져서 그나마 그나마 다행이었네. 안그랬으면 책을 던져 버렸을지도...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2295, 115, '인상깊은 구절들 p24 "모든것은 마음먹기에 따라서 달라지는 거란다. 좋은일을 생각하면 실제로 좋은일이 생기게 마련이지." - 정말 생각은 생각뿐이다. 마음먹기에 따라 달라질수있다. p67 강아지를 좋아할수는 있어도 사랑할수는 없다. 사랑은 자신이 갖고 있는걸 다 줘도 아깝지 않은것, 목숨까지도 -사랑한다는 것과 좋아한다는것의 정의를 이처럼 간단하게 내릴수있다니,,작가분이 존경스러웠다. p98 쨍쨍한 햇살이 세상을 고구마처럼 구워버릴셈인가봐요 - 고구마처럼이란 표현...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2296, 115, '가시고기는 이상한 물고기입니다. 엄마 가시고기는 알들을 낳은 후엔 어디론가 달아나 버려요. 아빠 가시고기가 혼자 남아서 알들을 돌보죠. 알들을 먹으려고 달려드는 다른 물고기들과 목숨을 걸고 싸운답니다. 먹지도 잠을 자지도 않으면서 열심히 알들을 보호해요. 알들이 깨어나고 새끼들이 무럭무럭...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2297, 115, '실제로 가시고기는 ... 암수는 알만 낳고 떠나버린다 . 그 알을 지키는 것은 수컷이다 수컷은 알이 전부 다 부화할때까지 ... 먹지도 않고 자지도 않으면서 지킨다고 한다 . 알들이 모두 다 깨어 나오면 ... 아버지의 살점을 뜯어먹고 ................ 시체를 버리고 가버린다 . 죽어서까지 자신의 몸을 새끼들의 먹이로 주는 것이 바로 ''가시고기'' 아기 가시고기들이 또 ,, 성장해 짝짓기를 하면 ... 자기 아버지가 그랬던것 처럼 ....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2298, 115, '아들을 사랑하는 아버지의 감동적인 이야기. 자신의 몸을 돌보지 않고 아들을 위해 희생한 아버지의 사람이 감동적이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2299, 115, '과연 많은 독자들이 선택한다고 해서 그 모든 선택받은 도서들이 수많은 독자들에게 같은 양의깊이와 감동과 교훈을 줄 수 있을까..? 물론, 결코 그렇지 않다고 생각한다. 베스트셀러라고 모든 사람에게 감동을 주는 것이 아니라는 것을 여러 경험을 통해 알았기 때문이다. 나만하더라도 많은 독자들이 택한 흔히 베스트셀러로 불리는 책을 몇 권 읽어보았지만..난 매번 다른 독자들과 달리 거듭 실패를 맛보았었다. 그러한 책 중 하나가 조창인의 라는 책이었다. 2001년도부터 꾸준히 사랑을 받고 많은 독자들의 눈물을 쏟게 하며 연극...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2300, 115, '너무나 가슴아프고 가슴따뜻한 책이다. 아주오래전에 이책을 읽었다. 그때의 충격은 사람을 떨리게 했다 워낙에 눈물이 많은 사람이라 펑펑울었다. 모든사람들이 그랬을것이다. 그리고 아빠를 사랑하는아들의 모습, 내가 이책을 처음 읽었을때는 결혼전이고, 결혼후 다시 이책을 읽었을때의 감동은 너무나 따뜻하다, 요즘같이 너무나 이기적인 부모가 많은시대에 사는우리들, 다시 한번 생각해보고 반성해야 하는거 아닌가? 내아이에게도 이다음에 읽어주고 싶은책이다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (116, '코스모스', 206, 4.71, 3, 1, 9, 27, 166, 193, 9, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2301, 116, '이 책이 나온지 올해가 40년 되었다. 40년 전이면 난 국민학교 6학년. 중학생 때 이 책을 읽었더라면 지금 내 인생이 달라졌을 것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2302, 116, '관련 분야에서 가장 좋은 책... 꼭 읽어야 할 책....', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2303, 116, '‘우주를 탐험하는 인류‘라는 새로운 정체성과 내러티브를 제시한 고전', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2304, 116, '비싸더라도 양장본이 좋습니다 ~_~ 컬러거든요 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2305, 116, 'Fantastic!!그야말로 하나의 우주, 하나의 문명을 한 권에 담고 있는, 아름답기 그지없는 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2306, 116, '반드시 양장을 사야하는 몇 안되는 책. 과학적 통찰을 감성적 기술에 담다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2307, 116, '방대한 분량.. 그러나 우주에 대해 알고 싶다면 이 정도는..!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2308, 116, '또 다른 세상을 꿈꾸는 모든 이들의 경전. 이 책 덕분에 삶이 외롭지 않습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2309, 116, '우주와 별을 사랑하는 모든이. 그리고, 지구를 사랑하는 사람에게 권하고 싶다. 이 책은 과학서이자 철학서이고, 교양서이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2310, 116, '우주는 우리 인간에게 무엇일까? 이 주제만큼 인간에게 오랫동안 골머리를 썩여온 의문도 없었을 것이다. 이 사실을?반영하기라도 하듯, 우주를 바라보는 관점은 시대에 따라, 계층에 따라 그리고 사람들의 취향에 따라 차이를 보여왔다. 현대의 점성술사들은 물론이고 고대인들은 별들의 운행과 별똥별 그리고 혜성을 관찰한 후 길흉화복을 점쳤다. 일반인들의 경우, 우주를 꽤 낭만적으로 바라보기도 했다. 알퐁스 도데는 ‘별’이란 작품을 통해 별자리에 얽힌 신화를 아름답게 그려냈고, 과거 우리 선조들도 달을 바라보며 절구를 찧는 토끼를 연상...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2311, 116, '지난해부터 공룡 시대를 지나 우주로 관심을 돌리고 있는 초등 1년생인 아들에게 사준 별똥별 아줌마의 책을 내가 먼저 읽다가 옛날 생각이 나서 중고등학교 때 읽었던 코스모스를 찾아 봤습니다. 라는 곳에서 나온 1983년판이네요. 가격은 3,900원... 그때는 이렇게 작은 글씨를 어떻게 읽었나 모르겠습니다. 하지만 이?한권을 다 읽은 덕에 학교의 과학분야 수업에서 남과 다른 이해를 했던 것만은 틀립없었습니다. (시험점수와는 무관하게...) 다시봐도 훌륭한 책입니다. 요즘엔 허블망원경 등 새 기술로 멋진 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2312, 116, '코스모스에는 별이 있다 코스모스, 칼 세이건, 사이언스북스, 2004. ??지나치게 걱정이 앞섰던 걸까. 마치 물리학이나 고급 수학 교재처럼 생각했던 까닭에 코스모스를 들쳐보기까지 오랜 시간이 걸렸다. 우주를 이해하고자 하면 더 쉽고 가벼운 책으로 하면 된다고 생각했다. 그렇다고 더 쉽고 가벼운 과학책을 보았던 건 아니지만…. 어느 순간부터 과학책을 읽고자 하는 강력한 열망이 생겼다. 코로나 19 상황이 가져온 긍정적 요인이다. 이해하지 못할 신천지 종교관과 행동에 대한 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2313, 116, '기독교는 알렉산드리아 도서관 파괴로 인류 지성을 탄압하였고 아메리카 개척과 칼뱅과 루터의 종교개혁에서 인류를 학살하였다. 오늘날도 그 정신은 무신론자들을 핍박하는 미국에 살아있고 코로나19대응에 관한 사회윤리의식이 약한 한국교회에까지 이어진다.2020년 10월 3일은 내 인생에서 「코스모스」를 읽은 날로 기억될 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2314, 116, '칼 세이건의 근간인 ''에필로그''를 먼저 읽고 이 책을 읽게 되었다. 처음엔 커다란 판형과 거의 600쪽에 이르는 부피감에 압도될지도 모르지만 인문학적 소양이 풍부하며 재치 넘치는 칼 세이건의 이야기를 따라가다보면 우주와 우리, 내 자신의 기원을 찾아가는 이 여행은 즐겁기만 하다. ''우주와 나의 일체감''- 종교에서 많이 나오는 표현이다. 그런데 칼 세이건의 과학적 탐구를 따라가다 보면 그것은 어떤 신비주의도 아닌 ''사실''임을 깨닫게 된다. 우리의 몸을 구성하는 성분이 바로 ''별의 재''-초신성 폭발로부터 생기는-인 것이다....+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2315, 116, '누구나 어릴적에 한번쯤은 밤하늘의 알록달록한 수많은 별들을 올려다 보며 참 아름답고 신기하다는 생각을 해봤을 것이며, 머리가 큰 후에는 서적을 통해 헤아릴수없을 만큼 큰?우주의 크기와 역사에 경외심이 들었을 것이다.? 나 역시도 어릴적에 밤하늘의 별을?넋 놓고 바라보다 목을 삐어서 몇날 몇일 고생한 적도 있었고, 천체망원경을 사려고 돈을 한푼두푼 모았지만 엄청난 가격에 좌절을 했던 기억들이 있다. 이처럼 인간은 누구나, 혹은 우주에 대한 체계적인 지식이 없는 사람들이라도 정도의 차이는 있지만 우주에 대한...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2316, 116, '이 책이 한글판이 지금 처음 출간된건가요? 저는 이책을 이년전에 교보문고 외서 코너에서 처음 접하고 바로 샀었는데, 페이퍼백이라 가격이 10000원정도 였습니다. 영어수준도 그리 어렵지 않고, 내용도 상당히 흔미진진해서 ?영어공부하실분들은 원서로?보시는것도 추천합니다. 이 책에서 다루는 가장 큰 주제는 이 것입니다. "이 광활한 우주에 우리 말고도?생명체가 존재하는가?" 가장?진부하면서도 가장 해결하기 어려운 호기심이지요. 그 정확한 내용은 아니지만 그 방향을 가리쳐준다는 면에서...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2317, 116, '요즘책방 책읽어드립니다, 칼 세이건, 코스모스???? 이 책을 다 읽었다.최종 쪼개읽기 리뷰를 남긴 게 2월 15일이니 한 달이 훌쩍 지났음이다. 왜 이제야 완독서평을? 사실 뭘 써야 할지 몰라서다. 총 18회에 달하는 중간리뷰를 어찌나 성실하게 해버렸는지(!) 완독서평을 엄청 짧게 쓰자고 마음먹었음에도 불구하고 뭐라고 써야 할지 감도 안 잡힌다.우리는 코스모스에서 태어났고 코스모스와 멀리 떨어진 지 오래됐지만 여전히 코스모스의 일부이다. 즉, 아무리 벗어나고 싶어도 사람은 자신을 둘러싸고 있는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2318, 116, '1980년대 이런 다큐멘터리를 만들어 방영한 미국이란 나라....생각해 보면, 우주에 대한 생각이 우리에겐 너무도 미천했다.?''지구에만 인간이 있다면, 너무 많은 공간의 낭비다''라는 영화 컨텍트의 대사 처럼, 이 무더운 여름을 코스모스와 함께 했다.한장 한장 너무 쉽고도 재미있는 과학과 생물과 역사에 관한 내용으로 넘어갔다.손가락에 침을 바르면서, ...두꺼운 하드 커버에 놀랄 필요가 없었건만, 사놓고 거의 5년이 지난 시점에 읽게 되었다. 그런데, 딱 13일 만에 모두 읽었네~~~하루에 한장(chapter)씩....너무 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2319, 116, '유행 가사 중에 이런 노랫말이 있다.?~밤하늘에 빛나는 수많은 저 별들 중에서 유난히도 밝은 별이 하나 있었다네~?문득 이 책을 읽으면서 연상된 가사말이 우주 속의 지구를 대변하고 있는 듯하다.?인류의 태동 및 많은 자연의 관계, 태고적의 이들의 탄생 기원은 어디에서 시작된 것일까? 하고 전문가가 아닐지라도 한두 번쯤은 묻게 되는 질문들, 칼 세이건이 전하는? 말에 담긴 의미와 뜻을 따라가다 보니 어느새 지구라는 작은 행성이 보인다.?우주의 대폭발이 어느 순간 생겨나고 많은 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2320, 116, '그다지 과학과 천문학에 대한 지식이 없는 사람 중 한명이고(북두칠성이 어디 있는지도 모르는 사람이니까), 다른 사람들도 이런 나와 비슷한 수준이라 생각하고 있기 때문에 누군가가 과학과 천문학에 대해서 흥미를 느낄 수 있거나 쉽게 접할 수 있는 책을 추천하라고 한다면 다른 사람들과 마찬가지로 칼 세이건의 코스모스를 선택할 것 같다. 꽤 많은 세월이 흘렀음에도 불구하고 일반 교양 수준의 과학서 중에서 가장 많이 알려졌고, 여전히 그 매력을 잃지 않는 좋은 책이면서도 과학과 관련된 책은 가장 최근에 나온 책을 읽으라는 말을 살짝 의심스...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (117, '신경 쓰지 않는 연습', 206, 4.79, 1, 1, 3, 30, 171, 201, 3, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2321, 117, '하루에도 수천번 떠오르는 쓸데없는 걱정들.. 이리저리 치이고 휩쓸리지 않고 오롯히 세상을 지혜롭게 살아가고 싶다면 이말을 기억해야한다.｀인생에는 기억에 남겨할 순간이 있기도 하지만 그순간이 삶의 구심점이라는 생각은 버려라.｀', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2322, 117, '사소한 것에 신경 쓰지 않는 태도는 삶을 여유롭게 하죠. 사소한 것에 연연하지 않고 마음을 넓게 가진 대인의 면모는 용기와 연습이 필요하기에 공감합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2323, 117, '성격이 좀 예민한 편이라 매사에 신경쓰느라 피곤한데 신경쓰지 않는 법을 좀 배워야겠어요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2324, 117, '불안 걱정등 불필요한 감정에서 벗어나 지친 마음을 쉬게 하는 신경쓰지 않는 방법', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2325, 117, '어느 순간 나자신이 아닌 남이 나를 보는 방식으로 평가하게 된것 같아요. 다른사람들의 시선에서 자유로워지는 법을 배우며, 나 자신을 돌아보면 좋을것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2326, 117, '소소한 일에 담대해지기, 사소한 일에 신경 쓰지 않기가 쉽지 않지만 욕심을 버리면 대인배가 되기도 합니다. 사소한 일에 신경 쓰지 않는 것도 습관이기에 연습이 필요한 것 맞습니다. 공감 가득한 내용이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2327, 117, '예민해 온갖 것에 신경이 곤두서 있는 사람에게 꼭 필요한 책인 것 같네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2328, 117, '겉은 백화점, 대형마트인데 실상 그 속은 시골 슈퍼만도 못한 책. 전형적인 일본 도서다. 과잉 의미부여와 가벼움이 적당히 어우러진 저자 개인의 일기장 같은 책.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2329, 117, '매일매일 저한테 말하는 내용을 담고 있네요. ｀일일이 신경쓰지 마라, 쓸데없이 걱정하지 말고 단단해지는 용기를 가져라.｀같은 것요. 다른 사람의 시선을 너무 신경쓰니까 그만큼 피곤해지고 지치더군요. 쉽지는 않지만 그래도 노력해보는 것이 좋은 것 같아요. 행복해지는 방법 중 하나거든요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2330, 117, '큰 마음의 편안이 세상을 움직인다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2331, 117, '좀더 온전한 나로 살 수 있도록 그 방향성을 제시해 주는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2332, 117, '때로는 둔함이 나에게 더 이로운 영향을 미칠 수 있다는 것이 솔깃하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2333, 117, '신경 쓰이는 것들이 너무 많아서 스트레스를 받고 있는데 다스리는 법을 배워야겠어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2334, 117, '세상의 시선에서 신경쓰지 않는법을 알수있어 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2335, 117, '사회속에서 살아가기 때문에 남의 이목을 무시하고 살아갈수는 없다고 생각합니다 그렇지만 그것이 과도하게 신경쓸수록 힘들어지는 것 같아요 본인이 편하고 마음이 안정될수 있도록 편한 마음으로 생활하는게 가장 좋을것 같아요 그러기 위해서 필요한 책같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2336, 117, '남이 아닌 나를 인생의 중심으로 두는 법을 알려주는 좋은 책이네요. 다른 사람들을 배려하는 것도 좋지만 그게 지나치면 남 눈치를 많이 보는 것이 되어버리는데 이 책으로 그런 시선의 강약조절을 할 수 있을 것 같아요. 마음가짐을 편안하게 관리하는 데에 무척 좋아보여요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2337, 117, '자신의 단점을 고치고 장점을 발견 및 계발할 수 있는 책같네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2338, 117, '사소한 것에 신경쓰지 않는 것이 정말 중요하다는 것을 알게됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2339, 117, '편안한 마음을 유지하기 위한 유익한 조언서. 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2340, 117, '귀족같은 사람들은 정말 이 책을 읽어야 한다.더구나 귀족이 아니더라도 평범하게 자신이 불행하다고 생각하는 사람들도 읽어 줬으면 싶다.자신의 마음을 추스를 수 있는 방법을 배울 수 있다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (118, '공중그네', 206, 4.18, 1, 8, 31, 79, 87, 166, 31, 9);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2341, 118, '이라부의 천진난만하고 다른 사람 눈치따위는 보지 않는 성격이 멋지다. 부럽다.소설은 가볍고 재미있음', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2342, 118, '룸메 추천으로 읽은 책재밌게 잘 읽었다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2343, 118, '내 오쿠다 히데오 입문작.이책을 읽으면서 굉장히 많이 웃었던 것 같다.중학교 때 읽은 기억이지만 지금도 기억이 난다.괴짜 의사와 독특한 간호사 둘의 캐미는 정말 이 소설을 더 감질맛나게 해준다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2344, 118, '오쿠다 히데오의 발견.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2345, 118, '부산 민락동에 위치한 주책공사에서 “사장님, 재밌는 책 좀 추천해 주세요.” 했더니 추천받은 책. 두 번째 장까지는 나름 유쾌했지만 곧 글의 패턴이 보이기 시작해 점차 지루해졌다. 꼭 봐야 할 명작이냐? 그건 아닐 것이다. 하지만 오쿠다 히데오의 글에는 독자의 숨을 고르게 만드는 이상한 힘이 들어 있다. 그리고 그의 글은 그것만으로 족하다.(참고로 이라부 시리즈에서 공중그네는 두번째 순서임)', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2346, 118, '살짝 평범에서 벗어난 뒤틀림이, 상처치료에 특효약이란 걸 보여준다. 이소설은..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2347, 118, '폭소보다는 미소, 감동보다는 공감', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2348, 118, '주인공처럼 낙천적인 내가되고 싶지만... 뒷감당이 안될듯^^;', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2349, 118, '실컷 웃고 싶다면...강추', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2350, 118, '엉뚱하고 유쾌한 상상...재밌어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2351, 118, '난왜그냥그렇지...ㅇㅅㅇ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2352, 118, '신나는 오쿠다 월드로의 초대~^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2353, 118, '이라부 같은 의사가 있다면, 매일 찾아갈수 있을것 같다. 다만 주사가 문제지만..^^', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2354, 118, '오쿠다 히데오 그의 유머에 치명적으로 감염된 경로', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2355, 118, '못말리는 ''이라부''의 좌충우돌 사회적 강박증 치료기, 그 폭소의 현장을 만나보자!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2356, 118, '누구나 하나의 강박증을 갖고 있는 이 사회의 다양한 인물을 이라부라는 유쾌한 의사와 연관시켜 재미있게 풀어나가고 있다. 누구의 눈치도 받지 않고 자신만의 생각과 가치관으로 실행을 옳기는 이라부는 정말로 매력이 넘치는 캐릭터이지만, 주변에 이런 사람을 받아들일 수 있을까 싶긴 하다..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2357, 118, '웃다보면 삶의 부정적인 요소가 말끔히 해소되는 기분이다^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2358, 118, '주인공 의사는 덜 떨어진 사람 같은데 말 한마디 한마디가 환자의 마음을 꼭꼭 집어 주네요. 재미 있어요. 육감적이고 섹시한 간호사는 남자들의 희망사항 아닌가요.ㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2359, 118, '어렸을때 엄마가 밤새 읽는 것을 보고 저 책이 뭔가 싶어 읽기 시작했다. 술술 넘어가는 문장과 기괴하지만 웃기고 유쾌한 이야기들이 결국 나 역시 밤을 새게 만들었다. 몇번이고 다시 읽어도 즐겁다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2360, 118, '그동안 읽었던 일본소설이 거의 몇몇 작가에 치중해있다보니 너무 이쁜 소품적인 느낌이 강해서 한번 읽고 나면 웬지 손이 다시 가질않아 좀 멀리 했다. 그런데, 친구가 공중그네 읽어봤냐고 괜찮다고 하길래 오랜만에 하는 느낌으로 구입해서 읽어보았다. 유쾌한 소설. 중간중간 큰 웃음소리가 나올 정도로 재미난다. 누구나 한가지면에서 편집증적인 면을 갖고 있는 인간과 그것을 너무나 쉽게 해결해버리는 이라부라는 정신과의사를 통해서 삶은 다 그게 그것이지 하는 느낌도 든다. 재미난 콩트를 몇편 보고난 느낌. 연극으로 만들어도 ...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (119, '당신의 사막에도 별이 뜨기를 (출간 10주년 기념 리커버 에디션)', 206, 4.85, 1, 0, 1, 24, 180, 204, 1, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2361, 119, '하나하나 놓치기 싫은 글귀들', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2362, 119, '편지는 이제 많이 쇠퇴했지만 이메일도 일종의 편지로 볼 수 있으니 어떤면에선 살아남았다고 할 수 있죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2363, 119, '따뜻한 글귀로 위로받으며 당신의 사막, 텅빈 공간에도 별이 빛나기를 기도합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2364, 119, '고도원의 아침편지는 조용한 명상의 순간에 음미하면 좋을 구절들이죠. 위로와 힐링의 글들이기에 필사하는 동안 깊은 명상의 시간이 되기에 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2365, 119, '저의 감성을 울리는 책이네요. 벌써부터 따뜻한 온기가 느껴집니다. 멋진 글귀들이 마음에 참 와닿네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2366, 119, '아침편지에 소개 되었던 글귀들을 모아 엮은 책이라고 들었습니다. 일상의 고단함을 털고, 상처에 힐링이 되며, 용기를 돋궈주는 아름다운 글귀들을 필사하며 영혼에 자신감과 휴식을 불어 넣어주는 시간이 될것입니다. 128편의 주옥같은 글귀 중 저도 저만의 사막의 별을 찾아 봐야 겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2367, 119, '요즘 필사의 재미에 빠져 있는데요. 이번에 고도원의 아침편지를 필사 할 수 있는, 당신의 사막에도 별이 뜨기를,이라는 책이 나왔네요. 반가워요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2368, 119, '읽은책 필사는 힘들겠지만, 좋은 글귀들 필사는 처음 필사로 선택하기에 좋은것 같아요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2369, 119, '고도원의 아침편지를 직접 받아적으며 그 깊은 우리네 이야기들을 온몸으로 체감할 수 있습니다. 정말 기대되는 기획이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2370, 119, '새로운 이야기와 함께 나아가는 멋진 글귀', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2371, 119, '메마른 감성을 일깨울 수 있는 사색의 시간', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2372, 119, '고도원의 아침편지 필사버전이기에 잔잔하고 평온한 글들이 가득하네요. 아침편지의 희망적인 이야기가 오늘의 힘이 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2373, 119, '아침편지 필사로 마음에 힐링을 받을수 있을것 같아 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2374, 119, '매번 매일로 받아보던 아침편지가 이렇게 책으로 나오니 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2375, 119, '마음이 괴로운사람들에게 단순하게 느껴지는 가벼운 감동인 아니라 가슴 속 깊이 파고는 감동을 선사해줄 것 같은 책이라서 기대가 되고 많이 마음적으로 힘드신분들에게 꼭 필요하다는 생각이 들어서 많은분들에게 추천하고싶은 책이에요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2376, 119, '책제목이 너무 가슴에 와닿는 것은...힘들고 지칠때 필사를 하면서 안식을 찾고 싶어지네요~~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2377, 119, '잠시 쉬워갈 시간을 갖게 해주는거 같아요. 글귀에 눈물이 글성거리기도 하고 용기를 주기도 하고.. 참 좋아요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2378, 119, '좋은 글귀들로 힐링하고 싶네요~^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2379, 119, '요즘같은 시대엔 글의 소중함을 느끼기 힘든데요 응원이 되고 위로가 되는 따뜻한 글귀로 힐링받고 싶습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2380, 119, '좋은 문구를 보고 쓰는것 그 자체가 명상이자 치유가 될 수 있다. 하루하루 꾸준히 해나간다면 삶이 풍요로워 질것이다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (120, '키친', 205, 4.03, 2, 4, 45, 88, 66, 154, 45, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2381, 120, '따뜻한 감성의 책~ !', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2382, 120, '누군가 죽어야만외톨이가 되어야만 상실과 자아를 찾고비로소 고독을 알게되어 뭉치는이상한 인간관계를 다룬책이지만대중적인 인기를 끄는 요소와 가독성은 좋다죽음마저 안심하게 만드는 이상한 책이다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2383, 120, '표지가 예뻐서 읽었다는 리뷰를 어디엔가 남겼었는데 찾을 수가 없다. 아 슬퍼.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2384, 120, '상실에 관한 소소하고 피상적인 접근에도 불구하고 더 나은 삶을 향한 의지가 마음을 움직인다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2385, 120, '작가는 독자가 대체 뭘 느끼길 바란 걸까', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2386, 120, '인생은 담담하게 살아가는 법짧은 묘사가 뇌리에 이미지로 남는다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2387, 120, '작가의 문장이 이쁘고도 아름답다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2388, 120, '죽음 꿈 음식 치유요시모토 바나나 씨의 소설은 아직 3권 밖에 읽지 않았지만 읽은 책 중에서 제일 맘에 들어요.소설 속 캐릭터들이 매력적이라서요.에리코 씨가 제일 기억에 남아요.읽다보면 나도 모르게 머리 속에서 일드가 상영되는 듯한 느낌을 받아요. 분위기 묘사를 간결하지만 무엇을 말하', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2389, 120, '처음 읽었을 때의 충격을 잊을 수 없다. 뜨겁지 않은 적당히 따뜻한, 체온같은, 부엌의 바닥같은, 그런, 감수성.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2390, 120, '무력함과 상실감으로부터 현실 도피가 아닌 담담하게 받아들이고 치유하는 책입니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2391, 120, '치유 그 자체를 경험하게 하는 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2392, 120, '슬픔과 아픔이 요시모토 바나나의 주제라면 단연 이 책이 으뜸!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2393, 120, '몇 번을 읽어도, 매번 마음이 따뜻해지는 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2394, 120, '｀죽음｀을 소재로 하면서도 이처럼 따뜻한 느낌을 주는 책이 과연 또 있을까, 하는 생각이 들었습니다. 결코 평범하지 않은 인물들에 깊이 공감하게 만드는 작가의 능력에 그저 감탄할 수 밖에 없는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2395, 120, '나는 요시모토 바나나의 간결한 문체가 좋다 그의 오묘한 세계가... 평범하면서도 특별한 세계가....', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2396, 120, '내가 읽은 최초의 일본 소설', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2397, 120, '처음 읽었을 때나 지금이나 똑같은 감수성을 느끼게 해주는 문체', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2398, 120, '하루키의 일상 속 판타지와 일면 비슷하기도 하지만 매력은 없다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2399, 120, '요시모토 바나나의 대표작', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2400, 120, '내면을 흔드는 문장과 감정묘사가 인상깊다.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (121, '13계단', 205, 4.58, 0, 4, 9, 57, 135, 192, 9, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2401, 121, '기대가 컸을까. 막상 반전을 거듭하는 걸 보니 재미보다는 뻔하고 지친다는 생각이 들었다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2402, 121, '속도감 넘치는 전개에 앉은 자리에서 뚝딱 읽은 책일본 사형 제도의 현실적인 문제점을 잘 녹여낸 것이 흥미로웠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2403, 121, '고민된다. 별을 네개 주어야 할지 다섯개 주어야 할지. 좋다는 얘기다. 지난 번 앍은 보다 복잡하지 않지만 재밌다. 사형제도와 그에 얽힌 사람들의 복잡한 심경을 잘 풀었다. 짧고 임펙트있게 영화처럼 치고 가는 스타일이 좋다.---이 책은 ‘추리소설‘에 해당하고, 아래 글은 스포일러에 해당하여 뒤에 덧붙여 본다. 책을 읽을 사람들은 읽지 않아야 더 재미있을듯 ‘-‘--- 어둠 속에서 준이치는 마침내 13계단을 다 올랐다. 준이치는 아직일까 싶어 중간층을 통해 회중전등을 비추어 보았으나, 빛은 1층 입구까지 닿지...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2404, 121, '다카노 가즈아키 장편소설/ 황금가지숫자 13의 의미는 뭘까^^ 소설은 도입부부터 흥미롭다. 파격적인 데뷔작, 47회 에도가와 란포상 수상 작가! 사회파 소설의 대가 다카노 가즈아키 데뷔 20주년 기념작!! 영화 연출 경험, 각본가로 활동한 경험이 소설에 모두 녹아있다. 장면 전환이 빠르고 마치 영화를 보는 듯한 느낌이다.한국에 대한 애정이 많으신 작가님이다. 우와 무려 2001년 작품이라는 게 믿기지 않을 만큼 문장의 세련미!! 시대적인 감각!! 최단기간 100만 부 돌파, 심사위원 만장일치 수상 작가, 미야베 미유키 작가님이 심사...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2405, 121, '과연 페이지 터너 소설이다. 다카노 가즈아키의 작품은 오래 전 임신과 유산을 다룬 만 읽었고 걸작으로 소문이 자자한 는 ''읽고 싶은 책'' 목록에 수년 째 머물고 있다.(이렇게 리스트에 머물러 있는 책만 수백권이다. 이걸 다 읽기 위해서라도 장수해야 한다.) 은 저자의 데뷔작이다. 일본의 저명한 미스터리 소설상인 ''에도가와 란포상''을 수상했는데 당시 심사위원 중 한 명이 미야베 미유키였다. 책 뒷부분에 미미 여사의 극찬을 담은 추천사도 재미있었다.사형 집행을 앞둔 사...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2406, 121, '열세 명.그 숫자에 눈살을 찌푸린 검사는, 사형 판결 선고 이후 집행까지 절차가 몇이나 되는지를 세어 보았다. 열세 가지였다.13계단. / p.40사형이 확정된 수감자의 누명을 벗기기 위해 가석방된 전과자와 교도관이 익명의 후원가의 도움을 받아 재수사를 펼쳐나가는 이야기.사형제 찬반 논의는 귀에 딱지가 앉게 들었고 이를 소재로 한 이야기는 질리도록 많다. 사형제 관련 형법의 맹점에 대한 토의 역시 질릴만 하면 한 번씩 하게 되는, 그다지 독특한 소재는 아니지만 그럼에도 이 책이 여전히 특별한 위치에 있는 이유는 무엇일까.솔...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2407, 121, '13계단 책 뒷표지에 있는 미야베 미유키 작가님의 추천사에 홀려서 읽게 된 책. ‘도저히 신인 작가라고 믿을 수 없다. 주도면밀한 구성과 탄탄하고 이지적인 문장에 읽을 때마다 감탄사가 터져 나온다.’는 문장에서 이 작품이 궁금해졌다. 책에 빨려 들어갈 듯이 읽고 난 후, 작가님의 이력을 보고 ‘13계단’이 데뷔작이라는 것에 기함했다. 어떤 글은 읽고 나면 나도 이렇게 쓰고 싶다는 부러움이 느껴지는데, 이 책은 그런 느낌도 들지 않는다. 데뷔작이 이런 완성도면 제노사이드나 도서전에서 나온 신간인 ‘죽은 자에게 입이 있...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2408, 121, '『어느 도망자의 고백』을 읽을 때도 생각했지만 자신의 죄에 무게감을 느끼며 살아가는 사람보다 그렇지 않은 범죄자가 더 많다고 생각한다. 우리나라는 사형 집행이 멈춘 지 오래고 현재 사형수들의 악행으로 교도관들은 고통받고 있다. 나는 호계동 안양교도소가 있는 곳에서 자랐는데 범죄자를 가두는 곳이었기에 내가 그들을 대면할 일은 없었지만 이후 근무했던 한림대학교성심병원에서 안양교도소에 복역 중인 수감자들이 입원할 때 종종 볼 수 있었다. 그들은 입원 기간을 늘리기 위해 체온계를 먹기도 했고 원인 미상의 복통 그러니까 꾀병인 경우도 있었다...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2409, 121, '그간 사형제도에 대해 생각해 본 적이 있었을까 싶다. 단순히 ‘존재해야 한다’, ‘폐지해야 한다’의 논쟁을 넘어 타인으로서의 인간이 누군가의 생명을 법적으로 사라지게 만드는 결정을 내릴 수 있는지, 그리고 그 무게를 감당할 수 있는 존재가 이 사회에 있을지에 대한 관점이랄까. 다카노 가즈아키의 소설 『13 계단』은 그 질문을 피하지 않는다. 오히려 정면으로 마주하게 한다.이야기는 전과자 준이치가 가석방 후 사회 복귀를 준비하던 어느 날 예상치 못한 제안을 받으며 시작된다. 퇴직을 앞둔 교도관인 난고는 준이치에게 특별한 제안을 하는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2410, 121, '13계단 - 다카노 가즈아키-이 나라에서는 흉악 범죄의 피해자가 된 순간, 사회 전체가 가해자로 돌변합니다. 그리고 아무리 피해자를 괴롭힌들 사죄하는 사람도 없고, 책임지는 사람도 없어요. (p.109)-범죄는 눈에 보이는 형태로 무언가를 파괴하는 것이 아니다. 사람들 마음속에 침투하여 그 토대를 들어내는 것이다. (p.143)-사형 제도를 유지시키는 것은 국민도 국가도 아닌 남을 마구 죽이고 다니는 범죄자 본인이야. (p.213)-육체의 상처에만 상해죄가 적용되고, 망가진 사람의 마음은 방치되는 것입니다. (p.401)-다카노 가...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2411, 121, ', 다카노 가즈아키 #도서제공 상해 치사로 2년을 복역하고 나온 ''준이치''는 교도관 ''난고''에게 사형수의 무죄를 같이 증명하자는 제안을 받는다. 준이치는 자신으로 인해 폭싹 주저앉은 집안의 사정을 생각하고 익명의 후원자가 제안했다는 거액의 의뢰를 받아들인다. 사형수 기하라 료는 사건 당시 오토바이 사고로 인해 아무것도 기억하지 못하며, 남은 것은 공포의 계단을 오르던 기억 뿐이다. 준이치와 난고는 사건이 벌어진 위치에서 계단이 있을 만한 장소를 뒤지고 다닌다. 과연 그들은 사형수의 무죄를 밝힐 수 있을까....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2412, 121, '#도서제공 #서평단이 소설은 형벌이라는 냉혹한 구조 안에 상처 입은 개인들을 그려낸다. 이야기는 한 사형수의 누명을 벗기려는 두 남자, 전직 교도관 난고 쇼지와 가석방 중인 미카미 준이치의 중심으로 시작된다. 난고는 사형 제도를 직접 집행해본 경험을 통해 공권력의 이면을 드러내고, 미카미는 사인으로서 사적 제재와 속죄의 의미를 묻는다.예전에 일본은 사형수에게 언제 사형할지 미리 알리지 않고, 사형 당일 아침에야 통보한다는 이야기를 들은 적이 있다. 그래서 사형수들이 매일 아침 떨면서 하루하루를 버틴다고. 이 이야기를 들었을 때는 단...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2413, 121, '죄와 벌의 경계에서 인간의 얼굴을 찾다얼마 전, 한 기사에서 일본의 사형 제도에 대해 읽었다. 극악 범죄자의 사형을 집행했다는 내용이었는데, 마침 이 책 『13계단』을 읽던 중에 마주친 소식이어서 오묘한 기분이 들었던 기억이 난다. 다카노 가즈아키 작가님의 대표작인 『13계단』은 단순한 미스터리 소설이 아니다. 사형 제도라는 현실의 심연을 거침없이 응시하며 정의란 무엇인가, 인간은 과연 바뀔 수 있는가 하는 질문까지 답하려 하는 사회파 미스터리의 정수이다.이야기의 중심은 상해 치사죄로 복역하고 출소한 청년, 미카미 준이치이다. 사회...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2414, 121, '다카노 가즈아키_ 13계단상해 치사죄로 2년형을 선고 받은 후 3개월의 가석방을 받고 사회로 나온 미카미 준이치, 그리고 28년의 교도관 생활에 지친 난고. 둘은 익명의 독지가가 거액의 현상금을 걸고 한 사형수의 무죄를 밝혀달라는 조사 요청에 응한다. 사형수는 강도 살인 사건의 가해자이나 사건 당시 교통사고로 상황을 기억하지 못한다. 난고와 준이치는 저마다의 사연으로 사건 해결에 집중한다. 난고는 일본의 사법체계에 회의감이 들어 자신의 손으로 무고를 밝히고 싶었고, 준이치는 가족이 본인의 배상금을 내느라 경제적인 어려움을 겪고 있어...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2415, 121, '* 본 도서는 서평단 활동을 통해 황금가지출판사(@goldenbough_books) 에서 도서를 제공받은 뒤 주관적 의견으로 작성하였습니다. 13계단은 출간된지 벌써 20년이나 된 추리소설이다. 그러나 오래된 책이라고는 믿기 힘들 정도로 추리소설의 재미와 감동을 선사한다. 전과자와 전직 교도관이 한 팀을 이루어 사형수를 구해내기 위해 진범을 추적하는 소설이다. 반전에 반전을 거듭하는 이야기 전개도 물론 인상깊었다. 그러나 이야기를 풀어내는 과정에서 전과자들이 다시 사회에 적응하기 위한 과정이나, 과연 사형 제도가 옳은 것인지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2416, 121, '이게 데뷔작이라니... 이 작가는 천재임이 틀림없다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2417, 121, '매우 놀라운 소설이었다. 작가가 슬며시 놓아둔 소소한 떡밥들을 남김없이 회수하고, 마지막까지 깔끔하게 마무리 지었다. 일본 사법부에 대한 비판적인 시각과 흥미진진한 이야기는 독자를 시간 가는 줄 모르게 만든다. 저자의 다른 책도 찾아봐야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2418, 121, '근래에 만난 최고의 작가 ^^ 다카노 가즈아키가 신인상을 받은 작품인데, 첫 작품부터 대단했구나 !!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2419, 121, '대단히 대단한 책이 아닐 수 없다! 병렬적으로 보이는 모든 사건들이 한 목표 지점으로 달려가는 서술의 치밀함이 일품이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2420, 121, '사람의 기억이란 참 정확하지 않다..흑백으로 나눌 수 없는 게 인생인듯~', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (122, '영어 발음의 신', 205, 4.85, 0, 0, 3, 24, 178, 202, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2421, 122, '파닉스가 영어발음교정에 훌륭하지 않다는 사실을 알려줍니다. 이책을 통해 자신에게 맞는 훈련법을 찾아보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2422, 122, '영어발음이 늘 고민이었는데요. 특허받은 칩도 있는 특별한 발음 교재네요. 아이들에게 시도하고 싶은 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2423, 122, '좀 더 자연스러운 영어 발음 교정을 위한 보고 듣고 따라하기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2424, 122, '음치도 네이티브 스피커가 될 수 있을까요?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2425, 122, '영어공부를 다시 시작하며 회화 뿐 아니라 발음교정까지 신경쓰고 있는차에 특허받은 영어발음 훈련법 [영어 발음의 신] 책을 알게 되어서 기쁘네요. 열심히 발음 교정도 하고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2426, 122, '제일 어려운 말하기를 공부할 수 있어서 정말 좋네요. 발음이 좋아야 외국인도 제 말을 이해 할 수 있고 저도 네이티브의 영어를 더 잘 알아들을수 있어서 발음교정이 정말 필요했는데. 이 책을 통해서 발음법을 알게되어서 좋네요. 강추!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2427, 122, '정확한 발음으로 차근차근 흐름을 이어가자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2428, 122, '원어민처럼 제대로 된 그럴듯한 발음까지 된다면 딱딱한 영어도 더 재밌게 배울 수 있을 것 같습니다.저자가 직접 녹음한 파일까지 있어 큰 도움이 될 것 같아요. 강력 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2429, 122, '영어 발음에 대한 자세한 비법을 알려주는 책이기에 발음에 자신없는 이들에게 도움이 될 책입니다. 영어 발음에 크게 신경을 쓰지 않았는데도 이 책을 보니 저도 발음의 신이 되고 싶어집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2430, 122, '어학연수없이 영어를 공부하는 사람들에게 좋을 교재같아요 영어의 말하는 방법, 리듬 등 영어공부하는 사람들이 자신의 발음을 어떻게 향상시킬수 있을지에 대한 고민해결 교재가 될수 있을것 같네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2431, 122, '이렇게 하면 될까?란 생각으로 했었는데, 신기합니다! ㅎㅎ 뭔가 더 자신감이 생기는 것 같아요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2432, 122, '영어발음때문에 놀림받으면 발음 좀 나쁘면 어때서하고 그냥 넘어갔는데 영어발음이 중요한 거였군요.저자가 가르쳐주는 정확한 영어발음법을 익히고 음성강의를 통해 충분히 연습해서 이제는 한국식영어발음을 벗어나고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2433, 122, '혀만 굴린다고 되는 발음이 아니라 올바른 영어 발음 교정을 도와주는 책이라서 기대됩니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2434, 122, '영어를 기피하는 이유 중 하나가 특유의 발음 때문에 어색한 느낌이 큰데 이 책으로 그런 부분을 좀 커버해줬으면 좋겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2435, 122, '올바른 영어 발음 교정을 위해서 쉽고 체계적으로 정리해놓은 책이라 많은 도움이 될거 같네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2436, 122, '보고 배우는 것도 좋지만 결국 중요한것은 연습.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2437, 122, '항상 말하기에 자신이 없었는데, 이 책이면 많은 도움이 될 것 같네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2438, 122, '발음칩이 있는 것이 신기하네요. 원어민과 영어로 어설픈 대화하며, 라쿤을 이야기 하려고 이리저리 얼마나 발음하고 설명을 해봤는지 그 때 발음에 대한 중요성을 매우 크게 느꼈어요. QR코드로 발음도 제공하니 단어 하나 더 외우는데 급급하지 않고 직접 들을면서 책 보면 발음교정에 도움이 될듯함', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2439, 122, '이왕이면 상대가 잘 알아듣기 좋은 발음을 사용하는 것이 좋겠지요. 직접 고안한 방법까지 있다니 궁금해집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2440, 122, '자신감 회복과 재미있게 공부하는 정확한 발음교정을 통한 자존감 상승', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (123, '난장이가 쏘아올린 작은 공', 205, 4.5, 0, 0, 20, 63, 122, 185, 20, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2441, 123, '책을 여러 번 읽는 걸 좋아하지 않는데두번 읽은 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2442, 123, '모르는것, 보고싶은것만 보는 것은 죄다. 이면을 알것, 지금도 이어져가고 있고 투쟁하고 있는 그들, 우리.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2443, 123, '출간된지 몇십년이 흘렀지만 여전히 대한민국이 주목하는 책. 이 시대의 난쟁이는 어디에든 있다. 작은 공은 무력하지만, 이 시대는 그것을 무력하게 보고만 있을텐가.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2444, 123, '난장이, 꼽추, 앉은뱅이 : 우리들 자화상. 시대와 형식은 변했어도 내용은 마찬가지. 삶이 고통.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2445, 123, '소설을 ''본다는 것''에 대한 내밀한 각도를 제시해준 책입니다. 후에도 계속 회귀되어야 할 걸작입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2446, 123, '그냥 인생에서 제일 좋아하는 소설이고 완벽한 소설이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2447, 123, '이거랑 선생님이 좋아요랑 괭이부리말아이들, 꼭 소장해서 갖고 싶은 책들입니다 ,.학교 도서관에서 빌려서 읽었는데 정말 난쏘공은 정말 안타깝고 현시대도 반영한 것 같아서 슬펐어요. 한국인이라면 읽어야할 책이라고 생각합니다. 나중에 읽으면 더 의미가 커요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2448, 123, '기억 속에서, 현실 속에서 영원한 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2449, 123, '이거 안 읽으면 고등학교 졸업시키지 말아야 함. 너무나 비극적이고 아름다운 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2450, 123, '현대 세태에서 이 책은 산업화 이후의 모습을 보여주고 있다. 지금의 세상, 시대에는 산업화 이후 정보화의 시대를 보여주는데, 그 이전의 시대를 절대 잊어선 안 된다고 생각한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2451, 123, '오래전에 읽어 디테일은 물론이고, 기억나는 부분도 거의 없지만... 이 글을 뿌리삼아 쓰려진 글을 읽으니... 마음 한켠이 허해진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2452, 123, '누구나 아는 제목!!(대입준비에 나오기에) 하지만 어렵다!! 책의 배경인 70년대와 변함없는 사람들의 고통과 슬픔에 슬퍼지고 읽을수록 이를 꿰뜷어본 작가님의 통찰력에 고개가 숙여진다 그래서 아직도 사랑받는 이유가 있다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2453, 123, '지금도 유효한 가슴 아픈 이야기!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2454, 123, '문학이 결코 나약하지 않음을 일깨워주는 책.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2455, 123, '80년대를 그린 책이 아직도 현실을 관통하고 있다는 사실이 서글프다. 시대를 넘어 읽히는 책을 고전이라 부른다면 이 책이 현대사의 그림자를 그린 고전이 아닌가 생각한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2456, 123, '이 책이 읽히지 않는 시대를 열망하는 마음으로.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2457, 123, '『전태일 평전』(조영래,1983)과 『투명인간』(성석제,2014)의 다른 이름, 『난장이가 쏘아올린 작은 공』(조세희,1978)', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2458, 123, '가슴 아프다. 이것은 소설이 아니다. 어른들의 현대사다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2459, 123, '사회가 너무 더러워서 짜증나게 되는 소설. 별 네개짜리.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2460, 123, '마음 아픈 이야기들', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (124, '스탠퍼드식 최고의 수면법', 204, 4.81, 1, 0, 4, 27, 172, 199, 4, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2461, 124, '왜 스탠퍼드인가? 저자가 스탠퍼드대 수면연구소 소장이기 때문이다. 30년간의 연구결과가 정리됐다. 오래 잘 수 없다면 짧은 시간이라도 푹잠 자야 할 텐데... 수면에도 골든타임이 있는데, 이를 도와주는 것이 ‘체온과 뇌’라고 한다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2462, 124, '잠들기 전 반복했던 나쁜 습관을 없애고 몸을 잠과 가장 가까운 상태로 만드는 방법을 구체적으로 알려주는 이책을 통해 하루의 피로를 확날려버리는 올바른 수면법을 배울수 있을것 같습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2463, 124, '잠을 잘 자고 일어난 다음날은 정말 하루종일 몸상태도 좋고, 머리회전도 달라지더라구요. 한국인들 잠을 너무 적게자요! 수면법 제대로 알고 실천해보고 싶네요! :)', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2464, 124, '병원에 입원한 환자들을 보면 숙면을 못 취한다.결국 잠이 얼마나 중요한지의 반증이다.건강한 사람은 잠의 중요함을 다시금 느끼게 해주는책인 것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2465, 124, '하나씩 시도해보니 제 삶이 변화하고 있다는 생각이 듭니다. 잠에 대한 최신 연구를 통해 상세히 알려주십니다. 황금시간을 최대한 활용해보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2466, 124, '어떠한 수면이 인생을 많이 바꾸어놓을수있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2467, 124, '적게 자도 피곤하지 않는 수면법을 찾고 있었는데, 잠을 잘자는 방법, 잠의 질을 높이는 방법을 알려준다고 하니 좋은 것 같아요. 숙면을 결정짓는 황금시간 90분의 법칙을 무엇인지 빨리 만나보고 싶네요!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2468, 124, '푹 자고 싶은 사람에게 정말 좋은 해결이 되네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2469, 124, '‘적게 자도 피곤하지 않은 90분 숙면의 기적‘이란 부제가 눈길을 끕니다. 이 무척 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2470, 124, '따라하기 쉬운 방법들이라는데 저도 숙면취하는데 도움이 됐으면 좋겠네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2471, 124, '잠의 양이 아니라 잠을 올바르게 자는법과 잠의 질에 대하여 좋은 내용들이 저술되어 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2472, 124, '잠의 양이 아닌 어떻게 자느냐에 대한 깊은 성찰', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2473, 124, '그래서 잠이 보약이라고 하죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2474, 124, '실제 사례를 통한 설명이 나도 해볼까 하는 의욕을 고취시킨다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2475, 124, '저는 이 책이 단순히 수면법을 알려주는 책인줄 알았는데요, 읽다보니참으로 놀라운 인간의 몸에 관해서 알게 되어서 유익했어요. 특히 체온과 뇌의 상관관계,엄밀하게 말하면 체온이 우리의 인체 상태를 결정짓는다고 해도 과언이 아니라는 사실이 참으로놀랍더라고요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2476, 124, '숙면을 취하는 최고의 수면법..궁금하고 기대됩니다~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2477, 124, '무조건 많이 자는 것이 아니라, 현실적인 수면의 방법을 가르쳐주네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2478, 124, '질 좋은 잠이 필요해서 더 공감이 갑니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2479, 124, '만성피로에서 벗어나 제대로 된 숙면이 되기를 기원하며 읽어봅니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2480, 124, '불면증으로 고생하는데 도움이 되겠네요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (125, '우리와 당신들', 204, 4.66, 0, 1, 5, 57, 141, 198, 5, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2481, 125, '우리 모두는 착하거나 나쁘거나 둘 중 하나가 아니라 회색이라는 것.개별적 존재들이 우리로 뭉쳐지면 의례 분위기에 쏠려 잔인해 질 수 있다는 것.소설 속 배경이 한국이였다면 마을을 뜨는 자, 남는 자가 바뀔 수도 있었겠다란 생각에 마야를 응원하게 됐다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2482, 125, '책 자체는 경이로울 정도로 좋았는데 막상 책이 끝나는 순간 이어져 자동적으로 읽게된 역자 후기의 수준이 너무 낮아서 여운을 확 깨게 된다. 소설에 대한 개괄적인 설명과 핵심 사건에 대한 확장적 해석, 여운을 주는 마무리를 기대하고 있었는데 ‘덕밍아웃’ 운운하는 중학생 독후감 수준의 글이..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2483, 125, '우리는 모두 견디고 있다. 심지어 리샤르드 테오조차도. 모든 선수가 그러하듯, 모든 사람들이 자기만의 악마와 싸우고 있다. 그래도 견뎌야 할 지라도 이야기가 있는 현실은 견딜 수 있다. 이야기를 만들 줄 아는 이 작가가 다음 번엔 또 어떤 이야기로 날 울릴 지 기대된다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2484, 125, '내 인생의 한권의 책이라고 말할 수 있어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2485, 125, '우리라는 의식의 나쁜 모습을 적나라하게 잘 보여주고, 그럼에도 불구하고 혼자가 아니기 때문에 각자의 문제를 차근차근해결하는 모습도 천천히 나와서 내 주변을 다시 돌아볼 수 있는 소설이다. 그리고 각자의 인물을 파고들면 그 매력을 제대로 느끼는 소설이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2486, 125, '다른것에 대해서 생각해볼수있었어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2487, 125, '전작인 베어타운 만큼 흥미로운 작품.커뮤니티 내에서 발생한 사건과 그로 인한 고통이 어떤 영향을 미치게 되는지를 같이 살펴보게 된다.받아 쥐면 두툼한 두께의 책이 부담스러울지 모르지만 쓱, 읽혀 내려간다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2488, 125, '소박한 마을의 아름다운 이야기 ..대단히 잘쓴 소설...그런데 전 이분 생각엔 도무지 공감하기가 힘드네요재미있게는 읽었습니다.앞으로 더 나올거 같은데...후편 기다리고 있어요..일케 끄는데 언젠가는 이겨야 하지 않을까요..하키~~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2489, 125, '베어타운 그 다음 이야기!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2490, 125, '알라딘 통해 구매하진 않았지만 추천하고 싶은 책이예요.이 유명한 작가의 소설을 저는 처음 접해봤는데, 괜한 명성이 아시구나 싶네요. 이전 작품들도 읽어보고 싶어졌어요.현실을 날카롭고도 예리하게 바라보는 작가의 시선이, 때로는 분노케도 때로는 뜨끔하게도 하는 이야기들로 마음을 때립니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2491, 125, '역시 나만 좋은게 아니였네요.아픔과 성장, 감동과 슬픔.. 읽는 내내 정말 다양한 감정을 경험할 수 있는 책이였습니다. 조금 긴 책이였지만 어느 한순간도 지루하지 않았습니다. 무엇보다 주인공과 같은 아픔을 격은 사람들의 마음을 조금이라도 더 이해하게 되는 경험이였습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2492, 125, '어린시절 폭력과 술에 빠져사는 아버지 밑에서 자란페데르는 수비라는 사람을 만나 하키를 배워실력을 쌓고 유명선수가 된다.그후 베어타운에 이사와서 하키 감독을 맡지만팀의 해체 위기에 몰린다.자신의 딸이 팀원에게 성 폭행당해 마을을 떠난다.그후 마을사람들의 상처치유 과정', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2493, 125, '[오베라는남자] 로 처음 접하고서 프래드릭 배크맨의 책을 믿고보게되었다.우연한 기회로 독서모임을 통해 서평단으로 받게된 이 책,벽돌책같이 두꺼운분량에 살짝당황했지만 읽다보면 배어타운의 주민이되어 어누돗 감정이입이되어있다 몰입도,가독성은 물론 인간의 심리표현조차도 감탄하게된다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2494, 125, '구매는 하지않았지만 한 이벤트의 참여보상으로 이 책을받아 읽게되었습니다. 전작 베어타운을 읽지 않은상태에서 읽는 후작이었는데, 무언가 우중충하고 동결된듯한 마을의 모습과 그 안에서 다시금 일어나는 불공평한 일들이 읽는 내내 답답하고 집중되게만들었네요. 재미있게봤습니다/', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2495, 125, '우리와 당신들우리와 당신들이라고 구분짓고 행동하는 책속의 등장인물들~우리라고 똘똘뭉쳐 구분짓다가도 어느새 우리만이 아니라는걸 다시 깨우치게 된다~마야의 말중에 《우리는 생존자야》라는 말이 그상처에서 자신을 구해낼수 있는말이었음을 공감한다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2496, 125, '책 두께는 중요하지 않았다.어느순간 베어타운에 빠져 들어 시간이 날때마다 베어타운으로 마실가는 기분으로 읽었다.영화를 보는듯한 전개와 잔잔히 읽히는 글 속에 사랑,절망,상처,배신,아픔,폭력들이 아이스하키라는 스포츠와 묶여있다.단순한 스포츠를 품은 베어타운은 단순 하기만 하지 않았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2497, 125, '베어타운은 복수심에 읽었지만 우리와당신들은 가족의 중요성을 무지무지 느끼게 하는 책이였습니다살아가면서 진심으로 행복을 느끼는 순간은 몇번이나 될까', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2498, 125, '우리와 당신이라는 제목의 우리는 하나로 뭉친 한편인것 같다는 생각이 들지만 우리라고 하는 베어타운에도 엄연하게 권력과 돈과 사랑과 가족의 문제와 스스로의 문제로 인해서 허우적 거리는 수많은 갈등이 있습니다. 베크만의 소설은 처음 읽었습니다.근데 재미까지 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2499, 125, '복잡다단한 삶의 전면들을 등장인물의 심리와 행동에 대한 치밀한 묘사를 통해 드러낸다. 쉽게 읽히면서도 뛰어난 통찰력억 가끔 책을 놓고 생각하게 되는 소설.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2500, 125, '개자식들 앞에서 울지 마요 벤이 선배무슨 수로 견뎠니? 지난봄에....그녀가 그를 기다린다기다려주는 누군가가 있어서 행복하게 견뎌내고 있음을 안다나도 그 누군가가 되고 있을까', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (126, '오페라의 유령', 203, 3.94, 3, 12, 44, 80, 64, 144, 44, 15);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2501, 126, '오페라의 유령은 정말로 존재했다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2502, 126, '#1. this is not a lovesong, 이건 사랑 노래가 아니야... 이 이야기는 사랑에 대한 이야기이면서 사랑에 대한 이야기가 아닙니다. [오페라의 유령]에 대한 가장 흔한 오해가, 추악한 외모를 가진 불우한 사나이 - ''오페라의 유령'' 즉, 팬텀과 아름다운 프리마돈나 크리스틴의 사랑이야기라는 생각이지요. 하지만, 이 이야기에 대해 조금만...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2503, 126, '오래 전에 영화를 봤다. 그 유명하다는 뮤지컬로 봤으면 얼마나 좋았을까, 하지만 영화도 나쁘지 않았다. 첫 장면에서부터 나는 헉, 하고 빨려들어갔으니까. 영화를 보고 그 아쉬움을 아마 책으로 달래보겠다며 책을 샀던 것 같다. 영화가 먼저였는지, 뮤지컬이 먼저였는지, 원작이 따로 있는지 그건 잘 모르겠다. 영화를 봤는데 책이 있었고, 그래서 읽어보려 했었던 것 같다. 한데 언제나 그렇듯이 읽겠다고 하고선 책꽂이에 얌전히 꽂아두었다. 근데 그 책이 새로 나왔다(-.-). 이.럴.수.가!! 이번 주부터 25주년 내한기념 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2504, 126, '노란방의 비밀로 유명한 가스통 르루가 오페라의 유령의 저자였다니..미처 몰랐습니다. 오페라의 유령은 뮤지컬로 유명한 런던에서도 가장 비싸고 유명하며 표를 구하기 어려운 것으로 명성이 높죠. 오페라의 유령에 대한 내용은 사실 많이 공개가 된 편입니다. 기가막힌 외모때문에 숨어사는 오페라의 유령과 그가 사랑하는 여성. 거기에 어린 시절부터 그녀를 사랑해온 남자. 이 슬프고도 아름다운 사랑이야기가 웅장한 음악과 함께 전편을 감싸는, 흥미진진한 내용입니다. 한가지 조금 아쉬웠던 것은 번역이 매끄럽지 않은 부분이 군데군데 보였다는 것입니다....+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2505, 126, '끊임없이 재생산되고 있는 컨텐츠 중 하나가 오페라의 유령이다. 당시 프랑스의 문화,예술, 그리고 사람들의 모습을 담고있는, 그러니까 한 시대가 통으로 보이는 작품일 것이기 때문이다. 그리고 로맨스와 미스터리를 아우르는 이야기는 모두의 흥미를 끌기에 충분하다. 다시 오페라의 유령 뮤지컬이 시작된다. 25주년 기념 내한공연이라 더욱 뜻깊다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2506, 126, '우선 이 책 얘기를 하기 전에 이 책의 번역에 대해 간단히 얘기하고 싶다. 우리는 흔히 오류를 범하게 되는데 외국어를 잘하는 사람은 번역도 잘 할 것이라는 생각을 한다. 왜냐하면 상당 수준의 외국어 실력을 갖추지 않고서는 책-그것도 문학서-을 번역하는 것은 어려운 일이기 때문이다. 그러나 번역을 잘하는건 외국어를 잘하는 것 만큼이나 한국어도 잘해야 하는 것이라는 것을 뼈져리게 느꼈다. 이 책 군데군데 보이는 어색한 표현은 정말 내가 오페라의 유령에 대해 기존에 가지고 있던 호의적인 생각을 완전히 무너뜨렸기 때문이다. 또한 이 책은 ...+ 더보기', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2507, 126, '이책은 얼마전에 다읽었다. 엊그제 쯤에;....처음에 책을 보고 이 두꺼운책을 언제 다읽을까 라는 생각이 앞섰다. 절친한 친구가 정말 재밌다고 해서 읽어봤다. 처음에 추리소설 이라고 했는데. 다 읽어본 지금은 심정은 전혀 그런것 같지가 않다. 읽는데는 (끝에가서는 정말 대충대충 읽어서;;;) 일주일정도 걸린것 같다. 학교 아침자습시간에만 읽어서 그런지-_- 어쨋든, 추리소설이라면 밀고 당기는듯한 그런 아슬아슬함과, 궁금함에 잠도 못잘만큼 그정도라면 정말 재밌다는 말이 절로 나올텐데..... 이건 정말. 끝까지만 보자는 심정으로 봤다...+ 더보기', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2508, 126, '미와 추의 진실. 사랑과 집착과 광기의 극명한 대비. 그리고 끝끝내 이루어질 수 없었던 애정의 비극적 최후. 이런 것 때문에 ''오페라의 유령''은 더 인상깊게 남아 있는지도 모르겠다.이 책은 단순한 공포소설, 또는 추리소설이 아니다. 또한 단순한 애정소설도 아니다. 둘 중 어떠한 갈래를 택한다 하더라도 깊은 모순이 남는다. 뭐라 형언할 수 없는 복잡다단한 요소들이 섞여 있는 것이다. 만약 지하 세계의 에릭이 천상의 크리스틴과 맺어졌더라면 ''사랑의 인내''와 같은 주제가 된다던가, 단순한 연애소설로서 끝났을지도 모른다.천성적으로 기괴하고...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2509, 126, '비극적인 운명의 슬픈 사랑 이야기. 흔히, 오페라의 유령을 두고 이렇게 말합니다. 불쑥, 이런 질문을 던지고 싶습니다. 여러분은 운명을 믿습니까? 아니, 믿어본 적이 있습니까? 바로 지금, 당신의 머릿속에서 떠오르는 그 사람, 운명이었습니까? 여러분의 대답을 알 수는 없지만, 오페라의 유령이 어떻게 대답했을지는 압니다. 오페라의 유령, 에릭은 운명을 믿었습니다. 바로, 크리스틴 디에가 그 주인공입니다. 운명이 있다면, 그것을 예감하는 순간은 언제일까요? 소설은 그 ‘순간’이 언제였는지 알려주지 않습니다. 이미 에...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2510, 126, '이 책을 읽고 난 뒤 한마디로 실망 그 자체였다. 책 표지가 영화의 이미지여서 아마 영화를 보고 난 뒤 감동 먹으신 분들은 그 때의 감동을 떠올릴 것이다. 나 역시도 그랬다. 하지만 읽다 보면 짜증난다. 소설에서는 로맨스 보다는 미스터리 형식에 초점을 맞췄는데 반해 영화는 로맨스 그 자체이기 때문이다. 미스터리 형식이다 보니 아무래도 로맨스와는 거리가 멀지 않는가 하고 생각한다. 특히 페르시아 안의 이야기.. 정말 비추할 부분이다. 지루할 뿐만 아니라, 영화 오페라의 유령에 나오는 눈물이 날 정도의 낭만적이거나 ...+ 더보기', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2511, 126, '''에릭''이라는 이름을 들이시면 대부분의 사람은 신화의 ''에릭''을 연상할지 모르겠네요. 저는 신화의 ''에릭''이 아닌 오페라의 유령 ''에릭''이 먼저 떠오른답니다. 그 만큼 이 책이 저에게 깊은 인상을 주었던 것은 사실이예요. 음악이 좋아서, 책을 선택했고 그 다음 영화를 보게 되었답니다. 영화를 볼때쯤 이 책을 읽은지가 꽤 흘렀던터라 영화를 본후 다시 이 책을 읽었어요. 솔직히 책과 영화 둘중에 어느것이 좋으냐고 물어보신다면... 재미면으로 볼때는 영화가 훨씬 좋았습니다. 오페라 무대가 배경인 만큼 영화에서는 책에서는 느낄...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2512, 126, '영화나 소설을 바탕으로 연극이나 뮤지컬을 관람하는 경우가 많아지고 있습니다. 경우에 따라서는 스토리의 극적효과를 배가시키기 위하여 스토리를 보완하기도 하고, 스토리가 지나치게 길어 줄일 수도 있어 원작을 읽어야 쉽게 이해되는 경우가 많습니다. 도 그랬고, 때도 원작을 미리 읽은 덕분에 영화를 제대로 이해할 수 있었던 경험이 있습니다. 뮤지컬 은 1986년 영국에서 초연된 이래 전 세계 27개국 145개 도시 공연, 1억 3천만 명...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2513, 126, '추남은 미녀를 원한다. - 물론 모든 남자는 미녀를 원하겠지. - 정정하자면, 추남도 미녀를 원한다. 하지만 그의 사랑은 이뤄지지 못한다. ''미녀와 야수''에서 야수가 야수의 탈을 벗지 못했으면 과연 그들의 사랑이 완성됐을지. 오페라의 유령은 왕자로 변하지 못했기에 크리스틴에 대한 그의 사랑은 미남 자작에게 양보(?)되는 운명은 어쩌면 처음부터 당연했던 결과였다. 흉측한 외모의 ''오페라의 유령''의 삐뚤어진 성격은 어디서부터 왔는가. 결국 그의 흉측한 외모를 두려워하고 비웃었던 사람들의 시선에서부터 출발하여 에릭 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2514, 126, '‘오페라의 유령’, 이 책을 몇 번을 읽어도 만족하는 건, 화려한 오페라하우스의 지하에 있는 미로 같은 길, 안개 속의 검은 호수, 벽을 통해 들려오는 마력적인 목소리, 의문의 사건들과 긴장감 그리고 사랑… 그것 때문이 아닐까. 대학교에 다닐 때 처음 만난 후, 종종 읽고 있다. 이번에 뮤지컬 개봉한다는 소식에 읽었는데, 역시 새롭고 감동적이다. 화려하면서도 애틋한 그 무엇… 이 소설이 아니면 언제 또 만나볼 수 있을지. 재정 때문에 뮤지컬을 볼 일은 없을 것 같다.하지만 난 괜찮아....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2515, 126, '-부제: 어장관리녀 크리스틴과 음악의 신 에릭, 그것이 알고 싶다!-내가 처음 만난 ‘오페라의 유령’은 적당한 그림과 큼지막한 글씨가 함께 들어있는 얇은 학생용 책이었다. 화려하고 큰 무대 위에 서 있는 단역 배우에서 프리 마돈나로 거듭난 크리스틴의 운명은 얼마나 부럽기만 했는지. ‘유령’이라는 신비한 존재 덕분에 음악적으로 더 많이 성장...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2516, 126, '이 책은작년 크리스마스에 외숙모가 수주신 책었는데..이 책을 다 읽은것은 몇일도 안되었다..;처음에 워낙 유명한 책이라서 읽어볼까 생각도 했지만 사전같이 책이 너무 두꺼워서 그럴 엄두가 안났다그리고 설날 연휴에 이 책을 친구에게 빌려줬는데친구가 재미있다고 그래서 그 때에도 읽어볼까 생각 해봤지만다으로 미루다가 결국 몇일전에 읽었다 하루만에 다 읽기는 했지만꽤 재미있는 책이었다책을 많이 좋아하지 않는 나로서는 꽤 재미있다는 생각이 다른사람은 아주 재미있다고 느껴질 것이다마지막장면이 인상적이었는데..오페라 유령에게 잡혀간 크리스틴 다에...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2517, 126, '친구들이 읽고 재미있다고들 해서 한 번 읽어 보았다. 언젠가 비디오로 본 영화의 내용과 비슷하단는 친구들도 있고...크리스틴 다에 라는 오페라 여가수와 그를 사랑하는 라울. 그리고 역시 크리스틴을 사랑하지만 흉칙한 유령의 모습을 하고 있는 에릭이라는 오페라의 유령 사이에 벌어지는 흥미진진한 갈등을 그리고 있는 책이다. 밤에 혼자서 책을 읽다보니 섬뜩한 느낌 마저 들었는데 크리스틴의 고뇌와 그녀를 사랑한 두 남자의 간절한 마음을 느낄 수 있었다. 라울은 그녀를 어릴 적 부터 좋아 했지만 왠지 그녀는 항상 그의 범위에서 벗어 난 듯 한...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2518, 126, '난 이책을 사서본건 아니고 친구가 빌려줬다. 너무 두껍고 두께가 정석과 비슷해서 부담스럽긴 했지만 그래도 유명한 책이니까 한번 보는게 괜찮을듯 싶어서 읽게 되었다.생각보다 읽는데 그리 오래 걸리진 않았다. 아마도 너무 지겹다 보니까 내가 군데군데 그냥 넘겨 읽었기 때문일까? 아무튼..프랑스 소설은 졸리다는 강박관념에 사로잡혀서 인지 실제로도 지루한 소설인지는 몰라도 정말 읽기에 괴로웠다;. 아무리 유명한 책이라고 해도.... 어떻게 이런 책이 인기가 있을까? 라는 생각을 하게될 정도였다. 그렇지만 어려운책일수록 명작이 많다는 말도 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2519, 126, '오페라의 유령... 유명하고. 베스트셀러이며 한창뜨고 있어서 인터넷으로 구입하게 되었다. 처음 책을 접했을때 책 모양도 이뿌고 해서 정말 맘에 들었다. 그런데 읽다보니 엄청난 상상력이 필요하다는것을 절실하게 느끼게되었다. 아직 만 16세인 내가 일기에는 좀 책이 지루하고 무겁다는 사실을 알게되었다. 그리고 뒤로 갈수록 내용이 계속 반복되고. 사람이름들도 도통매치가 되질 않았따. 그래서 도중에 읽다가 말았습니다. 1~2년 후에 다시 그 책을 펴볼 생각이다. 그때쯤이면 아마 제대로 읽을수 있을지가 의문이다. 어째튼 읽으면서 좀 지루하고...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2520, 126, '뮤지컬 ''오페라의 유령''의 명성은 익히 널리 알려져 있다. 지난 83년 이후 전세계적으로 큰 흥행을 거둔 뮤지컬의 원작이 바로 이 책이다. ''오페라의 유령''은 파리의 오페라 극장을 배경으로 일어나는 일련의 괴기하고 기이한 사건을 중심으로 이야기를 풀어가고 있다. 사건의 중심에 서 있는 라울과 크리스틴 그리고 오페라의 유령. 이들이 전개하는 사건들은 독자들을 책 한가운데로 빨아드리고 있다.''오페라의 유령''은 추리소설의 진수를 유감없이 보여주고 있다. 탄탄한 인물 설정과 치밀한 구성으로 독자들의 호기심을 자극하고 있다. 특히 유령에 의...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (127, '뇌 1', 203, 4.22, 2, 3, 34, 73, 91, 164, 34, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2521, 127, '아~ 베르베르 선조가 아프리카 베르베르족은 아닐까도 생각해봤습니다 ㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2522, 127, '내가이책에이렇게재미있게빠져들어서읽게되리라고는상상도하지못했다.고등학교때이과에있던친구가빌려준책에그다지반가움없이받아온책이였다.왠지딱딱하고,복잡하며,어려울것 같아서읽기를망설이다 펼친 이책에 정신없이뺘져들어읽은기억이난다.너무강렬해서나는결국이책을갖고야말았다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2523, 127, '뇌는 내가 개미 이후 접한 베르나르 책이였다 애초에 생물학을 공부하던 나는 이책을 접하면서 작가의 상상력에 더 놀라게 되었고 다른 책들을 보는 계기가 되었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2524, 127, '동기가 바로 모든 행동의 열쇠죠. 원한다는 건 할 수 있다는 뜻입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2525, 127, '출판된지는 조금 되었지만 인공지능이 재조명 받는 요새 분위기와 어우러져 재미있게 읽을 수 있는 책.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2526, 127, '학교 도서관에서 몇 페이지 읽고 바로 도서관에서 새 책 하나 삼', 4);
