INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2530, 127, '베르나르 베르베르 뭔 설명이 더필요한가!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2531, 127, '독서의 세계로 입문하게 만든 책. 추천.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2532, 127, '사후세계를 죽지않고 갈수 있다는 내용에 정말 흥미롭고 새로웠고 베르나르의 창의성에 감탄했다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2533, 127, '쾌락과 죽음 추리와 의학 소설의 종합? 너무 재미있게 봤어요~!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2534, 127, '베르나르 베르베르를 알게 된 첫번째 책. 베르나르 베르베르의 소설을 계속 해서 읽게 하고 다음 작품을 기대하게 만든 책. 묘사와 내용 구성이 기가 막힌다고 생각.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2535, 127, '베르나르 베르베르의 상상력이 무엇보다 돋보이는 소설. 생각지도 못한내용들이 많아서.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2536, 127, '인간의 상상력의 끝은 어디일까? 라는 생각을 하게 해주는 작품이다. 아직도 뇌리에 박혀 있기에 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2537, 127, '‘우리는 우리 뇌가 가진 능력의 10% 밖에 사용하지 않는다’는 그럴듯한 오해로 시작하는 베르나르 베르베르의 ‘뇌’는 작가 스스로가 이미 많이 써먹었던 공식에 갖혀버린 듯한 느낌의 작품이다. DNA를 본뜬 나선형의 이야기 구조가 처음 소개되었을 때는 확실히 신선했다. 이미 기존의 추리소설 등을 통해 많이 쓰였던 방식이지만, ‘개미’는 그런 상식적인 구조를 더욱 정교하게 다듬어서 완성도 높은 긴장감을 선사했다.(확실히 로빈 쿡의 작품들보다는 그런 점이 뛰어났다.)하지만 그것도 어느 정도지, ‘뇌’에 이르도록 변하지 않는 그런 식의 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2538, 127, '베르나르의 소설은 좀 많이 읽어봤다. 처음으로 개미를 봤고, 신선한 전개에 신선한 충격을 주었다. 이야기가 분할 형식으로 진행이 되면서, 전혀 만나지 못할것 같은 스토리가 이야기가 전개됨에 따라서 극적으로 만나게 되는 그러한 진행방식은 가히 천재적이었다고 생각했다. 그래서 개미에 매료되었고, 베르나르란 작가를 한번 보게 되었다. 그리고 타나타노트, 천사들의 제국, 백과사전, 나무 등을 읽어보면서, 베르나르의 소설은 흔한 fiction이 아니라 과학적인 느낌이 들면서 매우 수준높은 느낌이 들게 만드는 책이었다. 이러한 주제...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2539, 127, '이지도르 카첸버그. 뤼크레스 玭琯?/P> 두사람과 함께 핀처박사의 죽음의 비밀을 밝히기 위해 떠난 두세달간의 모험은 오늘로써 막을 내렸다.더 읽고 싶다는 아쉬움이 남는걸 보면 "베르베르 베르베르"의 책을 앞으로 내가 꽤나 좋아하게 될 모양이다. :)내가 좋아하는 작가가 이로써 한명 더 생기게 되는 건가?뇌를 읽으면서 구절.구절 정말 내 머리를 탁 때린 문장들이 너무 많았다.많은 생각을 하게 만들어 주는 책같다.그리고 인간에 대해 조금더 발전하라고 뇌를 조금더 개발하라고 경고하고 있는 책 같다.그렇지 않으면 미래사회에서는 기계에게...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2540, 127, '베르베르의 명성에도 불구하고 변변한 그의 책 한 권 아직 읽지 않았던 내가 첫 책으로 선택한 것은, 뇌라는 제목과 세계 체스 대회 챔피언인 정신과 의사의 갑작스런 죽음이라는 서두 역시 흥미진진하게 내게 다가왔기 때문이다. 휴가 가기 전 날 밤, 잠이 안 오기에 잠을 청할 목적으로(?) 상,하로 된 이 책을 집어들어 결국 새벽 2시가 넘어서야 휴가를 위해 억지로 잠이 청해야 했다는 사실. 2권으로 나뉘어진 것이 부담스럽지 않을 정도로 근래 읽은 책중 흥미로운 책이었다. 베르베르의 다른 책, 특히 ''개미''를 읽...+ 더보기', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (128, '봉순이 언니', 203, 3.76, 2, 7, 64, 95, 35, 130, 64, 9);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2541, 128, '뒤늦게 공지영 작가의 를 읽으려고 하니, 아현동 언저리에서 짱아네 집에서 식모살이를 한 봉순이라는 인물의 삶이 더더욱 짠하게 느껴진다...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2542, 128, '구판본 종이책이 맘에 들었었다.작가의 어렷을 적 이야기와 봉순이 언니그 둘의 이야기가 하얀 종이가 아닌 까슬한 재생지에인쇄되어 추억 곱씹으며 읽는 재미', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2543, 128, '너무 어릴 때 읽어서 잘 기억도 안나지만,어린 나이에 여자의 일생이란 고달프구나 하고 쓴 생각을 했던 기억이 난다.^^;;', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2544, 128, '부모님 세대를 생각하며 책을 다 읽었을 땐 감명깊고 슬펐다.그러나 현 세대에는 너무 변질 되버려서 이제는 아쉽다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2545, 128, '짱아와 봉순이언니 그리고 어머니순수했던 어린아이에서점점 세상을 알아가고 깨달아가는 그순간은그리 달갑지않다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2546, 128, '느낌표를 처음 봤을때의 괭이부리말 아이들.! 정말 최고의 작품이다...책이그런것이 아니라, 나에게 있어서....내가 책을 읽게 해준 계기가 된책일뿐아니라 내용도 쉽고, 가슴뭉클하고 나의 어린시절을 생각나게 해주는 좋은책이었다. 그래서 후에 봉순이 언니를 보았고, 최근에 다시 읽어보았으나 왠지 별로다. 아마 너무 어두운 내용의 책이기 때문인것같다. 식모인 봉순이 언니가 불쌍한거 같기도 하고, 어쨋든 암울한 것을 싫어하는 나로 서는 너무 내용이 칙칙했다. 봉순이 언니의 가진 실현을 볼때마나 왠지 안쓰럽기도하고.... 마지막에 나온 봉순...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2547, 128, '희망이 끔찍한 걸로 변하는 순간은 희망이 미래의 뒷문을 삐끔 열고 현재라는 좁은 방에 들어섰을 때이다. 그리고 그 순간 희망이라는 것은 사라진다. 그것이 미래에 위치해있지 않은 이상 이미 희망이라고 명명되어 질수 없기 때문이다. 그런데 희망이 끔찍하다니 그리고 구차하다니... 작가를 믿을 수 없고 독자들의 열화와 같은 성원이 의심스럽다. 책의 줄거리는 봉순이 언니의 순탄치 못한 일대기이다. 그러나 이런 이야기 자체는 왠지 별 감흥이 없다. 사람의 일생이란 어느 누구나 자기 나름대로의 역...+ 더보기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2548, 128, '일 때문에 급하게 마구 읽은 책 중 하나. 나란 인간은 서정보다는 서사를 선호하는 관계로 자신의 의식이나 내적 탐구, 혹은 주변의 미세한 변화에 집중하는 90년대 이후 작품과는 엄청 친하지 않다. 그래서 나의 글읽기는 조정래씨와 같은 몇몇 예외를 제외하곤 과거에 집중되어 있는데 올해는 하는 수 없이 그쪽 책들을 쌓아놓고 한숨만 짓고 있다.특히나 취미없는 386 세대 작가들의 작품을 위주로 한 독후감 쓰기가 되는데 첫 타자는 조금은 읽을 만한 스토리 라인이 있는 작가라 그나마 다행이란 생각.어린 시절 식모 언니에 대한 기억...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2549, 128, '이 책은 MBC에서 방영한 ‘책을 읽읍시다‘ 라는 프로그램을 통하여 전국적으로 베스트셀러가 된 책이다. 서울 아현동을 중심으로 한 일종의 성장소설이며, 또한 지은이의 자전적 소설이라고 한다. 그러나 무엇보다도 고아이자 식모인 봉순이 언니에 대한 인생 이야기이다. 60-70년대 갑작스런 경제성장을 배경으로 그 혜택을 받은 계층과 여전히 혜택받지 못하는 계층 사이의 일을 짱아 라는 아이의 눈으로 풀어쓰는 형식을 취하고 있다. 봉순이 언니는 남자를 따라서 집을 나가지만 결국 실컷 일만 해주다가 다시 짱아네 집으로 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2550, 128, '희망.희망이라...어둡고 질척한 길을 걸어가는 것같은 봉순이 언니의 삶이 마지막까지도 희망을 담고있었다는 말미가 인상깊다. 그림이 곁들여진 책이 아님에도 투박하고 순박한 봉순이언니의 얼굴이 쉽사리 그려진다.식모라는 자신의 위치를 당연하게 받아들였고 희망까지 부여잡고 있는 모습은 시대가 다른만큼 현대의 사고방식으로는 납득시키기 힘든 삶의 자세일지도 모르겠다. 그렇지만 그럼으로 지금의 우리에게 그 ''희망''이 인상깊은게 아닐까 그렇지만 처음 이책의 마지막 장을 덮었을땐 나는 조금은 화가나 있었다. 작가는 봉순이언니가 아닌 그녀를 지켜보...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2551, 128, '숨도 제대로 쉬지 못한 채, 한 시간 삼십분 동안 그녀를 ‘다시’ 마주했다. 책을 덮고 나서야 갑작스레 온 몸에 오한이 일고 있음을 알아차린다. 오랜만에 만난 그녀는, 처음보다 더 깊은 떨림을 안긴다. 나에게 그 떨림을 주는 이는, 봉순이 언니인가 아니면, 짱아를 가장한 공지영 작가인가. 그도 아니면 봉순이 언니를 바라보는 짱아일지도. &nbs...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2552, 128, '식모를 하면서 세탁소 남자와 눈이 맞았다가, 병이 걸린 남자를 남편으로 삼아 하늘로 보내고 많은 남자에게 휘둘렸다. 아직 난 살면서 그러한 아픔과 그러한 사람을 만나 본 적이 없다. 그러나 그녀가 불쌍했다. 사무치게. 다른사람들은 이 책을 보고 어떤 생각이 들었는지 모르겠다. 나는 이 책을 읽다가 문득 이런저런 생각을 했다. 짱이와 그의 언니나 오빠. 그들은 주인집의 딸년과 아들놈이 었다. 그들은 좋은 부모를 두어 (처음에는 가난한 삶을 살았지만) 부유하게 살았다. 좋은 중학교를 다녔다...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2553, 128, '6,70년대를 그리는 드라마에 나올법한 스토리, 사건.. 어린아이의 눈으로 본 세계, 그리 낯설지만은 않다. 벚꽃 핀 창경원에서 어린 나이에 버림을 받고, 식모로 일하던 집에서 반지 도난의 누명을 쓰고, 세탁소 총각과의 첫사랑에서 실패하고, 아이를 지우고, 뒤이어 만난 남편과의 사별,, 그리고 나이 오십에 애비 다른 자식 넷을 두고 새남자를 만나 떠났다는 봉순이 언니.. 아무리 조숙한척 하지만, 실제 너무나 어린 짱아(극중 화자)의 눈을 통해 본 엄마는, 봉순이 언니를 한 가족처럼 여긴다고 해놓고 실제 외식을 하러 나갈때 같이 가지...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2554, 128, '봉순이 언니... 그녀는 인생의 바닥까지 살아 본 인물이다. 좌절할 듯도 한데... 낙관적인 자세를 유지한다. 그녀는 희망을 노래한다. ''나''와 봉순이 언니와의 거리는 점점 멀어진다. 하지만 저자는 ''그런데, 혹은, 하지만''처럼 대립의 뜻을 나타내는 접속부사를 사용하면서 희망을 포기하지 못한다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2555, 128, '공지영의 소설에는 386세대의 향수가 자주 배어나온다. 그럴 수 밖에 없는 것이 작가 자신이 그 세대이고 또 그 시대엔 모든 것이 너무나 급작스럽고 혼란스러웠던 시기였기 때문에 하고자 하는 이야기가 많은 때문이다.하지만, 그때 대다수의 사람들은 모든 것을 자유로이 말할 수 있는 상황이 아니였다. 화려한 경제 성장에도 불구하고 암울한 시기이기도 했다. 소설 속 나의 가족은 그 변화의 한 가운데에 있다. 달동네에서 주택으로 경제 성장의 상징인 아파트로 이사가면서 시대의 부흥을 직접 경험하며 중산층으로 진입한다. 그 가족의 일부...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2556, 128, '오랜만에 소설을 접했다. 주로 실용적인 도서나, 최근에 가벼운 유머류 정도의 읽기에 급급했던지라, 김정현 작(作)인 ''아버지'' 이후로 적당한 대상을 찾기 힘들었다. 가장 최근에 읽었던게 그 작품이니, 그 때의 감동은 지속적으로, 아하 소설의 표준은 이 정도는 되야 하지 않겠는가 자답하는 습관을 갖게 되었다. 소설류가 실제와 같은 느낌을 주지만, 이렇듯 감동을 주는 것은 그 극적인 면에 있을 것이다. 일상의 소재를 바탕으로 하면서도, 전혀 예상치 못한 형국으로 사건이 전개될 수 있는 개연성이 있기에 시간이 부족한 독자들은 밤을 새워가...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2557, 128, '세번가량의 관성을 느낀후 겨우 매끈하게 읽어나갈 수 있었다. 읽는 내내 먹먹했고 마음이 아팠다. 봉순이는 나와 너무도 닮아 있었기 때문에. ...느낌표 선정 도서가 아니었다면 이런 제목의 책을 집어들지 않았을 것이다. 작가가 전하고자 하는 메시지는 충분히 이해했고 글도 재미났으며 책의 가치도 인정한다 허나, 홍성혜 개인적으로 독서 후의 씁쓸한 뒷맛때문에 나는 이 책이 싫다. 바로 앞 서평에서 언급했듯이 나는 아직 나 자신에게 솔직하기 못하기 때문에. 162p 누군가를 사랑한다는 것은 어떻게 사랑하는지를 아는 것이란다. ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2558, 128, '이제 막 다섯 살이 된 ‘짱아’가 식모인 ‘봉순이 언니’와의 만남을 통해 세상과 소통하고 눈 떠가는 과정을 쓴 아름다운 소설이다. 60～70년대 고도 성장의 뒷골목에서 한없이 짓이겨지고 추락하면서도 삶에 대한 낙관을 버리지 않는 ‘봉순이 언니’의 삶을 통해 그 속에서 끝끝내 포기할 수 없는 ‘희망’의 메시지를 찾는 책이다 처음 봉순이 언니란 제목을 봤을때 내가 상상했던 이미지,배경도 60-70년대고 하니 그 힘들었던 시기를...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2559, 128, '느낌표라는 프로는 굉장한 영향력을 가진 것 같다 물론 책을 소재로 신선하게 접근을 시도해 모든이들에게 책을 친근하게 다가가게하고, 그 이익을 공익으로 환원한다는것은 정말 많은 칭찬과 격려를 받아 마땅하다 책을 꽤 읽는 편이지만 무슨 심보인지 베스트셀러엔 마음을 잘 주지 않는 편이라 느낌표 선정도서들도 굉장히 좋은 취지이고 멋진 프로그램이다 라고 생각만 했지 내 손으로 그 책을 산건 몇권 되지 않았다 좋다고 생각은 하면서도 왠지 손이 안가는데 어쩔수가 없었다 (너무무책임한말일지도모르나)집으로 온지 3일이 채 지나지않아 나는 동생대신 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2560, 128, '짱아에게 봉순이 언니는 사람에게 거는 희망과 좌절의 상징이었다. 어렸을때 만난 봉순이 언니를 통해 주위의 사람들이 변화되어 가는 모습들을 아주 서정적으로 잘 묘사한 소설이었다. “개구리 올챙이적 생각 못한다”는 속담이 있듯이 봉순이 주위의 사람들을 보면서 가장 떠올리게 하는 말인지도 모른다. 힘든 환경속에서도 그것이 힘든 환경이라 여기지 않고 자기 나름대로의 희망을 갖고 살아갔던 봉순이는 어찌보면 아둔하고, 실속을 차리지 못하는 인물로 여겨질지도 모르겠다. 하지만, 그런생각 조차도 우리...+ 더보기', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (129, '스토너', 202, 4.68, 0, 0, 11, 43, 148, 191, 11, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2561, 129, '소설 처음 스토너의 신입생 교양수업, 세익스피어의 소네트가 주인공의 마음뿐 아니라 내 마음도 움직여 주인공에게 몰입하게 만든다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2562, 129, '이 고요함, 이 묵직함, 이 고독함. 시간이 흐르는 걸 막을 수 없다는 게 아프다.그래도 생애 한 순간, 가장 사랑한 사람과 함께 보낼 수 있어 다행이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2563, 129, 'p.355˝ 시간이 생겨도 난 어떻게 써야 할지 모를 걸세˝ . 스토너가 말했다.˝ 그런 걸 배운 적이 없으니까.˝', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2564, 129, '평범하면서도 특별한 우리와 닮은 스토너. 담담하면서도 치열했을 그의 인생은 아름다웠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2565, 129, '평범하지만 아름다운 연대기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2566, 129, '˝욕망과 공부.˝ 캐서린이 한 번은 이렇게 말했다. ˝중요한 건 그것뿐이죠, 안 그래요?˝캐서린과 함께 한 스토너는 스스로 빛을 내며 아름답게 박동하는 청년 같았다. 문학과의 만남, 삶에 대한 의연한 태도도 좋았지만, 단연코 절정은 사랑이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2567, 129, '마음에 여운이 길게 남는다. 한 사람의 인생을 펼쳐보이는 것에 있어, 영화나 만화 같은 다른 매체와는 다른 소설만의 고유한 방식이 있다면, 그 방식은 바로 이 소설에서 시도하고 성공한 그 방법일 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2568, 129, '묵직한 감동.간만에 만난문.학. ??', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2569, 129, '주어진 일을 성실하게 해내고 살아있는 시간을 조용하게 인내하는 한 남자의 인생기록이다. 아름다운 문장과 담담한 전개 속에서 익숙한 감정이 느껴진다. 그것은 인간이 겪어내야 하는 어쩔수없는 외로움이다. 끝까지 혼자였던 스토너의 외로움이 소설을 읽고난 후 오랫동안 마음속에 맴돈다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2570, 129, '스토너의 삶 속으로 온전히 빠져들어가 함께 살았던 순간들이었다. 쉽사리 동요하지 않는 차분하고 고요한 그의 삶과 같던 죽음. 감동의 ''스토너''', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2571, 129, '이 세상 누구나 그와 같이 살지 않을까. 열정을 쏟고, 사랑하고, 실패하고, 방기하고 그러면서도 어떻게든 각자의 삶을 살아내는 것. 이 소설이 쓸쓸하고 슬프지 않았던 이유.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2572, 129, '시종일관 담담한데, 벅차다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2573, 129, '잔잔한 내용이지만 폭풍감동!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2574, 129, '아주 잔잔하지만 단단한 파동.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2575, 129, '한사람의 인생을 따라가면서 잊고있던 나자신의 삶의 방향을 돌아보게 했던 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2576, 129, '너무나 투명하게 한 인간의 인생을 곧이곧대로 비치고 있기 때문에, 읽고 나서는 무언가를 읽었다는 느낌조차 없다. 한 인생의 모든 것이 여기 그대로 있다. 소설로서 아무런 특출난 개성을 견지하고 있지 않은 소설. 그래서 위대한 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2577, 129, '3년 내에 영화화 전망. 기대는 안함.마지막 옮긴이의 말은 사족을 넘어 공해.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2578, 129, '평범한 사람 빌 스토너의 삶을 통해 현재를 사는 우리의 삶을 되돌아 볼 수 있게 해주었다는 점을 높이 사고 싶다. 숨겨진 책의 발견이라는 점은 보너스.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2579, 129, '책을 사고 10년만에 읽었다. 당시에 막 주목받던 소설이라 냉큼 사두었지만, 잔잔한 이야기라는 평가에 늘 후순위로 밀어두었다. 한참 지나서야 보았지만 좋았다. 스토너의 삶이나 태도가 아마도 평범한 우리 삶과 크게 다르지 않다. 책을 읽는 내내, 지나온 삶과 앞으로의 삶을 그리게 되곤 했다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2580, 129, '읽을 땐 기쁨을, 읽고 나서는 위안을 주는 책. 담백하면서도 격조 높고 단아하면서도 시적인 문체가 인생을 말한다. 신형철 평론가가 작품 말미에 쓴 삶이 우리에게 제공하는 와 의 총합은 결국 0이라는 말에 또 한번 위안을 받으며...', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (130, '하쿠다 사진관', 202, 4.35, 3, 7, 23, 52, 117, 169, 23, 10);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2581, 130, '오래 산 도시의 익숙한 동네와 일상을 떠나 완전히 새로운 곳에서 새로운 사람들과 부딪히며 새로운 일을 하는 나를 가끔 상상해 본다. 혹시 나도 모랐던 내 천직을 발견하지 않을까? 우연하고도 낯설게 만난 사람들이 가족만큼 끈끈해지는 이야기에서 묘한 설레임이 느껴진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2582, 130, '글의 문장력이 아마추어 입니다.. 좀더 섬세하게 적어보세요..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2583, 130, '표지만 봐도 불편한 편의점 인기에 따라급하게 기획된 느낌이 강하다대사도 유치하고 뜬금없이주인공이 제일 존경하는 사람이 갑자기눈앞에 나타남ㅋ', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2584, 130, '제주배경이라고 인기드라마랑 바로연결짓는 무리수', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2585, 130, '나미야. 편의점류의 셀러를 좋아하는 사람들 겨냥한 기획 소설에 연애 구도 한스푼인 느낌.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2586, 130, '시원하고 맑아 보이는 표지부터가 넘 맘에 들었어요! 첫 장만 보고 덮으려고 했는데, 다 읽어버림... 넷플릭스 첫 화 열었다가 끝까지 다 본 느낌이네요. 드라마로 나와도 완전 재미있을꺼 같아요!! 추천합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2587, 130, '육아 6개월차. 여행은 꿈도 못꾸는 요즘이지만, ‘제주‘ 란 단어만 보아도, 표지에 야자수와 감귤만 봐도 가슴이 두근두근 거리네요. 애들 재워놓고 가장 편안한 자세로 요 책 ‘하쿠다 사진관‘ 읽으며 저만의 힐링을 해볼랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2588, 130, '˝바당에 들어가야 돈이 되주, 겉에서 미끄러지기만 하민 어떵헐꺼?˝ 깊이가 아쉽다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2589, 130, '제주도 사진관에서 사진을 찍는 사람들에게는 모두 나름대로의 사연이 있답니다. 그 사연이 감동적이고 정말 뭉클했어요^^ 그리고 대왕물꾸럭 마을의 이야기도 재밌고 아리송한 제주 방언은 정말 제주에 있는 것 같은 느낌을 준답니다. 제주의 풍경과 계속 등장하는 해산물 요리도 신의 한수~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2590, 130, '드라마 [우리들의 블루스]를 통해 만난 제주가 이곳에도 있다. 그런 감동과 그런 잔잔한 여운이 있다. 멀리서 보면 잔잔한 일렁임도 없을 것 같은 평범한 인생들이지만 가까이서 들어다 보면 누구든 하나쯤 굴곡진 면들을 간직한 채 삶을 살아가고 있다. 곁에서 연을 맺고 아는 사람이 되고 나면 보이는 희노애락이 내 주변의 이야기인 양 밀착되어 이입된다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2591, 130, '힐링이라는 말에 맞게 너무 무겁지 않은 문체로 내용도 크게 어려움 없이 쑥쑥 넘어가요! 여러 인물이 나오는데 그냥 각자의 사연이 담긴.. 그런 힐링 드라마같은 느낌? 300페이지 훨씬 넘는데 이틀만에 다 읽었습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2592, 130, '주인공인 제비를 통해 우리 모두에게는 찬란한 순간이 있다는 사실을 알게 돼요. 그리고 그 모습을 곁에서 사진으로 남겨주는 석영 덕분에 제 주변 누군가는 나를 진심으로 응원한다는 것을 알 수 있어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2593, 130, '제주스러움이 물씬 느껴지는 청춘들의 이야기. 제주도를 떠나고 싶어지는 뭉클한 우리들의 이야기가 너무 좋았습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2594, 130, '생각보다 더 재밌게 읽었다. 흔한 성장/힐링 소설일거라고 생각했는데, 배경이 제주여서 그런가 마음이 일렁거리고, 등장인물들을 응원하며 읽었다. 진짜로 있을 것만 같음. ??', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2595, 130, '인생은 좋은 사람들과 함께 여행하는 길... 멀고 때론 비바람에 지치고 힘겨울 때도 내 곁에서 따뜻하게 지켜봐주고 응원해주는 그들과 함께이기에 아름답다 말할 수 있다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2596, 130, '하쿠다 사진관을 보러 제주 여행이 가고 싶어지는 소설이었어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2597, 130, '여름의 제주도를 배경으로 삶에 지친 마음을 가진 사람들을 치유해주는 하쿠다 사진관을 통한 인연들로 주인공의 상처가 회복되고 미래에 대한 희망을 얻게 되는 힐링 소설이다. 덤으로 얻게되는 제주도의 풍경과 구수한 방언들 그리고 해녀이야기까지 속속들이 재미난 소설책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2598, 130, '행복한 순간만을 담은 사진보다 등장인물들의 사건, 사고, 갈등의 상황도 담아주는 이 사진관 덕분에 스스로에게 더욱 진솔해지는 문장들을 읽어보며 생각해볼 수 있는 시간이었습니다. 여행을 가서 다시 떠나오는 사람이 아니라 마을에 남아 괸당이 되어가는 과정이 따뜻합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2599, 130, '사진관을 운영하는 석영과 그 곳에서 일하는 제비, 동창생 라이더스, 프리다이빙러들과 같이 다양한 사람들이 각각의 사연을 가지고 하쿠다 사진관에 와서 서로를 통해 위로받고 다시 살아갈 힘을 얻는 이야기! 그들의 모습을 통해 나 역시 삶의 위로와 용기를 얻을 수 있는 책이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2600, 130, '플라맹고를 추는 남자를 통해 알게된 허태연 작가님의 신간! 넘넘 좋아하는 제주도를 배경으로 사람들의 인생 이야기가 쌓여가는 사진관의 이야기~ 정말 재미있게 었어요! 주인공 제비의 성장 스토리도 넘 풋풋하고 보송보송 하네요~', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (131, '흔들리는 나에게 필요한 한 마디', 202, 4.79, 0, 0, 3, 36, 163, 199, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2601, 131, '자기긍정도 의외로 어려워요~ 특히 상황이 안좋을땐 부정적인 생각만들어서 더 그렇고요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2602, 131, '언어의 힘을 믿기에 오늘부터 나를 사랑하는 언어로 바꿔야겠다는 생각이 들었어요.자기 사랑언어를 매일 하면서 나를 바꾸고 싶어집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2603, 131, '자신을 향한 부정적인 언어를 버리고 있는 그대로에 자신을 사랑하는법을 배웁니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2604, 131, '자신있는 그리고 자신을 사랑할 말을 하자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2605, 131, '매일 나를 사랑하는 언어를 말하는 것만으로도 행복한 하루임을 일깨우는 책입니다. 나에 대한 자존감을 높이기에 새 힘을 주는 언어들이 가득해서 좋아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2606, 131, '스스로에게 기운을 주는 메시지를 읽을수 있어 힐링이 되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2607, 131, '가장 가까이 있으면서도 돌아보지 못했던 나 스스로를 챙기며 격려해줄 수 있는 긍정의 힘을 선물해주는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2608, 131, '스스로를 기운나게 만드는 긍정적인 말에 관한 책이라 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2609, 131, '제목처럼 지친 저에게 꼭 필요한 말들이네요 힐링이 되는 책이었습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2610, 131, '지친 심신에 위안이 되는 책이라 읽으며 많은 치유가 되었습니다 꼭들 읽어보시면 좋을듯 하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2611, 131, '자기를 부정하고 두려움 죄책감에 시달리는 사람들에게 자신을 바꾸는 방법을 알려주고 이를 통해 변화 성장 치유가 가능하게 해주는 유익한 책인거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2612, 131, '변화, 성장, 치유가 필요한 사람들을 위한 책! 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2613, 131, '말과 생각의 힘이 얼마나 큰지에 대해, 스스로 강해지는 방법에 대해 이야기하는 ｀흔들리는 나에게 필요한 한 마디｀.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2614, 131, '나를 부정하지 말고 긍정적으로 자신을 믿어야 원하는 일이 이루어질수 있다는 자기긍정의 힘을 말하고 있습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2615, 131, '그동안 부정적인 말을 많이했는데 이책을 보고 반성합니다 책에서 소개하는 말들을 생활화해서 사용하도록 노력해야겠습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2616, 131, '자기 사랑 언어라는 것의 힘을 느낄 수 있을거 같아요. 그런 말을 통해 사람의 중심을 채워나갈 수 있는 그런 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2617, 131, '자신을 사랑한다는 것 주변에서 고독을 느낄때 자신만의 위로가 필요한것 같아요내소중한 인생을사랑하는법', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2618, 131, '자꾸 자신감이 없어지고 우울해지는 요즘 저에게 필요한 책이네요. 자기사랑 언어라는게 생소하지만 자꾸 사용하고 생각하면 저도 좀 힘을 얻을 수 잇을 것 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2619, 131, '한번 사는 인생이지만 나 스스로, 나 자신을 위해서, 내가 스스로 써 나가는 인생이 너무 힘들다 ˝주위에서 이래라 저래라, 내가 더 나이가 많고, 윗사람이고, 선배고, 상사니 넌 내 말을 따라서 사는게 낫다 니 생각은 틀렸어˝ 이런말든 이제 그만 신경쓰고 듣고 싶지 않다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2620, 131, '어떻게 보면 지금 이 순간 나에게 가장 필요한 책이 아닌가 싶습니다. 사랑하는 방법을 잃어버린 사람들, 내 자신을 믿지 못하는 분이라면 한 번 읽어볼 가치가 있는 책이라 생각합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (132, '밝은 밤', 202, 4.72, 1, 1, 9, 31, 160, 191, 9, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2621, 132, '그녀의 단편집을 보고 기대를 너무 많이 했다. 창의적이지 못한 구조에 매력적이지 않은 캐릭터. 흔한 소설을 최은영에게 기대하지 않았다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2622, 132, '와 최은영의 신간... 존버는 승리한다.... 헐잠깐만... 장편이라고..? 저 눈물좀 닦고올게요ㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2623, 132, '슬픔과 고통으로 가득한 시기를 여자들이 비틀비틀 건너간다. 사람마다 너무 다 다른 그들 개인의 역사는 차츰 변한다. 차오르는 고름을 짜내며, 깊은 상처를 한 땀씩 느리게 꿰매가며, 그렇지 않고서는 이루어질 수 없는 ‘함께 함‘의 공간에 선다. 그러므로 우리의 밤은, 밝다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2624, 132, '100년의 서사!!에서 나오는 탄탄한 스토리와 흡입력!! 한국의 대표작가를 넘어 세기의 작품입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2625, 132, '﻿최은영의 문장에 나는 감화한다. 그러지 않고는 못 배길 만큼 아름답기 때문이다. 최은영이 말하는 ‘마음‘이 좋고 그걸 다루는 방식이 좋다. 모든 것이 가능한 세상을 살아가는 우리에게 정말이지 필요한 것이 우리 자신의 마음을 직시하고 그와 함께 지치지 않고 살아가는 것임을 알기 때문이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2626, 132, '정말 오래 기다렸어요... 작가님의 소설들이 언제나 마음 한켠에 있어요. 늘 응원합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2627, 132, '전작 통틀어 가장 애정가는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2628, 132, '80%읽었습니다 아껴읽고 있네요...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2629, 132, '잠이 오지않아 아득한 밤도 어둡지않고 밝다면, 내내 잠들지 못해도 외롭지 않을 것만 같아. 마음만은 늘 함께여서 가능했던 긴긴 세월 속 밝은밤의 연대.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2630, 132, '소설은 나쁘지 않았다. 매끄럽게 쓰여지고 잘 읽힌다.재밌긴한데 요즘 젊은 여성작가 특유의 (여성=피해자 집단)(남성=가해자 집단)프레임이 이젠 지겹다엄마와 딸의 이야기도 피해자가 다른 피해자 여성을 어떻게 상처주는가에만 초점이 맞춰져 있다피해자 여성이 아닌 인간여성의 글이 그립다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2631, 132, '한 구절 한 구절 곱씹으며 읽게 되는 소설은 이 책이 처음이다. ˝햇볕이 잘 말려, 다시 가슴에 넣고 새롭게시작할 수 있겠지.˝ 나도 언젠가 이런 마음으로 모든 일을 새롭게 시작하고 싶다.#밝은밤#최은영#문학동네#북클럽문학동네', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2632, 132, '쇼코의 미소 이후로 처음 읽어보는 최은영 작가님 책입니다. 내용이 잔잔하면서도 장면묘사가 생생해서 깊게 빠져드는책이었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2633, 132, '아프지만 아프지 않았고 서러웠지만 괜찮았다. 할머니는, 엄마는, 그리고 나는 앞으로도 이렇게 서럽다는 말 대신 화가 난다고 말하며, 친구의 손을 잡고 나아갈 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2634, 132, '새로운 글이 나오몀 한상 기대를 가지고 읽게 되는 작가인데, 처음 만났던 느낌 그대로 계속 이어지는 게 신기하다. 마음이 허하면서도 따뜻해지고 이야기에 과몰입되기도 하지만 미소를 짓게 되는 이율배반적인 느낌이 나에게는 묻어난다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2635, 132, '나를 잘 이해해 주는 친구를 한명이라도 만날 수 있기를', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2636, 132, '할머니와 다시 대화하게 해준 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2637, 132, '단편소설로만 만났던 최은영 작가님의 장편소설티저 북을 읽고 출간 후 책을 사서 봐야겠다 할 정도로 흡입력이 장편 소설에서도 좋은 것 같다. 읽을지 고민하는 분이 계신다면 고민하지 마시라 이야기하고 싶다.#밝은밤 #최은영 #문학동네 #북클럽문학동네', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2638, 132, '동시대의 아픔과 폭력을 이렇게 자세히 세밀하게 찬찬히 그려내는 작가는 거의 없다. 여자의 연대와 여성 가족의 반목(애증)을 상세하게 풀어냄. #밝은밤 #최은영 #문학동네 #북클럽문학동네', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2639, 132, '이번에 최은영 작가님의 첫 장편소설이 나온다는 이야기를 듣고 티저북을 신청해서 읽고 있어요. 슴슴하면서도 선명하고, 날카로우면서도 부드러운 이런 아이러니함을 공존시킬 수 있는 작가가 아닌가 합니다. 줄거리 뿐만 아니라 문장 하나하나를 건져가며 읽는 재미라는게 이런 거구나 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2640, 132, '울컥하는 부분들이 많았어요..결국 중간에 손을 놓지 못하고 완독하고 말았네요..ㅜ 나도 최은영 작가님 좋아하네..ㅜ. ㅜ', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (133, '은교', 201, 4.24, 10, 4, 24, 53, 110, 163, 24, 14);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2641, 133, '특히 남자들에게 섹스는 환상이 아니라 현실 문제이다. 여자들은 종종 섹스를 통해 환상에 근접하는 것과 대조적으로 <- ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2642, 133, '좀 늙은 은교가 왔습니다.웩.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2643, 133, '소설인줄 알았는데,,,,본인,,,자서전이네요,,? 쒸익쒸익,,', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2644, 133, '은교라는 책을 너무 좋아했고 감동적이었고 그 두글자만 봐도 아련한 느낌이었는데.. 그동안의 기억들이 다 더럽혀졌고 주변에게 추천했던 스스로가 창피하네요.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2645, 133, '늙고 추한 남자의 늙었단 보상을 왜 어린 여자애로 (여자애 의사와는 상관없이) 받으려고 하나.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2646, 133, '예전부터 관심가던 책~ 이 책도 계속 미루고만 있다는...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2647, 133, '박범신 대~~작가 님이참에 은교 시리즈를 쓰면 좋을것 같습니다~~~젊은은교 늙은은교 병아리은교(부제 못먹어서 아쉽다나의청춘 나의욕망) 박범신 염치도 없는 방송에서 헛소리 마세요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2648, 133, '소녀는 빛이고 시인은 늙었으니 그림자였다..그게 전부였다고 본문에 있는 그대로~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2649, 133, '영화 줄거리만 봤을 때 처다보기도 싫은 구토가 나는 내용이라고 생각했다.그러나 소설은 아름답다.작가의 힘이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2650, 133, '욕망에도 아름다움이 있다는걸 깨달았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2651, 133, '박범신님이 네이버 블로그에 연재했던 작품을 다시 단행본으로 만나게 되어 반갑네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2652, 133, '인간 본성의 욕망에 대한 노인의 진솔한 고백에 사회적 이념,가치는 무색해진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2653, 133, '책을 다 읽고나서 다시한번 앞 장을 펴게되는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2654, 133, '고딩 때 작품 한 두권 읽은 느낌만 가지고 함부로 예단한 점, 죄송하고 낯부끄럽다. 그 세월동안 작가는 이렇게 멋지게 늙었는데, 나는 뭘 했지, 갑자기 두렵구나.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2655, 133, '노시인, 스스로 채운 갈망에의 족쇄, 공감도 안타까움도 아닌 답답함.. 허상 은교.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2656, 133, '꼭, 밤에, 읽어보세요. 나의 본능과 만나며...!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2657, 133, '세상의 끝엔 너와 나.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2658, 133, '마지막에 이르러서는 결국 울었다.이적요가 말한 ˝싱싱한 행복˝이 무엇을 말함인지 이 나이 되고야 알겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2659, 133, '자신의 심장을 읽는듯하다는.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2660, 133, '문장이 수려하다. 라는 말의 진정한 의미를 이 책을 통해 알았다. 아름답고 슬프고 현실적이면서도 환상적인 괴로운 책이었다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (134, '가치를 사는 소비자 공감을 파는 마케터', 200, 4.82, 0, 0, 2, 33, 165, 198, 2, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2661, 134, '소비자가 공감할 수 있는 가치가 무엇인지 설득력 넘치는 언어로 꽉차있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2662, 134, '효과적인 마케팅에는 무엇이 있는지 살펴보며 제가 하는 일에 잘 적용할 수 있었으면 좋겠어요. 소비자의 마음을 사로잡는 비결에 대해서 많이 배우고 연구할 수 있기를 바랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2663, 134, '공감을 파는 마케터라는 말이 와 닿습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2664, 134, '소비자들의 눈과 귀를 사로잡을 수 있는 독특한 마케팅 전략과 공감 가치 분석', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2665, 134, '그렇죠! 소비자는 가치를 사기에 가격이 중요하면서도 중요하지 않기도하죠!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2666, 134, '상대방이 미처 생각하지 못했던 가치를 팔 수 있다면 성공적인 마케팅이겠죠. 더구나 소비자의 공감까지 얻었다는 더욱 그렇겠죠. 경쟁력 있는 마케팅을 위해서 읽으면 좋을 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2667, 134, '남들과는 다른 새로운 가치를 찾아내기 위한 마케팅 이야기가 흥미롭게 다가오네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2668, 134, '마케팅의 기본을 익힐 수 있네요. 소비자들은 가치를 사고 싶어하죠. 그런 소비 심리를 꿰뚫는 책이기에 마케터라면 읽어 볼만한 책이군요. 공감을 얻는 마케터가 되는 노하우, 저도 받아보고 싶네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2669, 134, '소비자의 마음을 얻는 방법과 빠르게 변해가는 마케팅 전략도 배워볼수 있는 책인거 같아요. 소비자의 심리를 정확하게 파악하는법도 궁금해지네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2670, 134, '소비자를 열광시키는 ''가치'' 를 이용한 마케팅 전략!무엇보다 마케팅의 핵심은 소비자의 공감, 니즈를 파악하고 파고드는것!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2671, 134, '감성의 시대이죠 물건이 아무리 좋아도 어떻게 판매하느냐에 따라 매출이 결정된다고 봅니다. 소비자에게 가치를 팔기 위해 마케팅으로써 어떻게 접근해야 하는지 그 해법을 제시해줄수 있는 책이라고 생각합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2672, 134, '이제는 기술보다는 가치를 소비는 경향이 더 많은 것 같아요. 어떤 내용일 지 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2673, 134, '다른 경쟁사가 제공하지 못하는 새로운 가치를 공급자 입장이 아닌 소비자 입장에서 찾도록 도와주고 그에 따른 마케팅 전략을 세울 수 있게 해주어 좋은 거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2674, 134, '소비자는 물건만이 아니라 가치까지 산다. 하지만 그것이 진정으로 소비자가 원하는 것일까? 기업이, 마케터가 원하는 입맛대로 창조하고 제안한 가치를 소비자가 마치 내 스스로 원하는 것인 양 착각하고 소비하게 조종하는 마케팅. 그 전략을 볼수 있을것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2675, 134, '여러 마케팅에 대해 배웠지만 만약 포괄적인 분야가 아닌 가장 복잡한 분야에 대해서 알고 싶으면 이렇게 세부적인 내용을 담은 책을 참고하는게 좋습니다. 그리고 이 책은 단순히 마케팅만이 아닌 소설이나 문구 작성하는데에도 매우 참고할만한 자료이니 이 점 생각하길 바랍니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2676, 134, '마케팅에 따라서는 안 살 예정이었던 물건을 사게 될 수도 있습니다. 마케팅은 참 중요하죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2677, 134, '사람들은 물건의 가치를 생각하고 지갑을 연다. 경제활동에 있어서 가치라는 것은 참 중요한데 이 책에서는 ｀새로운 고객 가치 창출｀을 이야기 하고 있다. 각종 딱딱한 마케팅 단어나 이론 동원이 아닌 그 실례를 중심으로 하고 있어서 생각보다 읽기 편했고 평소 생각지 않던 마케팅이 많아 재밌음.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2678, 134, '소비자의 소비심리를 파악하고 정밀한 분석으로 어떻게 접근해야하는지 보여주는', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2679, 134, '소비자와 마케터 사이의 공감에 대한 이야기가 흥미롭네요. 다양한 마케팅 사례를 통해 마케팅에 필요한 것이 무엇인지 깨달을 수 있을 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2680, 134, '마케터는 고객의 마음을 잘 읽어야하죠. 저자님께서는 가치를 중요하게 생각하시군요. 미래에는 마케팅 시장이 어떻게 달라질지 궁금하네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (135, '몽실 언니', 200, 4.62, 0, 0, 12, 52, 136, 188, 12, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2681, 135, '큰조카 책장에 꽂혀 있어서 읽어봤는데 좋았다... 다시 읽고싶은 ''몽실언니''', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2682, 135, '5월 17일 권정생선생님이 돌아가셨다. 우리 문학계의 큰별이신 선생님의 따뜻함을 이제는 작품속에서만 만날 수 있다. ''몽실언니''는 해방후 1947년 봄, 변화무쌍한 격동의 우리 현대사를 일곱 살 몽실이를 주인공으로 이야기가 펼쳐진다. 어떤 상황이 닥쳐도 원망하지 않는 몽실이, 재가한 어머니를 따라 새아버지와 살아도, 또 친아버지를 만나 새어머니와 살아도 현실을 받아들이며 착하게만 사는 몽실이, 어떻게 이럴 수 있을까? 안쓰럽기도 하지만 한편으론 화도 난다. 요즘 아이들이 이런 몽실이를 이해할 수 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2683, 135, '‘몽실 언니’는 작년에 룸메이트가 갖고 있던 책이다. 그때만 해도 동화는 대학생이 읽기에는 수준이 낮은 책이려니 하고 관심이 없었다. 하지만 어느 순간부터, 한 번 이 책장을 펼친 이후로는 다 읽을 때까지 책을 덮을 수 없었다.‘몽실 언니’는 주인공 몽실이가 어머니와 함께 집을 나와 새아버지와 함께 살아가는 것으로 시작된다. 그 때부터 몽실이는 다리 병신이 되고 새아버지의 집을 나와 친아버지와 살아가면서 새어머니 북촌댁의 아이를 키우는 등 온갖 시련을 맞게 된다. 몽실이는 새어머니 북촌댁이 낳은 난남이를 돌보고, 또 이후로는 아버지...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2684, 135, '현실 주의 작품들에는 우리나라가 어려운 처지에 있던 시대를 그려낸 작품들이 많은 것 같다. ‘몽실 언니 라는 작품의 경우도 6.25 전쟁 전 후 우리 민족 간의 아픔과 설움을 ’몽실 이라는 인물을 통하여 그려내고 있다. ‘몽실’은 아버지가 두명이고, 어머니도 두명이 있는 소녀이다. 어딜가나 천대받고 버림받는 민족의 한을 대변하고 있는 듯했다. 어디를 가든지 친아버지 ‘정씨’를 잊지 못하고 다른 곳에 시집가버린 ‘밀양댁’에 대한 정을 항상 간직하고 있다. 어쩔 수 없이 헤어지고 , 해체되어 버린 가족의...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2685, 135, '강아지똥, 하느님의눈물, 밥데기 죽데기를 참재밌게 읽었었다. 이번책은 재밌기보다슬프다. 지금 얘기는 아니지만 정말 이런일도 있구나싶을정도로 몽실이가 불쌍하게느껴진다. 어린나이에 온갖 일 다하고 엄마가 재혼을 하시고 새식구들한테 받는 설움이슬프다. 그리고 거기다 다리도 다치고 엄마마저도.... 나라면이런때 어떻게살수 있을까 생각해보았다. 나도 몽실이처럼 힘든 일이 있어도 잘참아낼수 있을지 잘모르겠지만, 그랬으면좋겠다. 어떻게다 나쁜일만계속 생기는지 모르겠다. 몽실이가 빨리 힘을 내서 잘살수있도록 어른들이도와주면 좋...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2686, 135, '나는 평소에 독서를 참 좋아한다. 특히 소설을 가장 좋아하는데.. 문득 이 책이 내 눈에 띄게되었다. 우선 나는 책을 고를 때 제목을 많이 보는 편이다. 제목이 몽실언니.... ^^;;; 친구 생각이 나서 읽어보았다~ (친구별명이 몽실언니.. 머리때문에!!) 그래서 나는 기대반, 웃음반으로 이 책을 읽게되었는데.. 생각보다 너무 재미있는것이었다! 지금시대랑은 너무 다른시대여서 그런가? 약간 거리감도 들었긴했지만.. 그와 반면에 지금시대랑 많이 달라서였는지 더욱 애착이 간 건 분명하다. 사실 요즘 주위에서...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2687, 135, '''몽실언니라는 책은 엄마, 새엄마 그리고 아빠를 잃고 새엄마의 어린 동생인 난남이를 자신이 엄마처럼 돌보며 가난하고 살기 힘들었던 6.25전쟁 때를 살았던 몽실이라는 어린 소녀의 이야기이다. 몽실언니를 보면서 많은 것을 깨닫게 된 것 같다. 특히 그 중 한 가지는 부모님의 소중함이다. 몽실이는 6.25전쟁이라는 힘든 시기에 엄마 밀양댁, 아빠 정씨 그리고 심지어는 몽실의 착한 새엄마 북촌댁 마저 돌아가시고 고아가 되었다. 그런데 거기에 난남이라는 새 엄마와 아빠 사이의 동생을 업어서 키워야하는 처지까지 되었다...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2688, 135, '읽는 내내 마음을 불편하게 하였던 책 . 이제부터는 절대 배 안고프게 해주마 약속하며 몽실의 손을 잡고 댓골 김주사에게 갔으나 몽실을 지켜주지 못했던 친어머니 밀양댁. 몽실이를 친자식처럼 귀여워해 주겠다던 약속을 저버리고 다리 병신이 되게한 새아버지 김주사. 몽실을 배불리 먹여주지 못하고, 전쟁이 끝난 후에는 만신창이가 되어 돌아온 친아버지 정씨. 몽실이를 살갑게 대해주었으나 병으로 오래살지 못하고 난남이만 남겨둔 채 세상을 떠난 새어머니 북촌댁. 몽실의 부모들 중에는 누구 하나 몽실의 버팀목이 되어주는 사람이 없...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2689, 135, '한동안 한국 작가의 동화를 안 읽었던 적이 있다. "프린들 주세요" 라는 앤드루 클레먼츠의 동화를 읽고난 직후였다. 아무런 걱정없이 교육을 받고, 창의성을 키우며 자라나는 어린이들의 모습을 기가 막히게 잘 표현한 동화였다. 멋진 반전과 번뜩이는 재치로 가득 찬 이 동화는 읽는 내내 유쾌하고 즐겁다. 우리나라 동화를 읽고 이렇게 즐겁고 유쾌했던 적이 있던가 하는 생각을 문득 하게 되었다. 지지리 가난한 아이가 주인공이고, 그 어린 주인공 주위에는 왜 그렇게 큰 어려움들이 많...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2690, 135, '참 아픈 역사를 가진 나라다. 아픈 역사 만큼 많은 상처를 가진 우리나라.... 하지만 많은 기적을 일으키고 발전을 이뤄냈다. 지금 우리가 누리고 있는 평화로움과 넉넉한 여유로움 저 아래편에는, 그 아픈 역사를 온몸으로 지탱해낸, 수 많은 몽실언니가 있었기 때문이 아닐까.... 먹고 살기 힘든 그시절... 단지 먹고 숨쉬기 위해 처절히 싸워야 했던 절름발이 몽실언니. 그 작고 어린 어깨에 주렁주렁 매달린 불행한 동생들.. 아버지.. 엄마.. 새엄마.. 이웃어른들.. 과연 지금의 우리들에게 이러한 몽실언니의 일들이 현실로 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2691, 135, '유명한 책이고 읽어도 읽어도 가슴이 찡해서 샀어요ㅋㅋㅋ 저도 언니가 있지만 몽실언니처럼 챙겨주는 언니보다는 많이 싸우고 다투는 언니여서 몽실언니가 너무 너무 착해보이고 여린것같아요 몽실언니책추천해드려요ㅋㅋㅋㅋㅋㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2692, 135, '과연 우리의 아이에게 이렇게 어두운 이야기를 읽혀도 되는 것일까. 아이는 이 어두운 우리의 이야기를 어떻게 받아들일 것인가. 아직 어린 나이 탓인지(초등 1년)몇장 넘기고는 진도가 나가지 않습니다.... 굳이 억지로 권하지 않고 그냥 책장에 꽂아두었습니다. 언젠가 부모님들의 삶이 처절한 가난과 고전을 면치못한 치열한 전투 끝에 지켜진 삶이란걸 이야기 해주고 싶을 때가 오리라...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2693, 135, '우리의 눈은 늘상 착시를 일으키게 합니다. 길이가 똑같은 선도 화살표만 그어도 그 길이를 착시하니 말이죠.또 도둑질이나 하는 등의 여러 좋지못한 일들이 일어나면 또 눈은 착시를 합니다. 그저 도둑질을 한사람을 욕하는데 그치고 맙니다.요즈음 경제난으로 인해 많은 좋지못한 사건사고들이 많습니다, 그럴때에도 여러 매체들에서는 그저 적나라하게 급급한 보도하는데에만 그칠뿐입니다.그누구도 왜 그랬어야만 했냐는 사정과 상황과 배경을 주의깊게 보는사람이 없다는 것입니다.분명 그런 사건사고를 저지른 사람이 잘했다는 것이아닙니다. 그저 그사람이 그...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2694, 135, '이 책의 주인공인 몽실이는 정말 불우한 환경에서 자란 아이다. 어머니는 아버지가 전쟁에 나갔을 때 가난이 싫어 몽실이를 데리고 다른 남자에게 시집을 가고, 몽실이는 새아버지 때문에 다리를 다쳐 절름발이가 된다. 전쟁에서 아버지는 병이 들어 돌아온다. 몽실이는 다시 아버지와 살게 된다. 아버지는 새어머니 북촌댁을 맞이하는데, 아기를 낳고 지쳐서 죽는다. 그래서 몽실이는 새어머니가 낳은 난남이를 데리고 어렵게 살아간다. 그러던 도중...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2695, 135, '중학교 시절 단발머리로 머리를 잘랐어야 할 때... 머리를 촌스럽게 잘못 자르면 "몽실이 같이 되었다"라고 말하곤 했다. 그 때 사용하던 몽실이라는 사람이 이 책속의 주인공 이었다. 이름은 참 익숙하지만 이제서야 이 책을 읽었다. 슬프고도 아름다운 소설... 아니지 어찌 생각해보면 실화일듯한 그런 이야기이다. 어린 소녀인데, 마음은 이미 어른이다. 가난하지만 마음이 참 따뜻한 아이이다. 슬프지만 읽고나면 마음이 훈훈해지는 그런 이야기다. 사람은 누구나 사랑을 느꼈을 때만이 외로움도 느끼는 것이다. 그것이 친...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2696, 135, '빚바랜 겉 표지가 도망간 몽실언니~! 이책은 딸이 구입해 읽고는 책장에서 몇번씩 외출나와 옆집에 다녀오고 동생집도 다녀와 우리집에 이사온지 몇년만에 빨간 표지의 몽실언니는 나와 만나게 되었다. 삽화가 요즘과 달리 아주 컨츄리 풍 학창시절 고무판에 하던 판화 같은 느낌이다. 몽실언니는 지지리 궁상맞은 아버지를 벗어나 새로 시집간 엄마가 낳은 동생과 그 못난 아버지께 시집온 착하고 아주 약한 새어머니가 낳은 동생을 가슴으로 감싼 그저 누나며 언니 그외 아무 이유없는 사랑 요즘처럼 이해타산적이고...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2697, 135, '전쟁으로 배고프고 아픈 사람들이 많았다. 권정생도 평생을 그렇게 살았다. 물론 그의 작품이 널리 읽히면서 돈을 많이 벌게 되었지만, 그는 그 돈을 늘 가난한 사람을 위해 쓰고 자신은 여전히 가난하게 살았다. 그는 ｢몽실언니｣ 작가의 말을 통해 “이 작은 이야기가 통일의 밑거름이 되어주었으면 하는 바람과 함께 고통스럽게 살아온 전쟁의 어린이들에게 조금이나마 위안이 되었으면 싶었다”라고 밝혔다. ｢강아지똥｣, ｢몽실언니｣, ｢우리들의 하나님｣ 3종세트로 권정생의 바른 삶(정생, 正生)을 느껴보길 ‘권’한다. ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2698, 135, '과연 이런 사람이 존재할까? 시대적인 어려움과 가정적인 어려움, 신체적인 어려움까지 고난의 모든 조건을 갖춘 몽실언니의 모습에 몇 번이고 가슴이 저리는 안타까움을 느꼈다. 그러나 결코 해피엔딩이 아닌 몽실언니의 삶이 몽실언니 자신에게는 늘 행복이라는 생각 또한 하게 되었다. 팔자이기 때문에 포기하는 것이 아니라 인생이기 때문에 살아가는 것이며 어느 때이고 남을 이해하고 배려하며 늘 베풀고 도울 수 있다는 몽실언니의 삶의 모습은 우리에게 좋은 본보기가 된다. 행복이라는 보이지 않는 그릇이 있다면 몽실언니의 그릇은 허름하고 못생겨서 어...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2699, 135, '나와 같은 세대들은 전쟁이란 아픈 역사를 피부로 실감하지를 못한다. 그래서 분명 6.25라는 전쟁이 이 한반도 에서 일어났음에도 불구하고 ''몽실언니''와 같은 책을 소홀히 하는 경우가 많은것 같다.몽실이라는 인물을 보면 ''인간은 공평하다''란 말에 대한 의구심이 생긴다. 인간이 공평하다니, 그건 세상살기 편하라고 하는 소리가 아닐까. 이곳에 나오는 몽실이는 가난을 참지 못해 남편을 버리고 새로운 살림을 시작한 어머니의 딸이다. 물론 몽실역시 어머니의 딸임은 분명하지만 얼굴도 모르던 낯선 곳에서, 더군다나 ''전남편의 자식''이라는 조건속에...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2700, 135, '지금 현재는 그렇게 어려운 사람들은 많이 없다. 아니 그런 아픔을 우리는 겪지 못해서,이런''몽실언니''라는 책이 새롭게 느껴질 뿐이다. 가난해서 입에 풀칠을 못해서,남의 종이 되거나,구걸을 하는 사람들은 우리가 볼 때에는 정말 불쌍해 보인다. 하지만 그런 가난함을 이겨내고, 극복하려 하는 사람들이 늘거있다. 그래서 지금 현재는 옛날처럼 그리 어렵지는 않을 것이다. 몽실언니는 어렵지만,장애가 있지만,6.25전쟁의 참혹하고 비참한 시대를 이겨내었다. 하지만 지금 어린이들은 풍족하게 살고 있고,모자란 것 없어 몽실언니의 생활을 이해할 수 ...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (136, '할머니가 미안하다고 전해달랬어요', 200, 4.53, 1, 3, 9, 64, 123, 187, 9, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2701, 136, '너무너무 따듯한 이야기! 나에게 프레드릭 배크만의 다음이야기 ‘브릿마리가 여기있다‘ 가 있는게 얼마나 다행인지 모른다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2702, 136, '까칠하기 이를데 없는 의 핑크빛 버전이랄까? 슈퍼히어로 할머니와 일중독 엄마, 지나치게 성숙한 소녀 엘사에 이르는 3대에 걸친 여자들의 이야기~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2703, 136, '톡톡튀는 상상력과 틀을 부수는 아이디어나재치를 가진 이야기는 좋다그런데 조금 지루하다..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2704, 136, '˝나쁜 게 사라지지 않을 것 같으면 좋은 걸로 덮어버려야지˝세상의 모든 일곱 살짜리에겐 슈퍼 히어로가 있어야 한다.할머니는 거짓말을 그렇게 부른다. ｀또 다른 버전의 진실｀이라고', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2705, 136, '마지막 80쪽은 역겨울 정도의 유치찬란.문진이 날아가는 제본.오베를 봐서 별 하나 더.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2706, 136, '오베라는 남자에 비해 너무 산만하게 전개된다 싶었다. 상상속의 세계와 현실 세계를 넘나들며 지나가는 이야기에 현기증을 느낄 때쯤 흩어진 조각들이 하나둘 맞춰지며 감동을 자아내었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2707, 136, '할머니 편지읽으면서 울었다...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2708, 136, '큰 기대를 안고 시작했던 소설이었지만 1/3까지는 조금 집중이 어려웠다. ˝오베라는 남자˝에 이은 또 하나의 가슴 따뜻한 이야기.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2709, 136, '책은 전반적으로반전과 재미와 감동이 있습니다.중간 중간 약간 피식 웃음나는 부분도 있고,긴장되는 부분도 있어요.조금은 특이한 손녀가상처받지 않도록,모든것을 주고 싶었던 아주 까칠한 할머니의 동화같은 이야기.우라지게 궁금하고우라지게 사랑할 수 밖에 없는 내용이였습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2710, 136, '저는 소설작가를 꿈꾸고 있는 13살 아이입니다! 두꺼운 책이라서 읽기가 망설여지는 책이었지만 막상 읽기 시작하니까 하루만에 읽어버린 걸작이었어요. 할머니와 엘사하고 웃고 울며 읽는데 책을 덮고 나니 여운이 엄청나게 남더라고요. 봐도봐도 여운이 남아 지금 8번째 읽었는데도 질리지가 않네요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2711, 136, '오베라는 남자를 읽어보지 않은 상태에서 봤다.뭐가 반전이 있고 따뜻한 이야기라는 건지 모르겠다.꾹 참고 읽는데 상당히 힘들었다', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2712, 136, '오베와는 완전 다르지만, 그에 버금가는 재미와 감동을 선사하는 책이었어요!!사람을 웃겼다 울렸다를 자유자재로 하는 작가의 필력과 옮긴이의 글솜씨에 감사드리고 싶을만큼 감동과 재미를 준 작품입니다!!완전 강추합니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2713, 136, '잘 쓰여진 소설이지만 이북으로 보려니까 역시 힘들다. ㅠㅠ', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2714, 136, '놀랍도록 재미있고 감동적인 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2715, 136, '엘사가 아빠에게 자신이 “특이한” 아이라서 더 이상 아이를 낳지 않는 거냐고 했을 때 했던 대답을 생각하면 아직도 눈물이 날 것 같다. 우리에겐 엘사처럼 이런 이웃들이 필요하다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2716, 136, '미아마스의 기사 엘사가 할머니의 일곱번째 왕국 미파르도누스를 친구들과 함께 건설하는 이야기가 아닐까', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2717, 136, '프레드릭 배크만이 내 취향에 잘 맞는다는 것을 다시 한 번 느낀 소설. 진짜 재미있게 읽었다.어른들의 세상을 아이들을 위한 동화에 절묘하게 녹여냈다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2718, 136, '페이지수가 많아도 전자책으로 읽어서 그런가 완독하는 데에 제법 시간이 걸렸지만 말그대로 시간 가는 줄 몰랐다. 추천사대로 울고 웃을 수 있으니 휴지를 준비할 것.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2719, 136, '서점에서 직접 산 책이었는데..시작은 좋았으나 마지막에 해리포터의 악당을 연상시키 듯한 글에 실망감이 든 책이다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2720, 136, '유쾌함, 감동, 웃음이있는책! 추천합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (137, '삼월은 붉은 구렁을', 199, 4.6, 0, 2, 11, 52, 134, 186, 11, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2721, 137, '모호하지만 매력적인 책. 어떤 책을 찾으려 이리저리 독자들을 안내한다. 마치 청룡열차를 타고 터널을 통과 중인 책이랄까... 터널 안에 설치되어 있던 기계들을 보는 느낌', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2722, 137, '#일본소설 #삼월은붉은구렁을 #온다리쿠 #권영주 #반타* 추석 연휴가 유난히 길었다.친정까지 가는 길이 멀다 보니차 안에서 읽을 책을 몇 권 챙겼다.그중 하나가 바로 리세 시리즈의 첫 번째 작품,''삼월은 붉은 구렁을''이었다.* 붉은색 표지와 계단처럼 쌓인책더미가 인상적인 표지였다.그리고 시리즈의 시작이라는 타이틀이주는 설렘 덕분에 기대가 커졌다.평소보다 더 막힌 도로를 바라보며느긋하게 책장을 넘겼다.* 책은 총 네 장으로 구성이 되어 있었다.1장은 회장의 초대로 대저택을 찾은젊은 회사원이 ''삼월은 붉은 구렁을''이란책을 찾아 나서는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2723, 137, '반값도서~ 나도 책을 좋아하는데.. 읽어줘야 하나... 근데 평이 별로네...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2724, 137, '이게 그래서 어떻게 된 이야기야? 하면 지는 소설이다. 그냥 신비롭고 비극적인 이야기를 즐기시라.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2725, 137, '온다 리쿠님의 작품을 읽을 때 가장 먼저 [삼월은 붉은 구렁을]을 읽고나서 그 다음 책들을 읽으면 더 흥미진진하게 작가의 작품들을 받아들일 수 있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2726, 137, '3부까지는 몰입하면서 재미있게 읽었다.4부는 좀 이해불가, 혼란스러웠음', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2727, 137, '온다리쿠의 소설에는 설명하지 못할 뭔가가 있는거 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2728, 137, '온다 리쿠 문학의 원점이 되는 소설인 책을 읽고 이 책이 바탕이 된 또 다른 장편소설을 읽으면 책을 읽는 즐거움을 더할 수 있는 듯', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2729, 137, '온다 리쿠 책은 에세이를 주로 읽었고 소설은 이번이 두권째다. 번역상 받았다고 해서 관심이 갔는데 소설 속에 한국해 라는 표현이 인상적이다. 이 책으로 앞으로 온다 리쿠의 소설에 빠질듯. 일본 문학의 다양한 스펙트럼이 부럽다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2730, 137, '번역상 축하드립니다온다 리쿠의 소설중 가장 매력적인 소설이었어요 제목에서부터 뭔가 묘한 분위기를 자아냈는데 소설도 그 분위기와 긴장감을 내내 이끌어갔던책이에요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2731, 137, '좋은 번역은 독자의 이해와 책에 대한 감흥을 배가시킨다는 점에서 주목해봐야 할 작품', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2732, 137, '책값이 제법 저렴한 편인데?? 좋군@!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2733, 137, '환상과 현실의 사이의 모호한 설렘', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2734, 137, '단연코 온다리쿠의 소설 중에서는 최고. 다른 걸 읽으면 더더욱 그렇게 느낌.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2735, 137, '묘한 매력으 ㅣ제목과 표지가 궁금해서. 처음 보는 작가인데 끌립니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2736, 137, '온다리쿠의 소설을 대개 좋아하는 편이지만 이책은 그 온다리쿠의 책 중에서도 미스터리하면서도 특유의 스토리텔링이 잘 드러난 작품중하나인거같다. 이어지는듯 이어지지 않는 아슬아슬함이 책 전체에 녹아있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2737, 137, '이거 이상의 소설을 본적이 없다. 특히 3장의 엔딩은 두고두고 기억에 남을듯. 이 책을 통해 온다리쿠를 알게되어 그녀의 소설을 빠짐없이 읽고있고 만족하고 있지만, 이 ｀삼월은 붉은 구렁을｀ 이상의 소설은 없다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2738, 137, '책 한권을 찾아 갖가지 이야기가 펼쳐지는 요책 정말 재밌더라구요, 온다 리쿠를 좋아하게 된 책이에요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2739, 137, '온다리쿠의 대표작 삼월이라는 책을 둘러싼 기묘한이야기 현대의 노스텔지어', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2740, 137, '온다 리쿠님의 작품이라면 믿고봅니다! 신비로우면서도 흥미로운 소설이고 소장가치도 충분합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (138, '인간은 필요 없다', 199, 4.76, 0, 0, 6, 35, 158, 193, 6, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2741, 138, '인공지능시대에서 발생할 수 있는 다양한 문제들에 대한 분석이다. 저자의 다양한 실전경험과 치밀한 자료를 바탕으로 정교한 논리가 전개된다. 위트있는 구성과 과감한 통찰력이 읽는 내내 독자를 즐겁게 해준다. 5년 전에 나온 책의 내용이 오늘날 그대로 진행되고 있다는 것이 놀라울 따름이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2742, 138, '인공지능과 로봇공학의 발전으로 인간의 삶은 더욱 편리해지는 반면 일자리들이 차츰 사라진다는 사실, 인공지능에 지배 당할것인가? 협력하고 보조하는 방향으로 가야하는걸까?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2743, 138, '앞으로는 인공지능이 어느 정도 수준일지 무서워집니다. 인간보다 더 똑똑해지는 인공지능의 세계이기에 통제불능이 될까 두렵네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2744, 138, '미래의 인공지능이 인간을 어떻게 대신할것인가 노동자로써 궁금하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2745, 138, '슬픈 제목이네요. 인공지능은 여러문제를 불러올것입니다. 인간이 할 분야와 인공지능이 할 영역을 미리 확정지어놓을 필요가 있다고 생각합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2746, 138, '이 책을 공학서적으로 여긴다면 중요한 무언가를 놓치게 됩니다. 곧 우리 현실이 될 모습으로, 모두가 알아야 합니다. 필독!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2747, 138, '앞으로 많은 기계들이 인간을 대체한다는 점에서 인간들이 많은 일자리를 잃을 수 있다는 경고를 가지는 책으로서 머지 않은 미래에 일어날 일을 작가의 정확한 내용의 저술의 잘 되어 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2748, 138, '인공지능의 발전으로 가져올 편리성과 이득만 생각했었는데 문제점도 생각 해 볼 수 있겠네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2749, 138, '블레이드 러너, A.I., 터미네이터 등 인공지능 로봇에 대한 영화들을 많이 보고 자랐는데, 어느새 현실로 이루어지는 것을 목전에 두고 있네요. 실제 인공지능이 우리 세상에 어떤 영향을 끼칠 것인지, 노동시장의 변화에 따른 경제와 사회의 변화와 함께 어떻게 대처해야 할지 알 수 있을 듯 싶습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2750, 138, '100세 시대라고 하는데 미래에 인간이 할일이 없다면 우린 무엇을 하고 살아가야하는지 곰곰이 생각해 보게 하는 유익한 책인거 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2751, 138, '앞으로의 직업관이라고 할까나요? 많은 부분을 생각하게 하네요 ~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2752, 138, '현재에선 아직 크게 와닿지는 않지만, 머지않은 미래가 될 이야기라는 생각은 듭니다. 흥미로운 주제만큼 내용도 흥미롭길 바랍니다^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2753, 138, '영화에서만 보던 일이 이제 현실이 될 날이 머지 않았네요. 두렵기도하고 기대되기도 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2754, 138, '인공지능 시대가 도래하고 있음을 이 책에서 느낄 수 있었네요. 인간은 필요 없다 정말 그런 시대가 곧 올 것 같습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2755, 138, '이미 많은 일자리들이 인간이 아닌 기계가 대신하고 있고 앞으로 미래에도 지금보다 더 많은 일들을 인간이 아닌 기계가 대신하는 생활이 되겠죠 피할수도 없고 피할 방법도 없다면 변화를 받아들이는 방법밖에 없다면 미리 준비하고 아는 사람들이 더 나을거라 생각되네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2756, 138, '이 책에 나와있는 것들이 앞으로 일어날 현실이 될 수 있다는 사실에 알 수 없는 두려움을 느낄 수 있었습니다. 하지만 이 책을 통해서 앞으로 나가야 할 방향을 잡을 수 있는 것은 큰 수확으로 다가왔습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2757, 138, '점점 로봇의 진화가 이루어직 있는데 진짜 영화에서처럼 기계가 인간을 침공하는날이 오지말라는법도 없다는 생각이 드네요. 그 시대를 대비한 책 같아서 흥미롭습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2758, 138, '인간이 아닌 인공지능로봇의 시대에 관한 다양한 영화를 접하면서 정말 많은 생각을 하게 되었는데 책으로 만날수가 있네요 인공지능에 대한 고찰을 한번더 해볼수 있다는 면에서 읽어볼만합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2759, 138, '점점 인간의 설 자리가 좁아지는 앞으로 곧 다가올 현실적인 이야기라 관심이 갑니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2760, 138, '노동의 종말. 이게 어떻에 유토피아여야지 디스토피아로 가는 것인지, 그 책임을 져야 할 사람들이 확실하게 보여짐. 다른 나라는 몰라도 우리나라는 어느 sf에서 다루듯 컴퓨터가 재판관을 해야할듯함.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (139, '라이프 트렌드 2016 : 그들의 은밀한 취향', 199, 4.82, 1, 0, 1, 29, 168, 197, 1, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2761, 139, '2016년에 예상되는 생활 문화에 관한 트렌드를 소개한 책이라서 기대합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2762, 139, '일상의 삶속에 스며든 2016년 트렌드에 관한책이라는데 힙스터,테아스테셔널,웰족,에지스몰족 같은 외래용어의 의미부터 파악해야할것 같네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2763, 139, '라이프 트렌드를 읽는 것은 이젠 필수라고 생각합니다. 시대에 뒤지지 않으려면, 대화에서 소외도지 않으려면 알고 있어야 할 라이프 트렌드이니까요? 작년부터 읽어 온 라이프 트렌드, 잘 몰랐던 트렌드도 있기에 읽는 재미가 있어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2764, 139, '내년의트렌드 지금예측해보는다양한아이템과이이야기 지금만나보는트렌드 미리점쳐본다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2765, 139, '트렌드코리아보다 더 가벼운 느낌이 들어서 좋네요. 전자는 약간 기업의 입장에서 내년을 어떻게 맞이하여야할지 압박이 느껴진다면ㅋ 이 책은 그저 책제목처럼 가볍게 무엇이 유행할 것인가에 초점이 맞춰져 있어 읽기 부담스럽지 않습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2766, 139, '트렌드와 취향같은 흥미를 끄는 소재를 사용해서 비전을 제시하다니 굉장히 효율적이네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2767, 139, '내년 트랜드가 궁금하신 분께 추천합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2768, 139, '2015 가면을 쓴 사람들을 재밌게 읽었는데 이번 그들의 은밀한 취향도 기대가 됩니다.트렌드를 읽는 일상의 이야기가 흥미로울것 같아요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2769, 139, '컬러링 책을 봤을때 어렸을때 했떤 색칠놀이를 떠올리며, 무작정 책과 색연필 사서 한동안 즐거웠습니다. 그리고 요즘은 해보지도 않은 손뜨개나 캘리그라피 기웃거리는데, 이 책을 보니, 그게 바로 불안의 시대에 자기 위안을 하는 방법 중 하나였던 거군요. 마음 비우는데 서예도 괜찮던데~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2770, 139, '매년 챙겨보는 트렌드북중에 독특한 영역을 구축하고 있는 책입니다. ㅎ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2771, 139, '요즘은 정말 트렌드의 시대네요. 2016 트렌드에 대한 작가님만의 생각을 알고싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2772, 139, '소비 트렌드를 읽고 대중의 심리를 이해하는데 도움이 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2773, 139, '부제가 그들의 은밀한 취향이라니 뭔가 색다를거 같고 궁금하기도 하고 나 역시 그들에 속하는건지 궁금해서 읽어보고 싶네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2774, 139, '특별한 것을 찾으려는 세대에게 꼭 맞는 책일 뿐 아니라, 나이를 먹은 어른들도 이 책을 통해 그들 세대와 어느 정도의 소통이 가능하게 만들어 준 책이라 생각이 듭니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2775, 139, '2016년에 우리의 삶에 어떤 변화가 올지 기대되는데 이책을 통해 먼저 만나볼께요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2776, 139, '내년의 취향 트랜드는 어떻게 될것인지 이 책을 통해서 잘 알수있겠어요~~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2777, 139, '가슴아픈 키워들도 많네요. 우리네 현실이겠죠. 지금 한국 사회를 가장 여실히 보여주는 트렌드 북입니다. 유용한 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2778, 139, '암호로 말하거나. 부분에서 많은 공감을 얻었습니다. 불만과 건의가 제대로 표출되지 못하고 억압당할때 특정그룹만이 아는 말로라도 스며나오는 생태를 따끔하게 꼬집어주네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2779, 139, '경기 침체 불황이라고 하더라도 약간의 영향은 받을 수 있지만 소비 자체가 확 줄어 드는 건아닌 것 같은데.우리의 소비 패턴과 다방면에서의 2016 라이프 트렌드를 알아 볼 수 있어서 좋네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2780, 139, '요즘 2030세대들의 트렌드 취향과 소비가 어느쪽으로 흐르는지 잘 알려주는 책인것 같고 화제가 되었던 이슈들을 취향과 트렌드에 맞게 분석이 잘 서술되어 있어서 재미있을거 같습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (140, '키리에', 199, 4.6, 12, 3, 1, 20, 163, 183, 1, 15);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2781, 140, '대박사건..;;; 피어나다랑 넘나 똑같은것..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2782, 140, '보다 좀 싸게 출판해서 남이 일년여간 공들여해왔던 작업물들을 이렇게 베껴 수익 올리면 다인가요? (그런데 이건 왜 정가제프리??) 출판사고 작가고 양심도 없네요.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2783, 140, '비밀의정원 후속작 커팅책 출판사껀 줄알았는데 표지까지 똑같이 빼긴 짝퉁책이네 잘못살뻔했네ㅎ 대놓고 바로 카피북..ㅋ 이건뭐..', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2784, 140, '피아나다를 베낀 책인듯...남의 책 베껴놓고 이런식으로 하는게 부끄럽지도 않은지...', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2785, 140, '페이스북에서 보고왔어요. 저작권 문제가 걸릴지도모르겠던데요. 갖다가 참고로 놓고 만들었을거같은 생각이 드네요. 어떻게 생각하세요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2786, 140, '이런 행태는 저작권에 문제가 없나요? 한참 ｀피어나다｀ 페이퍼 커팅 아트에 빠져있는 매니아 독자로선.. 달갑지도 반갑지도 않을 뿐. 도안도 완성도 떨어지고, 암튼 기분나쁨;;; 작가님은 무슨 생각으로 ｀작품｀이라 내놓았을까. ｀작가｀라 말하고 다니면 부끄러워 하시길.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2787, 140, '피어나다로 페이퍼커팅 처음 해보고 재밌어서..키리에도 구입했는데피어나다보다 도안도 별로고 완성도도 떨어지는듯 하네요. 실망..ㅜ.ㅜ', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2788, 140, '˝피어나다˝를 그대로 따라한 책을 낸 출판사의 상도덕과 작가의 의도가 의심스럽네요. 무슨 사정인지 궁금하신 분들은 링크한 블로그글 참고하시길.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2789, 140, '페이퍼커팅의 도구부터 도안,단계별로 실력을 올릴수있는 도안으로 페이퍼커팅의매력에 푹빠져보세요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2790, 140, '종이예술의 한 분야인 종이조각, 종이오리기는 마니아들이 많은 듯 합니다. 종이접기를 가르치면서 종이조각을 한 적도 있기에 저자의 노력에 박수를 보냅니다. 특히 입체형이나 볼륨감 있는 커팅페이퍼가 매력적입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2791, 140, '예술의 종류는 참 다양하다는걸 느꼈어요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2792, 140, '페이퍼 커팅이라는게 선에 집중해서 자르다보니 마음의 안정을 찾는데 좋을 것 같아요 저같은 초보자가 쉽게 따라하겠어요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2793, 140, '평들을 읽다 잘 쓰지 않던 평을 남깁니다. 전부터 페이퍼 커팅 아트 동화책도 국내에서 다수 출간 되었고 국외에서는 동화책 작가 이외에도 전문 작가들이 많더군요. 저는 컬러링북이나 종이 오리기 책들처럼 이 분야도 다양한 소재와 도안이 계속 소개된다면 더욱 폭넓게 즐길 수 있을 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2794, 140, '어렸을적 나쁜짓이지만 수업시간에 칼로 책상에 흠집을내면 그렇게 안가는시간도 훌쩍 지났었는데 다시 하고싶네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2795, 140, '별이 최소가 한개라서 어쩔 수 없이 드립니다. 아무리 봐도 너무 비슷합니다. 작가의 양심을 지켜주세요. 책 속에 논란이 가득합니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2796, 140, '칼질이 서툰 나도 잘만하면 예쁜 무늬를 만들수 있다니', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2797, 140, '조금은 생소한 분야인 페이퍼 커팅이 이렇게 다양하고 아름다운 모습이라는 걸 알게 됐고,초보자들도 좀 더 쉽게 입문 할 수 있을 것 같아 좋습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2798, 140, '예술이라 불리기에 충분한 장르라는 것을 알게 되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2799, 140, '선을 따라 가는 그림의 세상', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2800, 140, '신기하기도 하고 재미있기도 하네요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (141, '왜 일류의 기업들은 인문학에 주목하는가', 199, 4.77, 1, 0, 1, 39, 158, 197, 1, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2801, 141, '300개 가까이되는 100자평 중 실제구매자 단 한명도 없음. ㅋㅋ 이젠하다하다 책에도 댓글알바가 생길 줄이야. 게다가 300개가 약 1주일안에 다 달렸다. 이게 말이나 된다고 생각하나?', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2802, 141, '삶의 기본, 인생의 본질을 말하는 것이 인문학이기에 중심을 잃지 않기 위해 개인이든 기업이든 필요한 책이라고 생각됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2803, 141, '세계 일류 기업들이 인문학을 바라보는 것, 왜 인문학인지 이 책을 통해서 알게 되기를 바라며...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2804, 141, '요즘 취업을 하기 위해서는 인문학에 대한 지식을 쌓아야 합니다.인문학과 과학기술의 조합, 세계적인 기업들은 이미 인문학적 발상과 창의성의 연관관계에 주목을 하고 있다고 합니다.그래서 이 책이 관심이 갑니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2805, 141, '기술과 인문학의 융합과 상생은 시대의 흐름이고 요청되는 사안입니다.철학에서 파생된 과학이 이제는 제자리를 걸어가야 할 때라고 생각합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2806, 141, '인문학은 모든 인간의 활동의 기초가 되는 지식이라고 생각합니다. 단지 그것을 너무 빨리 이익이나 성공을 얻기 위한 수단으로 생각하지 않았으면 하는 바람입니다. 그러기만 한다면 기업과 기업인에게도 좋은 지식이 될 거라 생각합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2807, 141, '기업에서 찾아낸 인문학의 중요성. 인문학에 대해 보다 자세히 알게되는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2808, 141, '인문학은 늘 어렵다고 생각하고 있은데 왜 인문학 공부를 해야하는지 알려주고 있어서 제겐 아주 유익한 책이네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2809, 141, '인문학이 없는 사회는 무덤과 같다고 합니다. 인문학이 기업의 돌파구가 될수있다니 이런 책은 많이 나와야 합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2810, 141, '인문학의 중요성이 날로 커져가는 요즘, 그에 대한 필요성과 의미를 되짚어 볼 수 있게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2811, 141, '개인적으로 생각으로 인문학을 배우야하는것은 우리가 알지못한 지적인 수준을 높일수 있기때문이다. 공부잘한다해서 잘사는것 아니고 돈잘번다고 해서 행복한것은 아니다. 그외 살아가면서 교훈을삶고 더 행복과 지혜로 삶을 살수 있지 않을까 싶다! 이책은 왜? 인문학이 중요한지 알켜줄것이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2812, 141, '인문학의 중요성에 대해 이책을 통해 다시 한번 느끼게 되네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2813, 141, '세계 최고 기업에서 찾아낸 인문학의 비밀이라니 무척 궁금합니다. 요즘은 인문학이 대세인데 쉽게 다가오지 않거든요, 세계의기업들과 인문학 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2814, 141, '우리나라에 인문학 열풍을 불게만든 사람을 스티브잡스로 뽑기도 하니까요.. 기업과 인문학의 조합 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2815, 141, '인문학이 밀려나고있지만 인문학은 모든 영역에 있어 필수입니다. 그래서 독서가 중요하다고 생각합니다. 이 책은 취업생분에게 많은 도움이 되겠네요. 기업이 원하는 인문학적 소양을 집대성해놓았다고 하니 더욱더 믿음이 갑니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2816, 141, '직장에서 살아남으려면 요즘은 책을 읽어야 함', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2817, 141, '요즘은 자기계발에도 인문학을 중점적으로 하는 서적이 많더라구요~ 인문학이야 말로 인간이기때문에 생긴학문이 아닐까 싶습니다. 기업과 인문학이 조화가 잘 되어야 회사와 직원 모두 같이 성장 할것 같네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2818, 141, '인문학이 왜 필요하며 가치가 있는 학문인지 보여주는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2819, 141, '기술만으로는 한계가 있다고 생각합니다. 기술을 넘어서는 비결은 바로 인문학에 있습니다. 이 책을 통해 기업들의 숨겨진 비밀을 알게 되기를 바랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2820, 141, '인`사`철이 더 이상 죄송하지 않았으면 좋겠다. 지금은 기업이 이윤(돈) 달성을 위해 ˝필요해서 인/사/철학을 갖다쓰는 느낌˝이지만, 이렇게라도 사람들 마음속에 그 가치가 스며들면 다시 향기를 뿜어낼 수 있겠지...', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (142, '오십, 마침내 내 삶을 찾다', 199, 4.81, 0, 0, 1, 35, 163, 198, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2821, 142, '치열하고 험난한 50대를 보낸 저자가 65세 된 후 쓴 ‘중년을 위한 자기 계발서‘이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2822, 142, '미국의 현실이 고스란히 한국사회 50대 남성들에게 통할것 같지 않지만 돈, 건강, 가족, 친구로 이어지는 상관관계는 비슷하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2823, 142, '백세시대 인생의 반 이제나에게 묻는 자신에게 바치는 인생의 살아가는법', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2824, 142, '12년만 있으면 나도 50이네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2825, 142, '백세인생이라면 오십은 절반의 인생을 살았고 절반의 인생을 살아야 하기에 인생의 한가운데 있는 셈입니다. 남은 생은 이전과 다를 수밖에 없기에 새로운 계획과 도전정신이 필요하겠지요. 오십대를 위한 책이지만 다른 세대에게도 생각할 거리를 주네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2826, 142, '어느 새 50이 눈 앞으로 다가오는 나와 남편에게 도움이 되는 글이 가득하네요. 이제 100세 수명에서 반이 지났기에 앞으로 남은 반 동안 나 자신을 사랑하고 나 자신을 위해서 사는 삶과 가치에 대해서 깊이 생각할 수 있는...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2827, 142, '이 나라를 이끌어주신 우리들의 아버지, 베이비 붐 세대. 그분들께 좋은 선물이 될 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2828, 142, '오십은 지천명이라고 한다. 가정에 충실하고 직장이란 전쟁터에서 물러나 이제 나를 돌아 보아야 하는 시간의 의미를 새삼 깨닫게 한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2829, 142, '지천명이라는 말처럼 50은 삶의 의미를 알게 되는 시기입니다. 누구나 오십이 되었을 때 멋 진 어른이 되었으면 하는 마음이 있지 않을까요? 저도 책을 읽어보고 도움 받아보고 싶네요. ~', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2830, 142, '100세인생이라고 봣을때 오십은 이제 인생의 절반밖에 살지 않은 것이라 생각이 듭니다. 남은 오십년을 어떻게 사는 지에 따라서 인생이 결정된다고 해도 과언이 아닐 것 같습니다. 오십살에 과연 무엇을 할 수 잇을까 걱정이 됩니다. 이 책을 통해서 돌파구를 마련하고 싶습니다. 강추!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2831, 142, '오심대에 새로운 삶을 찾은 남자의 이야기이기에 오십대를 준비하는 의미에서도 도전이 된 책입니다. 늘 새로운 도전에 마음을 열어야 한다는 생각도 했고요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2832, 142, '저희 부모님 이야기라 더 읽어보고 싶고 부모님에게 선물 해 주고 싶은 책입니다.50이라는 건 100세 시대에서는 딱 절반인데, 현실에서는 한 풀 꺾인 그 모습이 그려집니다.이 책을 통해 ｀나｀를 다시 찾을 수 있는 부모님을 응원합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2833, 142, '40대중반부터 이런 생각을 많이 하게 되는것 같아요 직장에서는 오랫동안 근무해 익숙하지만 점점 힘들어지고 미래를 생각하면 힘을 내야하지만 현실은 가족이든 직장이든 슬럼프에 빠지기 쉬운 나이니까요 읽어보면 좋을 것 같은 책이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2834, 142, '멋진 중년의 삶에 대한 좋은 가이드네요.앞으로 사람의 평균 수명을 100세로 보면 50이라는 나이는 그리 많은 나이가 아닙니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2835, 142, '주변인들에게 선물하고 싶은 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2836, 142, '가족을 위해 헌신한 모든 아버지들이 중년이 되어서 느끼게 되는 여러 문제들과 좌절감을 통해서 어떻게 중년을 이겨나가야 할지를 보여주는 책~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2837, 142, '숨가쁘게 목표와 책임으로 달려왔고 소위 말하는 갱년기, 중년의 위기에 접어든 남성들을 위한 지침서 입니다. 보람되고 행복한 중년, 어떻게 노년을 슬기롭게 대비할 것인가, 이무렵 흔히들 고민하게 되는 내삶의 정체성, 부부갈등 등 다양한 문제와 고민에 대해 건강하고 다양한 조언이 담겨있습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2838, 142, '저희 부모님에게 선물해드리고 싶네요~ 오십이면 새 삶을 출발하는 시기라고 생각합니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2839, 142, '오십이지천명(五十而知天命?논어 위정 편),즉 나이 쉰에 하늘의 명을 안다는 말이다. 그 명이 무엇인지 이 책으로 알게 될것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2840, 142, '50이라...사회적 관심도 없어지고 자식도 떠나려하고 건강은 나빠지고... 오십 무엇을 해야 하는가? 저도 한번 생각해보려고요. 나를 돌아볼 수 있다면...', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (143, '화차', 198, 4.42, 1, 4, 15, 68, 110, 178, 15, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2841, 143, '미미여사 현대 미스터리 걸작 중 하나(이유, 모방범까지 해서 현대 미스터리 베스트3). 에도시대 이야기도 좋지만 역시 현대물로 맹활약하던 예전의 미미여사가 더 좋았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2842, 143, '눈을 뗄 수 없는 이야기에 빠져들다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2843, 143, '강한 주제의식. 그러나 이야기 전체를 작가가 장악해서 독자들이 개입할 여지가 없다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2844, 143, '결말이 명확하지 않은 추리소설은 내 취향이 아니다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2845, 143, '미미여사의 따뜻한 시선이 강한 인상을 남긴다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2846, 143, '왜인지는 몰라도 이소설은 영화처럼 장면이 눈에 선하다. 여운은 정말 깊이 남는다..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2847, 143, '재미있는 교훈극. 절약하자 100번 다짐하는것보다 이책 1번 읽는게 효과적일 듯', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2848, 143, '처음 읽었을때의 충격을 10년가까이 지난 지금까지도 책을 펼칠때마다 느낀다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2849, 143, '일상 속 사건에서 사회문제로까지 주제의식을 확장시키는 소설', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2850, 143, '미야베 미유키는 써내는 작품마다 일본의 각종 추리문학상을 수상하는 최고의 작가다.그녀가 법률사무소에서 일하며 얻은 경험들을 바탕으로 써낸 수작들은 흥미진진한 스릴러로서의 재미도 출중할 뿐만 아니라, 사회고발적인 성격도 짙게 깔려있어서 비평가와 독자들을 고루 만족시킨다. ‘인생을 훔친 여자’라는 제목으로 출간된 ‘화차’ 또한 매우 빼어난 작품이다.끈질기게 한 여인의 정체를 좇는 주인공의 추적이 흥미진진할 뿐만 아니라, 등장인물들의 입을 빌어 신용카드와 사채 문제에 관해 경종을 울리고 있다.특히 등장인물 중의 한명인 이구치 변호사의 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2851, 143, '병가로 쉬고 있는 형사 혼마가 가즈야라는 먼 친척 청년으로부터 사라진 여자친구를 찾아달라는 의뢰를 받으며 이야기는 시작된다. 세키네 쇼코라는 이름의 여자는 가즈야와 약혼까지 한 상태에서 ''개인파산''이라는 과거의 이력이 드러나자 종적을 감춰 버리고 만 것이다. 세키네 쇼코의 현재를 알기 위해 그녀의 과거를 추적하기 시작한다. 그 과정에서 놀라운 사실이 밝혀진다. 혼마와 가즈야가 찾으려고 했던 세키네 쇼코의 과거는 그들이 알고 있는 세키네 쇼코의 과거가 아니라는 사실. 즉, 현재의 세키네 쇼코와 과거의 세키네 쇼코는 전혀 다른 사람인 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2852, 143, '일본뿐 아니라 우리나라에서도 이미 수많은 매니아를 거느린 미야베 미유키의 책을 처음으로 접했다. 그만큼의 기대를 저버리지 않을만큼 소설 화차는 사회의 병폐를 날카롭게 파헤친 수작이었다 말하고 싶다. 또한 여작가이기 때문에 더 밀도있게 그려지는 여자들의 심리묘사는 순간 순간 고개를 끄덕거리게 만든다. 무엇보다 지금으로부터 15년정도 더 거슬러 올라갔지만 책에서 보여주는 다중채무자나 개인파산, 대출, 사채로 인한 폐해는 현재 우리사회의 어두운 단면을 요목조...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2853, 143, '“화차(火車)여... 화차여, 오늘은 우리 집을 스쳐 지나가더니 또 슬픈 어느 곳으로 돌아가느냐.” 돌고 도는 불 수레. 그것은 운명의 수레인지도 모른다. 한 사람은 내리고 다른 한 사람은 그 자리에 올라 탈 수밖에 없는... 이 작품은 신용 불량자라고 우리가 소위 낙인찍어 살아 있으나 허공을 떠도는 유령처럼 만들어 버린 사람들의 이야기다. 이 작품을 다 읽은 지금도 사실 모든 사정을 이해하지는 못한다. 왜냐하면 행복이라고 하는 것이 어떤 것인가를 알고 있기 때문이다. 행복이란 가질 수 없는 것을 갖기 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2854, 143, '"미야베 미유키"의 "화차"는 이미 수년 전인 2000년에 한국에 번역되어 소개 되었다.이 소설의 저변에 깔린 신용사회의 신용불량자와 관련된 문제점들은 이 소설이 한국에 소개될 당시의 시점에서 당시의 DJ정권에서 신용카드사용등을 통한 경기부양책을 지향하고 있었다는 시점과 일치한다.물론 이 문제들은 이 책의 초판이 한국에서 출판된 것보다 거의 10여년 전부터 일본에서 큰 사회문제가 되어 왔었던 일이지만 한국은 많은 점에서 일본을 약간 뒤따라 간다는 것을 직시했다면, 한국에서도 이러한 비슷한 문제가 잉태될 것임을 어느 정도 예측할...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2855, 143, '미야베 미유키라는 작가를 만난 것은 지난 2006년의 가장 큰 수확이 분명하다. 그녀의 작품세계를 접하면 접할 수록 항상 기분좋은 놀라움을 선사해주고 있는데 이번 이야기의 화두는 "신용카드"이다. 스무살에 어설픈 사회생활을 시작해, 대학생활을 하는 중에도 크고 작은 경제활동을 계속해온 나 역시 ''플라스틱 카드'' 따위는 지금도 신용하고 있지않다. 물론 편리하다는 점에 있어서는 이의를 제기할 수 없음이 분명하지만, 단순히 조금 더 행복해지고 싶다는 소망과 현실은 전혀 다른 문제라고 생각한다. 그...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2856, 143, '사라진 약혼자쿠리자카 카즈야는 도련님이다. 인생에 있어서 실패한 경험이 거의 없다. 부유한 부모님 밑에서 부족한 것 없이 살아 왔고, 현재는 은행원으로서 엘리트의 삶을 살고 있다. 하지만 아내를 선택하는데는 크게 실패를 한 모양이다. 아름답고 똑똑해 보이는 세키네 쇼코와 약혼을 했으나 (부모님의 반대는 이럴 때 사람을 강하게 만드는 부록같은 것이다) 신용카드를 만들려다 신용불량자라는 사실이 밝혀진 후에 쇼코가 감쪽같이 사라져 버린다.쇼코를 찾기는 해야겠고 경찰에 알려서 일을 크게 만들고 싶지는 않았다. 결국 좀 먼 친척이긴 하지만 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2857, 143, '때로 명성이 너무 자자한 작가의 책을 만나게 되면 기대가 너무 커서 작품의 참맛을 다 느끼기도 전에 질릴 때가 있다. 그렇지만 명성이 있는 작가의 작품을 만나게 되면 그 명성이 절로 얻어진 것이 아니라는 것을 저절로 깨달을 때도 있다. 미미 여사가 내게 그랬다. 추리 소설, 미스테리 스릴러, 서스펜스 등등. 이런 종류의 책과 영화를 멀리한다. 워낙에 겁이 많아서 뒷감당이 힘들고, 진짜 재밌는 추리물을 만나면 거기에 빠져서 헤어나지 못할까봐 제어장치가 필요했다. 그랬던 나에게도 미미 여사는 피해갈 수 없는 관문이었나 보다. 실은 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2858, 143, '"상황을 보아하니 틀어진 것 같은데 앞으로 어떡하시려고요?""혼자서라도 조사를 계속 해야죠. 그냥 둘 수는 없는 일 아닙니까?""사라진 여자를 찾는 거죠?""그렇죠."혼마는 창 밖으로 눈길을 돌렸다. 어둠이 아파트 단지 전체를 휩싸고 있었다. 이 캄캄한 어둠 속 어딘가에 사라진 쇼코가 있을 것이다. 이 순간에도 그녀의 호흡이 어둠을 하얗게 물들이고 그녀의 목소리가 누군가의 귓전을 울리고 있을지도 모를 일이다. 눈이 지독히 내린 어느 겨울밤, 죽은 아내의 사촌이 사라진 약혼녀인 쇼코를 찾아달라며 혼마를 찾아온다.형사생활중 입은 부...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2859, 143, '미야베 미유키의 조금 오래된 작품을 접했다. 미야베의 인기에 힘입어 이 책의 개정판이 나왔지만, 난 누렇게 변색된 책으로 읽었다. 그러나 내용만큼은 지금도 우리 주변에서 흔히 볼 수 있는 소재를 다루었다고 할 수 있다. ''신용불량자''라는 단어가 언제부터인가 우리 귀에 무척이나 익숙하다. 아마도 많은 사람들이 플라스틱 카드 하나만으로 소비욕구를 충족시키고, 그로 인해 늘어나는 빚을 감당할 수 없게 되었기 때문일 것이다. 언제부터인가 이런 사람들이 너무나도 많아져버려 빚을 갚지 못해 야반도주나 자살...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2860, 143, '지하철을 아침 저녁 제법 오래 타고다니는 나로써는 손에 읽을거리가 없는 날은 지하철을 타려면 미리부터 불안하다. 후텁지근하거나 혹은 너무 과한 냉기를 꾸벅꾸벅 졸면서 버틸 재간이 없기 때문이다. 이 책은 그래서 구입했다. 일부러 버스를 타고 서너정류장을 가서 시내 대형서점에 들러 미리부터 점찍어둔 이 책을 고르고 집에 돌아오는 길에 있는 백화점에 도착할 때까지 한시간 가량을 정신없이 읽어갔다. 우선 표지그림이 섬뜩하다. 제목인 ''화차''와 달리 몹시도 쿨한 은색 세로선들은 냉동된 은갈치토막을 연상하게 했다. 그러나 자세히...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (144, '덕혜옹주', 198, 4.14, 10, 13, 21, 49, 105, 154, 21, 23);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2861, 144, '조선의 마지막 황녀인 덕혜옹주가 누구인지도 몰랐다. 관심가는 책이다!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2862, 144, '교보 쌤에서 무료로 준 소설이다.조선 왕실에 대해 별로 호의적이지도 않지만, 소설이 밋밋하고신파조의 쥐어짜기식 전개라서 갑갑했다.어떻게 올해의 책이 된걸까?', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2863, 144, '덕혜옹주의 비극적인 삶이 안타깝고 슬펐다. 우리나라 마지막 황녀 덕혜옹주에 대해 자세히 알 수 있다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2864, 144, '일본작가..혼마 야스코씨의 에세이집과 거의 똑같네요..더구나 소설로 나오다니??', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2865, 144, '우리가 너무 등한히 했던 우리 역사의 귀중한 부분이지요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2866, 144, '만들어진 베스트셀러 같은 느낌을 지울수 없었던 책.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2867, 144, '아 정말실망이다무기력함만 소설에가득하고 내용도무지 엉성한것같다연극으로도 만들어졌것 같은데많이 실망스러운 수준의 책이다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2868, 144, '마음이 참으로 아픈우리역사.... 우리의 마지막 황족을 기억하며....', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2869, 144, '역사에 관심이 많은 나~ 어렴풋이 들어봤던 덕혜옹주~눈에 띠는 책자에 구매해 본다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2870, 144, '아프고 가슴 시린 역사의 한 단편을 마음으로 느낄 수 있었던 소설이었습니다. 강추!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2871, 144, '요즘 서점을 쓸고있는 감동의 물결 ~..~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2872, 144, '마지막 황녀에대해 관심을 갖게 만드는 책. 그 이상도 그 이하도 아님.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2873, 144, '옹주보다 그를 지키고자 한 그 주위의 인물들을 위한 책이지 않나.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2874, 144, '관심조차 없었던 우리나라 마지막 왕족 역사에 관심을 가지게 된 계기를 준 책입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2875, 144, '왜 베스트셀러인지 모르겠다 내용의 깊이감도,,전개의 세련됨도 없다(예:유치한?대사)', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2876, 144, '황실의 슬픔과 아픔을 읽었다. 짠한 아픔에 오늘의 대한민국을 생각한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2877, 144, '유명한 책이긴 한건 같은데 안 좋은 평판들이 ;;; 갈등 생기게 하네 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2878, 144, '처절했던 그리고 감당할 수 없었던 그녀의 삶을 되짚어 본다는 의미에서 굿~~!!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2879, 144, '굉장히 오랫동안 베스트셀러 자리를 지키는 역사소설.. 읽어볼만합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2880, 144, '광고를 보고 꼭 읽고 싶었던 책 이었지만 읽고나서는 완전 실망했다.', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (145, '알고리즘 행성 여행자들을 위한 안내서', 197, 4.8, 1, 0, 6, 23, 167, 190, 6, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2881, 145, '마치 이젠 공기처럼 존재하는 알고리즘의 모든 것이 담겨있다. 알고리즘을 이해하는 것은 급변하는 요즘의 세상을 이해하는 한 길이 될 것이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2882, 145, '5월 17일 댓글을 다신 분 이전의 글 -100개 모두가 ... 비구매자의 글이네요... 헉...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2883, 145, '7일 동안 알고리즘 행성에서 다양한 알고리즘 서식지를 여행하는 테마로 구성된 책입니다. 이책을 읽고 나면 도대체 알고리즘이 무엇인지, 손끝으로 연결된 광범위한 네트워크 세상,검색 쇼핑 내비게이션 데이터보완 그리고 인공지능 학습 개념까지 한눈에 파악할수 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2884, 145, '제가 몰랐던 또다른 세상이었어요. 일반인도 쉽게 읽을 수 있도록 구성해서 더 마음에 듭니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2885, 145, '알고리즘은 우리의 영역에 밀접해 있기에 배우고 싶었어요. 알고리즘에 대한 상식과 기본기를 익힐수 있는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2886, 145, '알고리즘 어렵기만하게 아니라 좀더 쉽게 이해되는 내용으로 접근할수 있을것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2887, 145, '어렵기만한 알고리즘에 대해 그 의미와 기능을 알기 쉽게 설명한 책입니다. 첨단기술 부분에서 알고리즘이 어떻게 응용되고 있는지 예시를 통해 명쾌하게 알려주고 있네요!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2888, 145, '알고리즘은 무엇을 위해 존재하는가 그 해결을 위해', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2889, 145, '알고리즘을 이해하기 쉽게 설명해주고 있다고 하는데 저 같이 모르는 사람이 이해하기 어려운 알고리즘이라는 걸 어떻게 이해하기 쉽게 설명하고 있을지 궁금하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2890, 145, '알고리즘하면 인공지능이 떠오르네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2891, 145, '한때 과학도였던 그 때로 다시 돌아간 느낌입니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2892, 145, '우리 일상에 연결고리인 알고리즘 내가 문제를 해결하기 위해서 또는 정해진 순서들의 여러방법을 손쉽게 이해하고 생각하게 하는 도서입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2893, 145, '알고리즘의 의미나 기능을 짚어주며 우리주변에서 알고리즘을 어떻게 활용하고 첨단기술부분 및 경제,사회문제,고고학에서 알고리즘이 어떻게 응용될 수 있는지 실질적 사례를 통해 쉽고 흥미롭게 풀어낸 책이에요.알고리즘에 대한 궁금증과 오해를 풀고 알고리즘을 정확히 이해하는데 도움이 되겠어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2894, 145, '속지 마세요 이 책은 어려운 책입니다 오히려 링크나 버스트가 훨씬 나아요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2895, 145, '알고리즘이 실생활에 사용되는 예시를 통해 알고리즘이 어떤 것인지 보다 쉽게 이해 할 수 있어요. 우리의 생각보다 알고리즘은 생활과 밀접한 관계가 있다는 것을 느낄 수 있었네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2896, 145, '알고니즘이 우리곁에 , 우리가 사용하는것들에게 있다는 사실을 알게되었습니다.그래서 세상을 살때 필요한 알고니즘을 알아가고 싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2897, 145, '우리가 생활하는 모든 것의 알고리즘을 알 수 있는 책이라서 무척 궁금하고 재미있을 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2898, 145, '일상에서 다양하게 만날수 있는 알고리즘의 점점 커지는 영향력을 알아보고 원리와 기능을 흥미롭게 이해해볼수 있어서 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2899, 145, '알고리즘에 흥미가 좀 생기네요', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2900, 145, '우리의 삶을 둘러싼 알고리즘의 예를 다루고 있어 좀더 와 닿는 것 같습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (146, '뽀짜툰 3', 197, 4.87, 0, 0, 1, 23, 173, 196, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2901, 146, '고양이의 체온이 인간보다 높은 줄 몰랐어요. 고양이와 친숙해지면 심리적인 안정도 얻겠지만 고양이를 안으면 조금이라도 체온을 높일 수 있다니, 건강에 좋은 동물이네요. 귀여운 고양이 그림과 개성 있는 고양이 이야기가 감동적이었어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2902, 146, '길고냥이들과의 동거 생활, 고양이들의 습성에 관해 알찬 정보를 알려주네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2903, 146, '귀엽고 사랑스러운 고양이 애묘인이 아니어도 사랑스러운 고양이 참 ㅎㅎ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2904, 146, '사랑스러운 고양이들에 대한 책이네요. 너무 귀여워요! 고양이를 키우고 싶은데 사정상 못 키우는 제가 대리만족할 수 있는 책이에요!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2905, 146, '11년간이나 냥이들의 집사로 계셨던 채유리님의 일러스트로 그려낸 그들의 똥꼬발랄한 이야기! 그림도 이야기들도 완전 기대 됩니다옹~~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2906, 146, '고양이를 좋아해서 보게되었는데.. 정말 사랑스러워요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2907, 146, '동화와 함께하는 고양이 이야기 재미있을 것 같다. 요즘 문제가 많이 되는 길고양이의 편견을 없앨수 있는 책인것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2908, 146, '넘 귀엽고 사랑스러운 고양이 이야기, 감동적이에요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2909, 146, '정말 사랑스러운 책이네요. 읽는 내내 행복할 거 같아요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2910, 146, '책이 정말 앙증맞네요 ^^ 귀엽고 사랑스럽습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2911, 146, '웹툰에서 재미있게 읽고 있어요. 귀여운 고양이들의 이야기가 책으로 출간되어 반갑네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2912, 146, '고양이 너무 귀여워요 인간적으로 고양이는 보고 있으면 힐링이 됩니다!!! 보고만 있어도 손발이 따뜻!!! 사정상 키우지 못하는 고양이 책으로라도 ㅠㅠ 고양이는 사랑!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2913, 146, '고양이가 나오는 아주 재미나고 사랑스러운 만화같네요..^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2914, 146, '귀여운 고양이의 모습과 그들의 생활을 볼 수 있어서 좋습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2915, 146, '고양이가 마음을 치유해주는 느낌을 안겨줌.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2916, 146, '고양이들의 재기발랄한 스토리', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2917, 146, '고양이를 키우는 어머니가 계셔서 그런지 그림만 봐도 정다운 느낌', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2918, 146, '사랑스러운 고양이들을 보고만 있어도 마음이 따뜻해지네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2919, 146, '이 책을 통해서 고양이의 매력을 발견했습니다. 고양이 참 사랑스러운 존재네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2920, 146, '고양이와 함께하는 생활속 즐거움을 공유할 수 있어 좋아요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (147, '혁명 극장 1', 197, 4.82, 0, 1, 3, 26, 167, 193, 3, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2921, 147, '혁명의 화염에 휩싸이기전 지극히 평범한 일상을 살았던 사람들 로베스 피에르, 데물랭,당통 횃불을 들고 왕정폐지의 혁명을 울부짓고 정치적인 음모와 이념의 대립, 유럽동맹군의 침공,내란 결국 서로에게 등을 돌리고 혁명의 동지를 단두대에 올린다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2922, 147, '맨부커상을 두차례나 수상한 작가와 로베스피에로의 만남이라니 기대됩니다. 혁명은 언제나 격동적인 테마죠', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2923, 147, '프랑스 혁명이 세계사적으로서 무척 중요한 만큼 제대로 아는 게 중요한데 부록으로 함께 주니까 무척 좋네요. 역사를 좋아하는 저로서는 밤새 읽고 싶은 책입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2924, 147, '잘 모르고 봤을 땐 인문학 서적인줄 알았는데 프랑스 혁명을 소재로 한 역사소설이군요. 특히 맨부커상을 수상한 작품이라 더 기대가 되고 로베스피에르를 필두로 프랑스 혁명을 생생하게 느낄 수 있는 기회가 될 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2925, 147, '혁명가의 삶은 목숨을 걸고 사회를 바꾸겠다는 용기있는 삶이기에 흥미로워요. 많은 피를 뿌려서 겨우 일궈낸 혁명 이야기는 비장미가 느껴집니다. 프랑스 혁명은 많은 작가들에 의해 해석되어 작품으로 나왔지만 프랑스 혁명의 전문가의 소설이기에 더욱 매력적입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2926, 147, '위대했던 프랑스 혁명을 소재로 했다니! 얼른 읽고싶어지네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2927, 147, '보다 뭔가 번잡하고 정리가 안 된 책이네요.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2928, 147, '혁명은 매우 달콤한 말이지만, 때로는 그 달콤함의 댓가가 너무도 혹독할 수도 있다는 걸 로베스피에르와 그의 친구들을 통해 여실히 보여주는 팩션이다. 더 안전한 곳이 무덤일 수밖에 없는 피비린내 나는 프랑스 혁명 시기의 수많은 인간군상을 뒤로한 채, 혁명의 정신을 새로이 넘어설 필요가 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2929, 147, '너무 생동감이 넘쳐서 제가 마치 그시절로 돌아가 현장을 지켜보고 있는 것 같아요, 혁명의 시대, 권력과 정의에 대해 다시한번 생각해보게 하는책, 다소 무거울수 있는 이야기를 흥미있게 그리고 있어요 전개가 빨라서 몰입도도 높네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2930, 147, '소설이지만 프랑스혁명에 대하여 알수 있어 재미있을것 같네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2931, 147, '프랑스 혁명기에 살았던 사람들의 이야기를 다루었군요. 본인들이 혁명을 일으켰지만 각종 이해관계에 얽매여서 본인들도 기요틴의 희생자가 되었던 인물들요. 너무 급진적이었던 것으로 기억하는데, 그 이야기를 소설로 생생하게 풀어내서 프랑스 혁명에 대한 이해도를 약간 이나마 높일 수 있다 싶음', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2932, 147, '프랑스의 혁명을 이끈 세남자의 성장과 마지막 파국에 이르는 과정을 역사를 배경으로 그려지는 소설이라 과연 이세사람의 운명은 어떤 갈림길을 통해 서로 헤어질수밖에 없었던걸일까 궁금하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2933, 147, '재미없게만 느껴지던 역사소설의 새로운 재미를 느끼게 만드는 소설! 혁명이라는 혼란의 시대라니 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2934, 147, '프랑스혁명의 과정을 재미나게 잘 그린 작품이라서 기대가 됩니다~~~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2935, 147, '혁명에 대한 이야기는 많이 있지만 항상 흥미로운 것 같습니다.어떤 것이 역사적 사실인지 가끔은 헷갈릴 정도로 인물들도 멋있게 묘사 되고.이 작품에서는 또 어떤 모습으로 혁명을 다루고 있을지 기대 됩니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2936, 147, '서구사회를 발전하고 바뀌는 계기가된 혁명에 관한 이야기가 주제별로 잘 저술되어 있어서 읽기가 참 좋고 핵심이 잘 되어 있어서 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2937, 147, '혁명가들의 이야기라니 더 기대되는 것 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2938, 147, '혁명 우리는 혁명을 얼마나 알고 있는지 반성하게 됨. 무서운 줄 알아야 함부로 하지 못할 자들이 많아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2939, 147, '｀프랑스 혁명｀이 세상을 어떻게 변화시켰는지 그 결과도 궁금하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2940, 147, '시대를 앞서 나간 혁명가들의 이야기 기대되네요', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (148, '1984', 197, 4.58, 2, 2, 10, 48, 135, 183, 10, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2941, 148, '권력을 가진 자들이 아무리 지난 과거의 역사를 왜곡하고 말살할지라도, 유일한 증거는 ‘내 기억‘이다. 그 기억들이 모여 잊지 말아야 할 역사를 다시 기록해나갈 것이다. 그것이 곧 독재와 전제정치를 무너뜨릴 수 있는 도구가 될 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2942, 148, '내취향 오웰은 확실히 소설보단 수필인듯…오웰이 지금의 자본주의 세상을 살았다면 어떤 소설을 썼을까? 소설 속 주인공은 혁명 전 자본주의 세계를 궁금해하고 갈망하는데 지금을 살고 있는 나로선 여기도 전체주의 못지않게 척박하다고 밖엔…', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2943, 148, '분명 멋진 책이다하지만 이 기분나쁜 느낌들은 뭔지....무서운 책이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2944, 148, '조지 오웰의 천재성이 느껴진다. 미래사회에 대한 당신의 예언은 점점 확실해져 가고 있어요. 이제는 감시의 눈길에서 누구도 자유로울 수가 없다. 곳곳에 숨어있는 CCTV가 당신을 지켜보고 있기때문이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2945, 148, '아버지가 읽었던 헌책부터출판사별로 모은 1984가총8권이네요학교 다닐때 독후감으로 써낸기억남는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2946, 148, '영원한 것은 없다지만,변함없이 권력과 부정 부패 영원하도다~..^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2947, 148, '빅 브라더.지금 내 주변은 어떠한가?나는 그로부터, 이 소설로부터 완전 자유롭다고 할 수 있을까?어쩌면 방심이 제일 위험할 수도 있다.작가가 시사하는 바를 끊임없이 고민하며 비판적 지성을 깨워가야하는 거 아닌가 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2948, 148, '경고는 그대로 현실이 되었다. 조지 오웰의 1984년과 2010년인 현재는 다를게 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2949, 148, '오마이 빅브라더... 참 괜찮았어요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2950, 148, '내 생애 최고의 책. 중요한 것은, 빅브라더의 화면을 끌 수 있는 사람이 있었다는 것.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2951, 148, '아름답다. 그러나, 되돌아오는 것은 그 이상의 절망과 무력함 뿐이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2952, 148, '오웰의 진가는 에세이나 사실주의적 소설에서 발휘된다. 이 소설에 높은 점수를 주지 못하는 이유는 내가 (오웰에 대한) 쿤데라의 입장에 동의하기 때문이다. 즉, 오웰의 디스토피아는 세계와 인간을 단순화시킨다. 나는 그것이야말로 이 소설의 중대한 허점이자 치명적인 약점이라고 생각한다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2953, 148, '통제사회에 대한 예언. 아직까지도 대부분의 미래소설은 1984를 벗어나지 못하고 있는것같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2954, 148, '디지털기술이 날로 발전할 수록 감시 기술도 향상되고 있으며, 이에 따른 개인의 사생활보호가 논쟁의 중심이 되는바, 오웰이 50여년 전에 지은 책 같지 않게 오늘날에도 시의성이 인정되므로 고전중의 고전이라고 할 것입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2955, 148, '예전에 읽어 봤지만 지금 보면 더욱 생각이 많아지는 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2956, 148, '이 시대를 뒤집고도 남을 상상력을 보았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2957, 148, '1984년은 과거가 아니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2958, 148, '지금까지도 여전히 유효한 이야기들. 자신의 고통 속에서 사랑이란 어찌나 하찮은 것인지. 그럼에도 불구하고 사회라는, 고문이라는 세계는 어찌나 지독한지.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2959, 148, '조지 오웰의 1984는 세계 3대 디스토피아 소설으로서 전제주의라는 거대한 지배 시스템 앞에 놓인 한 개인이 어떻게 파멸해가는지를 보여주고 있다. 세계적으로 보이지않는 통제시스템으로인한, 인류의 우민화글러벌 전략시대에 저항하기위해 다시 한번 꺼내들게 하는 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2960, 148, '완벽한 통제의 대척점에 있는 사랑 그 본능적인 감각', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (149, '오무라이스 잼잼 컬러링북', 197, 4.84, 0, 0, 5, 22, 170, 192, 5, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2961, 149, '일상의 음식, 주전부리들, 군것질용,골목골목마다 자리잡은 음식점들의 MSG향기까지 느껴지는 일러스트, 색칠하다가 입안에 침이고여요. ㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2962, 149, '맛있은 음식이 색칠을 통해 먹음직 스런 음식들로 식욕을 자극하는 그림들', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2963, 149, '컬러라서 더 군침도네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2964, 149, '책보다가 책뜯어먹게 생겼어요.. 너무 리얼학', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2965, 149, '음식 컬러링북은 처음인데 재밌게 되어 있어서 해보고 싶네요. 왠지 하다보면 배고플 것 같아요 ㅎㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2966, 149, '음식이 일러스트러 그림으로 나온 컬러링이라서 그런지 색칠하는게 재미있고 정말 재미있게 구성되어 있어서 만족하고 재미있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2967, 149, '컬러링북 되게 좋아하는데 구매하고 싶네요. 그리고 그림도 진짜같아요! 칠하면서 재밌게 칠할수 있는 컬러링북인 것 같습니다! 가지고 있기만 해도 든든한 책일 것같네요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2968, 149, '컬러링북이 요리와 만났다. 우리의 풍성한 먹을 거리도 보고 소소한 재미도 느끼고... 이렇게 많은 먹을 거리가 있는 것 또한 놀라움을 준다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2969, 149, '이렇게 맛이있는 컬러링북이 있다니요!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2970, 149, '먹방을 왜 보는지 이해하지 못하는 사람은, 자신을 한번도 심각하게 객관적으로 바라보려 노력해보지 않은 사람이다. 인간 머리속은 의식주와 욕망이 대부분을 차지한다. 그래서 책이 매력적이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2971, 149, '웹툰이랑 비교하면서 색칠 하면 되겠네요ㅋㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2972, 149, '여러 음식을 가지고 색칠하고 체험하는 컬러링북은 매우 독특하다고 생각하여 이렇게 추천을 드립니다. 이런 오감을 자극하는 책은 한참 자라는 아이들에게 특히 더 좋게 느껴집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2973, 149, '초등학교 인기있는 책중 하나인 오무라이스 잼잼의 컬러북이라니 정말 색칠하면서 먹고 싶은 생각이 막 들거 같아요 화려한 색으로 칠하고 감상해보고 싶네요 정말 재미있을것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2974, 149, '넋놓고 칠하다보면 어느새 스트레스 해소', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2975, 149, '침샘을 자극하는 수백가지의 일러스트를 통해서 일상의 음식 이야기도 나눌수 있고 색칠하면서 새로운 재미도 느낄수 있을듯 해서 좋네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2976, 149, '맛있는 먹거리들을 잼미있는 일러들로 엮어 색칠한다는 것이 독특해요 잼미있는 아이템 컬러링북이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2977, 149, '음식을 소재로한 컬러링북을 통해서 책과 독자가 1:1로 소통하는 새로운 형태의 1인 쿡방과 같은 느낌을 주는 신선한 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2978, 149, '역시 이런 음식관련 컬러링북이 나와야했어! 사실적이면서도 보는 이를 흐뭇하게 하는 컬러링북.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2979, 149, '저자의 오무라이스 잼잼 만화책을 보면서 음식, 그에 대한 추억등을 떠올리며 침을 질질 흘렸었는데(절대 배고플때 보지 않는 책), 컬러링 북으로 나왔네요. 오무라이스 잼잼 책보다 좀 더 그림이 디테일하게 그려진 듯 하네요. 일단 먹는 것이라 참 좋은데, 문제는 색칠하면서 다이어트는 저멀리??', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2980, 149, '정말 참을수가 없는 책입니다. 다이어트 하시는 분들은 이 책을 피하세요ㅠㅠ 정말 맛있는 그림에 색칠하다가 음식사러 뛰쳐나가게 됩니다. 컬러링으로 힐링 좀 하려다 폭식하게 생겼어요ㅋㅋㅋ', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (150, '퍼니!', 197, 4.85, 0, 0, 1, 28, 168, 196, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2981, 150, '오래 전 나의 꿈은 만화가였다. 그 꿈에는 몇 가지 만화들이 영향을 주었다. 디즈니 만화로는 타잔과 라이온 킹이 그랬다. 그런데 이 만화들은 움직이는 애니메이션이고, 정지된 그림이 아니라 따라 그리기 힘들었다. 를 보니 그때 생각이 난다. 잊고 있던 오래 전 꿈이 떠올라 설레는 맘이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2982, 150, '디즈니-픽사 20년의 모든 작품이 수록된 아트북,스케치 노트에 따라 그리고 있어요.이런 스케치들이 화려하고 아기자기한 웃음을 주는 애니들이 였다니..원작들을 손으로 따라 그리는 재미가 큽니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2983, 150, '픽사의 모든 작품들에 대한 초기 아이디어를 고스란히 훔쳐볼 수 있는 책이겠군요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2984, 150, '디즈니픽사의 작품이라면 거의 다 봤답니다. 디즈니 명작의 탄생과정을 볼 수 있는 유일한 책이기에 소장 가치가 있네요. 애니메이션에 관심이 많은 아이들이라면 모두 좋아할 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2985, 150, '디즈니-픽사의 역사를 알수 있다. 수 많은 만화영화들이 어떻게 제작 되었는지 영화의 아이디어는 어디에서 얻었는지등 만화영화에 대하여 소소한것까지 알수 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2986, 150, '와우! 우리 아이와 함께 즐겁게 보았던 애니매이션 DVD로 여전히 소장하고 있는 작품도 많은데, 이렇게 디즈니-픽사 20년의 모든 작품이 수록된 아트북이라니 정말 멋지네요. 책을 읽는 순간순간이 더욱 행복한 시간이 되겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2987, 150, '이런 소장가치 넘치는 책이 출간되다니! 이런건 꼭 사야 해요! 토이스토리부터 디즈니-픽사 장품을 정말 사랑했는데 인사이드아웃도 대박나고 주옥 같은 만화 영화 작품을 울고 웃었던 기억이 나네요. 책꽃이를 꼭 장식해야 할 책이에요 매니아뿐만 아니라 일반인에게도 강추!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2988, 150, '요즘 웨스앤더슨의 그랜드부다페스트호텔 아트북에서부터 시작해서. 이렇게 픽사의 영화들이 어떻게 만들어졌는지를 다루는 책까지! 그 속이야기를 너무나도 반갑고 기쁘다. 그래서 얼른 사서 보고 싶어 죽겟다. 그러나 아직 한달이라는 시간을 기다려야 한다니ㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2989, 150, '합작의 힘! 소장가치로서 빛나네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2990, 150, '매니아들이 소장하고 싶은 픽사의 숨은 아이디어와 명장면이 들어있는 아트북', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2991, 150, '오호~~ 좋아하는 애니메이션인 디즈니 픽사의 작품들이 모두 모였군요. 애니메이션 탄생 과정, 초기 드로잉 등을 만날 수 있기에 멋진 책입니다. 기대가 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2992, 150, '사랑받는 애니들이 어떻게 만들어지기 시작했는지 원안 스케치들을 보면서 알수있네요. 간단한 스케치에서 무궁한 스토리가 나온다는 것이 신기하네요. 애니 좋아하는 친구에게 선물로 좋을 것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2993, 150, '픽사 애니가 나오면 꼭 챙겨볼정도로 좋아하는데 원안 스케치를 이렇게 볼수 있다니.. 한장한장 보면 오래전에 봤던 토이스토리 생각도 나고 흐뭇하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2994, 150, '요즘 아트북들이 인기가 많은데, 디즈니 픽사 아트북이라 훨씬 기대가 됩니다. 아이와 함께 읽으면 재미있을것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2995, 150, '와~ 처음 보자 마자 소장욕구 100% 이네요. 디즈니와 픽사의 아트 컬렉션이라니! 이 책을 통해 디즈니,픽사와 함께했던 긴 시간들의 추억을 다시금 꺼내보고 싶어요. 제 아들에게도 아빠가 이러한 애니를 보고 자랐다고 이야기 해보고 싶네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2996, 150, '원안 스케치라니 픽사 작품의 팬이라면 놓치지 말아야겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2997, 150, '픽사 작품들의 팬인데, 원안과 영화를 비교해보면 재미있을것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2998, 150, '인사이드 아웃의 우리 슬픈이가 도서로 나왔군요...일단 구매!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (2999, 150, '원안 스케치가 사랑받는 캐릭터로 탄생하기까지의 과정을 볼 수 있어서 재미있어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3000, 150, '팬뿐만 아니라 대작들이 어떻게 탄생했는지 알고 싶은 크리에이터들에게도 유용한 책!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (151, '열두 살에 부자가 된 키라', 197, 4.46, 1, 5, 21, 46, 124, 170, 21, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3001, 151, '어린시절에는 재밌게 읽었으나 그렇기때문에 아이들에게는 권하고 싶지않다. 경제상식을 가르쳐주는 책이지만, 열두 살에 알아야 할 필요도.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3002, 151, '어렸을때 읽고 저축의 중요성을 알게해준 고마운 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3003, 151, '이거. 초등학생때 본 책이거 꽤 재미있어요.초등학생들에게 추천.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3004, 151, '미하엘 엔데 작품을 선택하고 싶기도 하지만, 이 책은 어린이들이 꼭 봤으면 해서 입니다. 저는 성인이 되어 읽었는데도, 이런 걸 부모든 아이든 봤다면 인생에 아주 작은 변화라도 주지 않았을까 생각합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3005, 151, '열두살에 부자가 된 키라 이야기... 정말 재미있고 쉽게 쓰여져 있어 아이들이 읽기에 딱이네요. 초등학교 다니는 아이에게 매주 용돈을 주는데 늘 부족하다고 투정입니다. 아이에게 올바른 경제교육이 필요할것 같아 이것 저것 책을 보다가 열두살에 부자가 된 키라책을 읽게 되었어요. 키라도 우리 아이 처럼 처음에는 부모님께 받은 용돈이 늘 부족해서 어떻게 하면 용돈을 더 많이 받을까? 하고 궁리를 하게 됩니다. 하지만 키라네 부모님 역시 형편이 넉넉하지 못하지요. &nbs...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3006, 151, '우리 나라는 식민지, 전쟁을 거친 대표적인 후진국에서 거품경제고, 국가 독점 천민 자본주의 형태이긴 하지만 세계 몇십 위의 경제적 지위를 누리게 되는 특수한 구조를 거쳐왔다. 그래서 지금의 성인들은 무조건 근검, 절약 외에는 국산품 장려 정도가 경제 관념의 모두라고 할 수 있다. 조금 눈을 뜨는 사람들은 부동산에 투자하거나(이건 투기다. 범죄행위라고 할 수 있겠다.), 주식을 들여다 보고 있지만, 워낙 냄비 경제가 되다 보니, 몇 백 만원 오락 가락 하는데, 화병으로 골병들고 술값이 더 나가게 생겼다. 이제, 우리도 아이들에게 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3007, 151, '키라는 집 앞에 쓰러진 하얀 개 래브라도를 발견한다. 평소 개를 키우는 것이 소망이었던 키라는 정성어린 손길로 보살펴 건강을 되찾게 도와준다. 그러던 어느날 돈 때문에 고민하던 키라 부모님의 대화 속에서(머니 머니 해도 머니가 최고다....~~~~~) 래브라도는 ''머니''라는 멋진 이름을 얻게 된다. 이 신기한 개 머니는 키라와 침묵으로 말을 하기 시작한다...오호~ 키라에게 돈에 대한 이야기를 해준다. 돈이 인생에서 얼마나 큰 힘이 되는지를 조금씩 깨닫게 해준다. 키라는 돈이라는 무거운 주제에 대한 거부감을 머니의 도움...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3008, 151, '7.8어린이가 돈을 벌 수 있는 어떤 방법이 있을까? 이 책에서는 생각보다 쉬운 방법을 제안한다. 돈을 버는 법을 주변에서 찾을 수 있다. 이웃 어른들에게 심부름을 제안하고 그 대가로 돈을 받는 것인데, 요즘 대학생들이 생활비나 학비 등을 벌기 위해 아르바이트를 하는 것과 비슷한 방법이다. 돈을 번 뒤에는 그 돈의 용도를 나누어 알맞게 사용하는데, 용돈, 저축을 할 수도 있고, 투자를 할 수도 있다. 경제라고 하면 어려운 내용부터 떠오르지만, 이 책을 읽다보면 경제의 기본 개념들-이를테면, 기업이 어떻게 생겨나는지, 주식 투자가 무...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3009, 151, '이 책을 안 것은 3년 전. 산 것은 1년 전. 그리고 읽은 것은 바로 지금.. 돈에 늘 허덕이는 내 삶에 새로운 희망을 엿보이게 한 책이었다. 누구나 돈을 벌고 싶고 쓰고 싶다. 그러나 정말 확연한 목표가 있어서 그러는 것보다는 막연한 심리일 뿐이었을 것이다. 나또한 그랬으니까. 그런데 이 책을 읽으니 목표가 정말 뚜렷하게 보이게 되었다. 아이들을 위한 책이 아니라 모든 사람들을 위한 책이다. 함께 공유하고 싶은 동화책이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3010, 151, '전 그리 똑똑하지 못합니다. 돈을 버는 대로 쓰고 저축하는 가난한 서민입니다. 월급을 적게 받기때문에 모아지는 돈이 적다고 생각해 왔는데 우연히 이 책을 읽으면서 그 생각이 바뀌었습니다. 어린이 책이지만 너무나 많은 내용을 담고 있습니다. 부자가 되기위한 마음가짐과 준비, 실천, 결과. 경제학에 관심이 조금은 있었지만 시중에 있는 책들은 너무 어려워 펴자마자 덮고 좌절했었습니다. 하지만 키라는 어린이도 볼 수 있게 쓰여졌기 때문에 저 같은 무지한 이도 머리속에 쏙쏙 들어왔습니다. 어려운 말과 문장은 하나도 없어요. ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3011, 151, '보도 섀퍼의 어린이를 위한 경제 동화 >가 우리집 서재에, 아니 딸아이 방에 자리한지 꽤시간이 흘렀다. 딸아이가 초등학교 5학년때 구입했으니 꼬박 일년이 지났다. 언젠가는 한 번 읽어봐야지 하고 생각뿐이었는데 마침 한가한 시간을 틈타 단 몇시간만에 훌륭한 "경제 공부"를 할 수 있었다. 아이들을 위해 풀어쓴 경제 동화여서 그런지 딱딱한 느낌이 없고 손쉽게 어려운 경제 활동등에 대해 설명하고 있어 유익한 책이라고 할 수 있다. 비단 어린이들...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3012, 151, '이 책이 화제가 되어 베스트셀러가 되던때! 저는 ''저런 책이 뭐가 재밌을까?''하는 생각을 했지요?^^ 솔직히 12살에 부자가 된다니... 말이 안된다고 믿고 있었죠ㅇ_ㅇ 그래서 그냥 책을 사지 않고 다른 책을 보곤 했어요. 그런데 주위사람들은 모두들 이 책을 읽었다고 하더네요?? 그래서인지 요즘 부쩍들어 나에게 떡볶이를 아주 잘 사주던친구가 용동을 아껴야 한다며 떡볶이를 사주지 않더군요. =ㅠ= 그래서 저는...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3013, 151, '이 책은 지난 토요일, 동화읽는 엄마 모임의 토론도서였다. 수없이 쏟아져 나오는 경제관련 도서 중에서 상당히 오랜동안 사랑받는 책이고, 어린 독자들이 ''나도 한번 해봐~''라고 도전을 느낄만한 책이다. 하지만 책에서 아무리 좋은 것을 가르쳐 줘도 실천하지 않는다면 아무 의미가 없는데, 이 책도 외국의 사례라서 우리 실정에 맞게 실천하는게 관건이라 할 수 있다. 2004년 12월 29일에 읽고 독서노트에 남긴 내 기록은 좀 삐딱하다. 아무래도 내 성향이 좀 삐딱이라고 이해할 밖에... 게다가 요즘은 애 어른 할 것 없이...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3014, 151, '어린이 경제동화로 이만한 책을 찾아보기 힘들듯하다. 경제와 주식, 투자, 재테크라는 전문적인 내용을 알기쉽게 설명해놓은 것도 좋았고 재테크에 초보이거나 무관심했던 어른들이 보기에도 괜찮아보인다. 또한 아이들이 본문에 속한 내용을 모두 이해하고 실생활에 적용하지 못한다 할지라도 자신들의 용돈 하나만큼은 제대로 사용할것이라 여겨졌다. 우리가 살아가는데 돈이 최고는 아니지만 많은 것이 돈에의해 좌우된다. 나 또한 아이들에게 어릴적부터 경...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3015, 151, '우리 나라가 IMF를 거치면서 경제에 대한 일반인들의 관심이 상당히 높아진 것 같다. 그에 대한 반증으로 경제관념은 어릴 때부터 길러주어야 한다는 주장이 나오면서 어린이 경제서들이 눈에 띄게 출판되는 것 같다. 그 중 몇 권을 읽었는데 이 책은 ''팰릭스는 돈을 사랑해''와 닮아있다는 생각이 들었다. 책을 읽으면서 정리를 해 보면 돈을 벌려고 하는 목적에서부터 시작하여 돈을 버는 방법, 관리하는 방법까지 돈의 순환과 흐름을 한 눈에 알 수 있게 정리가 된 책이다. 이 과정을 키라라는 여자아이가 한 일을 예로 동화가 구성되는데 한 가지 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3016, 151, '나는 얼마전에 열두살에 부자가 된 키라라는 책을 읽었다. 처음에는 길고 그림도 별로 없어서 재미가 없는 책인줄 알았다. 그런데 꾹 참고 읽었는데 키라라는 애가 열두살밖에 되지 않았는데 벌써부터 돈을 모은다는 생각을 하다니.. 정말로 키라는 기특한 아이인것 같다. 나는 돈을 모은다고 해서 맨날 저금통에서 돈을 하나둘 꺼내서 지금은 돈이 10원짜리 몇개밖에 없다. 근데 나도 머니라는 강아지 하나쯤은 있었으면 좋겠다. 그래야 나도 돈에대해서 잘 알고 그만큼 아껴쓰니말이다. 머니같은 환상속의 동물을 책에서밖에 보지못한다니..휴~ 나는 돈에...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3017, 151, '호기심으로 사게 된 이 책에서 나는 경제에 대한 인식을 바로 갖을 수 있게 되었다. 돈에 대해서 개념이 없는 나는 돈을 흥청망청 쓰기에 바빴다. 하지만 이 책에서 열두살인 나와 같은 나이에 부자가 된 키라는 나에게 커다란 충격이 아닐 수 없었다. 물론 말하는 개 머니의 충고가 큰 도움이 되었겠지만 정말 부러웠다. 하지만 나도 물론 키라처럼 부자가 되고 싶기는 하나, 사실 우리 대한민국에서는 우리 같은 나이에는 무조건 공부만 하라는 어른들의 말씀만 있지 아르바이트는 꿈도 꿀 수 없다. 더구나 우리 나이를 받아주는 곳도 있지 않다. 주...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3018, 151, '이책의 줄거리는 키라라는 아이가 어느날 우연히 어떤개를 만나개된다.그 개를 머니라고 이름을 짓고 같이 살아간다.그런데 머니가 강물에빠지게 된다.키라는 무작정 강물에 들어간다.단지 머니라는 개를 구하기 위해 말이다.여기서보면 키라는 생명존중 의식을 가지고 있는 것 같다.머니를 구하고 나서 머니와 키라는 말할수있게된다. 머니도 자기를 목숨걸고 구해준 키라의 행동에 감동을 받았나보다.그렇게 머니와 돈에대해 많은것을 배우면서 여러사람들을 만나고 부정적인 사고에서 긍정적으로 바뀌는 이야기다.깊이생각한 부분은 골드슈테른 아저씨가 머니를 가져가...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3019, 151, '돈이라는 것에 대한 중요성과 그 이면을 가르쳐준 소설이다. 나에게 있어서 돈이란 어떤 존재일까? 과연 돈으론 어떤 일을 할 수 있을까? 라는 생각이 들었다. 이 책에선 그걸 가르쳐 주었다. 비록 우리나라에선 잘 하지 않는 어린아이들이 쥬스를 만들어 판다는 그런 내용도 있긴 하지만... 대략적인 부분에 비추어 보았을 이 책에 내용은 돈의 중요성과 돈을 사용하는 법을 가르쳐 주는 듯 하다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3020, 151, '저 개인적일지는 모르겠지만 우리나라와는 꽤나 거리가 먼 얘기라고 생각합니다. 우리나라 같으경우에는 저 나이에 부모님들이 공부만 시키는 실정이어서...', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (152, '시사경제잡설', 196, 4.81, 1, 0, 3, 28, 164, 192, 3, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3021, 152, '뉴스를 해석하는 저자만의 방법이 사실 속에서 진실을 가리고 했나 봅니다. 저자처럼 수많은 정보속에서 진실을 알 수 있는 시각을 가지고 싶군요.뉴스에 대한 진실의 통찰력을 키울 수 있는 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3022, 152, '번뜩이는 통찰력으로 베일에 가려진 경제 환경의 진실,페이지가 줄어드는게 아까울정도네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3023, 152, '우리가 역사를 공부하는 이유와 같다는 생각입니다. 시사경제 역시 ...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3024, 152, '우리가 이해하는 세상에서 진실과 거짓의 차이를 구분지어보자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3025, 152, '우리 삶은 경제를 빼놓고는 생각할 수가 없을만큼 지대한 영향을 받는다. 부동산에 관심을 갖기 시작한 이후 경제뉴스를 빼놓지 않고 보고 있다. 중요한 것은 다가올 미래를 현재를 통해 이해하고 준비하는 게 중요한 것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3026, 152, '교묘한 레토릭으로 투자 혹은 투기만을 부추기고 결국 책임은 개인에게 되돌리는 책이다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3027, 152, '시사경제를 올바로 보는 눈을 키우는 책이군요. 뉴스 속에서도 진실을 알 수 있는 혜안이 필요함을 느꼈기에 유익한 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3028, 152, '남들 하는대로하면 못벌죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3029, 152, '경제적 사실과 진실이 다르다는 것. 제대로 알지는 못 해서 더 알고 싶어요. 위기라는 것의 진정한 위기가 무엇인지 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3030, 152, '사실과 진실이 다르다는 것에 초점이 맞춰진 것이 무척 흥미롭구요 다양한 주제를 가지고 논의하는게 재미있습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3031, 152, '경제에 관한 책은 많이 접하지 않는 편인데 시사경제 잡설이라니 왠지 가볍게 읽을수 있어서 좋을거 같아요 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3032, 152, '시사경제잡설이라니 흥미가 생기네요. 가볍기만 한 책도 아니라 알아두면 좋을거 같아요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3033, 152, '경제를 전공하고 실 금융권에 몸담았던 저자가, 부동산 및 각종투자.등의 재테크시 유용한 팁과 정보들을 전합니다. 단편적인 정보만을 가지고 섣부른 실수에 쉽게 노출될수 있는 일반인들에게 가려진 진실을 알고 경제적 혜안을 갖출수 있게 돕는 훌륭한 경제 흐름 지침서라 할것입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3034, 152, '뉴스를 챙겨 보고 있지만 항상 약한 분야네요 모르고 있던 사실들을 시원하게 알려줄것 같아요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3035, 152, '니나가는 개도 위기라고 말하는 지금이라는 우숫개소리에서 웃었습니다. 아무튼 위기인데 시장 전체를 꿰뚫는 혜안과 통찰을 기대합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3036, 152, '경제에 대한 새로운 시각을 배울 수 있었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3037, 152, '다수의 책들이 하락을 얘기할때, 논리적인 반박.여러 의견과 데이터를 확인해야 남들이 못보는 미래를 볼 수 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3038, 152, '우리가 알고 있는 경제는 실생활에 얼마나 도움이 될까를 생각하게 하는 시사경제잡설이다. 미래 경제를 예측하는데 많은 도움이 된다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3039, 152, '주제가 꽤 흥미롭습니다. 평소에 생각해 보지 못하거나 당연히 그럴 것이라 생각하는 각종 경제의 이면을 이야기하고있기 때문입니다. 30일 무이자를 외치는 대부업체의 함정이나 서민주택정책의 해결책이 임대 주택이 아니라는 것 등등 아~ 싶은 것들이 꽤 많았거든요. 경제학접근이 아니라 안어려움', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3040, 152, '경제에 둘러싸야 살지만, 읽어내기가 쉽지가 않죠. 이 책에서 도움을 받고 싶네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (153, '정신의학의 탄생', 195, 4.86, 0, 0, 2, 23, 170, 193, 2, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3041, 153, '정신 의학에 대한 오해와 편견을 깨는 정신의학의 역사네요. 글을 재미있게 쓰는 저자이기에 네이버 캐스트에서도 인기가 있었을 것 같네요. 정신 의학의 역사는 인간 이해를 위한 역사라는 점에서 가치있는 학문이군요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3042, 153, '부서지고 찟겨진 마음의 상처를 꿰메주는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3043, 153, '프로스트나 융처럼 어렵게 느껴지던 심리학을 쉽게 배울수 있을것같네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3044, 153, '정신의학의 세계로 풍덩', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3045, 153, '현대인들이 정신질환을 많이 갖고 있다는 것 자체가 인생이 그만큼 힘들기때문이 아닌가 싶어요. 조금이라도 짐을 내려놓고, 욕심을 조금만 버리고 마음에 휴식을 취해보시면 어떻까요?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3046, 153, '보통 별 꽉꽉 채워서 잘 안 주는데, 대학에서 학문전공시 학문 간 공부 할때 배경지식으로도 좋고 교양입문서로도 매우 훌륭함. 기본적 배경지식은 모두 다 갖추고 있음.여기 나오는 내용들은 다 알고 있어야......', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3047, 153, '정신의학분야는 전문적인 분야라 일반인으로서 잘 알기 어려운 학문이라고 생각했어요. 그런데 이 책은 전문가가 일반인도 이해할 수 있도록 잘 풀어서 설명하고 있어서 읽어나갈수록 재미있어요. 과거의 정신의학에 대해서부터 현재까지의 정신의학까지의 이야기들이 담겨있어 흥미로워요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3048, 153, '정신의학의 역사를 따라가면서 정신의학 실험, 연구 등을 차례대로 설명하고 있습니다. 정신의학박사가 쓴 책만큼 내용들이 믿음이 갑니다. 정신의학이라고하여 심각한 정신문제에 대한 글만 실렸을까 우려했지만 성격이나 심리관련 등 재미있는 부분도 많아서 추천합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3049, 153, '현대인에게 있어 정신의학은 꼭 공부해야 할 분야 같아요. 누구나 정신이 힘들어 병이 나니까요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3050, 153, '의학의 한분야로 들어간 정신의학의 기본부터 탄탄히 다실 수 있는 교양서적이라 생각이 듭니다. 정신의학에 관심이 있었는데 이 책을 통해서 많은 기본지식을 쌓은 것 같습니다. 정신의학이 어떻게 발전했는지 알게 되어서 흥미롭네요. 내 인생 최고의 책!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3051, 153, '정신건강의학에도 관심을 기울여야겠네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3052, 153, '꼭 병원을 찾지 않더라도 크고 작은 정신적인 문제들은 현대인이라면 피할 수 없는 것 같아요 그동안 궁금했던 정신의학에 대한 오해와 궁금증을 한번에 풀 수 있을 것 같아서 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3053, 153, '정신의학의 역사를 재미있게 풀었네요. 인간 이해의 역사이기에 흥미롭네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3054, 153, '정신의학에 대해서 궁금한것들이 있었는데 책을 읽어보면서 자세히 알고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3055, 153, '정신질환에 관한 여러가지 정보를 읽어볼수 있는 책인거 같아 기대됩니다. 전문가들에게도 도움이 되는 책이라니 믿고 볼수 있을거 같습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3056, 153, '정신의학의 정확한 개념과 현실과 접목할수 있는 방법 제시등 좋았습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3057, 153, '정신의학에 대해 항상 잘 알고싶었습니다. 이 책을 통해 많은 것을 배웁니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3058, 153, '평소 정신의학에 관심이 많았는데 일반인이 볼만한 책은 많이 없었거든요. 이 책은 그동안 제가 찾던 책이라 반갑네요. 열심히 읽어서 우리의 정신에 대해서 배우고 싶고 알고 싶어요. 지금 구입하러 갑니다 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3059, 153, '정신의학에 대해서 자세하게 알 수 있어서 좋을 것 같습니다 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3060, 153, '아직 그리 일반적으로 알려져 있지 않은 분야라서 더욱 흥미롭네요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (154, '테오도루 24번지', 195, 4.84, 0, 1, 1, 26, 167, 193, 1, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3061, 154, '신의 선물이라는 뜻의 테오도루에서 들려주는 감동적인 이야기에 뭉클해집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3062, 154, '그리스 빈민가를 중심으로 펼쳐지는 상처입은 소년 소녀들의 우정과 사랑 이야기, 버려지고 버림받은 인생조각들, 삶의 진정한 가치를 찾아 헤메는 영혼들', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3063, 154, '제목만 봐선 외국작가의 작품인 줄 알았더니 우리 작가의 작품이네요. 경제위기속의 그리스를 배경으로 한 작품이라 뭔가 통하는 게 있을 것 같네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3064, 154, '이웃들의 함께 살아가는 그리운 정경의 이야기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3065, 154, '가족 해체의 아픔속에서 그리스 부자동네 테오도루(신의선물)에서 일어나는 갖가지 삶의 흔적을 볼수 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3066, 154, '그리스라는 이국적인 장소가 배경인 점과 피부색이 다른 이ㄱㄲ의 두 소년의 우정이 아름답답게 묘사되어 있을 듯 해서 기대됩니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3067, 154, '가슴에 톡- 톡- 신호가 왔다. 뭉클하면서도 뿌듯한.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3068, 154, '어디나 사람사는곳이죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3069, 154, '한국 문학이 어떻게 종횡으로 세계 문학과, 혹은 세계 그 자체와 접점을 가질 수 있는지 보여주는 작품이 될 것 같아 기대됩니다. 때로 상처를 어루만져 줄 수 있는 건 호의보다는 같은 농도의 상처라는 점에서 이 소설은 상처 많은 세상을 살아가는 우리에게 더욱 뭉클하게 다가오는 게 아닐까요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3070, 154, '나와너 가족간의 유대와 화해를 그리스라는 이국적인장소에서 그려지는데요 표지부터 내용까지 기대됩니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3071, 154, '그리스 빈민가를 배경으로 작가님께서 유학시절 거주했던 장소와 그 이웃분들을 모델로 만든 책입니다. 간만에 사람냄새를 느낄 수 있는 이야기였습니다.^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3072, 154, '한국소설인데, 배경은 그리스라 처음엔 낯설게 느껴지지만 그 낯설음이 신선했어요. 아이의 성장을 통해 외국인 노동자에 대해서, 부모자식간의 관계에 대해서 생각하게 하며 읽는 사람도 함께 성장하는것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3073, 154, '청소년소설이 아이들에게 교훈도 주면서 정말 수준이 높은 작품이 많은 것 같습니다. 대상을 수상한 작품이라서 더욱 기대가 되네요. 저자가 살았던 그리스가 나와서 사실감이 넘칠 것 같아요. 테오도루에서 어떤 일이 일어날지 궁금합니다. 청소년을 위한 소설로서 강추합니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3074, 154, '가족, 인간, 소년, 인생. 다채로운 이야기를 통해, 청소년들이 꼭 알아야할 관계적 조언을 풀어냅니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3075, 154, '좀 지루한 청소년 소설. 배경만 그리스일 뿐, 별다를 것도 없는 이야기. 경제가 무너진 후 그리스의 분위기 - 특히 외국인에게 적대적인 - 와 해체되었다가 다시 결합한 가정의 위태로움, 극복하지 못한 트라우마 들을 건드리지만 깊이 들어가진 않는다. 좀 시시했다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3076, 154, '그리스라는 생소한 나라가 배경이기는 하지만 평범한 사람들의 다양한 사연들이 있는 우리가 쉽게 볼 수 있는 현실적 삶을 바탕으로 한 것 같아 눈길이 갑니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3077, 154, '주인공인 민수의 상처와 비슷한 사람들과의 만남으로 성장하는 이야기라서 좋습니다. 각 인물들의 심리와 성격을 작가의 표현력으로 잘 저술되어 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3078, 154, '그리스 빈민가를 배경으로 한 소년의 성장기가 흥미를 끄네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3079, 154, '그리스를 배경으로 한 성장 소설이라는 것만으로 관심이 가네요잔잔한 성장소설 기대합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3080, 154, '아직은 오지 않은 그 순간을 기다리는 것', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (155, '화폐의 몰락', 195, 4.82, 0, 0, 4, 28, 163, 191, 4, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3081, 155, '언제나 위기의 연속인 것 같은데, 읽어보고나서 미리미리 예방해야겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3082, 155, '위태로운 금융위기를 어떻게 겪어낼수 있는지 도움을 받을 수 있는 책이로군요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3083, 155, '화폐라기 보다는 달러의 몰락이 더 정확한 표현이지 않을까 하는 생각을 해보게 된다. 달러를 대체할 금,SDR 그리고 비트코인 등 다양한 각도에서 설명하고 있지만, 달러 몰락의 시대에 그가 제안하는 대안은 부채에 시달리는 나 같은 서민에게는 어울리지 않는 것이서 결론이 많이 아쉽다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3084, 155, '백자평 폭발이네. 작업하셨나?', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3085, 155, '통화의 흐름, 강자들이 총칼 없이 현대를 사는 방법.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3086, 155, '현 상황에 있어서 이해가 될 만한 책이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3087, 155, '화폐의 몰락과 경제, 미래를 대비 하기 위해 꼭 읽어봐야할 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3088, 155, '세계 경제 흐름에 관한 내용이라 읽어두면 참 좋을것 같네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3089, 155, '국제 금융위기가 몰려온지 얼마 지나지 않은것 같은데 이번에 또 큰 폭풍이 몰아칠 것 같네요. 이 책에서 미래를 내다보고 앞날을 설계해야 할 것 같습니다. 모두의 나침반이 되어주는 책입니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3090, 155, '앞으로의미래는어떨지 예측해보는한권의책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3091, 155, '화폐의 몰락이라니, 말만 들어도 소름이 끼치네요. 그리고 통화시스템이 붕괴된다면 어떤 현상이 발생할지 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3092, 155, '현재 일어나고 있는 또 일어날 것 같은 이야기라 더 읽어보고 싶고 일어나지 않았으면 하는 바램이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3093, 155, '어려울 것 같지만 의외로 쉽게 풀어낸 경제책. 이 책 한 권 정도는 마스터해야지, 올해는.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3094, 155, '앞으로 다가올지도 모를 금융위기에 어떻게 대처해야할까를 생각하게 하는 책이네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3095, 155, '화폐의 몰락에 대해서 요즘 종종 나오곤 하는데.앞으로 미래의 세계 경제에 대한 생각을 해 보게 됩니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3096, 155, '화폐가치의 낮아지면서 발생할 수 있는 여러가지 상황들에 대한 이야기를 흥미롭게 읽을 수 있습니다. 그가 이야기하는대로 대비할 수도 있을겁니다. 하지만 정보에 너무 휘둘리지 말고 깊은 사색도 필요할 것 같군요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3097, 155, '화폐의 몰락 그리고 경제에 대해.. 읽어봐야 할 책 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3098, 155, '미국 금리 9월에 올린다에서 다시 올해 안으로 늦추어지는듯한데요. 원화가 어찌될지 걱정되는 사람이 읽어야 되는 것 맞죠?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3099, 155, '국제금융 위기는 어제, 오늘의 일이 아니다. 십수 년 사이에 미국발 금융위기 등 몇 차례 파동을 겪었다. 그러나 조만간 그보다 훨씬 심각한 금융 쓰나미가 몰려올 가능성이 농후하다. 과연 취약한 우리 경제는 어떻게 대비해야 할 것인가. 치밀한 금융 정세 파악 및 철저한 대비가 필요한 시점이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3100, 155, '두려운 현실을 직시하게 하는 미래 예언서. 정말 화폐는 몰락할 것인가. 진지한 주제를 다뤘다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (156, '어린 왕자 동화 컬러링북', 195, 4.86, 0, 0, 1, 25, 169, 194, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3101, 156, '위로가 필요한 어른들에게 어린왕자의 시선으로 본 세계를 색칠하다보면 진정으로 소중한 존재가 무엇인지 다시금 깨닫게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3102, 156, '컬러링을 하며 동화속에 빠져드는 느낌을 받는다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3103, 156, '여전히 아름다운 동화 어린왕자의 컬러링북 책속 명장면에 색칠하는 동안 다시금 눈으로 보는 명장면', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3104, 156, '컬러링북의 끝판왕이며 특히나 소재가 어린왕자라 마음에 드네요 이렇게 아름답게 표현된 컬러링북이 또 있을까 싶을 정도네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3105, 156, '어린왕자 컬러링북이라니 정말 최고의 기획이네요. 어린왕자를 그림으로써 어린왕자와 감수성을 공유해 보아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3106, 156, '단순한 컬러링이 아니라 어린왕자 이야기를 되새겨볼 수 있다는 점이 마음에 든다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3107, 156, '영원한 동화 어린왕자. 이렇게 직접 일러스트를 채색하며 작품과 어린왕자에 몰입하는 것 또한 색다른 경험과 의미인 것 같네요. 어린왕자와 여우, 코끼리와 보아뱀 등 손수 채색하며 느끼는 기분이 참 묘하면서도 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3108, 156, '어린왕자의 줄거리가 다시한번 떠오르는 듯한 느낌을 받는다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3109, 156, '책을 통해서 많이 접한 어린왕자가 컬러링북으로도 나왔네요. 예쁘게 색칠하면서 책을 읽을때의 감동을 다시한번 생각해보고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3110, 156, '컬러링을하면서 생텍쥐페리와 이야기를 나누는 기분일것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3111, 156, '컬러링북을 좋아하는데요. 더구나 고전명작 컬러링북은 무척 좋아합니다. 어린왕자 컬러잉북, 이상한 나라의 앨리스 컬러링북, 모두 아끼는 컬러링북입니다.특히 어린왕자 컬러링북은 동화 내용을 상기하면서 순수한 세계로 들어가기에 더욱 좋아합니다.마치 어린왕자를 만나는 기분이 들 정도예요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3112, 156, '어린왕자는 고전중에 고전인데 책도 읽고 그림도 그리고 일거양득이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3113, 156, '그림이 정말 세련되고 환타지하게 느껴지네요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3114, 156, '어린왕자를 컬러링하다보면 그 이야기가 마음속 깊이 전해질 거 같네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3115, 156, '너무나 재밌게 읽었던 어린왕자를 컬러링하면서 명장면들을 되새겨보고 싶어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3116, 156, '어린왕자 컬러링북인데, 그림이 오리지널이 아닌 창작인점이 마음에 들어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3117, 156, '요즘 어린왕자 책들과 컬러링북들이 많은데 그중에서도 이 책은 특히 그림이 예쁘네요 클레식한 그림은 아니지만 만화같은 그림체라 소장하기에도 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3118, 156, '어린 왕자는 이미 현대판 고전입니다. 그런 책의 내용을 컬러링북으로 만들었는데 그림이참 이쁘고 색칠하기에 좋네요. 책의 내용을 알면서 색칠하면 더 좋을꺼 같습니다~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3119, 156, '동화 중에서 가장 색감이 예쁘다고 생각했던 것이 바로 어린왕자였습니다. 어린왕자 스케치에, 제 나름의 색을 입히며 더 아름다운 동화를 그려보고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3120, 156, '어린 시절에 봤던 어린 왕자를 이렇게 컬러링으로 다시 만날 수 있다니 기쁘네요.생각하면 왠지 짠하고 그 신비로움이 이상스레 더욱 가슴 아프게 하던 어린 왕자의 그 고유의 분위기를 볼 수 있어조카와 함께 컬러링 북으로 다시 한번 읽어 보고 공감을 느낄 수 있는 그런 계기가 될 것 같습니다', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (157, '손자병법', 195, 4.8, 2, 0, 8, 15, 170, 185, 8, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3121, 157, '여기 출판사는 번역도 좋고 종이 질도 좋네요, 가격도 저렴하고요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3122, 157, '드디어!! 나왔구나!!!!현대지성 출판만 기다렸다..내가 또 어디 출판사에 고전ㆍ번역을 기다릴까,너무 좋다~.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3123, 157, '손자병법! 삶을 살며 싸울 일은 많은데 지혜롭게 싸워 이기는 법을 가르쳐주는 사람은 어디에도 없더라ㅠㅠ 이 책은 그런 나에게 정말 좋은 스승이 되어주었다. 무식하게 들이받기만 하던 나날은 안녕!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3124, 157, '싸우지 않고 이기는 법? No! 무너지지 않고 다시 일어설 힘을 주는 40대 인생의 필독서', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3125, 157, '손자병법은 책장을 덮고 나서도 그 내용의 잔상이 마음속에 머무르는 것 같다. 고전이 가진 힘은 바로 여기에 있는 것이 아닐까. 수천 년 전의 글이 지금의 나에게도 깨달음을 주고, 마음을 다잡게 하며, 더 깊이 있는 시선을 선물한다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3126, 157, '소준섭 선생님의 책은 다 구입했습니다. 맹자, 대학, 중용 등등 더 많은 양서를 현대지성을 통해 출판하여 주시길 바랍니다! 이번에는 직접 구입하지 않고 선물 받았습니다^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3127, 157, '컬러 명화가 수록된데다가원문, 해석들이 꼼꼼하게 들어가 있어서 좋다핵심 메시지가 잘 강조되어 있고그 메시지를 깊이 이해할 수 있도록역사적 인물들의 이야기를 알려준다여러가지 상황을 살피지 않고 (계', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3128, 157, '두께에 비해 가독이 나쁘지 않음. 뭘 느껴아만 할 것 같은데 못 얻은걸로 봐서 다른버전도 한번 봐야 할 듯', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3129, 157, '‘왜 셀럽들이 **손자병법(孫子兵法)**을 인생 필독서로 꼽는지 이제야 깨달았다. 회사에서의 경쟁부터, 내 채널 ‘X SMASH‘의 탁구 전략까지, 이 책의 지혜는 승리를 위한 현실적인 ‘전략 지도‘ 그 자체다. 이겨놓고 싸우는 법을 배운다.‘', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3130, 157, '“어떻게 하면 인간관계에서 힘을 덜 들일 수 있지?”하는 물음에 대한 답이 되어줄 책이에요우리가 정치를 할 수도 있고 사업을 할 수도 있지만사실 연애 같이 사소한 것에서도 우리는 싸움을 하고 있어요미시적인 분야에서도 큰 도움이 됩니다거창하게 생각하지 마시고 소소하게 읽어도 좋아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3131, 157, '손자병법은 뭐.. 최고죠!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3132, 157, '전쟁이란, 반드시 백성과 국가를 지키는 수단이어야 한다.손자병법을 읽는다고 하면 전쟁, 전략 그리고 승패라는 단어가 먼저 떠올랐다. 전쟁에 이기기 위한 책을 왜 그토록 많은 사람들이 동서양을 넘나들며 찾아 읽는것인지 어릴 때는 잘 몰랐다. 솔직히 성인이 되어서도 발췌본 등을 읽었을 뿐 정식으로 읽을 생각을 하지 못하였다. 이런 오해로 아직 접하지 못한 이들에게 도움이 될 수 있는 방향으로 서평을 적어보려 한다.우선 손자병법의 저자 손자(이름 손무)는 전쟁을 부추기거나 즐기는 사람이 결코 아니었다. ‘싸우지 않고 이기는 방법’을 먼저...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3133, 157, '*출판사로부터 책을 제공받아 직접 읽고 작성한 리뷰입니다.?그동안 읽었던 손자병법을 세어보니, 만화를 포함해 총 3권이나 되었다. 이번에 읽은 책이 네 번째 만나는 손자병법이었는데, 그럼에도 불구하고 또 손자병법을 읽었던 이유는 앞에 두 권이 만화로 읽었기에 손자병법의 내용을 쉽게 파악할 수 있긴 했지만 뭔가 아쉬움이 남았다. 그리고 또 한 권의 책은 지극히 병법과 전쟁사를 중심으로 쓴 책이었기 때문에 역자가 가지고 있었던 정확한 목적의식이 담겨있어서 날 것 그대로의(?) 손자병법에 대한 궁금증이 있었다. 그래서 네 번째 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3134, 157, '인간의 영욕은 지칠 줄 모르고 자기 확장의 세계를 갈망한다. 탐욕적인 정치인들은 교묘하게 민심을 자기방편의 수단으로 활용하여 대중선전의 기폭제로 사용한다. 그들은 철저히 자기 이익적이지만 평화공존이란 명분을 내세우며 감언이설로 대중을 호도한다. 그런데 그들이 주장하는 이상적인 평화가 전쟁으로 가능할까? 전쟁은 어떤 명분으로도 실체화될 수 없다. 전쟁으로 평화를 이룩한다는 전제가 허망성실이다. 전쟁 후 평화, 패권 후 안정, 혼란 후 질서, 지속될 리 만무하다. 결국 현실은 자기기만에 빠져 해결할 수 있는 가장 손쉬운 방법을 선택한다...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3135, 157, '출판사로부터 도서를 제공받아 작성한 리뷰입니다요즘 새로운 도전을 시작하면서 마음이 참 복잡했는데요. 그러다 우연히 손자병법을 읽게 되었는데, 정말이지 제 인생의 전환점이 되었지 뭐예요. 처음엔 병법서라고 해서 어렵지 않을까, 나와는 상관없는 이야기가 아닐까 싶었는데 생각의 반전이었습니다.제가 이 책에서 가장 크게 얻은 건 바로 ‘백전불태(百戰不殆)’, 즉 ''백 번 싸워도 위태롭지 않은 상태''라는 개념이에요. 사실 새로운 일을 시작한다는 게 매번 이기기만 할 수는 없는 거잖아요. 때로는 예상치 못한 문제에 부딪히고, 넘어지고, 좌절할...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3136, 157, '출판사로부터 도서를 제공받아 작성한 주관적인 리뷰입니다. ? 학생 시절 삼국지를 읽은 후 이야기 속 등장하는 각종 전략에 대한 지혜를 좀 더 읽기 위해 손자병법을 읽었던 적이 있다. 당시에는 기대와는 조금 다른 느낌이 들었고 완전히 이해하지는 못했던 것 같다. ? 이제 나이를 들어 다시 손자병법을 읽었는데, 학생시절과는 좀 더 이해할 수 있는 것 같다. 예전에는 재미 또는 역사공부를 위해서 중국 역사소설을 읽었지만 큰 교훈을 얻지는 못했던 것 같다. 하지만 직장생활을 하면서 동료가 초한지의 주제는 빠로 한 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3137, 157, '#도서협찬 #손자병법 #손자 #현대지성 #현대지성클래식 #우아페서평단 #고전문학 #2025고전읽기 #도서추천2500년간 입증된 ''불패'' 법칙을 97가지 스토리텔링으로 풀어내다 아무리 세상이 변해도 자연현상과 인간 심리는 변하지 않는다. 승자의 바이블이라 불리는 《손자병법》은 단순한 병법서만은 아니다. 인류 최초의 심리전술 연구서이자 처세의 경전으로 통하는 《손자병법》은 전쟁뿐만 아니라 사회 전반에 적용된다는 점에서 오늘날까지 그 가치가 빛나고 있다. 손자가 살았던 시기는 약육강식의 논리가 횡행하던 춘추전국시대였다. 손자는 그 한가운...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3138, 157, '『손자병법』을 처음 읽었던 시절을 떠올린다. 고등학교 1학년쯤이었을까. 당시 즐기던 PC 게임에서 ‘손자병법’이라는 아이템을 보며, 이 책을 읽으면 나도 지력이 높아져 게임도 더 잘할 수 있지 않을까 하는 단순한 마음으로 책을 펼쳤던 기억이 있다. 그러나 그때의 나는 무협지와 역사서 외에는 별다른 독서 경험이 없었고, 해설서조차 읽기 버거웠다. 한자투성이의 문장과 낯선 개념들 속에서 오래 버티지 못하고 덮어버렸던 책. 그것이 나의 첫 ‘손자병법’이었다.? 그 후로...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3139, 157, '* 출판사로부터 도서를 제공 받아 작성한 주관적인 리뷰입니다. ? 많은 사람들은 ‘손자병법’이라 하면 흔히 전쟁의 기술이나 전략 등 병법서로만 알고 있을 것이다. 하지만 이 책 ‘손자병법: 이겨놓고 싸우는 인생의 지혜’를 읽고 나면, 손자병법이 단순한 병법서가 아니라 삶과 인간에 대한 깊은 통찰을 담은 철학서라는 사실을 깨딛게 될 것이다. ? 이 책은 전쟁의 역사와 기술, 전략을 다루고 있지만, 그 속에는 인간의 심리, 판단, 그리고 삶을 살아가는 지혜가 녹아 있다. ? 이 책의 저자 손무는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3140, 157, '* 현대지성 출판사로부터 도서를 제공받아 작성한 주관적인 리뷰입니다.현대지성 클래식 69손자병법이겨놓고 싸우는 인생의 지혜??2500년전의 손무(손자)의 고전 서적 은 현재에 이르기까지 그 가치를 인정받아 꾸준하게 새롭게 번역된 책으로 만나볼 수 있다. 어떻게 이렇게 오랜시간 사람들에게 사랑받을 수 있는지 궁금했고, 책을 읽으면서 분명 그 이유를 알 수 있었다. 이 책은 세월을 관통하는 실질적이고 실천적인 가치를 담고 있기 때문이다.?참고로 책 제목은 인데 지은이가 ''손무''이다. ''손무''가...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (158, '참을 수 없는 존재의 가벼움', 194, 4.32, 2, 3, 24, 66, 99, 165, 24, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3141, 158, '베토벤 톨스토이 플라톤 니체가 자주 언급된다. 내가 최근에 본 작품들을 작가가 언급하면 찌릿한 쾌감이 목덜미에 녹아들었다. 고전과 고전이나 고전과 오늘 날의 텍스트가 맞물려 있음을 보는 것도새로운 즐거움이다.이 작품은 현실의 임무로부터 자유로워지고 싶은 영혼이 몸부림 치는 듯한 느낌을 받았다. 씁쓸한 여운이 남는다.번역도 잘 되어 있고 구소련의 체코 억압이 잘 묘사되어 있다. 동구권의 역사를 안다면 더욱 공감하며 읽을 수 있을 것이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3142, 158, '인간은 새털처럼 가벼운 존재라는 것, 쿤데라는 이 명제를 끝까지 밀고 나간다. 그는 인간이 가벼운 존재여야만 세상의 무거움과 키치적 성격에서 벗어나, 자유로울 수 있다고 보는 듯하다. 하지만 이러한 태도가 나에겐 또 하나의 냉소주의와 허무주의로 보이기도 한다. 그럼에도 이 작품은 훌륭하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3143, 158, '밀란 쿤데라의 참을 수 없는 존재의 가벼움을 읽고 한동안 밀란 쿤데라의 작품에 빠져있었다. 제목 만으로도 이미 반은 감동하고 들어가는 그런 작품이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3144, 158, '철학가, 작가, 평론가, 혼자서 다하는 쿤데라', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3145, 158, '모든것이 담겨있는 책의 무거움,그리고 가벼워진 나.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3146, 158, '전혀 와닿지가 않는다. 바람둥이의 이야기인가. 뭘 이야기 하고 싶은건지 모르겠다. 도중포기', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3147, 158, '깊고 풍부한 사유를 하게 만드는 책이다. 삶의 ‘가벼움‘과 ‘무거움‘ 중 무엇이 옳은가에 대한 답은 없다. 그저 인간은 이 사이에서 끊임없이 갈등하는 존재라는 생각이 든다. 이런 인간실존에 대한 고민을 4명의 남녀를 통해 상징적으로 보여주는 실험적이면서도 아름다운 작품이란 생각이 든다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3148, 158, '거래되는 가치매겨지는 현대인들은 거래되는 그가격만큼 가볍다고 암시적으로 웅변하는 쿤데라 아저씨의 글솜씨에 큰 행복감이 듭니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3149, 158, '이렇게 철학적이면서도 야한 소설은 본 적이 없었던 것 같다. 인간 존재의 가벼움과 무거움에 대한 이야기. 독특한 형식. 한없이 가벼울지라도 키치적인 것을 거부하는 그 모습에서는 자유의 냄새가 난다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3150, 158, '뭔가 엄청 깨우침 당한 선명한 기억이 있다.근데 뭘 깨달았더라?..다시 읽어야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3151, 158, '10.12.08너무 어럽고, 어렵고, 어렵다...무엇을 얘기하고자 하는 건지 알 수가 없다..* 참고아마 처음으로 대화(메모)하며 읽은 책.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3152, 158, '살면서한 책을 읽고곧바로 또 다시 처음부터 끝까지다시 읽은 것은 처음이다그만큼 나는 이 책을 내 머릿속에 각인시키고 싶었나보다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3153, 158, 'Love Island 라는 외국 예능이 있다. PC(politically correct)하지도 않고 외모가 출중한 등장 인물들에 대한 연민만 가중시키는, 정신적으로 조금은 피곤한 러브 리얼리티(?) 프로그램인데 이 책이 딱 그렇다. 스스로의 삶에 대한 철학적 성찰을 하게끔 하는 점과 둘 다 ‘키치’하다는 점 또한 같다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3154, 158, '역시 고전은... 생각할 힘을 주는듯.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3155, 158, '읽긴했는데 솔직히 이해가 잘 안되요 ㅎㅎ;;어려운 책으로 기억^^ㅋ', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3156, 158, '하루키가 말하길 어차피 모두가 광대라고..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3157, 158, '3.5 지루하면서도 재밌다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3158, 158, '사람이 무엇을 희구해야만 하는가를 안다는 것은 절대 불가능하다. 왜냐하면 사람은 한 번밖에 살지 못하고 전생과 현생을 비교할 수도 없으며 현생과 비교하여 후생을 바로잡을 수도 없기 때문이다. (17p)', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3159, 158, '이해가 잘 안된다. ˝불안˝이란 개념과 연결되는 것 같다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3160, 158, '밀란쿤데라님은 절대 무거운 주제로 책을 시작하지 않습니다. 그렇지만 절대 가벼운 마음으로 책을 덮게 하지도 않으시죠. ㅎㅎ 거기에서 많은 독자와 관심을 끌어 내시는 것 같습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (159, '예언', 194, 4.59, 6, 3, 9, 29, 147, 176, 9, 9);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3161, 159, '1983년의 KAL 007기 피격사건속에 담긴 미중일러 4대 강국의 팽팽한 긴장감,고아원에 남겨진 지민지현 남매의 비극적인 삶 속에그 시절 역사 현장을 생생하게 보여준다. 붕괴 직전의 베를린 장벽, 고르바초프의 소비에트연방해체 선언의 은밀한 뒷거래1980년의 대한민국은 무엇을 하고 있었나?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3162, 159, '김진명 소설 가운데 가장 실망한 책이다!한국사 X파일에 스포일러가 노출되지 않은 신선함에 읽었는데난데없이 사이비종교 교주와 아내가 등장하다니!김진명 작가가 통일교였던가?', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3163, 159, '가독성이 좋았던 작품입니다. 특히 반전부분이 흥미로웠어요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3164, 159, '김진명 소설은 항상 잘 읽혀내려간다. 하지만 항상 마무리가 어정쩡하게 끝난다. 이번 예언도 그 스타일을 벗어나지 못한다. 그냥 2025년이 되어야할듯...', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3165, 159, '진정한 복수란 그저 똑같이 갚아주는 게 아닌 법이지.. 역시나 큰 것을 본다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3166, 159, '역사를 정돈한다는 의미로 이 소설을 적어내려갔다면, 이렇게나마 알게 되는 진실 앞에서 숙연해진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3167, 159, '아래 174개의 글 중 -- 구매자의 글 -- 은 - 단지 8개 뿐. 한결같은 별 5개..신뢰성이 엄청 떨어지네요...', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3168, 159, '미제 사건으로 남겨진 역사와 작가의 상상력이 만들어 낸 팩션이란 사실을 인지하고서라도 은 독자들을 자극하는 논쟁거리란 사실은 자명합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3169, 159, '확실히 재밌는 책이다. 소련 전투기 때문에 격추된 칼기를 소재로 하여 흡입력 있는 이야기를 펼쳐내고 있다. 저자의 인터뷰에 의하면 책 속 문선명의 행적은 대부분 팩트를 기반으로 했다고 한다. 안타까운 비극에 문선명을 끼얹으니 좀 걸쩍지근하다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3170, 159, '양장판이라는 게 뭣보다 맘에 들어요. 이번 주말 읽습니다. 기대기대^^', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3171, 159, '역사는 거짓이 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3172, 159, '김진명 작가님 소설은 무궁화꽃이 피었습니다부터 계속 보고있습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3173, 159, '비행기가 피격된 사건을 두고 벌어지는 상황이 긴장감있게 펼쳐지네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3174, 159, '김진명, 이라는 이름만 보고 읽게되었습니다. 역시 한번 책장을 펴니 술술 읽히네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3175, 159, '요즘같은 시기에 더욱 몰입하며 볼수있는 책인듯 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3176, 159, '김진명 작가님 책들은 항상 많은 여운이 남는 책들이라 이번 작품도 기대됩니다. 일부러 스포 주의하려고 리뷰도 안찾아보고 있어서 더 기대되는 소설이에요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3177, 159, '항상 커다란 그림을 그리고 바라보는 작가님의 시각을 통해 다시 돌아 보는 우리 현대사 이야기 기대 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3178, 159, '한국의 정치에 대한 사건들이 등장하고 외교적으로 흥미진진한 사건들을 재구성하고 김진명 작가님의 필력으로 스토리를 이끌어 가는 것이라서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3179, 159, '허구와 진실을 놀랍도록 자유롭게 넘나드는 흥미로운 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3180, 159, '칼기 사건을 바탕으로 어떻게 자극적으로 그리고 주목받도록 이야기를 재구성했는지 읽어보고 싶어져요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (160, '정답부터 보는 꼼수 공부법', 194, 4.73, 2, 0, 9, 27, 156, 183, 9, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3181, 160, '3월 9일자에 올라온 리뷰가너무 많다. 이건 너무 마케팅의 냄새가 난다. 책이 진짜로 좋을지라도 이런 마케팅은 책의 진정성을 의심케 만든다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3182, 160, '기출문제의 정답을 외우고나서 참고서의 맥락을 이해하는 방법으로 성적을 올린다는 꼼수 한수배워보고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3183, 160, '별로 특별할 것 없는 내용. 아래 보니, 100자평이 쓰인 날짜가 3월 31일이 대부분이네.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3184, 160, '꾸준히 정석대로 공부하는 것도 중요하지만, 시험 대비 공부는 역시 효율을 생각해야겠지요. 고등학생 우리 아이 시험과 수능준비 공부법으로 도움을 받을 수 있는 책이라 여겨집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3185, 160, '공부를 많이 해보고 잘하는 사람이라면 스스로 터득했을 방법이고, 아직 공부가 서투른 사람에게는 꽤 유용할 법한 책이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3186, 160, '지금까지 해 온 공부법과는 조금 다르지만 실질적으로 시험 준비에 도움이 되는 방법을 제시해 주고 있어서 단기간에 꼭 합격을 해야 하는 사람들이 보면 도움이 될 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3187, 160, '무조건 외우는 것이 아닌 최단시간 합격을 할 수 있다는 꼼수 공부법이 궁금해지네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3188, 160, '간단한 과목들에서 시작하고. 사용할 수 있는 방법', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3189, 160, '필요한 공부법을 꼭 짚어 주는 거 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3190, 160, '정답부터 보는 꼼수 공부법은 어떤 부분에서 보면 맞다는 생각이다. 다른 무엇보다 합격을 위한 공부법으로 실제로 경험한 노하우를 전해줌으로써 많은 이들에게 도움이 되리라 믿는다. 거기에 꼼수이지만 그만큼의 남다른 비법으로 반드시 효과를 보리라는 것도.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3191, 160, '새로운 방법의 공부법인듯 하네요.. 기대합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3192, 160, '공부의 효율성을 생각한다면 저자의 방법은 더없이 좋은 방법인것 같아요. 결국 합격하기 위한 공부하면 보다 빨리 합격하는 게 좋은 일이니까요. 저도 생각을 달리해보려구요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3193, 160, '정답부터 보지 말라는 교육을 받고 자라서그런지 정답먼저 보는 것에 대한 거부감이 있었어요. 대체로 그렇게 교육받으니까요. 그런데 이 책을 통해 이것도 하나의 공부방법이라는 걸 알게되니까 마음에 안정도 되고 저는 아이들 교육시킬 때도 참고하려고 합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3194, 160, '공부에는 왕도가 없다고 생각합니다. 사는 방식이 10인10색이듯 공부법도 10인10색이라고 생각합니다. 독학하는 학생의 입장에서는 문제를 풀다가 모를 때 해설지를 보고 연구를 하기도 하기에 이런 공부법도 한 방법이라고 생각했는데, 이렇게 성공한 사람도 있음에 놀랍습니다. 대단한 이야기네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3195, 160, '답을 먼저 본다니 생각도 못한 공부법이네요. 정답을 먼저 외운 뒤에 문제를 이해한다는 거꾸로 학습법이 정말 효과가 있을지 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3196, 160, '꼼수공부법이라니 실제로 행했을 때 얼마만큼의 효과가 있을지 궁금하고 진짜 꼼수가 통했으면 좋겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3197, 160, '정답을 보고 꼼수로 공부하는 방법을 알려주는 책이다. 공부를 원래부터 싫어하는 사람이라면 이 책을 보고 공부하는 방법을 터득할 수 있을 것 같다. 시중에 많은 공부법 책 중에서 제일 기대되는 책. 내 인생 최고의 책 강추!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3198, 160, '공부를 많이 해야하고 그 범위가 넓으며 시험을 앞두고 있다면 효율적인 공부방법이 필요한데, 과연 정답부터 보는 공부법은 어떤 것인지 저자의 노하우를 통해서 차근차근 자신의 것으로 만들어나갈 필요가 있다고 생각합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3199, 160, '정말 뚜렷한 목표가 더 중요하지 합격에 무슨 자존심이 필요하겠어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3200, 160, '수능 시간과의 전쟁에서 최단기간에 합격의 영광을 누리는 정답부터 보는 시험공략법 너무 기대됩니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (161, '눈먼 자들의 도시', 193, 4.55, 1, 2, 11, 55, 124, 179, 11, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3201, 161, '자신을 잃지 않는 것이 얼마나 중요하고 어려운 것인가를 이 책은 말하고 있는 것 같다.사람이 사람이기를 포기해야할 상황이 되었을때, 마치 짐승처럼 본능에 따라 움직일수밖에 없게 되었을때를 상상하면 소름이 끼친다. 아무것도 보이지않는 환한 우유의 바다에 빠져 그래도 살아남기위해 먹을 것을 찾아 헤매고 짐승처럼 아무곳에서 배설을 하며 비가 내려야 겨우 몸이라도 씻을수있다. 모두가 눈이 먼 나라에서는 수치라는 것도 더이상 찾을 수 없다. 그저 본능과 이기심에 뭉쳐 무리짓는 짐승들일뿐이다. 책을 도서관에서 빌렸을때도, 책장을 열기 전까지도...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3202, 161, '우리가 이루어낼 수 있는 유일한 기적은 계속 살아가는 거예요, 삶은 눈이 멀어 어디로 갈지 모르는 존재처럼 연약하니까, 환상리얼리즘으로 유명한 주제 사라마구. 이 책에서 그의 상상력은 무섭고 치떨린다. 어느날 교차로 파란불을 기다리던 맨 앞줄의 차에서 비명이 들린다. '' 앞이 온통 하얘. 아무것도 보이지가 않아''? 지나가던 이가 그의 차를 운전해서 그를 집에 데려다주고, 그는 막상 차를 훔친다. 맨 처음으로 눈이 먼 자는 병원에 간다. 그의 상황을 응급으로 본 간호사와 백내장걸린 노인, 검은 색안경 쓴 여인, 사팔뜨기 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3203, 161, '어느날 갑자기 눈이 보이지 않게 된다면세상은 어떻게 될까?안경을 쓰는 탓에 자고 일어나 가끔 안경을 찾지 못하면 그 짧은 시간도 불편한데 말이다....영화로도 나온 책이다.책으로 먼저 보고 영화를 보는 것이 좋을 듯싶다. 물론 영화를 먼저 보고 책을 읽어도 되지만....아무런 일이 없을 때는 그 소중함을 모르는 것 같다. 눈이 아니라 어느 것이라도 소중함을 깨닫게 해주는 책이다.요즘은 가끔씩 옛날 골목에서 놀던 놀이가생각난다. 딱지치기, 말뚝박기, 제기차기남대문 놀이등등', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3204, 161, '어느날 갑자기 사람들이 앞을 볼 수 없게 된다. 앞을 못보게 된 사랑하는 남편을 혼자 보낼 수 없어서 자신도 앞이 안 보이는 척하는 부인. 눈이 먼 사람들만을 수용하는 한 공간에서 눈이 보이는 사실을 숨기고 생활하려는 아내와 그녀를 보호해주려는 남편. 그러나 수용소 밖 모두가 눈이 멀게 되고 세상은 온통 혼돈이 가득차고. 눈먼 자들로 가득찬 지저분하고 악취나고 질서도 없는 무법천지에서 살아남고자 유일한 보이는 눈을 가진 아내는 일행들을 이끌고 짐승처럼 변해버린 사람들을 피해가며 살아남기 위해 식료품과 머물곳을 찾기 위해 모험을 떠나...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3205, 161, '몇 년 전, 우연히 영화로 보고나서, 책으로 꼭 읽어봐야겠다고 기억한 책으로, 이제서야 읽다. 갑자기 눈이 안보이는 (이른바 백색 실명) 병이 유행하기 시작한다. 어떤 매개로 전염이 되는지 모르지만, 전염성은 확실하다. 그래서 정부는, 환자들을 격리시키기로 결정하고, 폐쇄된 정신병동에 환자들을 수용하고 음식과 각종 생필품을 제공하기로 한다.아이러니하게도 그 안에서도 힘과 폭력이 난무하고, 강자들은 음식을 독점하고 각종 터무니없는 요구를 하고, 약자들은 온갖 굴종을 강요받는다.최초의 환자를 진료한 안과의사 역시 눈이 안보이고, 그의 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3206, 161, '왠지 모르게 주제 사라마구씨는 여자라는 느낌이었는데,책 소개란에 보니 할아버지시더라.구체적인 묘사이지만 집요하지는 않다.인간 심리에 관한 묘사라기보담, 어째보면 상황에 비추어진 정당한(? 묘사.sf도 아닌데 인과없는 특이한 소재를 갖는 것이 이 소설의 큰 특징이지만, 개인적으로는 읽는 순간부터 취향은 아니겠구나- 싶었다.그리고 인류 도덕에 대한 얘기를 이렇게 대놓고 하는 것도 별로 좋아하지는 않아서.물론 시들해진 쟁점일지언정 보편적인 문제는 거듭 제기하는 노력이 필요할 것이고, 세련된 문체를 가진 작가들이 그 책임을 지는 것은 온당...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3207, 161, '"새벽의 저주"라는 공포 영화를 기억하는가? 그 영화에서 보았던 공포는 이 책에서 보여주는 공포에 비하면 그야말로 조족지혈이다.? 세상 모든 사람이 눈이 멀고, 단 한사람만 볼 수 있게 된다! 거침없는 상상력이 만들어 낸 밑도끝도 없는 설정임에도 불구하고, 치밀한 구성과 차갑도록 방관적인 문체는... 독자를 꼼짝못하게 만들어 버린다... 마치 작가 자신은 눈먼 세상을 경험해 보기라도 한 것처럼 너무나 구체적으로 묘사해 놓은 눈먼 사람들의 생존방식(?)은 피를 갈구하는 좀비들 보다 훨...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3208, 161, '전염병이 돈다. 이유는 누구도 알 수가 없다. 어느날 갑자기 한 남자가 눈이 멀었고 곧 그 남자를 본적이 있는 모든 사람들은 갑자기 눈이 먼다. 암흑의 세계? 아니다. 하얀 백지의 세계.... 순식간에 온 도시는 눈먼자들의 세계가 되어버린다. 단 한명. 최초로 눈먼 남자를 검사했던 안과의사의 아내만 제외하고.... 왜 눈이 멀게 되었는지... 또 왜 하필 의사의 아내만이 유일하게 눈이 멀지 않았는지는 알 수 없다. 그저 세상이 백색의 공포속으로 빠져든다. 인간이 흔히 규정짓는 인간으로서의 품위란 어떤 것일까? 그것...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3209, 161, '오래 전에 조금 읽다가 말았던 책이다. 홀로 눈 떠 있는 여자에게 심하게 감정이입을 하는 바람에 두려워서 더 이상 책 읽기가 꺼려졌다. 이번 세월호 "사건"을 겪고 나니 이 책 생각이 난다. 국민을 짐짝, 짐승처럼 대하는, 아무 때나 버려버리는 끔찍한 정부의 행태가 똑같다. 저번 청계광장 촛불집회 때 청년연합(?) 대표가 한 말이 떠오른다. 정부는 재난 컨트롤타워가 아니라, 재앙 컨트롤타워라고. 눈감고 싶은 현실에 차라리 눈이 멀어버렸으면 하고 바랐을 여자의 마음이 이해가 간다. 세상 천지에 홀로 눈 떠 있다는 것은 너무 잔인하다....+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3210, 161, '사실 이름이 우리에게 무슨 의미가 있을까, 개는 이름을 가지고 다른 개를 인식하는 것도 아니고, 다른 개들의 의름을 외우고 다니는 것도 아니잖아,개는 냄새로 자신의 정체를 드러내고 또 상대방이 누군지도 확인하지, 여기 있는 우리도 색다른 종자의 개들과 같아.(85쪽)?독서토론대회 도서로 이 책이 선정되었고,논제는 이다.?아이들이 오늘은 전체적으로 자유롭게 이야기를 나누는 자리를 마련했는데,다양한 이야기들이 등장했다.?우선 ''눈먼 자들''과 ''그들의 도시...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3211, 161, '아가씨가 부모님을 만났을 때는 둘 다 눈도 멀고 감정도 멀었을 거야.우리가 전에 지니고 살았던 감정.과거에 우리가 사는 모습을 규정하던 감정이 없으면 감정도 다른 것이 되어버려.어떻게 그렇게 될지는 모르고 다른 무엇이 될지도 모르겠지만.아가씨는 우리가 눈이 멀었기 떄문에 죽은 것이라고 말했는데, 바로 그게 그 얘기야.만에 하나 내가 눈이 먼다면, 내가 눈이 먼 다음에 다른 사람이 된다면,내가 어떻게그이를 계속 사랑할 수 있을까.무슨 감정으로 사랑을 할까.-주제 사라마구 이 책을 읽으면서 내...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3212, 161, '2004년 2월 1일 읽고 쓰다 ? 노벨문학상을 받는 주제 사라마구의 책을 이제서야 읽었다.꽤 늦게 읽은 편.권위있는 상을 받은 작가의 작품은 왠지 심오하고 난해할거라는 나의 예상과 달리 읽기 편하고 느끼고 생각하기 쉬웠던 작품.그러나 인간 본연에 내재되어있는 폭력과 무도덕과 더러움 등등으로나를 심하게 불편하게 했던 책이기도 하다.어느날, 갑자기 사람들이 눈이 멀기 시작한다.운전을 하다가, 얘기를 하다가, 부엌에 있다가 백색의 어둠(?)속으로빠져드는 것이다.처음에 눈이 먼 몇몇은 전염병 환자처럼 한 병원에 격리되지만나중...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3213, 161, '친한 선배의 추천으로 읽게 된 책이다. 평소 국내소설을 즐겨읽는지라, 외국소설은 아주 가끔씩 읽는 편인데, 이 책은 정말이지 최근 읽은 그 어떤 소설들보다 인상적이었다. 눈이 멀어버리는 전염병이 발생해 한 도시 전체가 아수라장이 된다. 그 와중에 눈이 멀지 않은 한 여자의 시선으로 인간의 탐욕, 본능, 허위의식을 파헤친 수작. 대화문에 따옴표가 없다. 문단 나누기도 절제되어 있다. 책을 펼치면 답답함이 밀려온다. 그러나 몇 장 읽지 않아도 단번에 사로잡힌다. 작품의 흡인력이 실로 엄청나다. 정영목 선생의 매끄러운 번역에 고마움이 절...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3214, 161, '어느날 아무런 조짐도 없이 한 사람의 눈이 멀어버린다. 그리고 마치 전염병처럼 한 사람, 두 사람, 이윽고 온 도시는 눈먼자들로 가득해진다. 어두컴컴한 어둠 대신에 백색의 어둠이 온통 눈을 가득 채우고, 세상은 혼돈스러워지고, 거리는 오물과 쓰레기, 쥐, 그리고 인간의 존엄이 무엇인지는 잃은 사람들로 가득하다. 그런 도시에 오직 한 사람만이 백색 어둠 속에 갇히지 않고 그들의 모습을 지켜보고 있다. 그녀가 바라본 눈먼 자들의 도시는 어떤 모습이었을까. ? 사람은 누구나 알게 모르게 타인의 시선을 의식한다. ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3215, 161, '인터넷?서점 사이트 중앙에 위치했던 눈뜬자들의 도시. 책표지가 나에게 얼마나 강한 인상을 주었던지 나는 어른 책이여서 못 사준다는 엄마의 만류에도 불구하고 끝까지 졸라 겨우겨우 이 책을 얻어 읽게 되었다. 그런데 한 200남짓 페이지 정도일 줄 알았는데 실제로는 472쪽이였다. 그러나 난 그 쪽수를 무시하고 열심히 이 이야기를 읽었다. 세상 사람 모두가 눈이 멀었다. 한 명 한 명 차례차례 눈이 멀어갔다. 사람들은 눈...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3216, 161, '"만약 이 세상에서 우리 모두가 눈이 멀고 단 한 사람만이 볼 수 있게 된다면" 이란 가정에서, 이 책은 시작된다. ? 어느날, 한 남자가 도로의, 자기 차 안에서 갑자기 눈이 멀어 버린다. 모든게 하얗게만 보이는 이러한 증상은, 전염병처럼 주위에 퍼져 나간다. 눈이 안 보이는 그를 도와 집으로 데려다 준 남자에게(그 남자는 눈이 안 보이는 남자의 차를 훔쳐간다), 눈이 안 보여 아내와 함께 찾아간 안과 의사에게, 맨 처음 눈이 먼 남자의 아내에게, 그 안과 의사에게 진찰 받은 환자들에게 .... 그러한 증상은 온 도...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3217, 161, '90년대 말 교회 이단들이 퍼뜨린 지구 종말론에 대한 두려움으로 순진한 수많은 사람들이 자신들의 가정과 직장, 학교를 내팽개치고 나와 단체 생활을 하던 때가 있었다. 교회 이단들은 자신들의 종교에 귀의하지 않는 자는 모두 죽음을 면치 못할 뿐 아니라 그보다 더한 고통에 빠질 것이란 협박 아닌 협박으로 많은 사람들을 혼란에 빠뜨렸다. 그들이 말하는 지구의 종말이란 개인의 죽음을 의미했는데, 죽음에 대한 많은 사람들의 두려움을 이용한 사기극으로 밝혀졌다. 그들이 말하는 가장 무서운 재앙이 과연 죽음뿐일까? 나는 이 책을 읽기 전 까지는...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3218, 161, '오래 벼르던 를 읽었습니다. 언젠가 시각장애우의 어려움을 직접 체험하기 위하여 눈을 가리고 길에 나서는 체험을 해보았는데, 막상 해보니 생각한 것과는 정말 다르게 어렵더라고 했던 것 같습니다. 그런데 세상의 모든 사람들이 갑자기 실명을 하게 되면 무슨 일이 벌어질까 생각해본 사람은 있을까요?주제 사마라구는 누구도 생각지 못한 세상을 그려냈습니다. 어느 날 한 남자가 실명을 하고, 그 남자와 접촉한 모든 사람들이 연쇄적으로 실명을 하는 상황입니다. 마치 들불보다 빠르게 전파되는 전염병처럼 그저 같은 공간...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3219, 161, '책을 덮고 눈을 감기가 두려웠다. 눈을 떴을때 나도 ''눈이 안보여''라고 말하게 될까봐 어쩔 수 없이 눈을 감게 되면 떨리는 마음으로 눈을 뜨게 되었다. 눈이 멀어버린 그들 모두는 갑작스럽게, 단지 눈이 멀어버린 사람을 봤다는 이유만으로 눈이 멀어버렸다. 그러나 왜 눈이 멀었을가? 최초로 눈이 멀어버린 남자가 눈이 멀게 된 원인은? 알수 없다. 왜 눈이 멀어 버렸는지 그리고 눈이 멀어버린 사람들을 보면 왜 눈이 멀어 버리고 마는지 아무도 알 수 없었다. 전염성이란 걸 알고 정부에서는 그들을 격리 시키지만 수용소에서의 생활은 비...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3220, 161, '그냥 재미있기만 한 소설을 읽고 싶을 때가 가끔 있긴 하다. 가치 있는 좋은 소설은 대개가 불편하다. 현실은 불편한데, 어디 도망갈 아름다운 다른 세계가 있긴 한 걸까. 고통 없고 의미 없는 그런 아름다운 세계는... 그런 뜻에서 는 마음 편하게 볼 수 없는, ‘좋은’ 소설이다. ? 당연한 일이 당연하지 않게 될 때, 사람들은 처음에는 당황하다가 나중에는 외로움을 느끼게 된다. 별 것은 아니지만 지하철에서 노인에게 자리를 양보하는 일, 문을 열고 닫을 때 다음 사람을 위해 손잡이를 잡아...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (162, '더 골 The Goal (만화판)', 193, 4.87, 0, 0, 2, 21, 170, 191, 2, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3221, 162, '실제로 경영학과에서 경영공학 관련 공부할 때 거의 필독서죠. 이게 만화로 나오다니 한결 시각적으로 재미있게 읽을 수 있겠네요. 후배들이 부럽네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3222, 162, '목표를 현실로 창출하는 비결을 만화의 생동감으로 확실하게 이해할수 있네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3223, 162, '만화로 보는 경영서출간 후 한동안 한국에는 국제 경제 이유로 출간 되지 못했다고 하니 더욱 책에 대한 흥미가있었던 원작, 그러나 어려워서 읽지 못 했는데.이 책으로 먼저 보면 될 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3224, 162, '이해하지 못했던 TOC이론을 다시 배웠습니다. 쉽고 빠르게 이해했네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3225, 162, '600쪽의 내용이 많아서 부담스러웠는데 반으로 줄여서 효율적이네요 더 골 만화판 추천합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3226, 162, '원작은 좀 딱딱하던데 그나마 만화로 나와서 약간 쉽고 편하게 이야기 하는 것 같아요. 간단히 말하면 목표에 이르는 법을 가르쳐줍니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3227, 162, '어렵지만 만화로 접하게 되서 좀더 쉽게 접할수 있게 해주네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3228, 162, '만화로 보는 경영이야기라니~신기하네요. 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3229, 162, '소설을 만화로 다시 출간되어 반갑네요. 글로 읽어도 좋지만, 만화가 곁들여 설명되면서 좀 더 쉽게 경영에 접근할수 있어 좋아요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3230, 162, '원작의 어려운 내용들을 겁먹지 않고 쉽고 이해할 수 있는 만화판입니다!!!! 만화로 친근하게 다가오니 어려운 내용도 좀더 쉽게 다가오고 이해하기 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3231, 162, '만화를 통해서 현실을 구현하기위한 방법을 좀더 잘 이해할수있게 되었네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3232, 162, '목표를 현실로 만드는 비법이라는출간한지 30년 동안 경영경제 1위를 고수하는 고전이라는 원작을 꼭 읽어야 될 책이라고 생각 되지만 어렵다는 선입견에 보지 못하고 있었는데.분량을 줄이고 만화를 통해 핵심 이론을 좀 더 쉽게 빠르게 이해할 수 있게 만든 점이 좋습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3233, 162, '이 책이 번역이 금지된 거라서 과연 무슨 내용일까의 흥미를 유발하며 경영에 관하여 만화로 쉽게 풀이된 점이 재미있을거 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3234, 162, '만화로 볼 수 있다니 좀 더 이해가 쉬울 것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3235, 162, '책도 흥미롭게 읽었는 데 만화판이 출간되었네요..글 읽기 싫어하시는 분들은만화판도 유용할 것 같아요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3236, 162, '만화라서 600 페이지 넘은 원작을 쉽게 접할 수 있어 기쁩니다. 만화책으로 단련해서 원작으로 넘어가야 겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3237, 162, '목표와 목적을 잘 구분할 수 있을까... 아니면 같을까 의문이 문득 들면서 이 책에서 해답을 찾을 수 있기를', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3238, 162, '경영서 쉽게 접근하는 방법 중 하나로서 만화로 접하는 게 신선하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3239, 162, '조금은 어려울 수도 있는 내용이지만 만화로 볼 수 있으니 재미있게 보면서 이해할 수 있어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3240, 162, '경영학 필독서인 더 골을 이제 만화로 읽습니다. 재미있고 유익합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (163, '액세서리 DIY에 꼭 필요한 Resin Art', 193, 4.88, 0, 0, 1, 22, 170, 192, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3241, 163, '레진 공예를 혼자서도 할수 있다니 직접 만들어 지인들에게 선물할 생각이에요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3242, 163, '보석감정사 자격증을 가지고있는데 저렴한 보석을 이용해서 이런 액세서리를 만드는것도 좋은 아이템이 될 수 있겠네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3243, 163, '레진공예라는 것을 이책을 통해 처음 알았어요. 딸이 있다면 배워서 딸에게 만들어주고 싶은 악세사리들이 많네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3244, 163, '레진공예 처음 알게 되었는데 정말 탐나네요. 원래 만드는 것 좋아해서 다양한 공예를 해봤는데 다양한 악세서리를 만들 수 있어서 좋네요. 제거 뿐 아니라 주위 선물로도 활용할 수 있어서 열심히 책을 보며 만들어봐야겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3245, 163, '다양한재료들로 나만이 만들수 있는 특별한 나만의 엑세서리를 만들수 있는 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3246, 163, '저도 뭔가 만드는걸 참 좋아합니다. 작가님따라 직접 만들어보고싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3247, 163, '레진아트를 이용해 만들어진 악세사리는 사는 것 외에는 생각해보지 못했는데 내가 만들어볼수 있다면 직접 만들어보고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3248, 163, '반짝 반짝 소소한 즐거움을 볼 수 있어 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3249, 163, '다양한 재료를 활용할 수 있어서 좀 더 폭넓은 소품 악세사리를 내 손으로 만들 수 있다는 장점이 있네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3250, 163, '하늘과 구름 악세사리가 젤 맘에 드네요. 레진공예를 배워 도전해보고 싶어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3251, 163, '액세사리에 관심이 있었는데 이러한 도서가 있다는 사실을 처음 알았다...멋진 도서로군요...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3252, 163, '이 책으로 쉬우면서도 독특한 나만의 악세사리를 만들고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3253, 163, '내가 요즘 관심을 갖고 있는 분야인데.. 적기에 책이 발간되어서 좋다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3254, 163, '틀에 박힌 악세사리가 아닌, 나만의 유일무이한 악세사리를 만들어 볼수도 있고 좋네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3255, 163, '예쁜 악세서리 만들어 보고 싶습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3256, 163, '나만의 개성있는 악세사리를 만들수 있는 좋은 기회가 될듯 해서 기대됩니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3257, 163, '한때 비즈공예에 푹 빠졌었는데 아이를 낳고 등한시하게 되었다가 어린이집에 보내며 나만의 시간이 생긴 지금! 레진 공예에 한번 빠져보고 싶네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3258, 163, '레진 아트가 생소했는데 사진 보니 예뻐서 따라해 보고 싶어요. 시간들여 강좌에 다니며 배우지 않고, 책 보면서 편하고 쉽게 배울 수 있어 시간절약도 되고 돈도 절약되니 좋을 것 같습니다. 초보자도 쉽게 다양한 재료와 모양들로 만들 수 있어 기대됩니다. 핸드메이드로 만들어 선물로도 좋겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3259, 163, '평소에 액세서리를 만드는 데 관심이 있는데 이 책을 통해서 더 다양한 종류의 액세서리를 만들 수 있을 것 같아 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3260, 163, '나는 악세서리 매니아다. 평범한 의상을 좋아하는 데 반해 악세사리는 늘 화려하게 하고 다닌다. 그런데 시중에 파는 악세서리는 나를 만족하는 게 별로 없는 까탈스러운 사람이기도 하다. 내 손으로 악세사리를 만들고 싶은 생각을 많이 했는데 별로 어렵지 않게 배울수 있다고 하니 사서 봐야겠다', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (164, '왓칭 2 Watching 2', 193, 4.82, 0, 0, 3, 28, 162, 190, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3261, 164, '이미 알고 있던 사실들과 저자를 통해 새로이 주목하게 된 내용들까지 모두 관심 분야이긴 하다. 하지만 이렇게 맥락지어보니 좀 더 개인적인 과거의 잔재와 현실과 수행에 있어 보다 나아간 시각을 갖게 된다. 안 읽었더라면 후회도 못했을 텐데 생각이 드니 아찔하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3262, 164, '시야를 넓힐수록 창의력도 좋아진다는 말을 들었기에 공감한 책입니다.왓칭1에 이어 흥미롭네여/', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3263, 164, '시야를 넓히면 넓힐수록 사람의 몸에서 빛이 넓고 멀리 퍼져나간다는 사실을 알려줍니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3264, 164, '보이지 않는 영적세계와 가까워질 수 있는 책이네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3265, 164, '왓칭 1 정말 재밌게 읽었습니다. 내용은 난해하지않아서 술술 읽힙니다. 강렬한 메시지를 던지는 책. 관찰자효과. 책으로 읽어보시면 와닿으실겁니다 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3266, 164, '내면의 기법의 힘으로 상대를 내것으로 만들자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3267, 164, '넓게 바라보면 시야가 넓어지고 생각이 트이는 느낌을 갖곤했는데요. 이게 실제 연구결과네요. 희한하지만 그런 경험이 잇기에 동감하는 내용입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3268, 164, '시야를 넓히면 그만큼 더 많은걸 볼수 있다는 생각의 틀을 넓히는데 도움이될듯', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3269, 164, '자신의 내면을 잘 살펴서 자아성찰의 기회로 삼는다는게 흥미롭네요. 좀더 시야를 넓혀서 스스로의 한계를 넓힐수있는 계기가 되면 좋을 책이네요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3270, 164, '무의식을 의식화 하지 않으면 그것이 운명이 된다는 칼 융의 말을 상기한달 때,무의식 안에 있는 억눌린 감정이 어떻게 현실화되는지 증명 가능한 사례들로 설명해준다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3271, 164, '1편도 재미있게 봤는데 2편에서는 다양한 과학적인 사실에 근거해서 시각을 다채롭게 해석되어 있는 점들이 재미있고 내면적인 심리를 책에 잘 표현 서술되어 있는점이 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3272, 164, '어떤 관점에서 보느냐에 따라 달라지겠지만 일단 시야를 넓히는 게 중요한 것 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3273, 164, '이 좋은 책이 2권이 나왔군요! 정말 좋은일이에요!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3274, 164, '자신의 내면세계에 대해 성찰해볼수 있는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3275, 164, '자칫 어렵게 느껴질 수 있는 복잡한 원리와 언어에 대해서 쉽게 잘 설명해주는 게 장점인 것 같아요. 두뇌에 관해 연구한 여러 책들을 봐왔지만 이 책은 육체가 아니라 뇌 자체에 시선을 두고 있어서 더욱 흥미롭네요. 아주 재미있어보여요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3276, 164, '자신의 시야를 넓히면서 내면의 세계에 대해 알수있는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3277, 164, '기자이신지라 역시 사실적이고 현실적인 조언들이네요 신선해서 좋았습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3278, 164, '마음속으로 사물을 보라는 느낌이네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3279, 164, '저자가 내면세계이 진실을 파헤쳐 알기 쉽게 전해준다는데요. 왓칭이라는 어떤 방법을 쓰는 것 같습니다. 그게 무엇일까 궁금해집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3280, 164, '인생의 고민과 걱정, 생각들을 조금만 시작을 달리하고 시야를 넓혀서 바라본다면 문제 해결을 쉽게 할수 있다는것을 과학적 근거를 통해 이야기 하고 있습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (165, '사자왕 형제의 모험', 193, 4.72, 3, 3, 7, 20, 160, 180, 7, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3281, 165, '은 아이들을 위한 동화인 동시에 시대를 거슬러 우리 곁에 있는 동화처럼 동심을 간직한 채 살아가는 모든 “어른 아이”들을 위한 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3282, 165, '7살 아이가 정말 재밌게 읽었습니다.죽음 개념을 어렵지 않게 이해하고 혹독하고 슬픈 과정에 용기가 필요하다는 사실을 재미있는 이야기를 통해 깨닫습니다.이 책이 끝나고 이후 이야기책 읽어달라고 난리에요.ㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3283, 165, '소년 형제들에게 가족의 애틋함과 상처 치유 용기 그리고 감동까지 모두 사로잡은 성장 동화 .', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3284, 165, '1980년대 초중간에 초판이 나오고 꾸준하게 개정판으로 새옷을 갈아입을 정도로 인지도와 인기가 있었던 책입니다. 어린이 책 카테고리로 묶어두기에는 그 재미가 만만치 않고 술술 읽히며 속도감 있고 작가의 전작들처럼 아이디어와 전하는 메세지가 뚜렷한 착한 동화이자 소설입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3285, 165, '죽음을 각오하는 용기를 갖기 위한 여정. 삶은 죽음을 향한 투쟁이다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3286, 165, '한강 작가는 "평범한 동화책이 아니다. 내 방의 벽에 기대앉아 오래 울었던 것을 기억한다."는 서평을 남겼다. 책을 읽기전에는 왜 한강 작가는 이 책을 평범한 동화책이 아니고 했을까 하는 궁금증이 있었지만 책을 읽고나서 한강작가의 서평에 격하게 공감하는 나를 발견했다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3287, 165, '연약한 소년 칼과 자유를 지키기 위해 악에 맞서는 사자왕 요나탄, 맑고 선한 심성의 두 형제가 죽음 이후의 세계에서 대면하는 모험이 아름답고 절절하게 펼쳐진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3288, 165, '1982년 당시 일흔네 살이던 저자가 이 책을 한국어로 번역하겠다는 유학생(김경희)에게 전한 말이 따뜻하다."그 나라에도 내 이야기를 듣고 싶어 하는 어린이들이 있거든 나 대신 얼마든지 들려줘요."', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3289, 165, '동화라고 쓰여져 있지만 생각해볼거리가 있는 책!낭기열라에서 낭길리마로 가는 그 길은 죽음과 함께 끝없이 이어진 길같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3290, 165, '가슴을 졸일 만큼 긴박감 넘치는 모험, 지고지순한 형제애와 인류애, 자유롭고 용감한 삶에 대한 희망, 두려움을 이기고 이룬 통렬한 승리, 죽음에 대한 혁신적인 통찰, 숨 막힐 듯 아름다운 묘사와 같은 절절한 매력들이 이 작품을 세대를 넘어 읽히는 고전으로 살아있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3291, 165, '두 형제의 모험을 통해 보는 사람도 성장하는 기분이 들어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3292, 165, '어른이 되고 다시 보니 새롭게 읽히는 것들이 있어서 좋네요. 아이가 지금은 다 이해 못해도 재미와 감동을 충분히 느꼈으면 좋겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3293, 165, '동화이지만 슬프기도 하고 두 형제의 모험이 있는 책이라 읽으면서도 다른 느낌으로 읽게 되는 동화입니다.성장하는 아이들에게 읽으면 좋은 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3294, 165, '주인공 형제의 새로운 세계에서의 용기를 가지고 나아가는 모습이 인상적이었어요 아름답고 슬픈 이야기면서도 어떤 것에 용기를 가져야할지를 생각해보게 하고 동화이면서도 순수한 두 형제의 모습이 특별한 모험이 너무 따듯하고 보기 좋았어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3295, 165, '두려움을 극복하고 앞으로 나아가는 용기를 사자왕 형제의 모험을 통해 배울 수 있어 좋습니다. 낯선 동화라 신선하게 느껴져요. 앞으로 살아가면서 많이 좌절하고 또 넘어질텐데 그럴 때마다 이 책의 사자왕 형제들을 떠올리며 다시 일어서고 싶네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3296, 165, '판타지적 설정과 소재로 흥미진진하고 스피디한 스토리 전개를 통해 중간중간 웃음도 나오면서 스토리 전체를 관통하는 형제애, 용기, 삶과 죽음에 대한 통찰 등 철학적인 생각을 많이 해볼 수 있어서 너무나 감동적이었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3297, 165, '진정한 용기는 무엇인가에 대한 고민이 담겨있다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3298, 165, '지키고자 하는 가치의 중요성을 깨닫기에 더 없이 좋다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3299, 165, '응원합니다. 화이팅입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3300, 165, '어린이용 판타지 동화로 묶어두기에는 재미와 이야기 구조가 참신하고 수준이 높고 재미 있는 작품입니다. 즉 나이때 상관없이 흥미진진하게 즐길수 있는 작품이기에 수십년간 전세계 독자들의 사랑을 받았을 것입니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (166, '쌤통의 심리학', 192, 4.77, 0, 0, 4, 36, 152, 188, 4, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3301, 166, '은밀한 감정 쌤통의 심리학을 이토록 통쾌하게 분석한 책이 있다니 흥미 가득 재미만점이에요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3302, 166, '남의 불행은 나의 행복의 동력. // 이번에 빨책에서 다룬 책 흥미로운데요. 빨책에서 다룬 책이라면 대체로 신뢰하는 편인데, 그 이유는 읽고 나서 더욱 공감되기 때문이기도 합니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3303, 166, '샘통의 심리학, 제목이 멋진데요. 누구나 사촌이 땅 사면 배 아픈 심리가 조금이라도 있지 않을까 싶어서 공감한 제목입니다. 남의 행복에 배 아파하고 남의 행운에 샘통을 부리는 이야기가 부끄럽지만 저의 이야기 같기도 하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3304, 166, '속시원한 이야기들 좀더 알고 싶은데요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3305, 166, '왜 다른 사람이 실수를 하면 우리의 기분이 좋아지곤 하는지 궁금했었는데 이 책 덕분에 처음 알았어요. 어떻게 보면 대리 만족과도 같네요. 쌤통이라는 감정을 경계할 것이 아니라 자연스럽게 받아들이고 상황을 객관적으로 파악할 수 있는 눈을 길러야겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3306, 166, '사촌이 땅을 사면 배가 아프다는 속담도 있듯이 인간의 본성중 하나죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3307, 166, '˝나보다 느리게 차를 모는 사람은 멍청한 놈, 나보다 빨리 모는 사람은 미친놈˝,˝내 손가락이 베이면 비극, 남이 뚜껑 열린 하수구에 빠져 죽으면 코미디˝ 이런 어찌보면 당연한 것들에 대한 실험과 사례. ˝사촌이 땅을 사면 배가 아프다˝는 한국속담이 기재되는 영광도.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3308, 166, '모든 사람은 배아파한다. 그것이 세상이치다...ㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3309, 166, '샤덴프로이데, 샘통 심리가 저에게도 약간 있기에 공감이 갑니다. 샘통 심리가 오랜 진화이 산물이라지만 타인의 행복을 빌어줄 수 있고 타인의 불행을 더 아파할 수 있도록 노력해야겠다는 생각도 들어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3310, 166, '누구나 가지고 있지만 정도의 차이와 그걸 드러내느냐 숨기느냐의 차이만 존재하는 심리가 쌤통 심리인것 같다 이것이 악의를 가지고 있다면 나쁜 행동으로 나타나겠지만 작게 존재할수 있도록 스스로 노력하는 게 중요한듯 싶은데 되도록 가지지 않는게 좋을것 같네요 재미있는 내용이예요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3311, 166, '참으로 솔직한 제목입니다.요즘처럼 결과를 중요시하는 풍토에서 자존감 낮은 사람이 많을 수 밖에 없습니다. 이 책을 통해 오히려 자신의 자존감을 높이고 주변 사람들의 자존감을 존중해 줄 수 있는데 도움이 되면 좋겠습니다. 기대합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3312, 166, '˝쌤통이다!˝ 란 말 대신 ˝그래서 그랬구나˝라는 말을 할 수 있다면...', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3313, 166, '예시가 잘 되어 있어 읽는 재미가 쏠쏠합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3314, 166, '˝쌤통의 심리학˝은 타인의 불행이 나의 행복과 같은 인간이 가지고 있는 본성중 하나가 아닐까 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3315, 166, '타인의 고통을 은근히 즐기는 것을 샤덴프로이데라고 부르는 것을 처음 알았네요. 모든 사람이 가지고 있는 질투에서 시작하는 감정으로 그것을 너무 심각하게 표출하지만 않으면 그다지 상관없다 생각하는데 이 책은 그것에 대해 심리학적으로 분석하여서 조목조목 이야기 하여 재밌다 싶습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3316, 166, '샘이 많은 성격이라 쌤통이다~ 하고 속으로 생각하는 경우가 많은데 이 책을 통해 제 심리를 좀 더 잘 알 수 있을 것 같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3317, 166, '쌤통 심리학이라니 궁금하고 재밌네요. 우선 쌤통심리가 정상이라는데서 기쁘고 왠지 재밌을 것 같아요. 어떤 내용일지 기대됩니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3318, 166, '왠지 제 모습을 보는 거 같아서 뜨끔했습니다. 동시에 나만 그런 것이 아니었구나라는 것을 알 수 있게 되어 한 편으로는 안도하는 제 자신도 있었고요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3319, 166, '쌤통도 결국 이유가 있는 법인데 이 책은 그런 쌤통의 마음을 심리학적으로 잘 풀이해놓아서 흥미롭게 읽을수 있는 책 같네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3320, 166, '꼴보기 싫은 사람 특히 질서를 잘 안 지키는 등 올바르지 못한 상태로 잘 되다가 망하는 걸 볼 때 그런 생각이 들게 하죠. 흥미진진한 책이네요.', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (167, '중국어로 승부하라', 192, 4.82, 0, 0, 3, 28, 161, 189, 3, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3321, 167, '경제의 핵심으로 떠오른 중국을 이해하기 위해 중국어를 염두에 두는 사람들에게 동기부여와 함께 어떻게 시작할지 막연한 사람들에게 좋은 가이드가 되어 줄 것 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3322, 167, '중국어 학습에 대한 열망의 불을 지펴주는 책입니다.자신에게 맞는 학습법, 용기 그이상의 비결이 담겨 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3323, 167, '중국어를 공부하는 우리 아이에게 왜 중국어를 공부해야하는지 동기부여를 더욱 할 수 있도록 도와주는 책. 더불어 문정아 중국어 회화 공부를 할 수 있는 기회가 생겨서 좋아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3324, 167, '중국에 대한 관심이 높아지면서 중국어에 대한 관심 역시 높아지는데.중국어를 처음 접하는 사람에게도 재미있게 공부 할 수 있게 의욕을 심어 주는 책입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3325, 167, '이해가 쉽게 가르쳐주시네요 광고할만 하시네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3326, 167, '중국어하면문정아문정아하면중국어', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3327, 167, '중국에 가보니, 중국이 커지고 있다는 것이 실감났습니다. 하루라도 빨리 중국어 공부를 해야겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3328, 167, '중국어를 공부할 수 있는 용기를 북돋아 주는 책입니다. 중국어를 배워야 한다는 말은 많이 듣지만 실천하기 어렵고 중국어가 어려워 머묻거리는 사람들에게 용기를 주는 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3329, 167, '친구가 문정아쌤한테 수업듣고 멈춰있던 중국어 실력이 늘었다고 해요. 신뢰가는 분!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3330, 167, '중국어에 관심이 많은데 배우기엔 꽤 어려운 건 사실입니다. 그런 중국어에 대한 이해를 도와주는 책이라 중국어를 배우려는 사람들은 꼭 읽어보면 좋은 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3331, 167, '중국어가 대세를 이루는 이때에 좋은 정보를 주는 책같네요~~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3332, 167, '중국어 교육의 최고봉 문정아 중국어를 통해 쉽고 깊이있는 중국어 학습을 경험해보세요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3333, 167, '의사면 얼마나 공부를 하고 자기만의 공부방법을 정리했을까. 그 공부방법을 언어에 적용하고 보완해서 사람들에게 알려주는 문정아 선생님. 배우려는 사람들에게 애정을 갖고 자신이 가지고 있는 모든 것을 아끼지 않고 투자하며 열심히 가르치려는 그녀의 마음이 감사하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3334, 167, '광고가 재미있어서 알게 된 학원쌤이시네요. 목차를 보니까 어떻게 중국어를 공부해야 하는지 궁금해지게 만드는 책이네요.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3335, 167, '중국이 국제 사회에서 위상이 높아지고 우리 나라에 중국인들이 관광이나 취업을 많이 하면서 중국어에 대한 관심도 높아지는데.중국어 하면 왠지 어렵다는 인식이 있어서 쉽게 배울 엄두를 내지 못 하는데.중국어 강사로 유명한 분의 책이어서 좀 더 쉽게 배울 수 있을 것 같습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3336, 167, '문정아의 중국어를 한번 강의를 들으신 분이라면 이책도 같이 읽어보는게 좋을거 같고 중국어에 대한 많은 정보와 공부의 방향을 설정할수 있을거 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3337, 167, '저자분은 중국어를 통해서 자기자신을 찾으신 분이군요. 비슷한 상황의 다른 분들에게도 도움이 될 수 있겠어요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3338, 167, '도움이 됩니다. 작은 걸음 걸음 하나가 목적지에 도달하게 만들어주리라 믿습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3339, 167, '21세기 글로벌경쟁력의 핵심은 역시 중국어, 오로지 중국어강의만 13년인 문정아 강사의 깊은내공을 배울 수 있는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3340, 167, '티비 광고로 알게 된 문정아 중국어 실제 중국어 공부에 대한 호기심이 생기네요', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (168, '왜 나는 너를 사랑하는가 (양장)', 191, 4.34, 2, 5, 21, 61, 102, 163, 21, 7);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3341, 168, '결국 사랑은 이러저러해야한다는 말이 성립되지 않는 마쉬멜로하기도 하고 방울방울하기도 한 감정의 여정. 재치와 능청이 빛나는 보통의 스물다섯살 처녀작이라는데... 모든 사랑은 처녀작이 아닐까.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3342, 168, '사랑 관련 책에 밑줄을 그으며 읽게 될 날이 올줄이야 ....', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3343, 168, '영화 한편본듯한 이름은 보통 책 내용은 보통이상', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3344, 168, '인간의 모든 불행은 자기 방에 혼자 있을 수 없기 때문에 생긴다 - 파스칼', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3345, 168, '나는 너를 마시멜로해', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3346, 168, '이 책을 또 읽느니 를 몇번 더 보겠다!', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3347, 168, '연애 소설을 읽은 것은 이 작품이 처음인데... 참 인상 깊었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3348, 168, '사랑에 대한 철학적, 인문학적, 알랭 드 보통적 고찰!!!!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3349, 168, '사랑의 속성에 대한 가장 친절하면서도 불편한 지침서', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3350, 168, '사랑에 대한 심오한 고찰꼭 한번 다시 읽어보고싶은 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3351, 168, '20대가 사랑을 하는 청춘들이 읽으면 좋을 책. 결혼생활에 찌들은 30대에게는 공감이 극히 적은 책이다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3352, 168, '남녀가 사랑을 하는 과정과 심적 변화를 심리학 혹은 철학적 관점에서 흥미롭게 묘사한 소설.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3353, 168, '이런 주제를 이렇게 이성적으로 서술했던 책이 있을까 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3354, 168, '내 감정을 그대로 옮겨놓은 책을 처음 봤다. 무릎을 탁 치면서 읽었더랬다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3355, 168, '그냥 사랑하면 안되는가...사랑과 연인에 대한 감정에 너무나도 철학적으로 접근하려는 것이 거북했다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3356, 168, '스테디셀러. 스테디한 매력.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3357, 168, '너는 내가 잃어버릴 수도 있는 모든 것을 벗어버린 나를 사랑하는가? 내가 영원히 가지고 있을 것들 때문에 나를 사랑하는가?', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3358, 168, '현실적인 연애 과정과 사랑에 대한 철학적인 고찰은 사랑의 낭만성을 깨부순다. 그럼에도 불구하고 책을 다 읽고 나면 사랑이 하고 싶어진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3359, 168, '단숨에 읽었다나를 현실주의자라고 판단하기때문일까 철학과 사랑을 접목시켜 풀어낸 이 책이 흥미로웠다.나의 연애를 적은 느낌이었다. 작가가 남성이기에 어쩔 수 없이 남성의 관점이 강했음에도 충분히 공감할 수 있었다.끝부분의 힘이 약하다는 느낌은 있으나 추천하고싶은 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3360, 168, '몇번을 읽어도 재밌다. 철학적이며 위트있고 사람의 심리를 꿰뚫는 알랭드 보통의 소설은 마음에 진한 여운을 남긴다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (169, '28', 190, 4.23, 0, 11, 28, 57, 94, 151, 28, 11);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3361, 169, '이 책도 보고싶은 책~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3362, 169, '배배꼬고 어렵게 은유와 환유로 점친 소설이 아님. 인간이 생명을 어떻게 대해야하는지 도시인간 학살과 개학살을 선명하게 대비하여 독자에게 생각을 요구하는 책. 읽어볼만함', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3363, 169, '가장 덜 악한 등장인물을 찾아내어감정이입을 하는 것으로 위안을 삼는따위의 불성실한 태도를 허용하지 않는 작가다...인간성에 대한 희망적인 소식은작가의 소설보다 의인의 죽음을 전하는뉴스에서나 보는 것이 더 자주일지도 모르겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3364, 169, '살아 있는 모든 것은 그 자체로 존재의 타당성을 지닌다. 마크 롤랜즈(동물의 역습)중반까지 매우 흥미롭다 후반부는 너무 뻔한내용에 실망', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3365, 169, '7년의 밤이 너무 기억에 남는다... 카뮈도 문득 떠오르고...', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3366, 169, '정유정은 그 투박한 문장이 결국 발목을 잡을 것이다. 7년의 밤에 비하면 졸작', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3367, 169, '작가가 하고픈 말이 참 많았다는 생각이 든다. 하지만 어디선가 듣고 본 듯한 상황들이 작품의 신선함을 떨어뜨렸고 어딘가 난잡하다는 느낌도 들었습니다. 개인적으로 조금 실망스러웠지만 링고(개)의 시선으로 바라본 인간의 모습은 충격이었습니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3368, 169, '7년의 밤보다 7배 퇴보한 작품.아쉽다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3369, 169, '한정된 고립된 공간에서 그 안에서 벌어지는 상황과 인물들간의 심리적인 갈등 그리고 스릴러라는 장르들을 결합되어 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3370, 169, '28주, 어떤 영화가 많이 생각나게 할만큼 줄거리 또한 전염병에 의한 아포칼립스물입니다. 세기말 소설을 좋아하는 사람들에게 매우 추천할 만한 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3371, 169, '이 책이 바이러스를 주제로 한다는 걸 독자평을 보고 겨우 알았다. 아쉽다...그러기에는 앞부분의 개설매 이야기가 넘 신선하다...그 이야기를 힘차게 끌어갔더라면 더욱 기이 있는 책이 되었을텐데..솔직히 7년의 밤보다는 재미있었다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3372, 169, '메르스는 격리하지만 28에서는 발생 지역을 봉쇄함. --;;예전에 읽었는데 메르스 유행하며 생각나서 코멘트 남김. 7년의 밤이 더 몰입감 있었음.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3373, 169, '˝대장, 내아이들을 어쨋어?˝.. 이 말이 가장 귓가에 맴돌게 하는 책, 정유정의 소설은 방대하고 디테일하다. 또한 우리사회에서 오랫동안 잊혀지고 무시하는 가치를 다시 수면위로 끌어당겨오는 힘을 지녔다. 인과응보의 스토리라인은 뻔한 거 같지 않고 무시무시할 정도로 리얼리티가 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3374, 169, '작가의 다른 책보다 재밌다. 그러나 그게 다다. 말하고자 하는 바를 위해 너무 많은 것들이 희생되었다. 화양시처럼.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3375, 169, '초반에 흥미진진하다가 중반부부턴 쭉 지루하게 억지로 다읽었네', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3376, 169, '현재의 ｀메르스｀와 화양의 인수공통전염병인 ｀빨간눈 괴질｀과의 공통점을 생각해본다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3377, 169, '빨간눈이 되면 급속도로 병이 발병되어 피를 토하며 죽게 되는 전염병이 전국적으로 확산되는 상황을 개와 사람간의 쫓고 쫓기는 이야기로 긴박하고 스릴있게 전개하고 있는데 어디선가 비슷한 내용을 본듯한 느낌이드는 소설이네요^^', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3378, 169, '왠지 주제 사라마구의 눈먼자들의 도시와 영화 연가시가 생각나게 하네요. 기대만큼 만족스럽지는 않았습니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3379, 169, '이 책의 가장 큰 장점은 책 표지 디자인. 디자이너의 크레에이티브함에 박수를, 둘째로 한국형 킬링타임 스릴러 수준의 내용을 두툼한 페이지의 ｀책｀으로 읽는다는 ｀자｀기 ｀위｀로가 가져다 주는 뿌듯함 그 이상은 없다. 뻔하고 어거지라 재미가 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3380, 169, '구제역 살처분과 광주민주화운동 이보다 더한 생지옥이었겠지.참 사람은 끝없이 잔인하다. 조용히 동물들과 함께 살고자 했지만 사람들의 비뚤어진 시선에 의해 이 또한 할 수 없었던 재형. 그의 마음이 전해져 너무 마음이 아팠다. 나 또한 항상 드림랜드의 삶을 꿈꾸지만 그렇게 살지 못하고 있기에.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (170, '경애의 마음 (리커버)', 190, 4.41, 2, 1, 18, 65, 104, 169, 18, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3381, 170, '마음을 쓴다는것 그건 아무것도 하지 않은것보다 낫고 마음을 버린다는것 보다는 서서히 녹아 스며들거나 사라지거나 하는게 낫지. 더디 걸리고 아프더라도. 단편이거나 중편이면 더 좋았을 텐데 상수와 경애의 마음에 오롯이 집중하기엔 다른 이야기가 넘 많았다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3382, 170, '상처받은 외로운 마음. 외면한 채 버리지말고, 부스러지면 부스러진 채 그대로 꿋꿋하게 견뎌내며 잘 먹고 잘 삽시다. 그런 마음들은 어디에선가 분명 만날 테니.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3383, 170, '좋은 설정, 좋은 문장 들이 없는 건 아니지만, 그리고 제목이 왠지 순수하여 마음을 끌기도 하지만 장편으로 끌어갈 만한 이야기는 못된다는 느낌입니다. 베트남에 가서 어쩌고 하는 것은 너무나 뜬금없고 관심도 안갔어요. 지루해서 후반부는 읽기 힘들 정도였어요.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3384, 170, '이 소설을 읽기 전의 나와 읽은 후의 나는 분명 달라졌다. 마음을 돌볼 것이다. 제철 음식을 먹고 잠을 잘 잘 것이다. 사랑할 것이고, 미워할 것이다. 어떤 모양새든, 그것이 찌질하든 옹졸하든간에 그건 내 마음이다. 더 잘 살아낼 수 있을 것만 같은 기분이 든다. 그런 소설이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3385, 170, '여전히 한국 소설은 작가의 상상력에 한계가 분명한 작품들이 너무 많은 것 같다. 언제나 동일한 범주 내에서 사소한 변주에 만족하며 자기들끼리 북치고 장구치고 있다. 고만고만한 이야기와 설정들이 연출, 출연진만 바뀐 채로 무한히 양산되고 있는 한국 드라마와 비슷한 느낌이다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3386, 170, '지금의 내가 이렇게 살고 있는 것은 내 인생에서 만났던 경애씨, 상수씨같은 사람들 덕분일 것이다. 그저 시간이 흘러 스스로 털고 일어난 것 처럼 생각했으나 다시 생각해 보면 누군가 있었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3387, 170, '경애와 상수와 은총이는 마치 학창시절 삼총사같다. 보기만해도 완전해보이는 셋', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3388, 170, '김금희 작가님이 상수와 경애의 마음을 글로 썼듯이, 누군가가 전지적 작가 시점에서 내 마음을 써줬으면 좋겠다. 요즘은 기쁜 마음인지 슬픈 마음인지 도통 내가 내 마음을 모르겠기에 말이다. 내 마음을 읽어보고 싶다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3389, 170, '은 어떤 마음에 점을 찍어놓고 곧게 선을 긋는다. 그게 읽는 나에게 닿아서 부유하는 기분이었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3390, 170, '우리는 상실한 것들을 안고, 그것을 밀고 살아간다. 실체가 없다는 것이 하나의 실체처럼 작동하고 결국 실체 없음은 실체가 되어서 상실로 생긴 구덩이를 덮는다. 투명하게 덮는다. 투명해서 결국 우리는 안다. 알고 만다. 이건 단단하게 채워진 구멍이 아니지. 결국 푹, 찌르면 마구 들어가 버릴 구멍이지. 상실의 구덩이지. 무엇으로도 다시 채울 수 없다는 걸 안다. 투명하기 때문에. 다만 걸려 넘어지지 않게, 넘어져서 멍이 들지 않게끔만 채우는 거다. 볼 수 있고 아플 수 있지만 적어도 거기서 그칠 수 있도록.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3391, 170, '그 오후의 풍경이 주는 감정들 속에서 무언가 버티는 것 같았기 때문이다.우리는 누군가에게 잊혀지기에 어려운 사람, 그리고 미련한 사람일 수도 있다. 사람의 마음이 뭐길래 그마음 하나 잃지 않으려다 자신을 다 잃어버릴만큼 힘들까.누구에게나 인연, 악연이란건 존재한다. 경애와 상수는 회사', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3392, 170, '''마음''이 말해지기까지의 그 여정과 개성있는 인물들과 재치있는 표현들 모두 좋았다. 마지막 문장을 마치자 눈물이 핑돌더라. 눈물의 이유가 뭘까? 어딘가에 있을, 이야기되지 못한 ''마음''들이 떠올랐음일까? 나의 마음은?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3393, 170, '사서 읽을 걸 빌려서 읽었어요. 저번 작품보다 훨씬 맘에 들었어요. 읽다가 저도 모르게 울컥울컥 하는 마음을 어쩌질 못하겠더라구요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3394, 170, '진짜 재밌음. 다음 장이 궁금해서 미치겠는 마음으로 읽음 *-*', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3395, 170, '이 책을 읽는 내내 , 나는 상수이고 경애였다. 완벽히 몰입되어 끝까지 아껴가며 읽는 책은 실로 오랜만이었다. 이런 책을 읽을 수 있어 나는 정말 행복했다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3396, 170, '김금희 소설을 많이 읽어왔지만 나는 그녀에게 딱히 관심이 없었다. 그냥 좋지, 정도였다. 꾸준히 읽어온 건 그녀가 주목받는 작가였기 때문이었다. 서평단에 신청한 것도 김금희에 대한 진정이라기보다는 호기심 때문이었고.내가 읽은 경애의 마음은 가제본 도서인데, 일단 출판되지 않은, 내가 곧잘 읽는 책의 형식으로 묶이지 않은 게 신기했다. 알바 중에 읽을 땐 손님이 대본이냐고 물어보기도 했고 친구들은 신기하다고 하기고 했다.경애의 마음은 좋았다. 좋지만 김금희의 소설을 읽을 때 느껴지는 허기는 여전했다. 그게 매력이겠지만, 이야기가 중심을 찾아가지 못하고 겉도는 느낌, 분명 인물들을 공감하고 이해하고 사랑하고 때론 나인 것 같다고 느낄 순 있으나 완전히 내 것이 되지 못하는 느낌. 그저 “김금희”의 인물인 느낌. 분명 수많은 밑줄을 치며 읽고 잘 쓴다 고개를 끄덕이며 읽었으나 그 느낌은 변하지 않았다.상수는 필용이자 희극배우 같고 경애는 양희 같다. 아직 반복되는 인물들에 질릴 정도까지는', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3397, 170, '파업이나 성추행같이 어디에나 존재하는 소재로 현실적인 사건을 구성한건 인상적이었다. 극적으로 억지로 짜내 이끌어가는 서술이 아니라 덤덤하고 단단하게 세워져있단 느낌을 주는 건 작가의 역량이 아닐까. 소수자/주변인에 대한 "대상화"에 대한 거칠게나마 남아있던 고민도 볼수 있던 것 같고.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3398, 170, '‘노동‘이라는 가치에 대해 결코 가벼이 여기지 않는 태도가 좋았다. 경애는 한 회사의 ‘노동자‘로서 회사의 부당한 대우에 항의하고 파업에 참여하는 장면이라든지, 그 파업안에서 벌어졌던 사건들이 흥미로웠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3399, 170, '누구를 인정하기 위해서 자신을 깎아내릴 필요는 없어.사는 건 시소의 문제가 아니라 그네의 문제 같은 거니까.각자 발을 굴러서 그냥 최대로 공중을 느끼다가 시간이 지나면 서서히 내려오는거야.서로가 서로의 옆에서 그저 각자의 그네를 밀어내는 거야˝김금희 작가의 문장은 따뜻하고 먹먹하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3400, 170, '경애는 온다 한번은 반드시.', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (171, '나오미와 가나코', 190, 4.43, 1, 2, 21, 56, 110, 166, 21, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3401, 171, '마지막 문장까지 숨졸이며 읽고 다 읽은 후 아껴둔 숨을 크게 내쉬고 소리나게 책을 덮었다. 에어컨 시원하게 틀고 서늘하게 긴장을 놓지 않은 채 읽으면 제맛일 듯 하다. 강추!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3402, 171, '어마어마한 두께에 불구하고 시간 모르고 빠져들면서 보게 된 책.하루만에 반 이상을 읽어버린 책. ^^결론은 해피엔드라 좋았다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3403, 171, '오쿠다히데오만의 유머가 상실된 느낌의 책살짜기 부족하게 느껴지는건 해피엔드를 위한 조금의 억지스러움이 가미되서였을까', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3404, 171, '내가 가나코 남편 죽인 줄', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3405, 171, '폭력을 일삼는 친구의 남편을 죽이고 매장한후 사건을 숨기려는 두 여자들의 우정과 이야기에 통쾌함을 느끼고 응원하게 되는 미스터리 추리소설^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3406, 171, '뻔한 전개와 진부한 스토리...습작인가..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3407, 171, '역시 오쿠다 히데오!책장이 저절로 넘어가는 힘은 여전함해피엔딩이라 더 좋은', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3408, 171, '처음 읽는 오쿠다 히데오 군더더기 없는 문장 매끄러운 글씨체를 보는 느낌이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3409, 171, '오쿠다 히데오의 책은 언제나 믿고 보고 있습니다. 지금까지완 좀 다른 분위기지만 역시 실망시키지 않네요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3410, 171, '죄 짓고는 못살겠다는 교훈을 주네요 읽는 내내 심장이 오그라들었어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3411, 171, '간만에 가슴을 두근거리며 읽어내려간 작품', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3412, 171, '충격적인 스토리 빠져나올수없어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3413, 171, '표지와 제목이 좋아서', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3414, 171, '읽다가 너무 조마조마해서 맨 뒷장 펼쳐보고 싶은걸 참으면서 읽었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3415, 171, '범인이 잡히지 않기를 간절히 바라게 되는 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3416, 171, '마음에 들었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3417, 171, '오쿠가 히데오의 글은 평균은 한다. 어쩐 소재의 글을 읽어도 책 산 돈이 아깝지 않다는 뜻. 그러나 는 좀 주저했다. 여성이 주인공인데다 결말이 이미 정해져있는 뻔한 스토리때문이었다. 기우였다. 두 주인공의 시건에서 이야기가 끊이지 않고 긴박하면서도 담박하게 이어졌다. 결국 그의 장점은 문체에 있었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3418, 171, '오쿠다히데오의 팬으로서 그의 책 많이 읽었습니다. 장편은 처음 읽어보았는데, 글자만으로도 이렇게 심장이 쫄깃해지는 책은 처음이네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3419, 171, '구도는 좋았는데 좀 지루했고, 읽고 있는 내내 살인의 헛점이 보여서 긴장감이 떨어졌다.오쿠다 히데오의 공중그네같은 익살이 그립다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3420, 171, '당연한 것이 당연한 것이 아니라는 것, 평범하게 사는 것이 얼마나 어려운 일이지...', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (172, '시민의 교양 (반양장)', 190, 4.66, 2, 1, 6, 41, 140, 181, 6, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3421, 172, '세금, 국가, 자유, 직업, 교육, 정의, 미래...이 7가지 화두를 생각하고 정리하는 시간이 된다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3422, 172, '채사장은 어려운 이야기를 쉽고 재밌게 풀어낸다. 혹자는 이를 두고 ｀얕다｀고 비판하기도 하지만 모든 책이 ｀깊을｀ 필요는 없다. 대중에게 쉽고 재밌게 풀어주는 일이 어쩌면 더 중요하다. 어쨌든 책은 전작 보다는 한발 더 들어갔다. 너무 깊지 않으니 걱정할 것 없다. 다음 책도 기대된다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3423, 172, '세금 국가 자유 직업 교육 정의 미래에 관한 현실적인 조언을 해주는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3424, 172, '쉽게 읽히기는 하지만 아쉬운 부분이 많이 남습니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3425, 172, '약간 지대넓얕 재탕 한듯 하네요 그래도 채사장 글은 재밌고 쉬워서 좋네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3426, 172, '문제는 경제로다. 자유, 교육, 정치, 정의의 문제는 돈때문. 자본주의에 사는 동안 문제의 핵심은 돈에 있을 수 밖에 없는 듯. 있어도 문제고 없어도 문제로다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3427, 172, '인문학도 재미있다는것을 알려주는 책', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3428, 172, '우리가 배웠던 여러 과목들을 이해하기 쉽게 하나로 정리해 놓은 느낌, 우리네 삶에 일어나고 있는 사건들과 접목해 놓았다. 이런 게 인문학이 아닌가...', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3429, 172, '삶에서 제대로 넓게 알아가고 싶어지는 것들이 많은데 배워보고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3430, 172, '다양한 인문학적 지식을 쌓을 수 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3431, 172, '인문학적 소양을 기를수 있도록 도와주는 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3432, 172, '보통의 시민을 위한 최소한의 교양서!채사장님 글 좋다. 필독!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3433, 172, '나의 교양 없었음에 놀라다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3434, 172, '평소에 인문학에 관심이 없었어도 쉽게 이해할수있도록 설명을 해주고 있다. 이제 선택을 하고 행동에 나서야 할 때이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3435, 172, '대통령, 비서실장, 시민의 등장과 이야기전개는 다소 작위적이고 생뚱맞다. 그들의 등장은 전반적인 책의 내용을 파악하는데 도움이 되지않았다. 구성의 집중도를 떨어뜨리고 흐름이 매끄럽게 이어지는 것을 방해하는 것만 제외한다면 교양서로써 한번 스윽~!!! 읽어볼만 하다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3436, 172, '뭔가. 지대넓얕의 재탕?하지만. 재미는 있다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3437, 172, '현실적인 인문학이라는 말에 끌려 보고 있습니다. 시민으로서 알아야 할 지식들, 권리와 으무 등 현실적인 이야기라서 팍팍 와 닿네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3438, 172, '작년 한 해 채사장의 책으로 즐거웠는데, 그 새 신간이 나왔네요! 기대됩니다. 이번에는 시민이 갖추어야 할 교양이라, 더욱 궁금해지네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3439, 172, '보통의 시민이가져야할 교양이라 좀더 현실적인 인문학이라 생각됩니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3440, 172, '보수vs진보 입장을 잘 대변하면서 중립적인 입장에서 설명합니다. 꼭 읽어봐야할 책이네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (173, '더 해빙 (40만부 기념 리커버 에디션)', 190, 3.37, 70, 6, 3, 6, 105, 111, 3, 76);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3441, 173, '중고시장에 파는 것도 미안한 책. 중고로 구매한 다른 사람 귀한 시간 낭비할까봐. 그냥 버리자.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3442, 173, '시크릿의 아류로밖에 보이지 않는 책. 그야말로 껍데기밖에 없는 책을 대단한 책인양 홍보하려고 애쓴다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3443, 173, '첫 장부터 마지막 장까지 읽으면서 이 책이 왜 9점을 넘는지 이해가 가지 않는다.어디서부터 어디까지가 진실을 적은것인지 이해가 안되는 판타지 소설과도 같다.대부분 독자가 40대 여성인데...공감능력이 매우 뛰어나거나 현실성이 매우 떨어지거나 둘중 하나같다...이딴게 베셀이라니...', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3444, 173, '추상적. 얕은 내용. 암시에 기반해서 근거 없는 성공을 약속하는 책. 사례들도 다 비슷비슷하고 구루의 조언이 도움이 되었다는 내용은 보편적이고 실질적인 조언보다 그 사람에 대한 점괘가 맞았다에 가까움. 자기계발서보단 심리치유서 혹은 종교서에 가깝게 느껴짐.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3445, 173, '고속버스 휴게소 트럭에서 파는 신바람 이박사 트로트 메들리 테입보다 가성비가 떨어지는 책', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3446, 173, '혹세무민 그 자체 - 데이터도 사실도 아무 것에도 근거하지 않은 종교성향의 소설. 방법론도 그저 안빈낙도 그자체. 아마존에는 한국에서 베스트 셀러 1위라고 소개하고 우리나라에서는 아마존에 소개되었다고 광고. 2020년 출판계 현실을 대변하는 책! 나무야 미안해', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3447, 173, '책은 평범한 한 여성이 이 책의 제목이자 키워드인 ‘Having’을 배우고 실행한 뒤 진정한 자신을 탐구하고 놀라운 행운을 만나게 되는 과정을 단계별로 소개한다. 이 책은 국내보다 외국에서 선출간 되었기에 더 화제가 되었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3448, 173, '내가 알라딘을 좋아하는건 그래도 비판적인 평이 달리기 때문이다. 이 책? 위화감이 들지 않는가? 그리고 걸러야 할 한가지 지표가 더 있지만 그걸 적었다간 신고 먹기때문에 적지 않겠다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3449, 173, '왜 베스트셀러인지 이해되지 않는 책...세계적 대부호들이 영향을 받았다는데...왜? 라는 물음이 떠나지 않는 책...작가님이 기자 출신이라는데 책을 읽는 내내 초등학생이 쓴 위인전이 떠오르는 건 왜 인지...구루의 구태의연하지 않는 얘기 해빙? 이 책이 담고 있는 내용이야말로 구태의연!!', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3450, 173, '미리보기 보고 구매를 결정하라는 말 듣기를 잘했다. 초반에 저자인지 멘토인지 그가 얼마나 인기가 많고 매력적인지를 묘사하는데 도대체 내가 이걸 왜 보고 있어야 하는 생각이 들었다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3451, 173, '왜 이리 평점이 높은걸까? 해외 선출간된 책이라기에 읽게 되었는데 솔직히 민망해서 읽기가 힘들었다. 메인 저자분이 컨설팅이 직업인 이서윤이라는 사람을 구루로 칭하는 것도, 완전히 성인인양 띄워주는것도 불편하다. 물론 그래야만 책이되겠지만... 인생사는데 도움되는 이야기는 약간 있다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3452, 173, '읽는내 마음이 불편하였다. 작가는 이서윤님을 마치 옛 성인처럼 묘사하고 있어 이게 진짜 맞는 말인지 의혹이 들게한다. 지금을 즐기고 감사하게 여기라는 말인데, 늘 알고 있던 평이한 조언인듯 싶다. 각계 ceo 누구를만났으며 연구,분석했다는 중요한 데이터들은 언제 나오나..끝까지 안나온다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3453, 173, '돈..그리고 노골적이라는 단어에 훗~ 하고 웃은 책. 개미지옥과 해빙.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3454, 173, '이게 무슨 베스트셸러인지. .진짜.돈아까움 읽으면서 다른 내용이 더 있을거라 기대했지만 없음 현재를 즐기란말은.나도하겠다 내인생 최대 워스트', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3455, 173, '홍주연 작가님이 이서윤씨에 대해 서술하는게 존경심을 넘어 신격화하는 느낌이 너무 강해 읽기 불편했습니다. 조언과 설명이 추상적이고 잘 꾸며놓은 무당정도네요. 돈 주고 읽기 아까운 책입니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3456, 173, '일단 3분의 1 정도읽었습니다.페이지마다 해빙이란 단어는 반복되고 의미가 부여되고 있지만 마케팅에 속은 기분이 아직 지워지지 않네요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3457, 173, '역술인의 신격화. 그 이상 무엇인가요.학창시절부터 줄지어 찾아갔다는 그분들도 역술인으로의 이서윤을 찾아간것 같은데 이 책이 왜 베스트인지 모르겠습니다. 과 짜깁기라 느끼며 읽다덮어버렸습니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3458, 173, '경제계리더들의 자문을 했다는 광고에 구입했는데 왜 이책이 상위에 랭크가 될까?밑에분이 지적하셨듯이 내용이 죄다 추상적이고 무조건 해빙이다 이서윤씨에 대한 작가의 노골적인 홍보에 깊이가 없고 글에 흐림이 없다보니 읽고나서 들인 돈과 시간이 너무 아까웠던 최악의 책', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3459, 173, '뭔가 있을까해서 끝까지 다 읽었지만 그냥 주유하는 도사님 따르기;', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3460, 173, '도대체... 아무리 읽어봐도 내가 흡수해야 할 건 한구절도 없던데.‘수지 큐‘하듯이 손가락을 이마에두다니 ㅋㅋㅋ자기계발서에서 이 무슨 ㅋㅋㅋ출판사에서 홍보를 잘하는거야 능력이라지만 내용이 아무것도 없는데 좋은 책인냥 사람들 현혹해서 구입을 유도하는 게 옳은 일인가 싶다.', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (174, '이휘소 평전', 190, 4.86, 0, 0, 5, 17, 168, 185, 5, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3461, 174, '책겉표지에 찍혀있는 사진은, 울 사무실 근처 슈퍼 아저씨와 너무 닮아서.. 단지 그것 하나만 친근하고 전혀 관심이 없었다. 졸다가 잠깐 읽은 앞머리에는 잘못 알려진 그에 대한 많은 것을 바로 잡고 싶다, 라고 쓰여있다. 그렇지, 자서전보다 더 힘든것이 평전이다. 그에 대한 일방적인 미화도 꾸밈도없이 담담하게 그를 추모해야 하는 것일 테니까. 인기몰이로 이휘소,라는 이름이 유명해졌지만 우리에게 그는 그런 의미가 아니지 않은가. 너나할것없이 모두들 읽던 그 책을 나는 모르지만, 오히려 그래서 그의 평전에 관심이 없었지만 이제 조...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3462, 174, '평전은 개인의 일대기를 서술자의 평가를 통해 살펴볼 수 있는 책이다. 객관적 사실들을 고증하고 자료를 열거하여 구성하는 전기와 다른 특징이다. 그렇다고 해서 평전에 허구fiction이 가능한 것은 아니다. 사실fact를 바탕으로 하되 서술자의 해석과 평가 적절한 분석들이 더해지면 한 사람의 생애가 오롯이 떠오른다. 한 사람의 일생을 평가한다는 의미가 아니라 개별적 사실들에 대한 인과 관계를 적절히 구성하고 배열하는 일련의 과정이라는 말이다. 결코 쉬운 일이 아니며 훈련된 글쓰기와 철저한 고증만이 책을 빛나게 한다. 단순한 사실들의 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3463, 174, '먼저, 쓴소리 부터 하고 넘어가자. 이 책의 저자는 이제라도 이휘소에 대해서 제대로 알려야 하고, 또 널리 알리려 이 책을 썼다. 하지만 그런 것에 반해, 이 책은 이휘소라는 사람에 대한 이야기보다 물리학에 대한 이야기가 지나치게 많다. 그래, 이휘소라는 사람이 물리학에 기여한 바가 높아서 그를 논하는 데 물리학이 빠질 수 없다는 건 이해한다. 하지만, 그렇다고 해서 일반인들이 이해하기 어려운 물리학적 역사와 흐름, 그리고 이휘소가 연구했다던 소립자니, 게이지 이론이니, 이런 것들을 지나치게 상세하게 기술 할 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3464, 174, '1965년경부터 SU(6) 이론 분야에서 두각을 나타내기 시작 1970년대에 물리학계의 큰쟁점이었던 Quark와Charm이론 연구로 명성을 높였고 약작용과 전자기력을 통합하는 통일장이론에도 기여한 것으로 알려졌으며 입자물리학의 대가 이휘소박사의 삶 그의 제자가 쓴 스승을 향한 존경 사랑이 느껴집니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3465, 174, '과학의 힘은 영원합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3466, 174, '우리나라 과학자분들의 정신적 지주랄까. 최정상급의 석학이셨죠. 우리나라에도 이런 과학자분이 계셨다는 사실이 자랑스럽습니다. 현대인이 꼭 기억해야할 인물입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3467, 174, '무궁화 꽃이를 통해 처음 이휘소라는 사람을 알게되었는데 다시한번 이휘소를 만나네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3468, 174, '이런분이 많아야하는데 우리나라 이공계가 참 열악하다죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3469, 174, '물리학자 이휘소의 생', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3470, 174, '한국이 낳은 천재 물리학자라니 관심이 없으면 모르는데 이런분에 대해서 서거 40주년 기념으로 알게 되는 것도 좋은 것 같네요. 한국의 자랑이라는데 모르고 있는 것도 웃기고 이런 분들에 대한 이야기들이 좀더 정확하게 자세히 알려졌으면 좋겠어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3471, 174, '한 소설에 의해서 진가가 가려졌던 이휘소박사의 실질적인 모습을 알수있는 책이네요. 노벨상에 가까왔던 한국인 이휘소박사의 일대기를 잘 알수있게 하는 책이라서 기대가 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3472, 174, '훌륭한 책은 시대가 지나도 계속해서 찾는 사람이 있다. 이 책의 복간이 그래서 참으로 반갑다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3473, 174, '이 분이 살아 계셨다면 우리나라의 역사는 또 한번 바뀌었을 거라고 하죠~어쩌면 정치의 희생양, 죽음에 대한 의심...학자로서의 삶과 갖고 계셨던 신념과 능력까지.. 우리가 기억해야 할 분이 아닐까 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3474, 174, '몰랐는데 이런 분도 계신다니 존경스러웠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3475, 174, '노벨상 후보로 거론될 정도로 훌륭했던 이휘소 박사의 업적과 그 가치를 제대로 알 수 있는 기록이 나와 반갑네요. 제자 강주상 교수의 사실적인 기록이라니 더 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3476, 174, '한국의 가장 위대한 세계적 물리학자인 이휘소에 관한 평전이 나와서 기대되구요. 그의 갑작스런 죽음으로 여러가지 설이 있지만 이 책을 통해 그에 대해 진실을 알게 되길 기대합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3477, 174, '한국이 낳은 천재 물리학자 이휘소님의 대한 이야기를 들어볼 수 있을 것 같아서 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3478, 174, '언론에서 한참 회자되기도 했던 한국의 물리학자 이휘소.현재 우리나라에서 천대시받고 있는 기초과학에서도 독보적인 명성과 물리학에 새로운 지평을 여신 이휘소의 평전.기초과학의 부흥을 위해서라도 이책이 널리 읽혀야 하지 않을가 싶습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3479, 174, '지금도 살아계시다면 우리나라의 과학발전과 미래는 어떻게 달라졌을까를 생각해봅니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3480, 174, '이휘소 박사 서거 30주기에 새롭게 나온 책이라 기대가 됩니다. 솔직히 과학 분야에 크게 관심을 가지고 있지 않아서 잘 모르는 분이었지만 이 책을 통해 어떤 분이었는지 자세히 알 수 있을 것 같아요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (175, '내일은 실험왕 33', 189, 4.88, 0, 0, 1, 20, 168, 188, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3481, 175, '점점 더 강력한 바이러스가 나타나는 것 같은데, 초등학생들에게 바이러스가 무엇인지 쉽게 알려주고 우리 몸의 면역에 대해서 알려주어서 과학지식과 교과 학습 연계 뿐 아니라 스스로 건강을 지킬 수 있도록 도와주는 책이라 그동안 읽었던 내일은 실험왕 시리즈보다 훨씬 좋아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3482, 175, '시리즈는 아이가 좋아하는 책이기에 온 가족이 흥미롭게 읽고 있어요. 만화로 되어 있어서 쉬운 과학이죠. 면역과 바이러스는 건강을 위해서도 도움이 되는 내용이죠. 집에도 10권 정도있지만 도서관에서도 빌려 보는 책이랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3483, 175, '면역체계에대항 유용한 과학적 상식이 만화를 통해 쉽게 원리와 과정을 재밌는 스토리로 엮었네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3484, 175, '만화로 과학도 가르쳐주고 간단한 실험도 하는 법 가르쳐 주고 교육만화 중에서 재밌게 보고 있는 책입니다. 이번 권의 주제는 세균, 면역등의 생물학 관련이네요. 맥박재는 법등이 있는데 볼만 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3485, 175, '어렸을 때부터 이 책을 통해 아이와 함께 하나하나 차근차근 실험을 통해 과학을 익힌다면 쉽게 원리를 터득하고 기억에도 오래 남을 거에요. 만화형식이라 더 보기도 좋네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3486, 175, '직접 실험할 수 있게 준비되어 있는거 같아서 아이들에게 선물해주고 싶은 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3487, 175, '쉽게 만화로 배우는 그래서 더쉬운책 어려운 과학도 이책으로', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3488, 175, '실험왕 시리즈 정말 재밌던데, 꼭 사볼게요!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3489, 175, '내일은 실험왕 시리즈 아이들이 마법천자문과 함께 좋아하는 책이예요. 아이들이 만화만 읽는것 같아 걱정되지만, 무언가 좋아하는것이 있다는것도 나쁘지 않습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3490, 175, '초등학생 아이들에게는 어려운 내용들을 만화로 친근하고 쉽게 배울 수 있는 책이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3491, 175, '늘 재미있게 읽는 학습만화 중 하나 내일은 실험왕. 다양한 과학지식을 얻을 수 있어 유익한 책인데 바이러스와 면역체계에 대해서 잘 배울 수 있어서 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3492, 175, '만화를 통해서 바이러스와 감염에 대해서 재미나게 배울수있게 하는 책이네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3493, 175, '실험을 통해서 아이들에게 과학의 원리와 용어를 쉽게 전달해 주고 있어서 좋네요.아직 애들이 어려서 과학에 대해 어려워만 하는데.실험을 통해 따라 하다 보면 재미도 느끼고 점점 관심을 갖게 될 것 같아서 좋네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3494, 175, '세균 바이러스 생물등 과학의 실험이 어떻게 구성되고 실험과 우리 인체 세균의 면역체계를 쉽게 풀어나가는 책인거 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3495, 175, '오, 과학실험부 방과 후 학습을 하면서 부쩍 ｀과학 실험｀ 이라는 것에 호기심을 보이는 저희집 첫째 딸이 좋아할 책이네요. 학습만화라서 글자 읽는게 아직 부담스러운 1학년에게도 좋을 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3496, 175, '과학을 쉽고 재밌게 배울 수 있을 것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3497, 175, '기초과학이 대우받는 세상이 되기를 바랍니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3498, 175, '공상과학의 힘이 발휘하는 세상이 왔으면 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3499, 175, '만화로 재미있게 읽으면서 과학 원리와 개념을 자연스럽게 익힐 수 있어요 이번에는 직접 비누를 만들어 볼 수 있어서 더 흥미롭네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3500, 175, '아이들이 좋아합니다. 막 실험을 하겠다고 난리입니다. 책의 효과가 큽니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (176, '노인과 바다', 189, 4.45, 2, 3, 14, 59, 111, 170, 14, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3501, 176, '인생의 허무를 말하기 이전 거친 바다에서 자신의 소신과 뚝심을 보이는 노인의 이야기가 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3502, 176, '매해 다른 느낌으로 다가오는 헤밍웨이의 책인 노인과 바다...이번엔 어떤 감동을 말해줄지 모르겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3503, 176, '헤밍웨이의 [노인과 바다]는 두 어번 읽었지만 고전은 한 두 번 읽는 것으로 끝나지 않으니까요!! 또 읽으면 또다른 의미들이 보일 거라 기대합니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3504, 176, '망망대해에서 만난 거대물고기.. 그리고 허망한 결말이지만 그 안에서 인생을 들여다보게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3505, 176, '헤밍웨이의 걸작을 다시 만나볼 수 있는 기회이니 선택할 수 밖에 없다! 인생의 가장 중요한 시점 그 시점에 결정할 수 있는 단 하나의 선택 과연? 어떤 결과를 가져올까?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3506, 176, '산티아고가 팔십사일동안 벌이는 사투는 인생의 여정, 삶을 그리는 한편의 드라마로 기억됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3507, 176, '노인과 바다. 그리고 노인을 사랑한 소년.시련을 안겨주는 바다 그리고 인생. 노인의 철학을 다시 배워본다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3508, 176, '『노인과 바다』​​​어니스트 헤밍웨이 (지음) | 황유원 (옮김) | 휴머니스트 (펴냄)​​​​[노인과 바다] 번역본은 과연 얼마나 될까? 아마 어마어마하게 많을 것이다. 지금도 인터넷 서점 조회 DB를 조회해보면 스크롤을 계속 내려야한다. 어린이판에서부터 만화도 있고 삽화 형식도 존재하고, 그림책으로도 존재한다. 그만큼 헤밍웨이의 작품 중 [노인과 바다]는 광범위하게 알려진 작품이고 회자도 많이 된 작품이라 하겠다.​이번에 휴머니스트에서 다시 번역된 [노인과 바다]는 과연 무엇이 다른가? 우선 번역자의 말에 따르면 마침표의 남발로...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3509, 176, '『노인과 바다』​​​​4개월마다 새로운 테마로 다섯 권의 세계문학을 만날 수 있는 휴머니스트 세계문학이 벌써 네 번째 시즌으로 돌아왔습니다. 흄세 시즌 4는 ''결정적 한순간''이란 테마인데요. 우리가 인생을 살아가면서 다가오는 수많은 기회들 중 과연 몇 번의 기회를 알아보고 잡을 수 있을까요? 결정적인 순간에 우리가 한 선택에 후회하지 않고 ''그때 그렇게 결정하기 잘했다.''라고 말할 수 있는 이는 또 얼마나 될까요? 이번 테마에서 만나는 작품 속 주인공들은 그들이 선택한 결정에 어떤 인생사를 담고 있을지 궁금해집니다. ​흄세...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3510, 176, '[결정적 한순간을 생각하며 새롭게 발견한 노인의 의지] 제 스스로가 세계문학을 대하는 자세에 대해 여러 번 말씀드렸을 거예요. 자고로 세계문학은 한 번만 읽는 게 아니라고, 여러 번 읽어야 감이 좀 오고 매번 다른 메시지를 발견하게 된다고요. 그 여러 번 읽은 세계문학 중 하나가 바로 어니스트 헤밍웨이의 [노인과 바다]입니다. 학창시절에는 다른 작품들에 비해 상대적으로 짧아서 골라 읽은 후 노인과 고기의 맞대결 정도로 기억하고 있었어요. 헤밍웨이의 삶을 대하는 자세, 저만의 무언가를 발견하기까지는 시간이 좀 걸렸...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3511, 176, '어릴 때는 빠른 시간에 많은 양의 독서를 하다 보니 그냥 글자를 읽는 수준이었습니다. 지금은 오히려 시간이 많아서일까 아니면 원인 모를 이유로 같은 페이지를 여러번 읽는 일도 생겨 납니다. 헤밍웨이의 주인공은 대개 혼자고, 외롭고, 때로는 완전히 고립되어 있었습니다. 이 외로움이 작가의 생애를 돌아볼 때 하드보일드일 수밖에 없었을 것입니다. 주인공 산티아고와 쿠바 연안을 배경으로 한 거대한 물고기에 맞서 사투를 벌이는 것은 늙은 어부의 고집이라고만 볼 수 없습니다. 인간의 삶과 자연에 대한 근원적인 질문을 하게 되는 작품입니다. ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3512, 176, '노인과 바다어니스트 헤밍웨이 (지음) | 황유원 (옮김) | 휴머니스트 (펴냄)인간은 패배하도록 만들어지지 않았어.인간은 파멸할 수는 있어도 패배할 수는 없어.- 노인과 바다, 본문 112페이지어니스트 헤밍웨이의 최고의 작품이라고 불리우는 . 그 유명세 때문인지 해적판과 표절작이 많아 번역 논란이 유난히 많은 작품이기도 하다.번역을 달리하며 매번 읽을때마다 느끼는 것이 한가지 있다면 ''그럼에도 삶은 계속 된다는 것. 그리고 계속해서 살아가야 한다''는 것.삶은 마음대로, 마음먹은대로 되지 않고 살아...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3513, 176, '어떻게 보면 지나치게 단조로울 수 있는 이야기가 바로 어니스트 헤밍웨이의 『노인과 바다』이다. 늙은 어부, 아니 솔직히 말하면 운도 없고 실력이 있나 의심받았을지도 모를 어부 산티아고는 거의 90여 가까이 고기를 잡지 못한 상태이다. 이렇게나 고기잡이에 실패를 했을테니 산티아고의 삶도 녹록지는 않았을것 같은데 그럼에도 산티아고는 계속해서 바다로 간다. 그리고 드디어 고기를, 그것도 거대한 청새치 한 마리를 잡게 된다. 얼마나 기쁠까. 어쩌면 산티아고보다 이 글을 읽은 독자들이 더 기뻐하고 안도하지 않았을까. 이제...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3514, 176, '휴머니스트 『노인과 바다』​​휴머니스트 세계문학 시즌 4 결정적 한순간이라는 주제로 노인과 바다를 읽게 되었다. 휴머니스트의 새로운 번역의 이번 노인과 바다 다시 한번 경이로운 인간의 모습을 느껴보려 한다. 84일 이 노인에게는 가혹한 시간이었을 도 모르겠다. 하지만 끝까지 포기하지 않을 그이기에... 운은 자신이 만들어 갈 수도 있는 것 아닐까? 믿음으로 하나 된 노인과 소년! 소년이 노인 곁에 있어서 다행이다. 산티아고 할아버지에게 행운이 깃들길 바라는 마음은 나나 소년이나 같은 마음일 테지... ​노인에게 바다는 과연 어떤 의...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3515, 176, '2년전 고전 입문용으로 얇은 두께때문에 선택했던 책. 실제로 항해하며 낚시하는 기분을 만끽할 수 있게하는 묘사력이 일품. 목숨이 와따리가따리하는 주인공의 스릴도 느낄수 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3516, 176, '인간은 파멸당할지언정 패배할 수는 없다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3517, 176, '왜 볼 때마다 마지막에 가서 우는지 모르겠다. ㅜㅜ 너무 좋은 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3518, 176, '쇠약해져가는 노인의 육체속에 점점 더 격양되어가는 노인의 영혼의 대조는 인상깊었다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3519, 176, '저작권이 어쩌고 하지만 이제껏 괜찮은 헤밍웨이 전집이 국내에 없다는게 참 의아했다. 이제 드디어 나오기 시작하나보다. 민음사 콜렉션에 포함되어서 기쁘다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3520, 176, '상어와 혈투하는 모습에서 젊음을 느꼈다', 3);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (177, '무지개 원리', 188, 4.48, 2, 2, 14, 56, 114, 170, 14, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3521, 177, '나는 이책을 그렇게 눈여겨 보지 않았다. 왜냐면 이 책이 기독교 관련 서적이라는 선입견이 있었기 때문이다. 그러나 지인을 추천을 받고서 읽어본 결과 얼마나 나의 생각이 어리석었는지 알 수 있었다. 이 책은 역사적 사실과 배경을 가지고서 부와 성공 그리고 행복을 얘기하는 진정성을 가지고 있다. 단순히 종교적 세계관을 가지고서 믿으라 따르라 하는 신념과는 다르게 구체성을 가지고 있어서 비 기독교임에도 불구하고 좋은 메시지를 얻을 수 있었다. 기독교인 이지만 일반인이 읽어도 무방할 노먼빈센트필 박사의 책 같다고나 할까,...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3522, 177, '퇴근하자마자 몇 페이지 남지 않은 분량을 마무리 지었다. 개인적으로 한 권의 책을 읽는 데 시간을 나누는 것을 매우 싫어한다. 이유인 즉, 책 한권 자체가 마음의 양식 한 덩어리인데 시간을 나누게되면 양식 덩어리도 덩달아 나눠지기 때문에 독서의 집중성과 통일성에 영향을 끼친다는 생각 때문이다. 그렇기 때문에 평일보다는 주말에 시간을 내서 몰아쳐서 읽는 독서를 즐겨한다. 상대적으로 읽기를 갈망했던 욕구도가 높은 책일수록 아껴서 주말에 미뤄 한번에 읽는 이유가 거기에 있다. 어디까지나 개인적인 독서경향이니 각설하고,, ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3523, 177, '2007년에 발가뇐 자기계발서. 구약성경 신명기 6장의 내용을 바탕으로 전체 내용이 구성되어 있다.가. 좌뇌 영역은 지성이며 여기에 해당되는 원리는 다옴과 같다.1. 긍정적으로 생각하라2. 지혜의 씨앗을 뿌려라나. 우뇌영역은 감성이며 여기에 해당되는 원리는 다음의 내용이다.3. 꿈을 품어라.4. 성취를 믿어라.다. 둘을연결하는 뇌간의 영역은 의지다.5. 말을 다스려라.6. 습관을 들여라.공통적으로 7. 절대로 포기하지 마라. 항목이 있다.자기계발서들은 대부분 명령형으로 되어있기에, 읽기는 쉽지만 그 결과를 보는 것은 쉽지 않다.또...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3524, 177, '희망을 이야기 하며 많은 예화들을 담고 있다. 아마 저자는 이 책을 펴내기 위해 수십 수백권의 책을 뒤졌을 것이다. 나중에는 읽다보니 이런 생각도 들었다. 이건 글을 지어낸 수준이 아니라 엮은 경지이지 않는가? 저자가 아니라 엮은이라고 소개해야 하지 않나? 본인이 만든 무지개 원리에 왜 이리 유명한 글귀들을 수두룩 빽빽하게 참조해서 부연하시는지 독창적인 글쓴이가 되셨으면 하는 바람을 가져본다. 그리고 글을 읽으며 희망을 가지려하다가도 갑자기 종교이야기로 삼천포에 퐁당 퐁당 빠져주시는데 이건 무슨 약장사인가?...+ 더보기', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3525, 177, '''자기계발서''류가 무섭게 출간되고 있다. 내용도 부실하고, 우화만 그럴싸하게 덧붙여 대단한 이야기인양 하는 책들…정말 질린다. 특히 처음 듣는 외국저자의 자기계발서들. ''이게 베스트 셀러? 이래선 안 되는데'' 한 적이 한두 번이 아니다. 서양의 기준에서, 그들의 관점에서 하는 이야기를 우리가 그대로 받아들일 수 있을까? 우리는 우리기준의 자기계발서를 만날 수는 없는 것일까? 항상 생각해 왔다. 저러한 물음의 해답을 던져주는 책이 여기 있다. . 저자는 이스라엘의 ''셰마 이스라엘''에서 영감을 얻는다. 셰마 ...+ 더보기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3526, 177, '내가 본 책 뒤를 보면 1판 105쇄 개정판 19쇄 라고 씌여있다. 1쇄에 얼마정도를 찍었는지는 잘 모르겠지만, 대략 2000부 정도로 계산하더라도 20만부를 훌쩍 넘기는 권수가 나온다. 여러곳에서 베스트셀러라기에 어떤 내용인지 궁금해 호기심에 책을 읽게 됐다. 저자가 종교인이라 다분히 특정 종교의 성향이 짙어 타종교를 선호하는 내 입장에서는 약간 거슬리는 부분도 일부 있긴했지만,좀더 객관적인 눈으로 본다면, 인간 본연의 마음가짐을 다 잡는데는 좋은 글귀들이 씌여있다. 저자의 의도는 아니겠지만, 최근들어 자기개...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3527, 177, '내 생애 가운데 무지개를 본 일이 있다. 그것도 쌍무지개를! 작년에 이스라엘여행을 마치고 암스테르담에 도착했을 때 한 동안 추적추적 오던 비가 그치고 햇볕이 나려나 싶은 그 어정쩡한 시간 날이 좀 개는구나 싶은 그 순간, 이제껏 먹구름 속에 갇혀있던 하늘이 열리면서 뜻밖에도 찬란한 무지개가 나타났다. 그 빛이 너무나 놀랍도록 신비하고 아름다워서, 이제껏 한 번도 본 적이 없는 것이라서 어떤 감탄사도 나오지 않았다. 내 눈으로 본 무지개는 어릴 적 그림책에서 본 빨주노초파남보의 경계가 딱딱 끊어지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3528, 177, '제목 : 빨주노초파남보~~ 어느날 우연히 ‘하는 일마다 잘 되리라’는 를 읽었다. 책을 모두 읽고나서 책을 덮은뒤 가만히 두손으로 보듬은 책을 가슴에 대고 두눈을 감았다. 무뚝뚝하고 경직된 얼굴 근육이 풀리면서 나도 모르게 잔잔한 미소를 머금었다. 저자는 유다인들의 지혜서인 탈무드와 매일 두 번씩 암송하는 ‘셰마 이스라엘(이스라엘아, 들어라)’에서 발견한 유다인의 성공원리를 구체적으로 체계화했다. ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3529, 177, '올해 연구학교 주무를 맡고 있는데, 주제가 학력신장이어서... 어떻게 학원도 못 올리는 학력을 학교에서 올리란 거냐... 하다가... 학습 기술을 통하여 학력을 올려 보자는 컨셉트를 잡았는데... 기술적인 측면에서 접근하는 것의 한계도 있지만, 어떤 학생을 어떤 교사가 지도하는가가 정말 어려운 것이어서 요즘 보고서 쓰는데 곤란을 겪고 있다. 아이들에게 긍정적인 효과를 유발하는 이야기들을 찾아읽던 중, 무지개 원리를 읽었다. 차동엽 신부라는 이가 이런저런 이야기들을 적어 둔 책이다. 잡학 사전으로 보면 된다. 그의 무지개...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3530, 177, '성공하려면 나 자신을 지금의 나와는 다른 나로 조련할 필요가 있기에 우리는 무수한 자기계발 책들을 읽게 된다. 그렇지만 나를 전과는 다른 나로 만드는 일은 결코 쉽지 않기에 그런 책들을 읽고 또 읽으면서 나를 조금씩 바꿔야 나가야 할 것이다. 이 책은 성공의 이르게 하기 위해 부족한 나를 채우고 변하지 않는 나를 바꿔주기 위해 일곱 가지의 각기 다른 무지개 빛처럼 7가지의 조언을 한다. ‘긍정적으로 생각하라’, ‘지혜의 씨앗을 뿌려라’, ‘꿈을 품어라’, ‘성취를 믿으라’, ‘말을 다...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3531, 177, '같은 학원 선생님께서 빌려주신 책. 이 책의 저자는 독자들에게 삶을 살며서 무지개원리를 지키면서 살면 성공할 것이라고 이야기하면서 삶을 대하는 우리의 태도에 대해 알려주고 있다. 하나 하나 좋은 말들이어서 곱씹으면서 책을 읽어나갔다. 그리고 강조한 것이 있었는데 ''무지개원리'' 이 책을 21번 정도 읽으면 몸에 배어 더욱 성공으로 가는 것이 쉽다고 많이 읽을 것을 권하고 있다. 기회가 된다면 책을 사놓고 틈나는대로 읽어야지~~ 작가가 소개하는 무지개 원리 1. 긍정적으로 생각하라 2. 지혜의 씨앗을 뿌리자 3. 꿈을 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3532, 177, '무지개 원리 1. 긍정적으로 생각하라 2. 지혜의 씨앗을 뿌리라 3. 꿈을 품으라 4. 성취를 믿으라 5. 말을 다스리라 6. 습관을 길들이라 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3533, 177, '''하는 일마다 잘되리라 '' 믿으면 된다... 이 책의 핵심이다. 성공이란 무엇일까? 필자는 부, 명예, 권력 등을 벗어난 그 이상의 것이어야 한다고 말한다. 그리고, 그 성공을 위해 유다인의 법칙, [셰마 이스라엘]을 들고 있다. "마음을 다하여, 목숨을 다하여, 힘을 다하여" ''마음을 다하여''는 모든 정을 합해서 즉, 감성을 다 하라는 말이다. ''목숨을 다하여''는 영혼을 다하라는 말로, 의지를 다하라는 말이다. ''힘을 다하여''는 생각의 힘을 다하라는 말로, 모든 지식을 모으라는 말이다. ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3534, 177, '일찍이 쇼펜하우어는『인생을 생각한다』에서 다음과 같이 말했습니다. 일상생활에서 일요일은 권태를, 나머지 6일은 가난이라고 했습니다. 어쩌면 우리도 삶의 여러 가지 문제에 짓눌려 삶이란 끝이 보이지 않는 우중충한 회색빛이라 여길지도 모릅니다. 하지만 이 책을 통해 차동엽 신부님을 알게 된 것은 행복했습니다. 그는 삶의 힘겨움 속에서 일곱색깔 무지개를 선물해주고 있습니다. 그만큼 그는 삶에 대한 믿음을 주장하고 있습니다. 더불어 깨달음의 울림이 메마르지 않아 답답한 마음을 시원하게 적셔주었습니다. 이로 인해 그가 말하고자 하는 긍...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3535, 177, '내용이 무척 쉽다. 저자가 말하고 싶은 내용들을 다양한 사례를 통해 설명했기에 더욱 마음에 와 닿는다. 기존에 나온 자기계발서들의 내용을 기반으로, 저자 나름대로 무지개원리라는 구조 하에 재조정한 글이라 그런지 독자들의 마음을 더욱 울리는 것 같다. 그만큼 검증된 이야기들이기 때문이다. 그 동안 자기계발서를 많이 봤던 사람일지라도 이 책을 보면서 예전에 봤던 내용들을 다시 한번 되새김질할 수 있을 것 같다. 책을 읽다 보면 저자의 마음 씀씀이를 느낄 수 있다. 어떤 사심 없이 자신이 느낀 것을 있는 그대로 사람...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3536, 177, '요즘 근 두주동안을 끼고 다니면서 3번이나 읽었던 책입니다. 다른 자기개발 서적처럼 두리뭉실하게 어렵고, 복잡하게 이야기를 하면서 비비꼬기보다는 구체적이고 명확한 예를 들어서 저를 공감하게 만들고, 제가 스스로 움직일수 있도록 도와주었던 책이였습니다. 정말 한국의 탈무드와 같다라는 말이 공감이 가더군요. 무지개의 7가지의 빛깔처럼 7가지의 1 긍정적으로 생각하라 2 지혜의 씨앗을 뿌리라 3 꿈을 품으라 4 성취를 믿으라 5 말을 다스리라 6 습관을 길들이라 7 절대로 포기하지 말라 메세지가 정말 ...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3537, 177, '불만이 폭발하다못해 뒷 목이, 머리가 뻣뻣해져 분을 삭힐수가 없는 마음을 가다듬고 책속에서 내 모습을 읽는다. 처음 읽을때 보지못한 또 다른 보물을 찾았다. “생각이 감정을 낳는다. 생각은 또한 행동을 변화시킨다. 마침내 생각은 인생을 바꾸어 준다.” 부정적인 나의 생각으로 인해 나를 더욱 나쁘게 몰고 가는 내 모습을 본다. 처음 읽었을때 그토록 나를 누르던 열등감이 아무것도 아닌 것을 책 속...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3538, 177, '무지개 원리 는 자기계발서이다. 개발이 물질적인 것인 반면에 계발은 정신적인 측면의 발전을 뜻한다. 더 나은 삶을 추구하려 노력하는 우리에게 는 시커먼 어둠 속에서 길을 알리는 빛이다. 모든 삶은 근본적으로 ''문제해결''라고 한 카를 포퍼의 말에 차동엽 신부님은 이렇게 덧붙인다. "이 세상에 답이 없는 문제는 없다." 비 온 뒤 무지개가 뜬다. 하지만 함께...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3539, 177, '무지개 원리라는 제목과 출판 50만부 기념 수정본이란 띠지를 보면서 무슨 내용이 담겨 있을까?란 생각에 이 책을 펼치게 되었다. 우선 전체적인 구성은 총 7부로 되어 있다. 각 부에서는 삶에 대한 자기계발을 수 많은 사례와 저자가 구성한 무지개 7가지 원리를 바탕으로 내용을 이끌어 가고 있다. 자기계발을 뇌와 접목 시켜, 좌뇌와 우뇌의 성향을 바탕으로 보다 자신의 삶을 개선하며 살 수 있도록 도움을 준다. 그리고 긍정적인 마음가짐을 갖게하여, 삶에 대해 다시 한번 생각할 수 있는 좋은 기회를 제공한...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3540, 177, '10번을 읽어도 좋을책 ... !!! 책속에 또 , 다른 책들이 들어있는 책 ~~!!! 이책을 읽으면서 .. 다시 여러권의 책들을 구입하게 됐다 . 말이 필요없는 책 ... 꼭 ~~!! 읽어보길 권하고 싶다 . 베스트 셀러가 되어야 할 .. 책 근데 .. 약간은 걱정이 된다 . 기독교인들이 읽을까봐 ... 하느님과 하나님의 차이로 ... 책 읽다가 던져 버릴수도 있지 않을까 ? 목사님이 아닌 ... 신부님이 썼기 ...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (178, '죽여 마땅한 사람들', 188, 4.21, 2, 3, 27, 77, 79, 156, 27, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3541, 178, '등장인물 전부가 다 이상한 사람들이다. 그렇지만 릴리의 궤변에는 기묘한 힘이 있다. 상관 없어 보이는 이야기와 설정들이 인물을 구성하고 행위에 개연성을 부여한다. 간만에 재밌는 스릴러를 만났다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3542, 178, '자신에게 상처를 준 사람들을 향한 사적 복수를 행하는 릴리.그렇다면 이 세상에 살아남을 사람이 있을까.어떠한 경우라도 죽여 마땅한 사람은 없다고 생각한다.죽어 마땅한 사람은?', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3543, 178, '2016-271_[관악도서관]이 책은 역자의 평이 더 재미있었다. 죽여 마땅한 사람들(Worth Killing) 수동적이지 않은 살인자의 능동적인 의지가 들어가 있다. 몇몇의 반전. 누가 결국 악인인지....악인의 최후는 어떻게 될지...우리 안에는 악마가 있는지도 모른다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3544, 178, '깔끔하고 소름 돋는 마무리가 인상적이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3545, 178, '최근에 본 소설중에서 최고다.이작가 두번째 소설이라는데.팬이 되버릴것만 같다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3546, 178, '이 책에서 묘사하고 있는 살인은 그닥 잔인하다는 느낌을 받을 수가 없다.저자는 살인을 미화시켜 제목과 같이 살인해도 마땅하다와 같은 합리화를 이끌어내고 있지 않나 생각한다.누군가 주변에 내 눈에 거슬리는', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3547, 178, '살인은 꼬리에 꼬리를 물고', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3548, 178, '내가 예상한 결말을 많이 벗어난 소설이었다. 각자의 관점에서 서술하는 방식이 긴장감을 유지할 수 있었던 것 같다. 강력 추천 소설이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3549, 178, '옮긴이의 말이 가장 재미있다 소설 자체는 텐션 나쁘지 않고 재미있긴 한데 곳곳에 성적 대상화 너무 심해서 눈쌀 찌푸리며 매직아이로 넘겨가면서 읽었다 ㅡㅡ', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3550, 178, '호모 사피엔스를 대체할 다음 종은 호모 사이코패스. 한국의 부모들이 선호할만한 품성을 모두 갖춘 주인공의 차분한 판단과 차근차근 실행하는 살인이 펼쳐진다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3551, 178, '반전에 반전에 반전에 반전.그런데 릴리의 마지막 행동은 좀 비이성적으로 보여서 좀 의아한 느낌이 들었음.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3552, 178, '꽤 흥미로운 설정이다. 사이코패스도 나름 매력적이다. 하지만 스토리가 전개되면서 막장드라마를 연상시킨다. (취향일지도 모르지만) 형편없는 수준의 소설이라곤 말 못해도 기대했던 것만큼 좋진 않았다는 게 솔직한 심정이다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3553, 178, '쫄려야할때 확실하게 쫄게해주는 소설.릴리는 도덕에서 벗어난 캐릭터인데 밉지않았다.그래도 소설 속의 나쁜 놈들은 조금 나쁘든 많이 나쁘든 다 죽거나 대가를 치뤘으니 릴리 역시도 그 법칙에서 벗어날 수 없을 것 같다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3554, 178, '스릴러 소설이 주는 즐거움이란 이런 것! 처음부터 끝까지 흥미진진. 이야기가 착착 맞아 들어가는 것이 아주 재미있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3555, 178, '재밌는데 추천하긴 뭔가 아쉽네.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3556, 178, '주인공에 이입해서 순식간에 읽어 가게 되는 소설! ｀그들이 정말로 죽여 마땅한 사람이었을까? 나라면 어떻게 했을까?｀ 싶은 의구심이 들기도 하지만 그보다 속도감 있는 전개에 짜릿함을 먼저 느끼게 하는 소설. 더운 여름을 시원하게 보내기에 딱 알맞다!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3557, 178, '잘 읽히는 게 전부인 것은 아니니까', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3558, 178, '너무 공감이되는 스릴러라고 할까. 예상이 되는 전개임에도 불구하고 완전 몰입해서 읽었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3559, 178, '길티 플레저에 빠져 타임길링하는데 제격이긴 하다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3560, 178, '재미는 있고 가독성은 매우 좋습니다. 다만 읽고 여운이 남을만큼의 매력은 없네요. 신선하고 번뜩이는 그런 플롯은 기대하지마세요. 그래도 킬링타임으로 역할을 충실히 해 준것에 대해선 감사.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (179, '애로우 중국어 첫걸음 Basic', 187, 4.87, 0, 0, 2, 21, 164, 185, 2, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3561, 179, '성조나 한어병음을 몰라도 ‘한글’과 ‘화살표｀를 따라 200개 중국어 문장을 읽다보면 반복학습이 이토록 효과 좋다는 사실, 어학에는 왕도가 없다는 사실을 알게 됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3562, 179, '문법위주의 중국어가 아닌 말하기에 초점을 둬서 초보자에겐 좀 더 실용적인 학습법일듯.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3563, 179, '중국어 공부를 꼭 해야할 것 같은데, 정말 어려운 중국어. 아이도 그러하고 저 역시 아이와 함께 중국어 공부하고 싶어요. 애로우 시리즈 영어로도 몇 권 읽었는데 중국어 시리즈도 많이 나왔으면 좋겠네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3564, 179, '거대한 괴물의 언어를 알고싶다. 이것으로 쉽게 배워보자', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3565, 179, '웬만한 중국어책들을 많이 샀는데 매번 앞페이지만 보기 일수다. 왜냐면 초보자들에게 맞춘 교재로서는 너무 어려웠기 때문이다. 초보자들은 발음에 약한데 그 발음을 표기한 게 맘에 든다. 게다가 그림과 함께 이미지 트레이닝이 될것 같은 점도 마음에 든다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3566, 179, '화살표를 통해서 중국어의 어려운 성조를 공부할 수 있다는 것이 놀랍네요. 강의도 무료로 볼 수 있어서 더욱 좋은 것 같아요. 시각화된 정보를 충분히 이용하는 방법을 꺠달았습니다. 이제는 중국어가 쉬워질것 같아요!! 강추!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3567, 179, '중국어의 시작을 쉽게 할 수 있는 책이네요. 중국어는 성조를 익히는 시간만해도 많이 걸리기에 이렇게 한글로 익혀도 된다면 환영입니다. 초보자에겐 쉽고 재미있는 방법이 좋을 것 같아서요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3568, 179, '중국어를 화살표와 그림으로 쉽고 재미있게 배울 수 있겠네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3569, 179, '중국어 배우고 싶지만 힘드네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3570, 179, '어떤 언어를 배우든 첫걸음, 시작이 정말 중요한데 이 책으로 중국어 시작에 많은 도움이 되었으면 좋겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3571, 179, '자세한 설명으로 중국어 더 쉽고 빠르게 배울 수 있을것같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3572, 179, '중국어에서 성조는 중요하죠. 그래도 성조만 배우느라 시간을 보낸다면 지겹기는 합니다. 한글도 발음이 나오기에 보다 쉽게 익힐 수있겠네요. QR코드 동강으로 언제나 보충학습이 가능하기에 편리한 책이네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3573, 179, '다시시작해 보는 에로우 학습 이번에는 중국어다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3574, 179, '복잡한 성조도 설명이 잘 되어있고 어순을 그림으로 배울 수 있어서 더 좋아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3575, 179, '중국어 공부의 정도를 알려주는 책입니다. 앞으로 중국과의 교류도 강화되겠죠? 남들보다 앞서서 공부해보아요 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3576, 179, '그림으로 이해하기 쉽게 되어 있다니 읽고 해보고 싶어요. 중국어 시도는 많이 해보는데 외울 것도 많고 한자도 어렵고 발음은 더 어려워서 힘드네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3577, 179, '중국어를 배우면서 한자도 많이 알아야 하지만 특히 발음에 신경을 많이 써야 한다는 것을 알게 되었는데, 이 책을 통해 어떠한 방법으로 발음을 해야 하는 지 알 수 있었습니다. 특히 우리말에는 없는 성조에 집중함으로써 실제로 연습할 수 있도록 구성된 것이 마음에 들었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3578, 179, '중국어가 성조때문에 배우기 어려운데 이 책은 그런 어려움을 좀더 덜어주는 책 같아서 기대가 되고 궁금하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3579, 179, '아.. 정말 성조-_- 중국어를 호기롭게 시작하다가도 결국에는 안하고 만다! 하게 만드는 진입장벽 성조를 mp3로 들으며 따라해서 굿! 한자를 계속 눈에 노출시키면서 한글로 발음하여 한번 더 굿!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3580, 179, '애로우 영어시리즈에 이어서 애로우 중국어도 나오다니 정말 대단합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (180, '좀머 씨 이야기', 187, 4.27, 0, 5, 19, 84, 79, 163, 19, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3581, 180, '목소리가 너무 좋아요 ! 글 내용과 잘 어울리네요 잘들었습니다 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3582, 180, '열일곱살 때 쯤 읽고서 리뉴얼판이 나왔길래 다시 읽었다. 예전이나 지금이나 의문이다. 좀머씨는 도대체 왜 죽었을까? 오랜 전 기억과 다시 읽은 책의 내용은 다소 다른 부분이 있었다. "그러니 제발 나를 좀 그냥 놔두시오" 이렇게 말하는 심정은 이해가 갔지만 "그러다 죽겠어요"라는 말에 한 반응이라면 좀머씨는 일생 죽음을 피하다가 죽음을 마주한 것이 아니라 죽음 속에서 죽음을 향하고 있었던 건지도 모른다는 생각이 들었다. 짧고 어...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3583, 180, '생생하고 귀여운 소년의 상상력이 더해진 긴장감과 물컹한 더러운 피아노 선생님의 코딱지가 주는 재미.좀머씨를 관찰하는 소년. 유년시절의 삶의 순간들. 성장. 어른이 되어가는 순간을 따뜻하게 들을 수 있다.이 책의 주인공은 나와 좀머씨다. 나와 좀머씨가 만나는 3번의 지점에서, 나는 성장하고 있었고, 가 그가 했던 말을 기억했다. 그러니/제발/좀/그냥 4번의 부사가 언제나 멈춰서게 한다. 폐쇄공포증의 가진 그는 걸어야만 하는 사람이었다. 병과 싸우고 지친 육체를 다독이고, 주위의 시선도...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3584, 180, '이 책을 읽고 파트리크 쥐스킨트의 책들을 모조리 찾아읽었다. 그 후 내 책장에는 파트리크 쥐스킨트의 초록색 책들이 가지런히 나열되어 있다. 처음에는 정말 이 작가의 에세이라고 생각했던, 섬세하고 몰입감있는 문장력.파트리크 쥐스킨트의 책은 무엇을 골라 읽어도 민족스럽다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3585, 180, '나는 훨훨 날아다닐 수 있을 만큼 몸이 가벼웠다. 그때 내가 바람을 뒤로 맞으며 학교 앞 동산의 초원을 가로질러 뛰어 내려 왔을 때 발을 조금만 힘차게 구르고, 팔을 양쪽으로 쭉 뻗기만 했더라면 내 몸은 바람을 타고 훨훨 날 수 있었을 것이다. 전혀 힘도 들이지 않고 2-3미터나 되도록 높게... 어쩌면 그렇게까지 멀리도 아니었고, 그렇게까지 높지 않았을지도 모르지만 그 따위가 무슨 큰 문제란 말인가! 어쨌든 나는 그때 날 수 있었고, 내가 만약 외투의 단추를 풀고 그것의 양 끝을 양손으로 잡아 주기만 했더라면, 바람을 타고 둥둥 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3586, 180, '언젠가 다시 읽어봐도 좋을 이 책을 읽기 전까진 파트리크 쥐스킨트에 대해 한 번도 들어본 적이 없었다. 그리고 책을 읽고 나서는 참 오랜만에 만족스러운 작품을 만났다는 생각이 들었다. 여기서 만족스럽다는 얘기는 순전히 주관적인 이야기 일 수 있지만, 어쨌거나 이 이야기는 그 분량이 짧은 만큼 가볍게 읽어도 좋고, 한없이 진지하게 읽어나가도 좋을 그런 책이었다고 생각한다. 결이 조금 다른 이야기 일 수는 있지만 생텍쥐페리의 처럼 아마 몇 년 뒤에 다시 찾아와 다시 읽게 만드는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3587, 180, '[좀머 씨 이야기]는 소년의 키가 100미터에서 170센티미터가 될 때까지 성장 하는 동안 소년 기억속에 비친 좀머 씨의 인생을 담담하게 그린 성장소설이다. 장자크 상페의 삽화가 들어 있어 읽으면서 쉽게 이해할 수 있다. 나무 타기를 무척 좋아하던 어린 시절, 우리 동네에는 라고 불리던 사람이 있었다. 마을에서 좀머 아저씨의 이름을 제대로 아는 사람은 한 사람도 없었다. 그리고 아저씨가 어떤 일을 하는지도 전혀 몰랐다. 하지만 우리 동네 사람들 중 좀머 씨를 모르는 사람은 없...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3588, 180, '좀머 씨 이야기 파트리크 쥐스킨트 (지음) | 장 자끄 상뻬 (그림) | 유혜자 (옮김) 열린책들 (펴냄) ​ ​ ​ 책 제목은 인데 좀머 씨 얘기가 얼마 나오지 않아 처음 읽었을 땐 ''왜지?'' 라는&nb...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3589, 180, '파트리크쥐스킨트 리뉴얼 시리즈 그 4번째 좀머씨의 삶은 무엇을 말하고 싶은 것이었을까 ? 책을 다 읽고 난 후에 남는 의문이 남는다. 그의 삶과 죽음이 의미하는 것은 무엇일지 생각해보지만 그건 언제나 의문일 듯 하다. 전쟁을 겪고 그 상처와 후유증이 남아 평생 죽음으로부터 벗어나기 위해 도망 다니는 삶.도망치는 것 만이 살길이다 그 생각만으로 살았을까 언덕 아래에서 발을 들고 잠시 손을 뻗으면 하늘을 날수 있을거라는 상상을 하고 자신이 관심을 가진 어린...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3590, 180, '파트리크 쥐스킨트, 좀머 씨 이야기 늘 조용하고 사람들의 방해를 받지 않을 수 있기에 나무 위에 있기를 좋아했던 ''나''는 우리 집과 2킬로미터도 떨어지지 않는 곳에 살고 있는 ''좀머 씨'' 이야기를 꺼낸다.계절에 상관없이 호두나무 지팡이를 짚고 우비만 든 배낭을 메고 이 마을에서 저 마을로 늦은 저녁까지 끊임없이 사방을 쏘다니는 좀머 씨. 그는 사람들과의 관계 맺기를 거부하고 그저 자신의 자연 회귀에만 관심을 두었나 보다. 죽음에 이르는 인생의 마지막 걸음마저 걸어서 가버...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3591, 180, '그러니 제발 나를 좀 그냥 놔두시오, 제발 나를 좀 그냥!절규처럼 들리는 저 문장은 좀머 씨를 떠올리면 생각나는 문장이다.긴 막대기와 밀짚모자 배낭을 메고 하루 종일 온 사방을 돌아다니는 사람.좀머. 독일어로 여름을 뜻한다는 좀머.한 소년의 푸릇푸릇 한 성장기가 전반적인 이야기를 이끌어 간다면 간간이 출연하지만 잠시도 존재감을 멈추지 않는 좀머 씨의 이야기는 소년의 파릇함에 대비되는 어두움이다.사람이 한 번에 두 가지를 다 가질 수는 없는 법. 세상에 대한 복수와 세상 안에서의 영생. 그래서 나는 복수를 택하기로 했다!지각했다고 노...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3592, 180, '“그러니 나를 좀 제발 그냥 두시오!”p.36표지에 그려져 있는 좀머씨가 내 눈에는 회중시계를 보며 어딘가 급히 가던 이상한 나라 앨리스의 토끼로 보였다. 그래서 파트리크 쥐스킨트 시리즈 도서 5권 중 가장 먼저 읽게 된 . 책을 읽고 나서 그 첫 느낌이 얼추 맞았다는 생각에 신기하기도 했다.나무 타기를 좋아하는 어린 소년 ''나''를 통해 듣는 , 어디에서 왔는지 무엇을 하다 온 사람인지 매일 어디를 그렇게 걸어 다니는지 아무도 모르지만, 좀머 씨를 모르는 사람은 아무도 없는 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3593, 180, '새벽부터 밤까지 걷고걷고 또 걷는 좀머씨는 내가 사는 호수 근처의 동네 주민이었다. 빵과 물, 그리고 비옷만 들어있는 배낭을 매고, 기다란 지팡이와 함께 하루종일 걸어다니는 그는 동네 주민들에게 신기하거나 거슬리는 존재는 아니었다. 그냥 산이나 건물같은 하나의 풍경이었다. 주민들의 질문에 어물어물 답을 하고는 재빠르게 다시 걸어가는 그에게 우연한 기회에 듣게 된 정확한 한마디는 나의 기억속에 남게 된다. “그러니 제발 나를 좀 그냥 놔두시오!” 무언가에 쫓기는 듯한 좀머씨. 자신을 붙잡지 말라며 내뱉는 그 한마디에서는 간섭에 대한 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3594, 180, '좀머 씨 이야기 작품은 서술자가 좀머 씨라는 인물을 통해 안식과 죽음에 대한 생각을 하게 되고, 서술자의 성장에 영향을 끼치게 되는 내용을 담은 작품이다. 단순하게 서술자의 성장소설로 비추어질 수도 있고, 서술자가 좀머 씨의 관찰자로서 관찰하고 있는 일기로도 비추어질 수 있는 양면성을 가지고 있는 작품이다. 화자의 집과 불과 2킬로미터도 떨어지지 않은 곳에 라고 부르던 한 사람이 살고 있었다. 좀머 씨는 배낭과 지팡이를 가지고 이른 아침 일찍부터 저녁 늦게까지 비가 오거나 눈이 오거나 진눈깨비가 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3595, 180, '좀머 씨 이야기 I 파트리크 쥐스킨트 I 유혜자 옮김 I 열린책들그러니 제발 나를 좀 그냥 놔두시오!나는, 아주 오래 전 그러니까 나무타기를 할 수 있을 정도의 나이에 있었던 일을 추억한다. 나는 날 수도 있었을거라고 생각하고 같은 학급에 좋아하는 여자아이가 있었으며 피아노를 배워야했다. 그리고 동네에 어디서 왔는지, 이름도 모르고, 왜 그러는지도 모르는 아침부터 밤까지 늘 걷기만 하는 좀머 씨가 있었다. 하루는 아버지와 경마장에 다녀 오는 길에 갑자기 주위는 어두워졌고 돌풍이 휘몰아치며 굵은 빗방울이 내리기 시작했다. 아버지는 차...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3596, 180, '돌이켜보면 유년기의 거의 모든 시절을 나는 나무 위에서 보냈던 것 같다. 빵도 먹고, 책도 보고 글씨도 쓰고, 잠도 나무 위에서 잤다. 영어 단어도 그곳에서 익혔고, 라틴어의 불규칙 동사라든가 수학 공식 그리고 이미 언급한 바 있는 갈릴레오 갈릴레이 낙하 법칙과 같은 물리학의 법칙들도 모두 다 나무 위에서 배웠다. 말로나 필기로 준비해야만 했던 숙제도 나무 위에서 했으며, 짜릿한 쾌감으로 잎사귀 위에 커다란 반원을 그리며 나무 위에서 오줌도 눴다.나무 위는 늘 조용하였으며 사람들의 방해를 받지 않았다. 듣기 싫은 엄마의 잔소리도 없...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3597, 180, '사람들에겐 각자의 걱정거리들이 있다. 그것이 나이 든 사람이든 어린애이든 사색가 이든 방탕아든 말이다. 이 책의 화자로써 성장하는 아이의 시선으로 선택된 이유는 이러한 맥락일 것으로 생각된다. 아이가 성장하며 그 순간들의 사건. 정확이는 그 시절의 걱정들을 묘사 중에 군데군데 좀머 씨의 이야기가 전개된다. 이 전개가 극에 달하는 순간이 3번 있는데 첫 번째는 아이가 아버지와 좀머 씨를 차에 태우려는 순간과 아이가 감정의 격류에 따라 자살을 위해 나무에 올랐던 순간 좀머 씨를 본 일. 마지막으로 호수에 걸어들어가는 좀머 씨를 본 마지...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3598, 180, '그러니,, 제발 나 좀 내버려 달라고 말하는 좀머씨,,, 나는 "그러니"라는 말에 꽂쳤다. 사람들은 자기가 누군가를 돕는다고 하는 행동이 때론 그들을 내몰고 있을 수도 있다는 사실을 알아야 한다,,,쥐스킨트의 작품들이 더 더이상 출간되지 않아 서글프다,, 중고서적을 뒤적여서 몇권 더 찾아내었다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3599, 180, '독일인은 세상의 중심이란 생각이 든다. 자신의 시간을 공유하지 않는 절대 정신이 느껴진 작품', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3600, 180, '읽기는 이 책을 먼저 읽었지만 좀머 씨를 생각하면 인간실격의 요조가 떠오르는 건 왜일까?', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (181, '죽은 왕녀를 위한 파반느', 186, 4.32, 3, 6, 21, 55, 101, 156, 21, 9);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3601, 181, '계속 앞에만 읽다가 결국 못 읽고 반납한 책 박민규의 가벼운 유쾌함을 예상한다면 못 읽을 책 거기다 문단을 지 맘대로 나눠나서 읽기 힘들었다 내용 파악이 전혀 안됨', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3602, 181, '정말 이 책은 꼭 읽어봐야하는데...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3603, 181, '옆 사무실 책장에 꽂혀 있던 책을 빌려 읽었다. 이 작가의 다른 책 삼미슈퍼스타즈...는 사서 읽었다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3604, 181, '박민규의 이전 작품들에 비해선 실망스럽지만, 중간중간 박민규다운 부분을 찾아보세', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3605, 181, '그 시절의 우리가 모두 행복한 결말은 없었던걸까요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3606, 181, '못생겨서 미안해요. 그래도 내 얼굴 보고 요들 송만 부르지 말아줘요. 하지만 그 얼굴을 가지고도 나는 살아가요. 그래도 날 사랑해주는 당신들 때문에.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3607, 181, '완벽한 감동과 완벽한 글! 최근에 읽은 소설 중 최고!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3608, 181, '우리는 어쩌면 세상이란 거대한 고아원에 살고 있는 것이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3609, 181, '오랜만에 밤새워 읽은 참 좋은소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3610, 181, '못생긴 여주인공의 얼굴을 상상하다가 대신 그 쓸쓸한 마음이 느껴지는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3611, 181, '오래전이라소... 암튼 꽤 재밌던 책으로 기억한다. 이후로 이작가의 책을 시리즈로 읽었던 ㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3612, 181, '난 박민규 작가가 다시는 삼미슈퍼스타즈의 마지막 팬클럽 같은 책은 쓸 수 없을 줄 알았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3613, 181, '외모지상주의가 곧 자본의 논리로 직결되는 인류의 비극을 이처럼 재미있게!(그렇다 재미있게!!) 설파한 작가는 박민규가 유일하다고 봅니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3614, 181, '드높고 달콤하고 서글픈 사랑. 그래서 아름다운 이름. 박민규의 문학성이 돋보이는 작품', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3615, 181, '˝무슨 말을 하는지 알아. 하지만 쟤는... 진심이야˝', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3616, 181, '아... 역시 박민규다. 세상을 보는 시선이 정말 간지러운 곳을 긁어주는 기분이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3617, 181, '외모지상주의+자본주의 이 시대 속의 사랑손바닥만큼 작은 외면을 코끼리 마주한듯 더듬지 말고 내 내면을 사랑해줄 수 있나요? 있나요? 여주인공의 대사로 묻고 또 묻는다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3618, 181, '빌려읽고, 사 읽고..가장 좋아하는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3619, 181, '종이책으로 또 읽기내 인생 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3620, 181, '완소 작가, 완소 작품, 적극 추천~!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (182, '열정은 쓰레기다', 186, 4.81, 0, 1, 4, 25, 156, 181, 4, 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3621, 182, '열정이 성공을 이끄는 게 아니라, 성공이 열정을 이끈다는 말에 주목한다. 열정보다 지속적인 에너지를 유지시키는 것이 관건이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3622, 182, '열정보다 집안배경 부모의재력으로 판가름나는 대한민국 마음한구석 슬픔과 우울 포기할수없게 만드네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3623, 182, '열정이 쓰레기가 아니라 쓰레기처럼 버려지는 열정의 결과물이 문제겠죠.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3624, 182, '비즈니스 풍자 만화의 전설 [딜버트]의 작가의 작품을 통해서 열정만 있다고 성공하는 것이 아니며 또 다른 무엇인가를 갖고 있어야함을 알아보고 싶어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3625, 182, '제목이 자극적이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3626, 182, '왜 멍청한 상사들이 가장 먼저 승진하는지 사회를 비꼬았어요 공감갑니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3627, 182, '굉장히 큰 감명을 받았다. 이제 애쓰지 말고 가늘게 길고 살아야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3628, 182, '왜 열정이 쓰레기인지 궁금해진다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3629, 182, '제목부터 특이하다고 생각했는데, 만화를 보니 정말 공감할 수 밖에 없는데요~ ㅎ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3630, 182, '이제는 한우물로 성공할수 없는다 말을 알려주네요 결국 다양한 우물로 형편에 맞쳐가는 삶의 지혜가 요구되넹', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3631, 182, '제목부터가 좀 충격적이네요. 실패를 어떻게 극복해야하는지 저자분의 생각이 궁금합니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3632, 182, '열정페이가 생각나서 어떤 내용인지 더 궁금하네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3633, 182, '열정만으로 되지 않는 것을 신랄하게 비판해서 더욱 흥미가 끌리네요. 직장인들이 보면 정말 공감가는 내용이 많은 것 같아요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3634, 182, '열정도 좋지만, 역시 열정만 있으면 안되겠지요. 스콧 애덤스의 날카로운 풍자와 교훈을 이 책에서 만나볼 수 있습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3635, 182, '이렇게 구미가 당기는 부제는 오랜만이네요. 왜 우리의 열심은 대부분 실패하는 걸까죠? 그 답을 찾기를 원합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3636, 182, '열정이라는 이름으로 우리의 노력이 값싸게 느껴지게 만드는 일이 종종 있는 요즘한번쯤 읽어 볼 만한 책인 것 같습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3637, 182, '사람들의 열정도 중요하지만 그것을 어떻게 해처나가야 되는지 그리고 어떻게 대체해야하는지 알려주는 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3638, 182, '현실적인 제목과 묵직한 내용으로 도움을 받을 수 있을 것 같은 책이네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3639, 182, '실패에 익숙해지는 것. 그게 말이야. 미국에서나 가능하다는 게 문제란 말이지.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3640, 182, '호기심을 일으키는 제목이지만 실제 도움이 되는 책', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (183, '흥, 손철주의 음악이 있는 옛 그림 강의', 185, 4.83, 0, 0, 0, 32, 153, 185, 0, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3641, 183, '우리 옛 그림과 소리의 만남이라는 새로운 컬래버레이션(collaboration)을 새로운 관점으로 펼쳐보이는 이책은 옛그림에 스며든 ‘흥‘이 한국인의 삶속에 어떻게 스며들었는지 그리는 행위와 흥을 부르는 몸짓들이 어떻게 판소리와 가곡이라는 장르로 발전해나갔는지 흥미로운 시각을 안겨주는 책입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3642, 183, '그림은,특히 우리 옛그림은 오래 보아야 하고 지그시 즐겨야 한다. 그래서 느껴야 한다. 온몸으로 느껴야 한다. 우리 그림을 다룬 책으로 주로 오주석 선생의 책을 보아왔으나 손철주 주간의 책은 또 어떨까 궁금하다. 더군다나 음악과 버무렸다고 하니, 책을 기다리는 마음은 제목 그대로 흥이 난다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3643, 183, '우리는 애환의 민족입니다. 그 아픔이 있기에 우리만의 분위기가 있고 우리만의 예술이 있는 것이죠. 이 우리 미술을 손철주 미술평론가의 시각에서 분석하고 있습니다. 보기만해도 흥겨워지네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3644, 183, '옛흥취와 재미가 있는 그림들 흥부자로 이끄는 시간들', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3645, 183, '예술에 대한 높은 문턱을 쉬이 넘도록 해주고 신선한 해석이 가미되어 우리 그림과 음악을 제대로 이해해볼 수 있는 지점으로 안내해준다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3646, 183, '미술을 알아갈 수 있는 맛과 멋, 그리고 흥을 느껴볼 수 있을 것 같네요. 기대가 많이 됩니다. ^^', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3647, 183, '외국의 미술품들 관련된 책들을 많은데 우리나라 그림들을 볼 수 있는 책은 적어서 볼 기회가 별로 없었는데 이번 기회로 그림과 이야기들을 같이 즐길 수 있겠네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3648, 183, '우리의 음악과 우리의 그림이 만난다면 그야말로 금상첨화가 아닐까요? 우리의 흥을 잊지말고 우리 후손이 먼저 찾아봐야겠어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3649, 183, '옛 화가들의 그림을 보면서 즐길 수 있도 당시 민중들의 생활 모습과 자연경관들을 같이 감상할 수 있어서 만족합니다. 그리고 재미있는 설명들이 그림과 같이 저술되어 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3650, 183, '음악과 그림의 흥겨운 조화가 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3651, 183, '그림과 음악의 합치 그 속의 역사와 흥을 배웁시다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3652, 183, '음주가무를 즐기는 백의민족이라고 불렸죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3653, 183, '선조들의 멋과 지혜가 담겨있는 우리 옛 그림이 담고있는 이야기를 들을수 있어서 의미있는 시간이 될 것 같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3654, 183, '미술에 대한 정보를 잘 담은 책이 흔치않은데 정말 좋은 도서네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3655, 183, '가끔 교과서에서만 접해본적 있는 옛 그림의 새로운 그림속 이야기를 알아봤으면 좋겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3656, 183, '이 책은 옛 그림에 관해 우리가 미처 알지 못했던 디테일과 배경지식을 알게 해주는 책입니다. 옛 그림은 그저 그 옛날 조상들이 그린 그림 정도가 아니라, 우리 민족을 관통하는 느낌을 발견할수 있는 것이 아닐까요? 그래서 저는 옛그림에서 발견하는 정서가 궁금합니다. 흥미롭게 읽어볼만한 책이죠', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3657, 183, '음악은 ‘소리가 그리는 그림‘이라는 말이 무척 멋지게 와닿습니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3658, 183, '일상적으로 접하기 어려운 우리음악을 옛그림에과 연결시켜 보여주면서 흥미를 가지고 친근하게 느낄수있게 합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3659, 183, '옛그림을 보는 재미를 알려주시는 손철주님이 우리 음악을 듣는 법을 알려줍니다. 그림과 연결된 방식이 흥미롭습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3660, 183, '문학평론가인 저자가 옛그림 속에 자주 등장하는 옛음악의 모습을 세상과 절연하고 자연속에 혼자 연주하는 은일, 아름다운 모임에서 여럿이 연주하며 즐기는 아집, 음악으로 놀아보자는 뜻의 풍류로 나누어 보여줘서 옛문화에 대해 깊은 이해를 할 수 있어요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (184, '책은 도끼다', 185, 4.45, 2, 5, 11, 56, 111, 167, 11, 7);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3661, 184, '십여 년 전 읽었던 책을 다시금 보았다. 그때도 좋았고, 지금도 여전히 좋다. 조금 놀랐던 것은, 평소 내가 가졌던, 또는 가지려고 노력하는 삶의 태도나 관점이 실은 이 책에서 비롯됐던 것이었음을 이제와 발견했다. 그야말로 내 안의 얼어붙은 바다를 깬 도끼와 같은 책.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3662, 184, '삶의 철학, 통찰이 가득~ 책을 읽는 마음가짐을 다시 정립해준 소중한 책. 책을 읽으며 삶을 어떻게 바라봐야 하는지 그냥 책을 읽어야할 이유에서 끝나지 않고 그것으로부터 삶의 통찰을 끌어내는게 너무 좋았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3663, 184, '열심히 읽고 있습니다.좋은 책이 많다는 것과 작가의 식견과 저를 비교할 수 있어서 좋은 교본으로 읽고 있습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3664, 184, '독서를 하는 이유와 인문학을 왜 읽어야 하는지에 대한명쾌한 해답을 주는 책.결국 창의성과 아이디어의 바탕은 ''일상''이라는말이 나에게는 너무나 와닿은 말이다.그리고 다독에 대한 강박과 인문학에 대한 편견에 도끼질을 해준 책.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3665, 184, '삶은 빈 줄의 목걸이 하나를 받아서 여기에 진주알을 하나씩 꿰는 과정이라는 말이 있습니다. 우리가 살면서 문득 떠올릴 수 있는 순간, 마지막에 당신은 뭐가 생각나느냐는 질문을 받고 떠올릴 순간, 이런 것, 진주알 하나가 더 생길 수 있을 거라고요. 그런 진주알은 내가 눈이 있고, 훈련이 되어 있어야 생길 수 있는 것이거든요. 그런 순간이 잊히지 않을 겁니다. 그리고 이런 순간이 얼마나 각인되어 있느냐가 내 삶의 풍요를 결정할 겁니다. | p50#책은도끼다 #박웅현 #인티앤출판사- 어떤 행동을 할때,어떤 상황에서 판단을 내리고 선택을...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3666, 184, '작가가 소개하는 몇 가지 책을 공유하며 인문학적 깊이 있는 시선으로 탐독의 묘미를 알려주는책.제목처럼 책이 우리의 인생에 도끼가 되어 우리의 삶을 찍어주는 책들에 관한 이야기. "책은 얼어붙은 감수성을 깨는 도끼가 돼야 한다." ⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀ -프란츠 카프카 여러분의 삶에 얼어붙은 감수성을 깨는 도끼가 되어줄 책으로 각자의 바램과 소망을 싣고건강하게 2024년을 시작할 수 있기를.... ⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3667, 184, '책을 많이 읽는것보다 한권의 책을 읽더라도 뜻과 의미를 정독하라는 박웅현님 말씀이 마음에 와 닿습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3668, 184, '이 책이 내게 말한다.급하게 책을 읽어도 체합니다.천천히 즐기면서 읽으세요.그래야 책이 내게 제대로 소화됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3669, 184, '가벼운 마음으로 읽기 시작했지만 잊고 살았던 깨달음을 다시 기억 할수 있었다.현재에 집중해라 순간 순간을 즐겨라', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3670, 184, '누군가로부터 빌린 책 근데 다시 돌려줄 수 없을 듯...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3671, 184, '우리가 책을 읽을때..''과연 많이 읽는것이 좋은것인가?'' 반드시 그것만이 정답이 아니란걸 이 책을 통해 배웠다. 한 권을 읽더라도 우리는 얼마든지..그 속에서 좋은 지식과 경험을 얻을 수 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3672, 184, '고은시인 부분이 매우 거슬립니다.책이 고은시인의성추행 파문이전에 출간되었지만, 독자들에게 고은시인에대해 큰 영향력을 미치고있습니다. 저자는 고은시인을 자연과 인간을 경외하는 관점으로 칭찬하고 있으나 실제 고은시인 행적에 관한 의혹들을 보건대 읽기에매우 불편하네요.수정이필요합니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3673, 184, '완전 팬입니다! 신간이 나왔군요^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3674, 184, '꼭꼭 눌러담아 한 글자도 버리지않고 읽을 수 있는 글이고, 그렇게 읽혀지기를 바라는 작가의 마음이 느껴진다. 열권의 책보다 독법을 설명하는 이 한권이 나은 이유이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3675, 184, '어디 도끼 뿐이랴!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3676, 184, '"책 한권을 읽어도 머릿속의 감수성이 깨졌다면 충분하다."라는 문구가 가슴에 와 닿는다. 참 의미있게 읽은 책이 아닌가 한다. 꼭 읽어보시길... 아마도 독서에 대한 풍요로움을 느낄 수 있을 겁니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3677, 184, '간만에 만난 괜찮은 책이에요^^ 작가가, 느리게 읽기에대해 말하고 있어, 절대 빨리 책장을 넘길 수 없다는.. 문장을 곱씹게 하고, 소화도 시켜주는 책이네요 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3678, 184, '두 번 읽은 책,처음 읽을 땐 저자가 세상을 보는 눈(창의성)에 감탄했고,두번째 읽을 땐 그에게 그런 생각을 하게끔 던져준 그 책들이 궁금해졌다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3679, 184, '이 책을 읽고 사고싶은 책이 많아졌다.역시 광고인.뽐뿌온다.젠장.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3680, 184, '책 자체를 읽는 재미도 있었지만 내 스스로를 성장시켜줄 단계를 제시해 준 것 같다. 소개된 책들은 꼭 읽어 보고 싶다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (185, '사서함 110호의 우편물', 185, 4.48, 2, 3, 15, 49, 116, 165, 15, 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3681, 185, '한국 로맨스소설을 다시 보게 해 준 작품. 이도우 작가님의 전작 ‘사랑스런 별장지기’도 다시 만나볼 수 있길 바랍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3682, 185, '어휘나 표현들만 수정하셨다니 그럼 이건 피디 줘 패고 싶은 건 여전하겠네요', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3683, 185, '사랑은.. 이별을 경험했을때 그사랑의 진한 가치를 더 느낄수 있는듯해요.. 덕분에 무사한 사랑에 진한 감동을 받았습니다. 양장편! 축하드립니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3684, 185, '이도우하면 생각나는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3685, 185, '세상의 모든 사랑이, 무사하기를. 개정판 사서함110호의 우편물도 여전히 좋아합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3686, 185, '약간 드라마 응사를 소설화한 느낌 ?? 전형적인 아날로그 사랑..ㅜㅜ 읽을 때 재밌었고 설레는 기분이 들어서 좋았어용 ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3687, 185, '마음 몽글몽글해 지는 현실적이면서 잔잔한 어른들의 사랑 이야기. 시간가는 줄 모르고 읽었습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3688, 185, '그저 드라마에 나올법한 뻔한 스토리지만 그안에 문장표현 하나하나가 뻔하지 않고 읽는 내내 행복하게 만들어 주었습니다. 책을 이렇게 아껴 읽은적은 처음이에요,..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3689, 185, '지난 2004년 초판이 나온 이래 2022년 기준 110쇄까지 나왔다고 하니 이 책의 인기가 어느 정도인지 짐작이 간다. 젊을 때도 읽지 않았던 로맨스물을 이제야 읽는 건 저 통계 때문이기도 하거니와 (어떤 책이길래 110쇄...? 하는) 순순하게 책 읽는 재미를 느껴 보고 싶어서일 뿐이었다.일단 작가가 물 흐르듯 막힘없이 글을 잘 쓴다. 무슨 단막극이나 영화를 보는 것 같기도 하고 수채화 같기도 하다. 수채화가 같은 이야기가 그렇듯 등장인물들이 대체로 착하고 밝은 것이 특징이라 하겠다. 차분하면서도 진지한 공진솔도 좋지만 이건의 ...+ 더보기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3690, 185, '한 소설을 여러 번 읽다 보면 꽂히는 문장들이 있다. 매번 읽어도 같은 문장이 눈에 들어오는데 아마도 그건 개인의 취향 때문인지도 모르겠다. 예를 들면 이런 문장들이다. ? 지나가는 바람일지도 몰라요. (244페이지) ? 네 사랑이 무사하기를내 사랑도 무사하니까세상의 모든 사랑이, 무사하기를 (427페이지) ? 이런 감정은 나만 그런 게 아닌가 보다. 많은 사람이 좋아하는 문장을 꼽아보면 비슷하다는 걸 알 수 있다. 『사서함 110호의 우편물』은 이렇듯 20년째 사랑받고 있는 소설이다. 처음 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3691, 185, '"갑자기 당신이 문 앞에 서 있었어요, 그럴 땐, 미치겠어.꼭 사랑이 전부 같잖아."??12년 전 북카페 활동하며 알게 된 사서함 110호의 우편물,정말 인기가 대단했는데, 이건 피디 앓이도 팬클럽 수준,분명 나쁜 남잔데 미워할 수 없는 캐릭터!!!그 시절 여의도가 출근길이었던지라, 더욱 생생했다지~(소설 속 서울의 지명 하나하나가 2~30대 주로 다니던 곳들이라 새삼 반갑고 정겨워서 눈물 찔끔!)?언제 읽어도 두근, 아릿하지만 뭉클하고 미소 짓게 되는 만이 줄 수 있는 감동, 결국… 날을 새며 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3692, 185, '우리는 아주 멋진 사랑을 하게 될 거예요. 그리고 책을 읽다 보면 아마 그 순간이 조금 앞으로 당겨지리라 믿습니다. 그런 믿음이 제가 독서를 멈추지 않게 하는 원동력입니다.??작가님을 처음 만난 곳은 군대였습니다. 사회도 뉴스도 "이제는 정말 독서가 열풍입니다."하지만 군대는 꼭 그렇지만도 않습니다. 진중문고에는 먼지쌓인 책들이 관리되지도 않으며 방치되어 있고, 다 쓰러져 가는 책장들 사이에 끼어서 책장 대신 기둥 역할을 하고 있기도 하고.. 하지만 책은 끊임없이, 꾸준히 들어옵니다. 가끔 먼지를 털고 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3693, 185, '_잘 자요.?좋은 꿈꾸고.건의 메시지였다.?휴대폰을 제자리에 올려놓고 진솔은 스탠드 조명을 켰다.?형광등을 끈 뒤 침대로 들어가서는 눈을 감고 잠을 청했다. 1분, 2분, 3분....?감은 눈꺼풀 위로 스탠드 조명이 밝게 스며들어 그녀는 몸을 한 번 뒤척였다._p83??_말도 안 돼.?그녀에게 문득 쓴웃음이 스쳐 갔다.?그 남자가 언제 사랑한다고 했는데??그 남자가 언제 입맞춤을 했고...?언제 내가 기대하도록 했는데??그는 아무 짓도...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3694, 185, '이 책은 관악구 연합독서회를 통해 알게 되었다.이건과 공진솔의 사랑 이야기가 가슴 설레여 이도우 작가가 이건같은 남자일거라 생각하며 기대했었다.검색을 하다가 작가가 여자분이라는걸 알게 되고 쬐금 실망했지만 작가와의 만남은 비내리는 날의 행복한 추억이었다.P43그런 걸 왜 물어요.작가 손을 떠난 글은 읽는 사람 몫인데.본인들이 알아서 느끼겠지 (이 건)공진솔이 심란할 때 연필을 깎는다는 대목에서 사각사각 연필심을 갈았던 기억이 떠오른다.나는 심란할 때 산책을 하면 기분전환이 되고 힘이 난다.추석연휴에 동네 산책길에서 보았던 목화꽃과 ...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3695, 185, '이미 하나 갖고 있는데 또사고싶다..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3696, 185, '몇번을 읽어도 좋은 사서함110호의 우편물! 에세이를 읽으니 작가와의만남이라도 한 것 같은 기분이 듭니다. 올칼라에 내용도 알차고 예쁜 사진까지.. 부록으로 딸려왔지만 그 자체로도 한권짜리 좋은 에세이입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3697, 185, '제가 정말 아끼는 책. 이미 예전에 나왔던 사서함도 가지고 있지만, 이번에도 꼭 소장하고 싶어요.정말 정말 정말 좋아하는 책입니다.^^*', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3698, 185, '누군가 책을 읽고 싶어하면 소장하고 있다가 아낌없이 빌려주는 책이랍니다 ^^ 같이 공감하고싶어서~~ 현실적인 느낌이 더 강해서 누구든 권해주고 싶더라구요 ^^ 현실적이지만 로맨스라서 좋아해요 ㅋㅋㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3699, 185, '사랑이란 게 이런거라면 사랑하고 싶고, 사랑받고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3700, 185, '그냥,, 오랜만에 소설을 읽고 운것 같다공진솔이 딱해서, 애리가 마음에 걸려서, 희연이가 나 같아서', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (186, '나인 (양장)', 185, 4.71, 2, 4, 5, 23, 151, 174, 5, 6);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3701, 186, '기대한 것보다 별로', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3702, 186, '읽고 계속 눈물이 났다. 정체성 혼란과 관계, 그리고 정의로운 마음까지. 작은 히어로같기도 하며 사랑이 가득한 힘을 느꼈다. 다들 행복하길.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3703, 186, '식물외계인의 지구정착기!아 너무 재미있었다. 기적인 나인, 그리고 또 다른기적인 미래와 현재. 박원우의 실종을 맞닥들인 나인이 한단계 한단계 자신의 정체를 사건의 실체를 밝힌다. 건강하고 푸릇푸릇한 소설이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3704, 186, '외계인을 꿈꾸게 하는 책.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3705, 186, '최근들어 가장 신선하고, 섬세하고, 애정가는 책입니다. 서로를 무조건 믿는 나인, 미래, 현재의 관계도, 나와 같지만 내가 갖지 못한 것을 가진 나인 곁을 지키는 승택도 예쁘기만 합니다. 청과 적의 경계를 넘어서는 인간답지 못한 이들로 인한 사건이 넘쳐나는 요즘이라 더 깊은 여운이 남았습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3706, 186, '읽다 좀 짜증이 남. 서술이 왜 이리 장황한지. 불필요하게 들어간 서술을 빼면 절반 분량으로 줄어들 듯. 발상의 신선함과 트랜디한 주제에 비해 가독성이 떨어지고 지루함.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3707, 186, '주제는 흥미로웠지만 한숨에 읽을 정도의 집중력을 이끌지 못해 아쉬웠다. 오타도 종종 보이고 스토리 자체도 성인이 읽기에는 완성도가 아쉬웠던 책. 놀라웠던건 나인이 여자라고 생각하며 읽었는데 남자인가? 미래가 좋아했던 건 나인인가..?', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3708, 186, '1/3정도까지는 힘들었다. SF는 나에게 1/3에 고비인듯하다. 1/3이 넘어가는 시점부터 정말 순삭했다. 서늘한 사건 속에서도 가슴 따뜻해지는 소설인듯 하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3709, 186, '‘식물들과 이야기할 수 있다‘라는 비현실적인 문장으로 시작하여 판타지 소설인줄로만 알았다. 그러나 이 책은 우리에게 사랑의 힘이 얼마나 위대한지 깨닫게 해준다. 바쁜 삶에서 이 책을 읽고 많은 위로를 받았다. #나인 #천선란 #창비 #소설Y #소설Y클럽', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3710, 186, '프롤로그만 보았을 때는 정말 흥미로워 보였다. 식물의 말들이 들린다는 것과 손틈에서 새싹이 자란다는 등 소재는 참신했으나, 그것을 재미있게 풀지는 못한 것 같다. 후반부에는 사건들이 나와서 조금 재미있었지만, 전체적인 내용은 조금 아쉬웠다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3711, 186, '주인공 나인이 있는데 대체 무엇을 하는지 식물을 기르는 애 인지 참 아무것도 모르겠더군요. 재미도 감동도 없고,그냥 시간만 좀 아까워요 스토리도 이해가 안 됩니다. 제 머리가 문제 인지 모르겠지만 이게 무슨 내용인지도 짐작이 안 가여', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3712, 186, '사람 한 명이 사라진다는 건 그 한 명의 멸종이라는 나인의 그 말이 얼마나 위로가 되어주었는지. 한 명의 멸종을 잊지 않아 준 나인이 고맙다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3713, 186, '아니, 이렇게 재미가 없는데 평점이 다들....나는 모르겠다. 아무튼 초반 1/4만 읽고 말았으니 뭐라 하기 어렵긴 하다만...', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3714, 186, '천선란 작가님의 소설들은 왜이렇게 슬프고 왜이렇게 아름다울까. 나는 나인의 친구가 미래와 현재라는 게 참 좋았다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3715, 186, '작가님의 상상력과 그 독특한 세계관에 빠져들게 만드는 스토리텔링, 신비한 분위기와 인물들의 따뜻한 정서가 잘 어울러진 것 같아요. 재밌게 읽었습니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3716, 186, '최근 읽었던 SF소설 중에서 가장 스토리가 치밀하고 묘사가 좋은 작품. 최근 몇몇 SF소설들이 소재는 재밌으나 내용 전개가 엉성해서 아쉬웠는데 이 책은 끝장을 넘길 때까지 숨막힌다는 표현이 들 정도로 집중해서 읽었다. 추천, 두 번, 세 번 추천.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3717, 186, '나는 천선란이 말하는 용기가 좋다! 신작을 찾아 읽게 되는 작가.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3718, 186, '읽다가 울컥했어요. 너무 좋은 이야기였어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3719, 186, '1. 내가 생각하는 ‘나인’의 매력- 내가 좋아하는 생태 SF여서 마음을 확 끌었다. 식물이 동물보다 훨씬 큰 능력을 가지고 있다는 생각을 오랫동안 해온 사람으로, 우리 주위의 식물에 대해 생각해보고 느껴볼 수 있는 이야기가 좋다. 나는 인류가 아직 신화라는 철학의 세계에 살 때는 분명 식물과도 소통할 수 있었다고 믿는다. 그런데 지금 우리에게 식물은 너무 먼 타자가 되었다. 하지만 이 이야기를 읽으면 식물은 더 이상 먼 타자가 아니다. 이 이야기의 주인공은 놀랍게도 식물이니까. 그게 무척 마음에 들었다. 더 말하면 스포가 될 것이라 말하기 어렵지만 엄청 감동받은 부분이다.- 이방인으로서 느끼는 나인의 불안감과 문턱성을 역시 천선란 작가만의 문체로 잘 드러내고 있어서 좋았다.- 나인이 이방인의 문턱성을 과감히 휘둘러 답답하게 묻혀 있던 것을 끄집어내고 마침내 변화를 이끌어내는 과정이 흥미로웠고 재미있었다.^^;; 앞부분 등장인물의 소개가 약간 지루한 면은 있지만 그 부분만 후딱 넘기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3720, 186, '나인을 읽고나니 귀와 눈의 능력이 100배쯤 더 좋아진 느낌이다. 우리집 선인장도 저 길가 은행나무도 내게 무언가 말을 하는거 같아 귀를 기울인다.더 착하게 끝까지 살고싶어지는 마음이 생긴다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (187, '설득의 심리학', 184, 4.27, 1, 3, 24, 74, 82, 156, 24, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3721, 187, '사람심리를 잘 활용한 세일즈에 도움이 많이 될듯하네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3722, 187, '마케팅이 아니었다면 베스트셀러가 될수 있었을까? 그다지 메리트가 있는 책은 아닌..', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3723, 187, '마음을 읽는 설득의 달인이 되는 방법을 알려줍니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3724, 187, '이런건 꼭 봐야하는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3725, 187, '이유 없다... 누구든 무조건 한번은 읽어보라', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3726, 187, '상술의 원리를 알게 해 준 책, 남을 설득하기 보다는 남에게 설득당하지 않는 방법을 터득했다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3727, 187, '일상생활에서 설득의 숨겨진 비밀을 알게 해 주는 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3728, 187, '이 책을 읽으면 더 이상 남에게 속거나 쉽게 설득 당하지 않는 부작용이 있을수 있습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3729, 187, '아직도 베스트셀러 목록에 있다니.. 이런게 진짜 스테디셀러죠~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3730, 187, '고등학교때 읽어봤는데.. 아주 특별한 내용이라고 생각되진 않지만 편하게 읽을 수 있고 고개를 끄덕이게 되는 책이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3731, 187, '어떻게 타인을 설득할 것인가에 대한 책. 이 분야에 나름 명저로 알고 있다. 이 책만 읽으면 왠만한 설득류 책은 다 본 것과 마찬가지!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3732, 187, '설득에 대한 겉핡기 지식이 아니라 인간에 대해 깊이 생각할 수 있는 기회를 제공한다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3733, 187, '설득과 순응 변화에대한 심리학이다', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3734, 187, '다른 심리학책들에 비해 통합적인 관점에서 살펴보는 것이 좋다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3735, 187, '쉽게 씌여져 있어, 이해하기 쉽다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3736, 187, '여건상 책을 직접 보고 고를수가 없어서 책을 구입할때, 첫번째는 리뷰를 보고 선택하고 두번째는 베스트 셀러를 살펴보고 세번째는 세일%를 보면서 고른답니다.^^ ''설득의 심리학''은 세가지 요건에서 많이 눈에 띈 책이라 한번쯤 읽어보고 싶었던 책이었어요. 솔직히 소설외의 책은 그리 찾아보는 성격은 아니지만, 이 책을 읽는동안 많은 도움이 되었습니다. 읽으면서 어느정도 인간의 심리를 이해했다고나 할까요. ''설득의 심리학''을 읽은후에 평소 생활에서도 쉽게 찾아낼수 있는 설득 심리학의 법칙들이 눈에 들어오더라구요. 어머니와 저 사이...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3737, 187, '사람에게는 공통적인 심리가 있다. 이것을 잘 이용하는 사람은 주위의 사람들과 더 친밀한 관계를 유지할 수도 있고 또는 자신의 사업적인 부분에 이용함으로서 더 많은 이익을 낼 수도 있을 것이다. 이런 심리학적 지식에대해 사람들은 관심을 갖지만 어디에 유용한 정보가 있는지는 알 지 못한다. 인터넷에서 찾아 보기는 하지만 단편적이며 신뢰가 가지 않는다. 그렇다고 어려운 심리 전공서적을 볼 수도 없는 노릇이다. 가벼운 심리서적들은 유행에 편승해 쓰여진 것이 많으며 허술하기 짝이없다. 이 책은 이런 분들에게 도움이 되지 않을까 싶...+ 더보기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3738, 187, '아내의 책꽂이에 꽂혀있던 한권의 책 "설득의 심리학"이 나의 시선을 사로잡았다. 그냥 그렇고 그런 말장난이나 하는 책이거니 하고 거들떠도 보지 않다가, 우연히 앞의 몇장을 읽고 너무 재미있어 한번에 쭉 읽어 내려갔던 내가 본 책들중 인상 깊었던 몇안되는, 그러면서 이러한 책을 이제야 접하다니 하는 아쉬워 했던 그런 책이다. 우리는 매일매일 결정의 순간순간을 맞이하며 살고 있다. 회사에서나 학교에서나 길거리에서나, 출퇴근, 등하교 차안에서나 언제 어디서나 말이다.&...+ 더보기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3739, 187, '우선은 가볍게 읽으실 요량으로 사시는 분이시라면 서점에서 한번 둘러보시고 결정하시라는 충고를 드리고싶네요.. 책 내용이 무작정 어려운것만은 아닌데 그렇게 가볍지도 않아요. (혹해서 샀다가 땀좀흘렸다는...) 알고보니 교재용으로도 쓰이는 책이더군요. 이런 책으로 수업을 들으면 정말 재미있을것같네요. 살아있는 사회학교과서라고나 할까.. 정말 읽다보면 아~!하는 감탄성이 절로 나옵니다. 이제 사회생활을 시작하는 대학생이나 사회인들이 한번쯤 읽고가면 좋은 교훈(?)이 될 책이라고 생각합니다.^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3740, 187, '이 책의 두께와 제목과 서문을 읽고 꽤나 딱딱한 책일줄 알았다. 그런데 첫번째 장부터 이 책의 말랑말랑한 예화들이 눈에 쏙쏙들어와서 잠을 못 자면서 읽은 보기드문 인문 서적이 되었다. 이 책은 ''치즈''류의 값싼 처세술도 아니고, 심리학의 논점들을 우리가 다른 사람들에게 설득당하는 상황에 비추어 잘 파악하고 있다고 읽었다. 작가는 우리가 설득당하는 상황의 법칙을 여섯가지 이야기하면서 사례를 적는다. 상호성,일관성,사회적 증거,호감,권위,희소성 등이 그런 법칙들이다.내가 얼마나 공짜 술 먹으면서 마음이 불편했던가. 술값낸 사람이 다음에...+ 더보기', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (188, '완전한 행복', 184, 4.32, 14, 6, 14, 24, 126, 150, 14, 20);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3741, 188, '완전히 낯설고 집요했던 정유정 소설에 단련되었다는 증거인지 감각이 덜해진 느낌이다. 유년의 기억이란 참 무섭도록 끈질기다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3742, 188, '혐오스러운 범죄를 소재로 했다고 별로라는 반응을 접할 때마다 헛웃음만 나온다. 죄와 악을 다루는 창작 행위(A)가 죄와 악을 합리화한다는 착각(B)으로 매도된 셈. A에서 B로 가는 섣부른 폭력이 더 혐오스럽다. 치밀한 심리 묘사와 서사 구성으로 직조된 소설. 소위 출세작보단 못하나 읽을 만하다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3743, 188, '처음으로 산 걸 후회한 책. 최악이었음.결국 이 책이 사회에 미칠 영향을 생각하면, 유명해지지 않아야 하는 책임.상업소설로는 성공, 작가로서-책으로써는 최악.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3744, 188, '우리가 추구하는 행복은 누구를 위한 것인가! 어느 나르시시스트의 이야기.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3745, 188, '실제 사건을 넘어서지 못한다. 실화의 주름을 메꾸는 작업이었겠으나 이야기보다 작가 개인의 목소리, 노력, 창작의욕만 읽혀 아쉬움. 소설에서 작가가 그려지면 안되지않나. 차라리 논픽션으로 우리가 몰랐던 디테일한 이야기들을 들려주지', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3746, 188, '작가님의 글을 좋아하지만 이번은 좀 실망스러웠습니다 이미 알고 있는 사건에서 모티브만 가져오셨다고 했지만 이미 매체에서 알려진 극악한 범죄의 사연 외에 무엇이 더 있는가 묻고 싶네요 이번은 비겁한 선택, 아쉬운 신작이었다고 감히 표현하고 싶습니다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3747, 188, '의아하네요.누군가의 이야기를 이렇게 똑같게 써놓고 그 이야기가 아니라고요? 읽으면서 내내 피해자가, 아니 피해자의 유가족이 이 이야기쓰는걸 하락했나? 하는 의문이 들었는데...남의 아픈 가정사로 돈을 버시다니...???별점 주기가 참 난감하네요', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3748, 188, '이 정도면 고유정한테 로열티 줘야지.그냥 고유정 얘기지 이게 무슨...작가의 말 민망하지 않나.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3749, 188, '그냥 조금 바꾼 고유정 사건...', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3750, 188, '26쪽까지 읽다 덮음...굳이 고유정사건을 바탕으로 해야했나...딱봐도 고유정사건같아서 토나올거같아 뒤에는 안읽습니다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3751, 188, '모티브만 얻은게 아니라 너무 제주도 사건 그대로 인듯 하네요 카레가 허세도 아니고 유럽음식 굴라쉬는 너무 웃기네요 카레대신 굴라쉬 우리나라에서? 너무 있는이야기를 소설로 실망스러움', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3752, 188, '스릴러 여왕의 귀환 이네요.지갑 열어요.ㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3753, 188, '전작들을 읽고 기댄했지만 분량을 반으로 줄였으면 하는 아쉬움이. 작가말 하고 책 내용은 다른듯한데. 어릴때 부모와 따로 산 동생의 피해망상과 삐뚫어짐 같은데.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3754, 188, '작가 이전에 인간으로써의 양심을 묻게 되는 책. 그것이알고싶다는 취재와 보도에 대한 법적책임을 짊어지기라도 하지, 픽션이란 방패 뒤에서 과연 이렇게 다뤄도 될지, 이렇게 다뤄져도 되는 소재인지, 질문하게 됨. 쓸데없이 긴 분량은 작가로서 필력도 의심스러운 정황.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3755, 188, '7년의 밤이후 재능이 소진된건지...암튼 100 페이지 정도부터 고유정사건 떠올라서 같은 책 두번 읽는 느낌...˝이건 아닌데..이러면 나가리인데˝...신세계 최민식이 조선족 연변거지킬러 보면서 독백하던 말이 떠오른다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3756, 188, '나르시즘의 끝판왕. 남 얘기가 아니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3757, 188, '오늘 유퀴즈온더블록 보고 소리지르고 작가님 얘기 들을 수 있어서 넘 좋았는데.. 우연히 알라딘 들어왔다가 또 작가님 신작 발견…. 진짜 뭐야 이정도면 운명인가봐 사랑합니다 작가님 ㅠㅠ 항상 응원하고 있어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3758, 188, '이 작품은 피해자에 대한 엄연한 2차 가해다! 누군가의 끔찍한 공포와 고통을 돈벌이로 이용했다. 작가의 무개념이 놀라울 뿐이다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3759, 188, '을 보고도 덤덤했는데 이 책은 텍스트만으로 소름이 돋는다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3760, 188, '실화에서 모티프를 얻으신 것을 알았으면 읽지 않았을 것 같아요. 아직 슬픔이 가라앉지 않은 이들을 위해서 너무 최근의 사건은 모티프로 삼지 않아 주셨으면 하는 바람이 있습니다.', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (189, '1Q84 3', 184, 4.34, 5, 8, 18, 42, 111, 153, 18, 13);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3761, 189, '1,2권으로 끝나는 열린 결말인 줄 알았는데.3권이 나온다니..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3762, 189, '드디어 3권이다.. 소장가치 100% 기대 만족 100%', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3763, 189, '아 기다림조차 두근거리는! 또 어떻게 풀어낼지 너무 기대된다 T.T', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3764, 189, '기다리고 기다렸는데 이제 나왔네요..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3765, 189, '1,2권은 빌려 보고 3권만 샀다. 덴도 아라타의 와 함께 소장하고 싶은 하루키의 . 1,2권도 구입해야지..우아한 音樂같은 하루키.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3766, 189, '겉표지가 왜이래? ㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3767, 189, '목차는 3권 것이 아니네요. 근데 표지가 왜 저래...씁...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3768, 189, '번역본 드디어 등장! (원서 나온지 몇개월이지났는데. 이제서야...;;;)', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3769, 189, '마침내 3권이 나왔네요. 기대합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3770, 189, '3권도 읽어버렸다. 그리고 후회한다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3771, 189, '덴고?아오마메?후카에리 선물세트는 뻔데기 깡통?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3772, 189, '1권은 참 좋았는데, 2권부터 좀 처지더니 3권은 그동안 읽은게 아까워 억지로 읽었다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3773, 189, '하루키의 소설이다. 재미있다! 무슨 말이 더 필요한가??????????', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3774, 189, '3권이있는줄은 미처몰랐네요^^; 아오마메를 찾아나섭시다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3775, 189, '기다리다 목 빠질뻔..ㅠㅠㅠㅠㅠ 이제서야 나오는구나...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3776, 189, '무라카미 하루키의 철학으로 어떤 결말이 날지 기대된다...', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3777, 189, '4권 나오겠죠? 4권 나와야 하는데... 제발...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3778, 189, '후카에리 세트 뭔가욬ㅋㅋㅋ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3779, 189, '왜 난 아이큐 84로 보았을까?ㅋㅋ..내 머리보다 눈이 나빠진게 분명해..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3780, 189, '서점에 있는 일본판 3권 보면서 차라리 일본어 배울까 고민했었는데, 이제야!!!!', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (190, '하버드의 사생활', 183, 4.85, 0, 0, 1, 25, 157, 182, 1, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3781, 190, '학생들의 잠재된 능력을 키워주고 학교가 구축한 막강한 인맥과 멘토들을 연결시켜주는 학교단순히 비싼 등록금만 꿀꺽 삼키지 않고 학생들에게 어떻게 사는것이(재학4년동안)의미 있는 삶을 살수 있는지 끊임없이 자극을 주는학교인재들이 목표를 세우고 이를 달성하기 위해 무엇을해줄지고민하는학교', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3782, 190, '하버드가 세계 최고의 자리에 있는 이유가 공부와 실천, 실험 정신이겠죠. 학교 밖에서의 사생활은 사회진출을 이한 디딤돌이 되기도 하고 자신의 목표를 향한 실험이겠죠. 대단한 이야기가 자극이 됩니다. 대학을 준비하는 아이들, 대학생들, 부모들에게 자극이 될 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3783, 190, '보통 하버드 학생들이 어떻게 공부하는지에 대해서 이야기해줘서, 더욱 궁금해집니다. 강의실 밖에서 하버드 학생들의 삶은 어떠할까요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3784, 190, '하버드의 힘은 봉사, 동아리등 강의실 밖에서 나온다는 말, 정말 공감합니다. 우리나라도 꼭 본받았으면 좋겠네요 ^^', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3785, 190, '하버드 생들이 인생을 배우는 모습을 읽고 싶었다. 마침 이런 좋은 책이 나와서 무척 기대된다. 그들의 학교 밖 진짜 모습을 보고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3786, 190, '대학 유학을 목표로 하고 있는 저에게 많은 도움이 된 책입니다.추천합니다!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3787, 190, '공부이외의 활동에 대해 자세히 배워볼 수 있을 것 같아요. 큰 도움이 되었으면 좋겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3788, 190, '그들은 공부하지 않을 때 무엇을 하는지, 궁금해했던 적이 없었는데, 이 책을 읽고 그 궁금증이 해소되었으며, 내 인생에도 많은 도움이 된 것 같다. 많이 배울 수 있었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3789, 190, '자기계발서는 잘 읽지 않는 편인데 가끔씩 보면 참 유익한 내용들이 많은 것 같아요. 이 책을 보고 인생에 있어 올바른 답을 찾아나갈 수 있는 계기가 되었으면 좋겠네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3790, 190, '세계최고의 대학이라고 해도 과언이 아닌 하버드의 학생들은 교육과정내의 수업이 아닌 동아리 활동이나 기숙사 생활 등을 훗날 기억한다고 하는데 과연 하버드 학생들은 어떤 활동을 하였으며, 어떤 것을 배우는 지에 대해서 알려주는 책이라는 점에서 기대되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3791, 190, '하버드의 천재들이 성공하는 비법 뭔가 보통의 사람과는 다른 그들만의 성공법 궁금합니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3792, 190, '나와는 먼 하버드지만 책에서라도 하버드의 생활은 어떤지 알고 싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3793, 190, '수업이 끝난 이후의 이야기라니 어떤 내용일지 궁금하고 기대됩니다. 내가 하버드에 갈건 아니지만 어떤지 궁금하잖아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3794, 190, '하버드 학생들이 성공하기 위해 실천에 옮겼던 5개의 전략을 소개한 것이 인상적이었지만, 무엇보다도 공부벌레가 되지 말라는 말이 가슴 속에 깊숙히 와 닿았다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3795, 190, '오늘 신년사에서도 나왔죠. 미국을 따라가긴 너무 힘드니 죽도록 공부해야한다고. 그들은 공부 안할때 무엇을 생각할까 궁금하네요.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3796, 190, '공부도 중요하지만 공부를 하고 난 다음 자신의 인생을 어떻게 돌아볼 것인지도 중요할 것 같습니다. 학벌만을 중요시 하는 우리나라와는 다르게 하버드에서는 공보 외적인것도 중요시한다고 들었습니다. 이 책을 통해 하버드 대학교와 학생들의 진면목을 볼 수 있어서 좋았습니다. 내 인생 최고의 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3797, 190, '하버드가 왜 성공을 하게 되고 어떤 노력을 하는지 이책에서 그 비밀을 알수있겠네요. 하버드 안가도 그들처럼 한다면 성공에 이르는 길도 가까와질듯~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3798, 190, '공부에만 묻혀서 보이지 않았던 그들의 진짜 모습과 삶을 전체적으로 볼 수 있게 해주는 책이라 왜 공부를 해야하는지, 왜 목표를 세워 노력해야하는지 무엇때문에 그렇게 사는 건지 생각해볼 수 있는 좋은 기회가 될 듯', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3799, 190, '궁금했던 하버드 학생들의 생활에 대해서 알 수 있어서 좋습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3800, 190, '하버드생들의 무엇을 생각하고 어떻게 행동하는가 그리고 그들이 배우는 것이 무엇인가에 대하여 많은 궁금증을 풀수 있어서 좋은 것 같습니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (191, '모순', 183, 4.4, 3, 1, 24, 47, 108, 155, 24, 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3801, 191, 'N23089 이 책을 읽고 나서 내 인생이 왜 이렇게 꼬였는지 알 수 있었다. 그냥 삶 자체가 모순이니까, 이유를 찾는건 의미가 없다, 무수한 갈림길에서 선택만 있을뿐 정답은 없다. 20대에 읽었다면 그저 그랬을텐데, 40대에 읽으니까 확실히 좋다. 에세이 같은 느낌의 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3802, 191, '소설이 나온 시점을 감안하고서도 유명해진 것의 원동력이 무엇일까? 궁금해서 읽게 되었다.‘인간에게 행복만큼 불행도 필수적.‘(295쪽)이란 모순적 삶에 관한 문장은 인정도 부정도 하기 힘들다. ‘내 속에서 체험된 후가 아니면 마음으로 들을 수 없는..‘(296쪽)말처럼 각자의 몫일 것이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3803, 191, '무엇을 선택하든 그 이면에는 ‘반대어‘가 있기에 ‘뜨거운 줄 알면서도 뜨거운 불 앞으로 다가가는‘ 삶을 기꺼이 살겠다는 마지막 안진진의 선언이 인상적이었다. 어차피 삶에 완벽이란 없기에 그 불완전함, 모순을 껴안고 살아갈 때 우리는 발전할 수 있다는 인생의 진리를 보여주는 소설.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3804, 191, '이십대란 나이는무언가에게 사로 잡히기 위해서 존재하는시간이다. 그것이 사랑이든 일이듣 하나씩은 필히 사로 잡힐 수 있어야 인생의 부피가 급격히 늘어나는것이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3805, 191, '공감 수 많은 댓글보면서 아 저런 책이면 어쩌지 걱정하면서 구매하고 샀는데 실망이다. 집을 떠나버린 아버지나 조폭인 남동생이나 옹호하기 힘든 남성 캐릭터들을 계속 자기합리화하며 손가락질 받을만한 일을 별 거 아닌 일처럼 그려내는게 불쾌했다.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3806, 191, '이 책을 여전히 인생 책으로 꼽는 이들이 많은 곳은 어떤 세상인가. 슬프고 의아하다.촌스러우며, 자의식 과잉이며, 그리하여 많은 순간 참을 수 없이 오글거린다.길고길고길고긴 작가의 스스로 해설은 이미 친절하고도 비장하고도 과잉으로 끝난 소설의 화룡정점이다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3807, 191, '책소개에 양귀자 세번째 장편소설이라고 나와 있는데 세번째가 아니라 네번째다. ‘희망‘, ‘나는 소망한다 내게 금지된 것을‘, ‘천년의 사랑‘에 이어 네번째로 발표한 장편소설. 내용은 청춘성장소설+ 로맨스(연애)+가족소설 정도가 되겠고 재미있게 잘 읽히는 편이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3808, 191, '올해 읽은 책 중에 아마도 최고일듯하다작가가 전달하고자 하는 말과 마음의 깊이가 얕지 않은데도 불구하고 문장이, 글이 술술 읽혀서 일부러 천천히 봤다양귀자 작가 도장깨기 시작1', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3809, 191, '사랑하지 않고 스쳐 갈 수도 있었는데, 사랑일지도 모른다고 걸음을 멈춰 준 그 사람이 정녕 고맙다고. 사랑이란 그러므로 붉은 신호등이다. 켜지기만 하면 무조건 멈춰야 하는, 위험을 예고하면서 동시에 안전도 예고하는 붉은 신호등이 바로 사랑이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3810, 191, '그 시대에나 공감받을 수 있을 소설 현재는 가당치도 않다', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3811, 191, '｀김장우와 만나면 나는 이렇게 선명해진다.｀엉엉 울음을 토해낸 책.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3812, 191, '읽고 함께 이야기 하자는 이가 있어서 ...그에게는 다 읽었노라 보고를 마치고!언제 마주 앉아 이야기 하려나?시간은 많지만 시간이 없다고 하는 모순 속에 살고 있기에.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3813, 191, '훔치고싶은 문장들 많다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3814, 191, '‘쟤 부럽다. 구김살없는 밝은 표정과 말투. 화목한 가정에서 평생 걱정없이 살았겠지?‘ 누군가와 비교하고 내 인생에 대해 불만족이 커질땐, 안진진을 떠올릴거다. 그럼에도 살아가면서 인생을 탐구하겠다던 안진진을. 같은 분량의 행복과 불행을 누려야 사는 것처럼 사는 것이라던 안진진을.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3815, 191, '진짜 사랑을 택하지 않고 현실을 택한,이모가 그렇게 떠나간걸 알면서도 이모부와 같은 남자를 택한 여자의 이야기', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3816, 191, '인간은 모순 투성이, 삶의 모순을 고민하게 만드는 소설', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3817, 191, '불행과 행복 삶과 죽음삶은 모순이다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3818, 191, '인생은 모순 속에서 선택하고 살아가고 있다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3819, 191, '타인의 삶은 함부로 평가할 수도 예단할 수도 없다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3820, 191, '인생의 책.인생은 모순이다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (192, '1Q84 1', 183, 4.32, 2, 8, 26, 40, 107, 147, 26, 10);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3821, 192, '오래전부터 읽어봐야지 싶어 묵혀둔 하루키의 소설이었는데 음,이상도 하지?너무 오랜 시간이 흘러 내가 나이를 먹은 탓인지? 겹쳐 읽기하고 있는 다른 작가 소설과 비교가 되어서인지?읽으면서 줄곧 갸웃거리게 된다.내가 알던 하루키씨 맞나요?몰입해서 읽은 걸 보면 하루키 작품이 맞긴 한데??', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3822, 192, '예전부터 관심가던 책이였는데... 아직까지 못 구매했다는...ㅠㅠ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3823, 192, '지인의 추천으로 읽게 된 책이다. 장르를 찾아보니깐 로맨스라고 나오는데 나는 아직 그런 분위기는 느끼지 못했다. 오히려 스릴러에 가깝다고나 할까? 덴고와 아오마메의 연결고리가 드러나는 부분이 무척 흥미로웠고 나머지 시리즈들도 읽어보고 싶다. 중간 중간 자극적인 묘사가 나와서 당황스럽기도 했지만 단순히 ‘야한 장면‘이 아니라 내용 전개에 무척 중요한 것이여서 거부감이 덜 했다. 나는 이 작가의 문체가 마음에 든다. 일본 고유의 문체인지 이 작가만의 특별한 문체인지는 일본소설을 읽은 것이 이번이 처음이라 잘 모르겠다. 여튼 이 작가의 다른 소설들도 찾아 읽어볼 생각이다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3824, 192, '상상력과 재미가 결합된 하루키의 소설! 일단 읽어보라. 빠질 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3825, 192, 'lunatic 과 insane두개의 나란한 달', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3826, 192, '할배 갈수록 교묘한 판매능력만 느네. 궁금증 유발 능력에 박수를. 잘 꾸며진 싸구려', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3827, 192, '다 좋은데, 표지가 너무 맘에 안들어 ㅠ', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3828, 192, '왜 그렇게 사람들이 많이 보는게 궁금해서 빌려 조금씩 읽기시작한게.. 단숨에 읽고 인터넷에 들어와있다. 일본소설이 이렇게 매력적으로 느껴진건 처음이다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3829, 192, '많은 분량이지만 지루함을 느끼지 않고 작품 속에 푹 빠져들었어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3830, 192, '정말 흥미롭게 읽었어요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3831, 192, '역시 베스트셀러가 될 만큼 뛰어난 작품임을 느끼게 되었습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3832, 192, '조금은 묵직한 주제의 소설이지만 단숨에 읽어내려 갔습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3833, 192, '역시 무라카미 하루키구나 하는 생각이 들게 한 작품이에요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3834, 192, '설정이 전작들과 유사한 부분이 많아서 신선도는 떨어지지만, 구성력이나 상상력 같은 부분은 전작들보다 뛰어난 듯', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3835, 192, '왕년의 흡입력이 돌아왔다..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3836, 192, '1권 읽음. 요란한 소문에 비해 너무 평범.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3837, 192, '하늘을 다시 봤다.. 혹시 달이 몇개인지.. 현실과 비현실을 넘나드는 자유로운 영혼', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3838, 192, '어떻게 이런 소설을 감히 쓸수 있을까 싶은 정말 감탄하게 하는 책이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3839, 192, '상실의 시대의 하루키는 좋은데.. 1Q84는? 하루키만의 방치된 유머(?)가 빠져있다', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3840, 192, '역시... 흥미롭다... 방대한 양을 엮는 기술 또한 ... 2편에 이어 3편이 어떻게 될까', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (193, '수상한 중고상점', 183, 4.35, 2, 5, 18, 60, 98, 158, 18, 7);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3841, 193, '˝거짓말도 다정하면 죄가 아니다‘ 독자평 때매 기대가 되네요 ㅎㅎㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3842, 193, '예전에 나온 가사사기의 수상한 중고매장의 재판입니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3843, 193, '마음이 따뜻해지고 미소가 지어집니다. 나의 중고상점은 어디일까? 나도 누군가의 중고상점이 될수있을까?', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3844, 193, '거짓말의 나라 일본의 또하나의 트렌드ㅇㅇㅇ 서점 시리즈현실이 지옥인 일본이 만든 허상에 속지말자', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3845, 193, '추천받아서 읽었는데 따땃하니 좋았습니다 ㅎㅎ 표지도 넘 이뻐요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3846, 193, '큰 재미가 없고 캐릭터가 이해되지 않아요', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3847, 193, '가사가기 중고상점에서 고교동창인 나(히구라시)는 일거리 제안에 넘어가 함께 공동경영자로 일한다. 가사사기는 ‘머피의 법칙‘을 몇 번이나 읽으며 범죄를 해결하는데...사건이라기보다는 에피소드에 불과하지만 의뢰인과 중고 물건에 얽힌 사연들이 밝혀지는 과정과 결과는 재미와 웃음을 자아낸다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3848, 193, '묘한 매력이 가득한 수상한 중고상점. 마음이 몰랑몰랑해지고, 때론 사람에게 피해가 안가는 하얀 거짓말이 살면서 누군가에게는 위로가 된다는 것을 제대로 보여준다. 물건을 파는 것보다는 사건 해결에 진심이 그들의 모습에서 인간미가 느껴진다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3849, 193, '읽기 시작한 것이 아까워 끝까지 보았고, 힐링을 기대하며 읽었으나 기대는 저 하늘 위로.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3850, 193, '11년전 소설이라고는 하지만, 큰 시대적인 차이가 느껴지지 않아서 요즘 소설이라고 해도 믿겠더라구요. 약간 유치한 부분이 없지는 않았지만 생각보다 재밌었습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3851, 193, '잔잔한 글들이 마음 속을 왔다갔다 합니다. 책 제목이 요즘 인기있는 책들에 편승한 기분이 들었는데 훨씬 이전에 나온 책이라고 하네요. 고단한 일상에서는 외려 이런 글들에 좀 기대어 쉬어가고 싶습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3852, 193, '머피의 법칙”영의 무생물 이동의 법칙의 의미를 묘하게 되새기한 소설. 오동나무, 청동상, 그리고 가재도구,기타몇개,스피커와 오디오, 값비싼 목재 가구도 수상한 가구점에서 매매가 이루어진다. 그 과정에서 사물에 얽혀진 비하인드 스토리와 감정에 관한 비유가 결코 가볍게 느껴지지 않는다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3853, 193, '물건에게도 기회가 있는데 인생도 다시 도전할 기회를 주는 책!! 남모르게 간직했던 사연까지도 해결해주는 환대와 위로를 경험해 보세요!!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3854, 193, '오늘도 정상 영업 중인 중고상점˝비싸게 사서 싸게 팝니다아픈 마음까지도 매입합니다˝손때 묻고 상처받은 물건도 반짝반짝 새것이 되는곳 수상한 중고상점에서 벌어지는 따뜻한 이야기!!!힐링되는 소설 감사합니다#다산북스#독서나눔#세포미인#팀독서경영#수상한중고상점', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3855, 193, '처음엔 약간 오잉(?)하며 읽었는데... 미스테리라고 하기엔 사건이 너무 잔잔하고, 주인공이 너무 쉽게 파악해버려서요... 그런데 그 모든 걸 극복하고 읽었던 마지막 장... 겨울 파트가 참 좋았습니다. 다 읽고 나니 괜찮은 따뜻한 이야기였다! 라는 생각이 들었습니다!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3856, 193, '일본 문학은 생소하고 낮선 소설이다하지만 이 수상한중고상점은 나에게 호기심을 자아내기에 탁월했다나에게 자기개발서의 노력함을 요하는 책이 아닌저자가 의도하는 상상의 나라를 펼치기엔 충분한 소설인듯하다특히 목록중 가을이란 대목에서 읽다보면가을-남쪽인연 에서 나오는 나미…', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3857, 193, '처음에는 이게 추리인가?? 라는 의문을 가졌지만..읽으면 읽을수록 왜 이런 추리를 했는지를 느끼게 하는 책~누구가의 수치심을 덮기 위해, 누구가의 순수함을 지키기 위해, 누군가의 아름다운 기억을 남겨주기 위해 하는 마지막 진실은 남겨두는 주인공... 마음이 따뜻해지는 소설이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3858, 193, '이쁜 표지만큼 잘읽히는 책이다. 서향의 향 이야기가 나왔을때, 그 진하고 달달한 향을 어떻게 알까?라는 생각을 했고, 독자로 하여금 힘들때 피식 웃게하는 그럼 힘이 있는 책이었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3859, 193, '일본 느낌이 물씬 나는 이 소설은 총 4편의 에피소드로 구성, 중고 물건을 거래 할 때마다 물건이 담고 있는 사연을 듣게 되고 해결까지 해주게 되는 내용을 담고 있다. 네번째 이야기인 주지스님의 양아들에 대한 사랑을 엿볼 수 있었던 에피가 기억에 남는다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3860, 193, '돈벌 의지가 없는 상점 주인들이라니 ㅎㅎ혹시 쉽지 않은 현실을 내려놓고 마음은 그래도 따뜻하게 만들고 싶을 때 읽어봄직 하다.예쁘고 눈이가는 표지에 먼저 호감이가고 주인공들의 다정다감함에 적당히 기분 좋게 읽어내려간다', 4);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (194, '7번 읽기 공부법', 183, 4.22, 9, 6, 24, 41, 103, 144, 24, 15);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3861, 194, '이런류의 책을 찾을 때는 대개 뭔가 동기부여가 필요해서 찾을 것이다. 하지만 이 책은 내용도 없고 동기부여도 안 된다. 별하나도 아깝다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3862, 194, '공부법 대한 일반적인 담론. 자기계발서에는 역시 큰 기대를 걸면 안되고 이런방법이 있다는것만 알면 성공한 독서라 볼수있을것 같다. 사실 책 목차만 읽어도 한권을 다 읽은것과 다름이없다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3863, 194, '애들이 셋이다 보니 학습법에 관심이 많이 가서 읽어 보았다. 회사원이 된 지금도 공부를 계속 하고 있지만, 7번 읽기를 통해서 사법시험과 행정고시 그리고 도쿄대 수석 졸업을 할 수 있었던 것은 본인에게만 맞았던 것이 아닐까 싶다. 각자의 몸과 마음에 맞는 방법은 따로 있지 않을까 싶다.', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3864, 194, '하나하나 외워가며 꼼꼼히 공부하는 스타일이었는데....늘 그렇게 하다보니 중간에 지쳐버리기 일쑤였어요. 그래서 모든 문제집이 중간에서 멈춰있죠. 그나마 7번읽기하니 처음부터 끝까지 뭔가 해나가고 있다는 느낌이 들어서 좋은데요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3865, 194, '고승덕책이랑 비슷하네요. 두사람 모두 공부에 있어서 지나치게 겸손하다는 것! 두사람 다 머리는 평범하거나 오히려 남들보다 못하다면서 학창 시절에 무려 전국일등 경험있는 것 까지 같네요~ 맥이 좀 빠지기는 했지만 .. 어쨌든 누구보다 열심히 했다는 점만은 배울만 합니다.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3866, 194, '빌려 읽었다.안 사길 잘했다.구매해서 볼 정도의 책은 아니다.빌려보시길!!', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3867, 194, '내용은 딱히 알찬내용은 없네요 기본에 자기계발서에에서 본듯한 내용들이 주를 아루네요. 핵심은 책제목입니다. 뭐든지 실천이 중요하죠^^', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3868, 194, '제목과 목차만 봐도 어느정도 알수있는 책', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3869, 194, '제목 외에 특별한것이 없을것 같은. 여러번 보라는 조언. 그래야 알게된다는 것.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3870, 194, '공부를 좋아하지는 않는다. 하지만 공부를 해야 했다고 저자는 말한다. 7번 읽기 쉬운일은 아니다. 하지만 처음부터 꼼꼼하게 뜯어보라는 것이 아니다. 공부해야하는 하는데 말만 하지않고 이번에는 진득하게 해봐야겠다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3871, 194, '그래, 너가 공부를 잘했다고하는데 그래서 뭐? 여기서 알려주는 작가의 공부방법보다도 중요한 것은 배움을 행하는 모든 개개인들에게 맞는 공부법은 따로 있다는 점. 이런 공부방법도 있구나 하고 참고하면 될 듯 .', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3872, 194, '자기 공부법은 이렇다고 말하는거지. 저는 결국 사람 각자마다 공부법이 있다고 생각합니다. 하지만 반복이 중요하지 않다고 말하신 분은 못봤습니다. 같은 분야 여러 책을 보든 한 책을 여러번 보든 여러분이 원하신대로 보세요. 그게 정답이구요.', 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3873, 194, '3년간 학원에서 고3 상대로 국어 영어 가르쳐봤다. 수능은 머리 좋은 놈들에게 너무 유리하다...', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3874, 194, '나름 나에겐 도움이 되었다. 읽는다기 보다는 뇌리에 새긴다는 표현이 적절한듯. 제목이 7번 읽기공부법이라 제각각 생각하는 ｀읽기｀를 기준으로 생각하게 되는거 같다. 그냥 읽기가 아닌 뇌에 새기는 방법인데..', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3875, 194, '내스타일 ㅋㅋㅋ하지만 공부 과목에 맞게융통성있게 적용시키기', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3876, 194, '공부를 목적이 아닌 수단으로 활용해야한다는 저자의 주장이 정말 와닿았는데 단순히 7번 읽어라가 아니라, 7번을 어떻게 효율적으로 읽어야한다는 점에서 분명 이득될게 있긴 하다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3877, 194, '음독할 시간에 묵독 더 하겠다. 인강 들을 시간에 책을 더 읽겠다. 교수님 말씀의 요지를 찾아 별표하고 밑줄 긋느니 그 말들을 빠짐없이 적어버리겠다. 틀린 문제 분석말고 해설만 더 읽겠다. 읽겠다. 많이 읽겠다. 시간 아까우니 더 읽자. 일단 의자에 엉덩이 붙이고 읽자!', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3878, 194, '저자의 정신력 하나는 확실히 본받아야겠어요. 사실 공부법이 별거 있겠냐만은.. 쉬운방법이라고 하고자 하는 의지를 배웠다는 점에서 만족해요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3879, 194, '7번 읽기 공부법으로 자신만의 공부법을 터득하는 것도 좋습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3880, 194, '대학 3 학년 때 사시패스 ㅡ 4 학년 때 행시 패스한 저자 ㅡ 동경대 수석 졸업자 ㅡ 그래서 뭔가 비결이 있나 하고 열심히 읽었으나 ㅡ 내용은 그냥 7 번 읽어라 ㅡ 그러면 저절로 멍청한 사람도 내용이 외워진다 ㅡ 는 식의 문과주의자의 공부 습관 ㅡ 1 번 읽고 바로 팔아먹음', 1);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (195, '지도로 읽는다 중국 도감', 182, 4.81, 0, 0, 5, 25, 152, 177, 5, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3881, 195, '중국이라는곳을 각각의 성 단위로 나눠 역사와 문화를 파악해야 중국 대륙이라는 전체 그림, 하나의 문명권으로 이해할수 있게 도와주는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3882, 195, '슈퍼차이나의 시대이기에 중국의 모든 것을 정리한 도감이라니, 중국에 관심 있는 이들에게 도움이 될 책이네요. 중국은 워낙 방대하기에 한 권으로 담기엔 버겁지 않나 싶었는데요. 마카오까지 담았다니, 대단해 보입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3883, 195, '주마간산이라도 유익! 이름 알아도 위치 가물가물한 도시들 점검하고, 네이멍구나 광시좡족자치구처럼 평소 관심 안 가는 성들도 훑어보고, 중국인들 갖고 있는 각 성에 대한 이미지/느낌도 알게 되고. 론리플래닛 느낌 나는 간단하고 위트 있는 설명 좋고, 나름 세련된 거리두기 감각도 높이 살만.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3884, 195, '중국을 구성하는 34개의 기본행정단위를 퍼즐로 만들어 각 구역의 특징을 쉽게 이해할 수 있도록 한 점이 마음에 듭니다 단편적으로만 생각했던 중국 관련 지식을 자세하게 알려줘서 좋네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3885, 195, '원서를 찾아 보니 2001년 간행된 일본책이군요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3886, 195, '거품이라고 하지만, 중국은 꼭 알아두어야 하는 나라인 것 같아요. 지도를 통해 대륙을 알아가고 싶어요!', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3887, 195, '중국은 34개로 나눠서 각 특징들을 알려준다는게 참신하네요. 중국을 통째로 이해하는 것보다 나눠서 이해를 하는 것이 더 좋은 것 같습니다. 각 구역의 중심지로 여행을 떠나고 싶어지네요. 지도를 통해서 중국의 역사와 문명을 알수 있어서 더욱 뜻깊습니다. 강추!!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3888, 195, '지도도 자세히 수록되어 있고 그래서 중국을 이해하는 데 좋을 것 같네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3889, 195, '가깝거나 먼 나라 중국에 대해 자세히 알 수 있는 책 같아요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3890, 195, '대륙 하나의 구가 미국의 웬만한 주하고 맞먹을 만큼 땅덩어리가 큽니다. 아무튼 그에 비해문화적으로는 아직까지 아닙니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3891, 195, '하나로 설명할 수없는 넓은 나라 중국을 지역별로 나눠 설명해 놓아 중국을 이해하기 좋을것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3892, 195, '요즘 TV에서 많은 중국 지명을 듣는데,어디에 있는건지 알수없을때가 있는데 이렇게 정리해놓으니 도움이되겠습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3893, 195, '지도와 사진들이 같아 구성되있어서 재미있게 읽을 수 있을 것 같네요 기대됩니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3894, 195, '중국은 하나의 나라가 아니라 하나의 문명으로 이해해야 한다고요? 중국의 많은 인구가 어떻게 구성되는지 궁금해집니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3895, 195, '중국은 하나로 설명할 수 없는 복잡한 나라죠. 중국을 근본적으로 이해하는데 많은 도움을 줄 수 있을 것 같습니다. 이렇게 체계적으로 자세히, 지형을 기본바탕으로 중국을 설명하는 책은 없었으니까요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3896, 195, '중국을 막연히 큰 나라로만 생각했는데 우리와 가까운 나라이기 때문에 지역별로 문화와 특징을 알아두면 좋을 것 같습니다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3897, 195, '중국에 관련된것들을 34개의 퍼즐로 완성한다는 점이 흥미롭고 중국 전체 지도를 이해하는데 많은 도움을 주는것 같습니다!중국에 대해 관심있는 사람들에게 특히 좋은 책같고 매우 기대됩니다!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3898, 195, '가까우면서도 G2가 된 중국. 그럼에도 이나라에 대한 지명은 널리 알려져 있지 않다. 그런면에서 이 책은 도움이 된다. 중국 각 성들과 직할시, 자치구들을 지도와 함께 하나하나 살피며 정보를 제공한다. 그런데 너무 많아 막상 뭔가 남는게 적다는게 아쉬운 현실', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3899, 195, '중국의 방대한 지역을 34개로 보니까 그나마 좀쉽게 접근할수잇을듯', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3900, 195, '중국에 대해 한권으로 알아볼 수 있다니 좋아요', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (196, '성균관 유생들의 나날 1', 182, 4.55, 2, 1, 13, 44, 122, 166, 13, 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3901, 196, '요거 드라마로 너무 재밌게 보고 소설을 읽었는데 소설도 정말 재밌더라구요, 이 책을 읽고 정은궐이라는 작가를 알게 되고 다른책들도 재밌게 읽은 기억이 나네요, 역사를 배경으로 한 달달한 로맨스 소설로는 짱인듯^^', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3902, 196, '드라마보다 책이 더재밌다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3903, 196, '책을 펼치면 나를 조선이라는 낯설지만 익숙한 그 때 그 곳으로 보내주던 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3904, 196, '전부터 매우 재미있게 본 책,진짜 완전 재밌는책.ㅋ잘금 4인방은 완전 갠소임.-_-*', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3905, 196, '남장 여자 유생의 유쾌한 남자 유생들과의 동거 이야기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3906, 196, '우와!!! 대박!!! 한동안 이보다 재미있는책 찾기 어려울듯...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3907, 196, '여인이 포함된 조선 4인방 로맨스물, 칭찬일색이지만 그저그럼 로맨스팬이라면 권함', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3908, 196, '진짜 책읽다가 미친듯이 웃고 자지러진 책은 처음이다. 진짜 나만 숨겨놓고 보고싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3909, 196, '이거 믹키유천이 드라마 찍는데 ㅋㅋ', 1);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3910, 196, '주제도 신선하고 스토리도 탄탄하고 1권읽으면 2권 기다려지는게 재밌어요ㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3911, 196, '진짜재미잇음ㅋㅋㅋㅋ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3912, 196, '한마디로 너무재미있는데 왜 자꾸 문근영의 이쁜 얼굴이 겹치는지.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3913, 196, '성균관 스캔들의 원작 달달함을 넘어 까무라칠 정도의 재밌는 드라마 그리고 책~!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3914, 196, '조선의 성균관에 대한 전방위적 기록이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3915, 196, '사놓고선 아직 읽지 않았다는... 그런데 드라마를 보고있어서 언제읽을런지..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3916, 196, '정은궐님을 알게 해준 작품 짜임새있는 스토리와 눈에 그릴듯한 묘사.. 그리고 통통튀는 제각각의 캐릭터들... 너무 재미있었어요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3917, 196, '드라마나 책이나 정말 최고중에 최고의 책!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3918, 196, '성균관을 눈에 그릴 수 있을 듯 생생한 고증과 고증이 빛나는 드라마.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3919, 196, '당시 성균관의 모습 속에 유쾌하고 달콤한 캠퍼스 러브 스토리 ! 술술 넘어가네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3920, 196, '내가 주인공과 함께 매 사건 뛰어다니는 듯한 생생한 묘사와 작가가 부지런히 공부하며 쓰는구나 싶은 성실함도 읽혀져 좋았습니다', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (197, '유대인 생각공부', 181, 4.76, 1, 1, 6, 25, 148, 173, 6, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3921, 197, '유대인의 특징은 절망에서도 희망을 가진다는 거죠. 이 책을 통해 유대인들의 남다른 재테크 방법, 부자들의 사고방식, 남다른 생각들을 익힐 수 있기에 그들의 생존력이 강한 이유를 알 수 있답니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3922, 197, '자잘한 지혜를 창의적 사고로 전환시켜 부의 크기를 키우는 유대인들에게 배울점이 많습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3923, 197, '책을 보면 유대인의 생각이 남다름을 볼 수 잇어요. 조상대대로 내려오는 탈무드 교육이 밑바탕에 있겠지만 유전자도 남다른 것 같아요. 근면하고 성실한 유대인들은 절망 속에서도 늘 희망을 갖기에 험난한 세계사 곳에서도 살아남았죠. 유대인의 지혜, 상술, 부자되는 법 등을 알 수 있는 책입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3924, 197, '유대인은 세계 역사에서 굉장히 중요한 부분들을 차지하고 있으면서도 그들이 어떻게 그렇게 되어왔는지 연구한 책은 드물었는데 고무적인 책이네요. 탈무드를 통해서 유대인들의 생각을 조금 엿보았다면 이 책을 통해 객관적이고 분석적으로 알 수 있는 기회같아요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3925, 197, '유대인을 특별하게 만드는 남들과는 다른 그들의 생각의 차이를 배워 볼 수 있을 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3926, 197, '유대인 생각 공부라니. 생각을 공부한다는 관점 자체가 매우 독특하고 참신하게 와닿습니다. 최고의 브레인으로 손꼽히는 유대인들의 생각을 배워보고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3927, 197, '유대인들 중에 특히 세계적으로 성공한 사람이 많은데, 그들의 생각을 배우고 싶네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3928, 197, '항상 빌게이츠, 워렌버핏,같은 유명하신 분들을 우상으로 삼으며 그분들의 자서전을 많이 읽어보았습니다. 이 책은 그분들에 대해서 구체적인것을 말해주지는 않지만 그분들이 그렇게 될수있었던 환경에 대해서 구체적으로 알게 될수있을거같은 느낌이 듭니다. 세계를 움직이는 종족 유대인.....', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3929, 197, '한동안 유대인의 교육법이 인기였는데 이 책은 유대인의 성공비법이네요. 세상을 바꾼 5가지 물품이란 책을 보면 유대인들이 참 새로운 아이디어로 돈을 벌던데요. 이 책의 3번째 창의적인 사고가 구체적인 사고다가 거기에 해당한다 싶어요. 부자 유대인이 어떻게 부자가 되었는지 궁금해서 읽어봄.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3930, 197, '세계의 부를 지배하는 유대인들의 생각방법 그저조언들', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3931, 197, '세계를 조종하고있는 유대인. 그들의 저력이 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3932, 197, '맹목적인 유대인의 경제관을 지지하는것은 아니지만, 좋은점을 취하고, 나쁜점은 버릴수 있는 지혜를 배우기에 좋은 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3933, 197, '어떤 일이나 직업을 가지든 필요한 조언들!!! 부와 지혜의 비밀 궁금합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3934, 197, '단순암기와 거기에 따른 시험에만 익숙해져버린 이 때, 이 책을 이제서야 접하게 된 것이 못내 아쉽기만 했다. 지금부터라도 9가지 생각법을 습관화하는 버릇을 들이고 싶다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3935, 197, '세계를 이끄는 유대인 경제력의 힘이 어떤 생각으로 이루어졌는지 그 단초를 알수있게 하는 책이네요~~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3936, 197, '유대인을 대표하는 부, 창의력, 인맥을 통해 성공으로 가는 길을 알려줍니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3937, 197, '정말이지 아직까지도 미국사회의 상층부는 대부분이 유대인의 영향력을 무시할수 없으며 노벨상인물로도 거론이 많이 되고 있지요 그만큼 유대인에 대한 공부는 꼭 해야 되는거 같은데 이런 책이 나와 기쁘네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3938, 197, '세계를 지배하는 유대인. 무엇이 그들을 특별하게 만들었나 궁금한데.책을 통해 그들의 남다름을 볼 수 있을 것 같습니다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3939, 197, '책에서 유대인들이 좋은 상황이 아닌 곳에서 어떻게 성공할 수 있었는지에 대한 특징과 그들의 사고 방식 행동들의 핵심 내용과 표현이 잘 자술되어 있어서 좋은거 같습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3940, 197, '삶 속에서의 지혜를 유대인을 통해 배울 수 있어서 좋습니다. 평소에 만날 일이 없는 부자 아저씨의 조언을 듣는 기분이네요.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (198, '애프터 피케티', 181, 4.84, 0, 0, 6, 17, 158, 175, 6, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3941, 198, '부의 불평등을 해결할 비법이 들어있는 지성들의 대답인데요. 피케티의 이후 3년간의 부의 불평등에 대한 해법이 들어있습니다. 하지만 부의 불평등이 점점 심화되고 있기에 그 방법은 쉽지않지요. 여하튼 읽을 가치가 있는 책입니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3942, 198, '하버드대학 특별 프로젝트 21세기 자본이 제기한 문제 21개 주제로 나눠 각계 전문가들의 검증을 통해불평등의 진단과 해법 부의 불평등에 대해 시대 지성들의 혜안과 통찰력이 담긴책입니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3943, 198, '과거에 우리는 몰랐습니다. 이 사회를 지탱하는 부의 진실을. 하지만 이젠 다릅니다. 피케티가 말하는 불평등을 듣고 인지하여 그의 목소리에 동참해봅시다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3944, 198, '부의 계층으로고착하되고 있는 한국에서도 적용할수 있을지 궁금하네요', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3945, 198, '˝21세기 자본˝이 제기한 문제에 대한 전문가들의 답변이 정말 궁금해지네요. ˝부의 불평등을 어떻게 해결할 것인가?˝ 최고의 지성들의 응답이 기대됩니다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3946, 198, '부의 개념과 그 결과가 낳은 불평등에 관하여', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3947, 198, '맨큐는 학부 애들 질문에도 답을 못 하고 딴소리하고. 누가 누구를 뭐라고 하는 지.', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3948, 198, '부의 불평등에 대한 각 분야 최고의 경제학자와 사회과학자들의 의견을 들어볼수 있을것같아요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3949, 198, '21세기 자본이 얘기된 피케티의 저서가 나온지 3년이 지난 시점에서 부의 불평등은 과연 얼마나 극복되었을까요. 갈수록 심화되는 부의 불평등이기에 누구나 관심가질텐데요.사회학자와 경제학자의 시각이 아니더라도 부의 불평등은 관심이 있기에 읽게된 책입니다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3950, 198, '그어떤 방법으로도 부의 불평등이 해결 될것 같지는 않네요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3951, 198, '‘불평등의 진단과 해법‘이라는 난제에 대해서 각계 전문가들이 어떤 해답을 내놓았을지 무척 궁금합니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3952, 198, '책 ‘애프터 피케티‘ 는 현 경제적 삶에 무엇이 잘못 됐는지, 불평등의 21세기 자본의 논리를 통해서, 현제의 나에 삶을 관통해 주는 깊은 의미의 활자 한 페이지 한 페이지가 피부로 전달해주지 않을까 싶습니다.지금 내가 밟고 있는 이 곳의 삶을 새롭게 되세김질 해주듯 말이지요.고마워요~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3953, 198, '부의 불평등을 해결하기 위해서는 어떤 노력들과 변화가 있어야될 지 알 수 있는 시간이 되네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3954, 198, '경제에 관심이 많은데 최근 경제사에서 가장 광범위한 논의가 이루어진 책이라고 하니 경제에 대한 시야가 넓어질 수 있을 거 같고 무슨 내용인지 궁금해서 구매해서 읽어봐야겠습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3955, 198, '재작년인가 ‘21세기 자본‘을 읽었고, 작년에 ‘세금혁명‘을 읽었습니다. 솔직히 저에겐 참 어려운 책이어서 읽고 또 읽고 했네요. 이 책은 앞선 책에 대해 다른 석학분들의 의견을 적어놓은 거라 또 다른 지식과 생각거리를 주네요. 저에겐 여전히 어렵지만 이번에도 읽고 또 읽어보렵니다. ㅎ', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3956, 198, '부를 어떻게 나눌 것인가는 역사적으로 참 많은 논쟁이 되어왔는데 이번 기회에 이 책을 읽으면서 다시 정리하고 싶습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3957, 198, '경제학계에서 변두리로 밀려났던 불평등이라는 철이 지난 듯한 주제가 다시 경제학의 핵심 주제로 떠올랐다. 자신만의 아지트에 파묻혀 놀던 경제학이 다시 정치와 사회 같은 사회과학의 영역으로 연결되는 계기도 됐다. 이런 점을 살펴 보는 것만으로도 이미 애프터 피케티의 공은 적지 않을 것이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3958, 198, '한동안 유명했던 피케티의 주장을 다시 점검하고 부의 양극화로 인해 생기는 문제들을 해결할 수 있는 방안이 무엇인지 조금이나마 알 수 있었습니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3959, 198, '늘 항상 궁금했던 주제입니다. 왜 부는 불평등하게 배분이 되는 것인지. 부의 불평등을 이 책은 어떻게 해석하고 어떤식으로 풀어나가는지 궁금했던 많은 질문을 시원하게 해결하고 배울 수 있는 책이었으면 합니다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3960, 198, '여러 석학들의 대담을 통해 많은 것을 깨닫고 능동적으로 해결해 나갈 수 있었으면 좋겠습니다. 조금 어렵게 느껴지기도 하지만 많은 도움이 되리라 기대합니다.', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (199, '자기 앞의 생 (특별판)', 181, 4.66, 0, 0, 4, 54, 123, 177, 4, 0);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3961, 199, '검은색 안에 흰색과 흰색 안의 검은색을 헤아려 보게 하는 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3962, 199, '자신을 둘러싼 상황과 여건이 안좋을지라도 그 안에서 감사할 것들을 발견하고 사랑할줄 아는 주인공 모모의 모습을 보면서 저 자신은 어땠는지 돌아보게 되었습니다. 유한한 인생속에서 주변 사람들을 좀 더 사랑하고 품을 수 있는 넓은 마음을 가지길 바라는 작가님의 마음이 느껴졌습니다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3963, 199, '｀사랑해야만 한다｀가 소설의 핵심으로 보인다. 사랑없이 살 수 있을까? 살 수는 있을 것이다.그들은 내게 말했다.˝넌 네가 사랑하는 그 사람 때문에 미쳐버린 거야.˝나는 이렇게 대답했다.˝인생의 참 맛은 그런 사람들만이 알고 있는걸.˝', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3964, 199, '제목 때문에 읽어보고싶어진 책~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3965, 199, '사랑이 삶을 관통하듯, 책 말미에 ˝사랑해야 한다.˝는 이 책을 관통하고 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3966, 199, '˝사람은 사랑할 사람 없이는 살 수 없다˝', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3967, 199, '이 염세적인 세상에서..사람은 사랑 없이는 살 수 없구나.. 라는 진부한 진실을 다시 느끼게 해 준 책.열악한 상황에서도 모모의 앙큼한 순수함과 가난한 이웃의 인간적인 정이 보석처럼 빛난다..', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3968, 199, '무심한것 같으면서도 극적인 내용. 사랑없이는 살 수 없다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3969, 199, '지금도 다시 읽고 싶어지는 책.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3970, 199, '읽은 지 10년 가까이 된 작품. 다시 읽어야 할 책', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3971, 199, '다시 태어나면 개로 태어나고 싶다라는 주인공의 말, 가슴에 깊게 와닿는다.생(生)이 주어진 것이 때로 축복이 아니라면...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3972, 199, '에밀 아자르이든, 로맹 가리이든 그는 일급소설가다. 그가 쓴 자신의 어린 시절을 그린 자전적 소설. 아름답고 슬프고 아픈 소설.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3973, 199, '소중한 이와 헤어져도 살아갈 수 있는 방법은 ''사랑해야 한다'' 오직 그것 뿐이다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3974, 199, '책을 다 읽은 사람만이 느낄 수 있는 감정이 있다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3975, 199, '벼르고 벼르다 드디어 읽게 된 책.작가에 대해 먼저 알게 되어 읽은 책이지만책을 다 읽은 지금, 작가에 대해 더 알고 싶어졌습니다.다른 책들도 이어서 읽어보려구요~', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3976, 199, '그럼에도 불구하고, 살아야겠다. 살아있는 한 열심히 사랑해야겠다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3977, 199, '생이라 적고 죽음을 이야기 하는 책. 살아 있는 한 사람은 사랑하며 사는것. 로자의 곁을 지키는 모모... 그래도 모모는 자기앞의 생을 꿋꿋하고 의연하게 살아낼 것 이라고 믿는다', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3978, 199, '生의 계속됨.... 무겁지 않으면서 생각이 많아지는~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3979, 199, '고등학교때 읽고 친구의 추천으로 다시 읽게된 책. 책은 역시 타이밍인듯...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3980, 199, '이유를 설명하긴 힘들다', 5);
INSERT INTO BR_BOOK (NO, TITLE, REVIEW_COUNT, AVG_RATING, DIST1, DIST2, DIST3, DIST4, DIST5, POS_COUNT, NEU_COUNT, NEG_COUNT) VALUES (200, '천 개의 찬란한 태양', 181, 4.64, 1, 1, 7, 44, 128, 172, 7, 2);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3981, 200, '이 작가는 왜 이리 가슴 아픈 소설만 쓰는걸까 너무 아파서 외면하고 싶은 아프간 이야기', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3982, 200, '여자로 태어나 이슬람권이 아닌 이나라에서 살고 있다는 것에 감사한다. 억압받고 차별당하는 아프간여성들에게 평화가 있기를 기원하게 하는 이야기', 3);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3983, 200, '하 너무 좋았던..현실을 느낄 수있었던 책주인공이름을 못외우는 나인데도 주인공이름을 외우며 마음졸이며 단숨에 읽었던 책근데지금은 그글이 사라져버려서 안타깝다 다시읽고 독후감다시써야지', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3984, 200, '나나는 마리암에게 ˝북쪽을 가리키는 나침반 바늘처럼, 남자는 언제나 언제나 여자를 향해 손가락질을 한다...˝라고 말한다~', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3985, 200, '읽은지 몇년이 지났지만, 마리암에게 내가 무언가 해주어야 한다는 책임감을 느낀다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3986, 200, '그렇게 천시하는 여성들이 없었다면 이 세상은 이미 사라지고 없었을 것 같다.폭력과 억압과 멸시와 천대속에서도 여자들을 앞으로 전진시키는 힘의 원천은 무엇일까.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3987, 200, '할레드 호세이니의 작품은 흡입력이 있다.연을쫓는 아이보다 천개의 찬란한 태양이 더 마음이 아프다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3988, 200, '이 책을 읽고 할레드 호세이니 팬이 됬습니다. 총 3권의 아프가니스탄의 관한 소설을 쓰셨던데, 세권중에 가장 마음에 들어요. 아프가니스탄 어딘가에서 실제로 일어나고 있을 것 같은 느낌. 책 정말 좋네요', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3989, 200, '……우리는 저기에 있는 벽과 같다네. 부서지고, 쳐다봐야 아름다울 것도 없겠지만, 아직도 저렇게 서 있지 않은가……라일리, 우리 아프간 사람이 쳐부술 수 없는 유일한 적이 있다면 그건 우리들 자신이란다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3990, 200, '제목이 멋져요. 천개의 찬란한 태양이라니...', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3991, 200, '수 년 지나 다시 읽었는데 더 감동적이었다. 처음엔 온통 놀라움으로.. 다음에는 깊게', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3992, 200, '압도적인 이야기의 힘. 뻔히 예상했던 줄거리지만 그럼에도 눈을 뗄 수 없었다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3993, 200, '아프가니스탄 여성의 삶이란 가능한 것인지. 반대의 상황이라도 나는 버티지 못할 것 같은데. 마음이 아프고 현실보다 리얼하다는 게 이런 게 아닌지 생각하게 한다.', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3994, 200, '아프가니스탄의 생활상을 그대로 표현한책연을쫓는 아이와 이 책 이후 작가의 다음책을 오랫동안 기다렸다', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3995, 200, '지구의 어딘가에 이런 곳이 있다는 사실이 가슴아프다.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3996, 200, '감동적인 책이다. 아프간의 여성들의 비참한 삶을 너무 생생히 묘사했다!!', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3997, 200, '내용도 제목만큼 멋진 소설', 4);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3998, 200, '전쟁의 극한과 무자비한 폭력 속에서도 빛을 발하는 두 여인의 숭고한 사랑, 우정', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (3999, 200, '이슬람판 ''여인잔혹사'' 같아요. 읽는 동안은 물론, 읽은 후에도 가슴이 아프네요.', 5);
INSERT INTO BR_REVIEW (NO, BOOK_NO, CONTENT, RATING) VALUES (4000, 200, '감동이었어요....', 4);
